-- Poems batch 232
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f4810b58-9012-41f2-a2b3-861fd16722e7','次韻田園居','方岳','宋','宋诗','song-poetry','','[]','带郭林塘儘可居，秫田雖少不如歸。',64,'全唐诗/poet.song.212000.json','["带郭林塘儘可居，秫田雖少不如歸。", "荒烟五畝竹中半，明月一間山四圍。", "草卧夕陽牛犢健，菊留秋色蟹螯肥。", "園翁溪友過從慣，怕有人來莫掩扉。"]'),
('000ca2b0-3d83-4ef1-951f-f2630ef99b50','次韻閒中','方岳','宋','宋诗','song-poetry','','[]','玲瓏壓轡繫絨鞍，付與詩人洗眼看。',64,'全唐诗/poet.song.212000.json','["玲瓏壓轡繫絨鞍，付與詩人洗眼看。", "老子只憑雙脚健，梅花相對一溪寒。", "吾生焉往不三黜，此樂未央并四難。", "併與竹間孤鶴語，倦飛底用插脩翰。"]'),
('5d609fd7-da64-4e6d-8ced-affe1b904a3f','牛庵睡起','方岳','宋','宋诗','song-poetry','','[]','自束生芻起飯牛，隔林扣角更深幽。',64,'全唐诗/poet.song.212000.json','["自束生芻起飯牛，隔林扣角更深幽。", "半分不得詩書力，一飯常存𤱶畝憂。", "老去有腸堪貯酒，生來無骨可封侯。", "開荒厓下田無幾，種秫寧須與婦謀。"]'),
('5ff9dbbe-09ba-47e4-b002-7aab05d883a2','牛庵後古松五株','方岳','宋','宋诗','song-poetry','','[]','山中老子一間屋，屋後秦人五大夫。',64,'全唐诗/poet.song.212000.json','["山中老子一間屋，屋後秦人五大夫。", "丘壑得專閒日月，衣冠甚偉古眉鬚。", "計今當是百年物，著我添成六老圖。", "已有茯苓巢可俯，待烹石鼎療詩癯。"]'),
('9d496546-e27b-4614-b194-92cab0663a2e','竹下','方岳','宋','宋诗','song-poetry','','[]','松陰竹影當行窩，日日扶筇一再過。',64,'全唐诗/poet.song.212000.json','["松陰竹影當行窩，日日扶筇一再過。", "與世無求干牘少，對人可語笑談多。", "一夔一契付公等，某水某丘如我何。", "歲晚只愁年穀盡，杞其毋棘菊毋莎。"]'),
('e7a7b1ec-48be-4711-b7cd-8a5bd6fbcfb4','山行','方岳','宋','宋诗','song-poetry','','[]','野鶴相將拄杖前，倚松穿竹各欣然。',64,'全唐诗/poet.song.212000.json','["野鶴相將拄杖前，倚松穿竹各欣然。", "山行一匝又一日，雲作四鄰今四年。", "名教之中元有地，吾心以外別無天。", "平生老僕猶疑我，不是凡夫不是僊。"]'),
('0c1a9cef-c527-4697-a043-1acef4852af8','山中  其一','方岳','宋','宋诗','song-poetry','','[]','久無筋力踞虬龍，西崦東塘漫倚筇。',64,'全唐诗/poet.song.212000.json','["久無筋力踞虬龍，西崦東塘漫倚筇。", "白練带隨紅練带，木夫容並水夫容。", "寧消幾兩生前屐，忽憶當年飯後鐘。", "孤負草堂今夜月，徑眠誰與吐奇胸。"]'),
('f24b57c9-3e21-4069-9646-9601ee6cb110','山中  其二','方岳','宋','宋诗','song-poetry','','[]','解纓聊復濯滄浪，晞髮松陰蘚石床。',64,'全唐诗/poet.song.212000.json','["解纓聊復濯滄浪，晞髮松陰蘚石床。", "有味是貧琳館俸，無功於懶玉函方。", "自參老子鼻端白，未羨諸公腰下黄。", "蔗境漸佳惟習靜，筆床茶竈併荒唐。"]'),
('dc6e3f07-bc2c-444e-8d57-8cc3a5c0a8f0','山中  其三','方岳','宋','宋诗','song-poetry','','[]','已付身心畢竟空，念頭了不到窮通。',64,'全唐诗/poet.song.212000.json','["已付身心畢竟空，念頭了不到窮通。", "既愚寧免日三省，是聖未妨時一中。", "物外禽魚相爾汝，生前烏兔幾西東。", "誰云雙手都無用，自種山田歲便豐。"]'),
('1808d116-55b5-4216-8833-18f1292f9f81','探梅','方岳','宋','宋诗','song-poetry','','[]','穿林傍水幾平章，合有春風到草堂。',64,'全唐诗/poet.song.212000.json','["穿林傍水幾平章，合有春風到草堂。", "自入冬來多是暖，無尋花處忽聞香。", "枝南枝北一痕月，山後山前兩屐霜。", "直看過年開未了，醉吟且放老夫狂。"]'),
('0b126361-01f3-410c-ad69-286c41a21710','梅邊約客','方岳','宋','宋诗','song-poetry','','[]','昨日今日雪欲落，一梢兩梢梅正開。',64,'全唐诗/poet.song.212000.json','["昨日今日雪欲落，一梢兩梢梅正開。", "携壺野亭醉復醉，折簡故人來不來。", "山翁意重百金值，俗士面有三寸埃。", "臨風歎息重歎息，玉飛片片相徘徊。"]'),
('cc23487e-b7a5-468e-bdb6-a2506537695d','與客觀雪  其一','方岳','宋','宋诗','song-poetry','','[]','鶴帳奇寒被欲冰，開門千嶂雪崢嶸。',64,'全唐诗/poet.song.212000.json','["鶴帳奇寒被欲冰，開門千嶂雪崢嶸。", "頻年無此豐年玉，一夜移將不夜城。", "富貴園林行樹密，模糊水墨畫圖橫。", "與詩小住爲佳耳，莫管梅花太瘦生。"]'),
('b0124b1b-3a84-4f2d-b5de-40c9c87c19ff','與客觀雪  其二','方岳','宋','宋诗','song-poetry','','[]','未怕風威酒亦冰，憑虛吞以氣崢嶸。',64,'全唐诗/poet.song.212000.json','["未怕風威酒亦冰，憑虛吞以氣崢嶸。", "何人出此六奇計，我輩賢於五字城。", "松壓釣簑銀獨速，麥分棋局玉縱橫。", "自然石鼎煎魚眼，解致鄒枚漢兩生。"]'),
('ccf2027c-adef-4c31-91c8-c5303edc0554','與客觀雪  其三','方岳','宋','宋诗','song-poetry','','[]','肺渴初供醒酒冰，又思携客上崢嶸。',64,'全唐诗/poet.song.212000.json','["肺渴初供醒酒冰，又思携客上崢嶸。", "十分宇宙無塵事，一色瓊瑶是化城。", "病起未堪論斗醉，詩狂且莫到參橫。", "剡溪可是忙回棹，凍合琉璃作麽生。"]'),
('bd77c91f-19dc-4037-a4b4-33af63a9bdff','次韻梅花  其一','方岳','宋','宋诗','song-poetry','','[]','歲晚何人肯卜鄰，梅於我輩最情親。',64,'全唐诗/poet.song.212000.json','["歲晚何人肯卜鄰，梅於我輩最情親。", "兩山盡是經行處，一雪不知多少春。", "先後花隨人意思，橫斜枝寫月精神。", "寒香嚼得成詩句，落紙雲烟行草真。"]'),
('69edc35a-8e93-4c0a-a3ec-52ebeb8f3e15','次韻梅花  其二','方岳','宋','宋诗','song-poetry','','[]','雲藏山塢塢藏梅，春意適從何許來。',64,'全唐诗/poet.song.212000.json','["雲藏山塢塢藏梅，春意適從何許來。", "天與此翁娛寂寞，日携扶老上崔嵬。", "草堂須小難爲客，霜月正高誰與杯。", "分上下番開自好，登臨且莫遣詩催。"]'),
('8988da76-33f4-49a3-83c7-fb69adf6bb34','次韻鄭總幹  其一','方岳','宋','宋诗','song-poetry','','[]','底須咄咄漫書空，未覺人間欠此翁。',64,'全唐诗/poet.song.212000.json','["底須咄咄漫書空，未覺人間欠此翁。", "黄犢自隨諳寂寞，青山亦諱話窮通。", "人方怒及水中蟹，我亦冥如天外鴻。", "醉眼不知人幾品，久將樵牧等三公。"]'),
('d58b2809-c10f-41ab-8969-1c34d0c26559','次韻鄭總幹  其二','方岳','宋','宋诗','song-poetry','','[]','我亦思兮天一涯，樊川詩老此曾家。',64,'全唐诗/poet.song.212000.json','["我亦思兮天一涯，樊川詩老此曾家。", "九夫容隔秋風浦，一獨速眠春雨蛙。", "竹屋有燈誰與共，秫田可釀不須賒。", "何年又賦高軒過，豆粥猶能辦咄嗟。"]'),
('be393568-ca71-4188-8172-0c793d0d57e1','次韻鄭總幹  其三','方岳','宋','宋诗','song-poetry','','[]','過從一笑酒瓶空，不是樵翁即釣翁。',64,'全唐诗/poet.song.212000.json','["過從一笑酒瓶空，不是樵翁即釣翁。", "偶種竹成俱崛强，旋移花活尚神通。", "前身已化歸遼鶴，醉帖猶傳戲海鴻。", "新貴少年吾自老，世間白髮幾曾公。"]'),
('ed76d4a8-321b-48d5-93c0-365d3898d9b3','次韻鄭總幹  其四','方岳','宋','宋诗','song-poetry','','[]','蟻丘得喪事無涯，冷眼難瞞老作家。',64,'全唐诗/poet.song.212000.json','["蟻丘得喪事無涯，冷眼難瞞老作家。", "公等功名千里馬，山居鼓吹兩池蛙。", "牛羊野逕通村近，虎豹天關去國賒。", "本是秋風釣竿手，故吾猶在復何嗟。"]'),
('898b503e-aa23-4352-b791-ac44ff50c9bc','宿多景樓奉簡吳總侍','方岳','宋','宋诗','song-poetry','','[]','客懷孤倚夕陽樓，烟老平蕪岸岸秋。',64,'全唐诗/poet.song.212000.json','["客懷孤倚夕陽樓，烟老平蕪岸岸秋。", "往事六朝南北史，晴江一片古今愁。", "嘅其嘆矣山吞吐，何以酬之酒拍浮。", "此意政須諸老共，容分蘆雨寄漁舟。"]'),
('e7f1671c-18f6-41f2-b7bf-0a9d1d8a1674','書戴式之詩卷','方岳','宋','宋诗','song-poetry','','[]','七十行年戴石屏，同時諸老各凋零。',64,'全唐诗/poet.song.212000.json','["七十行年戴石屏，同時諸老各凋零。", "扁舟歸去自漁舍，冷骨秋來更鶴形。", "天地無情頭盡白，江山有分眼終青。", "剡溪定有人乘興，月下柴門不用扃。"]'),
('c89e7d5f-46f2-4594-b229-b2bb28c58bee','石孫受命','方岳','宋','宋诗','song-poetry','','[]','聖澤如春雨露寬，棄遺猶不絕衣冠。',64,'全唐诗/poet.song.212000.json','["聖澤如春雨露寬，棄遺猶不絕衣冠。", "萬釘寶带翁無分，一幅花綾孫有官。", "得免白丁何啻足，親曾黄甲不堪看。", "九經幸自瀾翻熟，但守青燈雪屋寒。"]'),
('ac2a4292-024b-4133-b17b-077d5baabf5c','答趙玉汝','方岳','宋','宋诗','song-poetry','','[]','人間無處不風波，潮打西興雨一簑。',64,'全唐诗/poet.song.212000.json','["人間無處不風波，潮打西興雨一簑。", "難與命爭俱老矣，徑尋詩去奈吾何。", "園成次第自花草，山是知聞空薜蘿。", "頼有月明千里共，烟寒數筆落行窩。"]'),
('c743a766-d782-4bec-b360-45f011ea0e50','夢陳和仲如平生交有三言覺而記其一曰錯後亂夢中了了以爲事錯之後此心撩亂不如早謀其始也','方岳','宋','宋诗','song-poetry','','[]','睡殘寒月海東頭，不起斯人孰與遊。',64,'全唐诗/poet.song.212000.json','["睡殘寒月海東頭，不起斯人孰與遊。", "天下事寧堪幾錯，夢中語亦戒前籌。", "江湖浩浩二三子，風雨寥寥十五秋。", "莫向斷雲多感慨，孔顔無命不伊周。"]'),
('1d4c7aa5-32c0-459b-8ed5-ceba957f0173','夢余義夫以劍請銘','方岳','宋','宋诗','song-poetry','','[]','黑水梁州百二關，青天蜀道古云難。',64,'全唐诗/poet.song.212000.json','["黑水梁州百二關，青天蜀道古云難。", "貔貅夜柝身何在，麋鹿秋風骨未寒。", "寵辱可驚漚起滅，荒凉只有月悲酸。", "蒯緱忽墮空山夢，不道幽人意轉闌。"]'),
('23699ef0-d1f6-496a-a3e0-e9f44b5878ee','次韻費司法  其一','方岳','宋','宋诗','song-poetry','','[]','有客誰爲數擊鮮，西風孤我雁聲前。',64,'全唐诗/poet.song.212000.json','["有客誰爲數擊鮮，西風孤我雁聲前。", "酒無多酌何如醒，詩不能奇莫浪傳。", "秋色淡於人寂寂，桂花香得月娟娟。", "五經不到山翁腹，且聽便便引老邊。"]'),
('669927e8-96d9-4da2-834f-95752e1d1d19','次韻費司法  其二','方岳','宋','宋诗','song-poetry','','[]','山居未省佩弦韋，緊閉柴扉不問誰。',64,'全唐诗/poet.song.212000.json','["山居未省佩弦韋，緊閉柴扉不問誰。", "自釣鱖魚西塞雨，久盟猿鶴北山移。", "古今不遇豈惟我，宇宙無窮付與詩。", "直道背時寧敢爾，白雲深處要耘芝。"]'),
('ae3bf1bf-2a6c-4b49-a222-068ee62f8659','次韻費司法  其三','方岳','宋','宋诗','song-poetry','','[]','空谷跫然餘故人，且談風月未論文。',64,'全唐诗/poet.song.212000.json','["空谷跫然餘故人，且談風月未論文。", "長房僊去幾何日，陸羽泉邊多少雲。", "誰向唐詩參句律，只將周易對爐熏。", "縱無今古飛談屑，稼穡平生亦飽聞。"]'),
('67c40191-a69f-404b-8a92-657e5b8ea860','次韻滕和叔投贈  其一','方岳','宋','宋诗','song-poetry','','[]','猶及溪齋識老成，萬琅玕外一溪清。',64,'全唐诗/poet.song.212000.json','["猶及溪齋識老成，萬琅玕外一溪清。", "諸郎與我雪燈共，兩眼觀書霜月明。", "二十一年如夢過，五三六籍尚誰賡。", "鹿車忽到蒼厓底，老木驚秋亦向榮。"]'),
('dc350fae-e19f-46a2-80e1-df20e45e4f8e','次韻滕和叔投贈  其二','方岳','宋','宋诗','song-poetry','','[]','白髮相過各暮年，顔間老氣自軒軒。',64,'全唐诗/poet.song.212000.json','["白髮相過各暮年，顔間老氣自軒軒。", "滄浪供硯心猶在，博雅藏書手自翻。", "舉世共知名父子，此身莫負晦翁門。", "重陽風雨何堪別，只和名章當贈言。"]'),
('bda152bc-738a-4bd5-bf70-5ae3dfe8d088','觀諸弟子射石孫七齡亦能二十步四十的','方岳','宋','宋诗','song-poetry','','[]','飽聞吾季藝穿楊，試手春風百步彊。',64,'全唐诗/poet.song.212000.json','["飽聞吾季藝穿楊，試手春風百步彊。", "赤白羽飛低日月，東西朋立凜冰霜。", "共觀棲鵠如環堵，亦笑童烏敢擅場。", "莫計草間狐兔盡，關河久已失耕桑。"]'),
('d6bd4059-7443-44e8-bd5c-35b601c9318a','次韻汪宰見寄  其一','方岳','宋','宋诗','song-poetry','','[]','行行驄馬劾粗豪，叱叱黄牛倦作勞。',64,'全唐诗/poet.song.212000.json','["行行驄馬劾粗豪，叱叱黄牛倦作勞。", "窮則有餘名迹在，言之無作語聲高。", "誰求封禪家徒壁，自謂羲皇人似陶。", "見說醉鄉天地闊，此生聊向此中逃。"]'),
('4fbd22d0-8864-4000-b150-6464673b3f6a','次韻汪宰見寄  其二','方岳','宋','宋诗','song-poetry','','[]','半世青燈眼欲昏，誰知曾亦望中原。',64,'全唐诗/poet.song.212000.json','["半世青燈眼欲昏，誰知曾亦望中原。", "雨荒塞草秋如洗，雪擁春蓑夜自溫。", "寵辱易生分別想，是非政可鶻崙吞。", "不論茅屋鋤犂外，但守平生六二坤。"]'),
('1b6cf344-5b75-41ba-9e45-9a15f24903d8','石孫試童子郡廣文贈之詩代賡爲謝  其一','方岳','宋','宋诗','song-poetry','','[]','不緣青紫不明經，科目多慙舊兩生。',64,'全唐诗/poet.song.212000.json','["不緣青紫不明經，科目多慙舊兩生。", "三豕魯魚曾未學，一蝸蠻觸已爭名。", "棟梁材欲丘山重，滄海珠遺星斗明。", "未必童烏能辨此，乃翁先已荷陶成。"]'),
('dc6a5e28-78d0-4a50-b9a6-bcd9159fa390','石孫試童子郡廣文贈之詩代賡爲謝  其二','方岳','宋','宋诗','song-poetry','','[]','命窮久已付之天，草木閒兮月一川。',64,'全唐诗/poet.song.212000.json','["命窮久已付之天，草木閒兮月一川。", "無地可容携鍤處，有孫猶在佩觿年。", "老夫耄矣耕方熟，小子識之攻益堅。", "萬歲石場今爾耳，當家衣鉢底須傳。"]'),
('76b4999f-59d0-46a3-a744-5fc3d2cc07e1','次韻胡兄  其一','方岳','宋','宋诗','song-poetry','','[]','釣蓑烟雨斷磯頭，戀闕丹心付子牟。',64,'全唐诗/poet.song.212000.json','["釣蓑烟雨斷磯頭，戀闕丹心付子牟。", "腹有一丁長作祟，背無三甲不封侯。", "慣貧已識山林趣，投老歸從造物遊。", "自笑骨寒癯似鶴，忍饑猶未怯茶甌。"]'),
('919e61d3-77bd-4642-a2ae-12c1de1aaedc','次韻胡兄  其二','方岳','宋','宋诗','song-poetry','','[]','猿驚鶴怨老江蘺，留得離騷到景差。',64,'全唐诗/poet.song.212000.json','["猿驚鶴怨老江蘺，留得離騷到景差。", "愚智共知窮有分，浮休俱與醉無涯。", "人間狡兔自三窟，身外鷦鷯只一枝。", "非意相干吾豈敢，年來端爲冷虀吹。"]'),
('b883b547-0d5d-4daf-9343-239f002dd5e6','輸棋','方岳','宋','宋诗','song-poetry','','[]','半崦山雲舊草堂，鳥啼花落幾平章。',64,'全唐诗/poet.song.212000.json','["半崦山雲舊草堂，鳥啼花落幾平章。", "酒無賢聖同歸醉，風有雌雄各自凉。", "頼與鷗盟同保社，不隨蟻垤夢侯王。", "未償詩債逢棋敵，誰信閒人最得忙。"]'),
('da4cdd47-badf-40dd-9eda-81db397af23e','次韻劉簿禱雨西峰  其一','方岳','宋','宋诗','song-poetry','','[]','句律清圓蚌剖胎，斷無塵土到靈臺。',64,'全唐诗/poet.song.212000.json','["句律清圓蚌剖胎，斷無塵土到靈臺。", "開張九虎排雲入，約束五龍驅雨來。", "造物無私心感動，太平有象筆追回。", "焚香小待生呈佛，未放青天萬里開。"]'),
('64969570-fd58-43a9-9369-450696014469','次韻劉簿禱雨西峰  其二','方岳','宋','宋诗','song-poetry','','[]','愛民端與共胞胎，消得黄金爲築臺。',64,'全唐诗/poet.song.212000.json','["愛民端與共胞胎，消得黄金爲築臺。", "一道香烟隨牒去，五更風雨入詩來。", "雪燈字暗心猶在，霜葉衫枯首獨回。", "氣格老蒼能過我，柴門不厭爲君開。"]'),
('f172ba9d-8643-4b7b-b13b-6f440b49ee6e','感懷  其一','方岳','宋','宋诗','song-poetry','','[]','獨擅松風一壑哀，竹門雖設爲誰開。',64,'全唐诗/poet.song.212000.json','["獨擅松風一壑哀，竹門雖設爲誰開。", "宦情已矣隨流去，老色蒼然上面來。", "已慣山居無曆日，不知人世有公台。", "天生此手終何用，只解持杯亦快哉。"]'),
('016132b7-07dc-4c7c-81e0-ea16df53f901','感懷  其二','方岳','宋','宋诗','song-poetry','','[]','三十年前氣挂天，老來身世竟茫然。',64,'全唐诗/poet.song.212000.json','["三十年前氣挂天，老來身世竟茫然。", "窮愁正坐識丁字，生事不聊稱子錢。", "得見古人千載上，已忘今我一漚邊。", "劉伶墳上寧須酒，併與聲名不用傳。"]'),
('165c5eb3-df86-4a60-bd9a-c1046642dfaa','感懷  其三','方岳','宋','宋诗','song-poetry','','[]','異人曾授相牛經，奇字初傳瘞鶴銘。',64,'全唐诗/poet.song.212000.json','["異人曾授相牛經，奇字初傳瘞鶴銘。", "敲月不知僧某甲，鋤烟頼有老畦丁。", "山靈呵護閒居賦，象緯森羅處士星。", "俯仰中間無愧怍，芋區瓜隴亦朝廷。"]'),
('18868c24-002d-4718-8689-5889713886b4','感懷  其四','方岳','宋','宋诗','song-poetry','','[]','去國何年老一丘，於今已換幾公侯。',64,'全唐诗/poet.song.212000.json','["去國何年老一丘，於今已換幾公侯。", "不知我者謂爲拙，是有命焉那用求。", "舴艋舟應容釣蟹，麒麟閣不畫騎牛。", "百年長短身餘幾，付與西風汗漫遊。"]'),
('717606ba-3d28-4964-9a1f-23953a6d4178','感懷  其五','方岳','宋','宋诗','song-poetry','','[]','野壙風高一欠伸，平生俯仰已成陳。',64,'全唐诗/poet.song.212000.json','["野壙風高一欠伸，平生俯仰已成陳。", "老天無意獨窮我，直道有時能誤人。", "悔不可追身是膽，怒何堪觸腹生鱗。", "忍饑罷乞祠官祿，只麽扶犂亦幸民。"]'),
('88b4535e-6232-4541-8ece-ecf18f97c33c','感懷  其六','方岳','宋','宋诗','song-poetry','','[]','非干寵辱不能驚，一付之天莫我攖。',64,'全唐诗/poet.song.212000.json','["非干寵辱不能驚，一付之天莫我攖。", "舉世忙時贏得懶，是人愛處放教輕。", "生爲柱國身何在，死象祁連冢亦平。", "千古在前兒戲耳，且容高枕聽秋聲。"]'),
('445ff123-e8a6-49ac-bab5-1035a5995b01','感懷  其七','方岳','宋','宋诗','song-poetry','','[]','從古幽閒在澗阿，不將齒髮犯風波。',64,'全唐诗/poet.song.212000.json','["從古幽閒在澗阿，不將齒髮犯風波。", "共知韓愈亦人耳，子謂伯寮如命何。", "野處生成盤谷序，襟期寫在醉時歌。", "尚嫌山淺人知處，更與移床入薜蘿。"]'),
('53493e29-4c83-43f3-bc24-d493b7ff9d3e','感懷  其八','方岳','宋','宋诗','song-poetry','','[]','拄入風烟更一層，瘦藤對倚玉崚嶒。',64,'全唐诗/poet.song.212000.json','["拄入風烟更一層，瘦藤對倚玉崚嶒。", "左花右竹自昭穆，春鶴秋猿相友朋。", "五畝園爲終老計，半間雲住在家僧。", "蹲鴟生嬭菰如臂，莫道山翁百不能。"]'),
('ae0d6fb4-ba2e-42ba-ac6c-ddd285c8db0f','感懷  其九','方岳','宋','宋诗','song-poetry','','[]','四壁空空長物無，松風之外復何須。',64,'全唐诗/poet.song.212000.json','["四壁空空長物無，松風之外復何須。", "竹夫人爽夜當直，木上座臞新給扶。", "老去雲山空跌宕，秋來風月不支吾。", "何人能敗吟詩興，自在成章不欠租。"]'),
('6235a18e-23cd-4a83-b6fa-a36c4c777442','感懷  其一○','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曩昔行藏已熟籌，最爲上策是無求。',64,'全唐诗/poet.song.212000.json','["曩昔行藏已熟籌，最爲上策是無求。", "看人面孔有何好，如此頭顱只麽休。", "草草園廬山北住，匆匆歲月水東流。", "莫因一片梧桐葉，瘦損能詩沈隠侯。"]'),
('5519c296-e938-4517-b7a5-04843620a131','山居','方岳','宋','宋诗','song-poetry','','[]','春溪甘滑漱山瓢，歸卧藤陰蘚逕遥。',64,'全唐诗/poet.song.212000.json','["春溪甘滑漱山瓢，歸卧藤陰蘚逕遥。", "雲氣釀成巫峽雨，松聲寒似浙江潮。", "書生與世例迂闊，山意向人殊寂寥。", "却喜庾郎貧到骨，韭畦時一摘烟苗。"]'),
('d3b6b835-beef-4021-b1e7-3765d383ec60','次韻行甫小集平山  其一','方岳','宋','宋诗','song-poetry','','[]','不奈花時兩手閒，共携詩硯對孱顔。',64,'全唐诗/poet.song.212000.json','["不奈花時兩手閒，共携詩硯對孱顔。", "江南江北音書外，春去春來楊柳間。", "騎鶴重尋烟雨句，征鴻欲沒夕陽山。", "百年風物一杯酒，歎息人間兩觸蠻。"]'),
('b55e9423-f57e-4171-83eb-cbf83ed459ef','次韻行甫小集平山  其二','方岳','宋','宋诗','song-poetry','','[]','春風多可幾曾閒，又爲平山入醉顔。',64,'全唐诗/poet.song.212000.json','["春風多可幾曾閒，又爲平山入醉顔。", "流恨不窮江萬里，與翁長在月三間。", "半清半濁聖賢酒，似有似無烟雨山。", "試問黄鸝相識否，綠陰深樹自綿蠻。"]'),
('48730786-4d35-4c99-9acc-fe933ddc75e8','次韻行甫小集平山  其三','方岳','宋','宋诗','song-poetry','','[]','一片花飛不等閒，對花空手亦何顔。',64,'全唐诗/poet.song.212000.json','["一片花飛不等閒，對花空手亦何顔。", "醉鄉別在乾坤外，詩社寧容季孟間。", "妙句屢移青玉案，佳遊仍隔小金山。", "只應江上烟霏笑，蠻府參軍語自蠻。"]'),
('95016141-3cdf-4a60-aadb-3d095be59942','次韻行甫小集平山  其四','方岳','宋','宋诗','song-poetry','','[]','欲將春睡了春閒，誰遣楊花點暮顔。',64,'全唐诗/poet.song.212000.json','["欲將春睡了春閒，誰遣楊花點暮顔。", "世事不如眠白墮，人情何啻抵黄間。", "茫無措手句中句，悔已噬臍山外山。", "蚤晚定編長慶集，併教傳寫落烏蠻。"]'),
('401367cf-be4f-48f5-b5cd-4020e060def5','次韻行甫小集平山  其五','方岳','宋','宋诗','song-poetry','','[]','客愁聊以酒防閑，非復春風桃李顔。',64,'全唐诗/poet.song.212000.json','["客愁聊以酒防閑，非復春風桃李顔。", "北望未忘諸老在，中興已是百年間。", "非無烟雨無奇語，自有乾坤有此山。", "楊柳豈知興廢事，夕陽依舊舞腰蠻。"]'),
('f08f0a35-766c-4f14-952c-41bd3221cea6','次韻潘令君訪予半村','方岳','宋','宋诗','song-poetry','','[]','鋤烟荷雨自村村，不慣高車入里門。',64,'全唐诗/poet.song.212000.json','["鋤烟荷雨自村村，不慣高車入里門。", "石老只堪麋鹿伴，山寒未放蝶蜂喧。", "欲分桃李春何限，共話桑麻道轉尊。", "但得諸公如卓魯，晚菘早韭且窺園。"]'),
('3a1a9dca-b334-4044-b7c9-fd304b0ce265','再用韻','方岳','宋','宋诗','song-poetry','','[]','終須西塞老漁村，抵用南昌隠市門。',64,'全唐诗/poet.song.212000.json','["終須西塞老漁村，抵用南昌隠市門。", "時序略如飛鳥過，世終何啻聚蚊喧。", "竹其安否六太息，梅自癯然三可尊。", "貧味却愁兒輩覺，未妨壁立病文園。"]'),
('aab0d361-6ba1-4e56-9762-7eef09ea52a8','三用韻酬諸丈','方岳','宋','宋诗','song-poetry','','[]','家在江南黄葉村，歸來重葺柳邊門。',64,'全唐诗/poet.song.212000.json','["家在江南黄葉村，歸來重葺柳邊門。", "溪雲排闥硯猶濕，山溜通池水自喧。", "但得梅花容著語，無煩桃葉爲開尊。", "逢迎車馬荷衣老，面目何堪向綺園。"]'),
('4b5cf72d-e81e-4149-8be0-a2258163011f','四用韻答才老','方岳','宋','宋诗','song-poetry','','[]','江山带郭數家村，窮僻誰敲月下門。',64,'全唐诗/poet.song.212000.json','["江山带郭數家村，窮僻誰敲月下門。", "謝絕往來緣事盡，爭論勝負爲棋喧。", "愛閒寧有萬金産，投老當誇兩足尊。", "不惜梅花三寸雪，併令回施給孤園。"]'),
('65303b3f-41c3-43cd-b737-671206ca3910','勸耕  其一','方岳','宋','宋诗','song-poetry','','[]','郡如斗大亦何堪，耕雨鋤烟亦飽諳。',64,'全唐诗/poet.song.212000.json','["郡如斗大亦何堪，耕雨鋤烟亦飽諳。", "共話桑麻真有味，久拋蓑笠得無慙。", "野田春水自深淺，晴日鳥聲時兩三。", "安得一牛橫短笛，南山之北北山南。"]'),
('064b194b-a96f-481a-af38-946ae06c3ba2','勸耕  其二','方岳','宋','宋诗','song-poetry','','[]','歸歟我亦耦耕人，麥隴桑畦意自親。',64,'全唐诗/poet.song.212000.json','["歸歟我亦耦耕人，麥隴桑畦意自親。", "纔出郭收連日雨，已拚花負一年春。", "農安用勸村村急，文不須工字字真。", "自是非材頭白盡，不緣方寸在吾民。"]'),
('5ac3f493-82d6-4518-8eae-6fc98c2dc3d4','熙春臺用王簿韻','方岳','宋','宋诗','song-poetry','','[]','共携社甕上春臺，踏破緣雲一徑苔。',64,'全唐诗/poet.song.212000.json','["共携社甕上春臺，踏破緣雲一徑苔。", "歲月略如飛鳥過，賓朋不爲看花來。", "霜前老翠依然在，眼底凡紅不用開。", "未害慳風相料理，放遲歸與月徘徊。"]'),
('3f5cb052-786e-49e2-afb5-97e8e47af2a1','又用胡尉韻','方岳','宋','宋诗','song-poetry','','[]','便覺尋春負一籌，老懷無復少年遊。',64,'全唐诗/poet.song.212000.json','["便覺尋春負一籌，老懷無復少年遊。", "茶桑天似鵝黄酒，楊柳花飛狐白裘。", "試問獨醒觀衆醉，何如一笑失千憂。", "不知多少人間事，付與溪聲自在流。"]'),
('1dcf40e1-ede5-4ab2-a43f-b001b6e03897','別陳尉','方岳','宋','宋诗','song-poetry','','[]','市橋晴柳拂朱旗，天際九華勞夢思。',64,'全唐诗/poet.song.212000.json','["市橋晴柳拂朱旗，天際九華勞夢思。", "鸂鶒灘深猶昨日，鸕鷀杓醉復何時。", "微官梅隠亦風度，寒食梨花更別離。", "蚤晚暮雲春樹底，烹魚倘有入京詩。"]'),
('d0009361-1931-4589-9da4-13ab0d7f9527','寄別參政','方岳','宋','宋诗','song-poetry','','[]','一見臞仙眼爲清，寒溫未了與談經。',64,'全唐诗/poet.song.212000.json','["一見臞仙眼爲清，寒溫未了與談經。", "有書欲問文中子，無策重窺傅說星。", "馬瘦不妨吟下澤，鶴歸寧復唳華亭。", "獨於知己難忘在，投老殘編儻乞靈。"]'),
('9a18e3af-0b42-406b-898a-443b0a0fb474','次韻王尉賀雨','方岳','宋','宋诗','song-poetry','','[]','老天自不負吾君，誰向靈均三沐熏。',64,'全唐诗/poet.song.212000.json','["老天自不負吾君，誰向靈均三沐熏。", "鶴立待收連夜雨，龍歸看带入山雲。", "摩挲一飽豈易得，愁嘆多年不忍聞。", "亦欲買牛橫短笛，華山一半倘容分。"]'),
('c4434ab2-10df-4102-91cd-81dcf002545b','觀稼西庵用文懿壁間韻','方岳','宋','宋诗','song-poetry','','[]','太平只是豐年做，山雨不休公出遊。',64,'全唐诗/poet.song.212000.json','["太平只是豐年做，山雨不休公出遊。", "捲野晴雲堆作堵，翻匙香雪滑如流。", "人行黄犢夕陽外，詩在丹楓古渡頭。", "老我無田歸自種，可憐鶴怨賈胡留。"]'),
('e064d208-c686-4775-ad80-57cd5115ac1c','禱晴','方岳','宋','宋诗','song-poetry','','[]','曾幾何時屢乞晴，爐烟未斷已收聲。',64,'全唐诗/poet.song.212000.json','["曾幾何時屢乞晴，爐烟未斷已收聲。", "天於老子亦多可，國有豐年方太平。", "風土不堪人佩犢，月明無復夜啼鼪。", "及今便可歸田去，牛背斜陽一笛橫。"]'),
('a4884902-2012-45cc-97bf-e648b20705b2','聞罷','方岳','宋','宋诗','song-poetry','','[]','面骨巖稜不入流，放歸何止四宜休。',64,'全唐诗/poet.song.212000.json','["面骨巖稜不入流，放歸何止四宜休。", "束書自可供兒讀，斗酒聊須與婦謀。", "舊藁如山應有誤，老夫於世本無求。", "一犂春雨平生事，莫與諸公作話頭。"]'),
('b45c9e20-dfbc-4ceb-a21a-4b055bf15221','報具闕','方岳','宋','宋诗','song-poetry','','[]','百不如人且罷休，又携書冊上孤舟。',64,'全唐诗/poet.song.212000.json','["百不如人且罷休，又携書冊上孤舟。", "歸歟雅有一黄犢，愧甚向來雙白鷗。", "但得濁醪供燕社，不妨明月老菟裘。", "研冰自補山人處，莫爲區區費廟籌。"]'),
('9c1f2f5a-bb03-40db-a010-f3810d47ec42','得歸','方岳','宋','宋诗','song-poetry','','[]','日日言歸始得歸，歸歟好在舊牛衣。',64,'全唐诗/poet.song.212000.json','["日日言歸始得歸，歸歟好在舊牛衣。", "青山未害欠詩屋，白鳥倘能看釣磯。", "欲問古人今在否，不知吾道是耶非。", "里中父老如相過，應嘆艱難带解圍。"]'),
('c88965b3-1274-4766-83a2-23d04181dba5','山行漫興','方岳','宋','宋诗','song-poetry','','[]','野性惟便水竹居，老來自覺轉迂疎。',64,'全唐诗/poet.song.212000.json','["野性惟便水竹居，老來自覺轉迂疎。", "圖書四壁飯不足，烟雨一犂春有餘。", "紙上古人俱已矣，山中今我定何如。", "春風獨立鳥聲碎，不是言詩亦起予。"]'),
('3b8effe4-a757-49f7-9d55-a90dfbf829e8','次韻雨阻遊人','方岳','宋','宋诗','song-poetry','','[]','村塢花飛片片紅，橫遭澁雨又慳風。',64,'全唐诗/poet.song.212000.json','["村塢花飛片片紅，橫遭澁雨又慳風。", "無何春事三分過，不肯遊人一笑同。", "窮勝園林惟我輩，儻來軒冕付諸公。", "烟雲兩屐亦堪醉，莫問聖賢時一中。"]'),
('9511961f-1196-495f-9565-c40631105cb3','登山  其一','方岳','宋','宋诗','song-poetry','','[]','一番雨過長莓苔，乘興登臨倦眼開。',64,'全唐诗/poet.song.212000.json','["一番雨過長莓苔，乘興登臨倦眼開。", "花落無聲春取去，社寒有信燕將來。", "人間事已不啻足，海上翁今莫見猜。", "負郭曾微耕雨處，自題詩句覓榿栽。"]'),
('eaaddd40-115e-429c-acc9-2d92a37d3cd6','登山  其二','方岳','宋','宋诗','song-poetry','','[]','物華無處不東風，只恐東風笑此翁。',64,'全唐诗/poet.song.212000.json','["物華無處不東風，只恐東風笑此翁。", "雙鬢不隨春草綠，一尊聊借老顔紅。", "棋聲未急雨聲急，眼力無窮脚力窮。", "穿徑本爲行散計，却將籃笋上空濛。"]'),
('1157c574-1b1f-4d50-bbfc-ef89889b0dd0','種松先公墓下','方岳','宋','宋诗','song-poetry','','[]','一壑風衰二十秋，俛行詰曲翳松楸。',64,'全唐诗/poet.song.212000.json','["一壑風衰二十秋，俛行詰曲翳松楸。", "冢前無路草欲沒，泉下有知山亦愁。", "翁仲不言關氣運，衣冠如在想神遊。", "何年夾道虬龍侶，淚濕春泥兒白頭。"]'),
('8f965e9e-47b2-4e86-a6d8-7311a82c37d0','採蕨','方岳','宋','宋诗','song-poetry','','[]','野燒初肥紫玉圓，枯松瀑布煮春煙。',64,'全唐诗/poet.song.212000.json','["野燒初肥紫玉圓，枯松瀑布煮春煙。", "偃徐妙處元無骨，鈎弋生來已作拳。", "蚤韭不甘同臭味，秋蓴雖滑带腥涎。", "食經豈爲兒曹設，弱脚寒中愁未然。"]'),
('f5064cd0-2efc-45b7-a4e5-a607d685b938','舟行省墓','方岳','宋','宋诗','song-poetry','','[]','半篙新綠落寒沙，芳草王孫自物華。',64,'全唐诗/poet.song.212000.json','["半篙新綠落寒沙，芳草王孫自物華。", "春事已隨蝴蝶夢，人情猶有杜鵑花。", "百年易盡一彈指，兩曜不停雙轉車。", "手種寸苗今老大，滿山鱗甲動龍蛇。"]'),
('5af16b1d-e37d-48fe-87b7-e389e2c1c86e','次韻所居龍池巷','方岳','宋','宋诗','song-poetry','','[]','從來絕技似屠龍，莫倚神奇阿堵中。',64,'全唐诗/poet.song.212000.json','["從來絕技似屠龍，莫倚神奇阿堵中。", "但得直聲如汲黯，儘渠曲學付孫洪。", "草堂自作冥鴻計，藥市寧收汗馬功。", "古井無波門巷靜，再三不用起雷風。"]'),
('03062d11-4985-4715-8bdf-3ad554a6d28a','次韻羹莧','方岳','宋','宋诗','song-poetry','','[]','琉璃蒸乳壓㹠膏，未抵齋厨格調高。',64,'全唐诗/poet.song.212000.json','["琉璃蒸乳壓㹠膏，未抵齋厨格調高。", "脫粟飯香供野莧，荷鋤人飽撚霜毛。", "斷無文伯可相累，比似何曾無大毫。", "見說能醫射工毒，人間此物政騷騷。"]'),
('8f551194-e717-41d5-8779-af2efbf3bc06','次韻閒中','方岳','宋','宋诗','song-poetry','','[]','區中何日了塵緣，落草牛須驀鼻穿。',64,'全唐诗/poet.song.212000.json','["區中何日了塵緣，落草牛須驀鼻穿。", "乾沒一生空歲月，見成三逕老風煙。", "山林有味從今我，鐘鼎無心付老天。", "田彼南山多種豆，不愁饑火苦相煎。"]'),
('38d1420a-0943-4990-9c82-44809ad705e2','麥嘆','方岳','宋','宋诗','song-poetry','','[]','田家望麥在須臾，何啻中流濟一壺。',64,'全唐诗/poet.song.212000.json','["田家望麥在須臾，何啻中流濟一壺。", "黑雨漫天殊未已，黄雲委地不堪扶。", "禽聲快活真成誤，鳩婦流離空自呼。", "亦笑此翁長負腹，又尋杞菊誑齋盂。"]'),
('0225e561-65c0-4358-89c5-d80805f712af','舊傳有客謁一士夫題其刺云琴棋詩酒客因與談笑戲成此詩','方岳','宋','宋诗','song-poetry','','[]','癡書到底成何事，只有窮愁上鬢絲。',64,'全唐诗/poet.song.212000.json','["癡書到底成何事，只有窮愁上鬢絲。", "鑄錯空糜六州鐵，補鞋不似兩錢錐。", "誰歟莫逆溪山我，幸甚無能詩酒棋。", "依舊挂書牛角去，笑渠到底是書癡。"]'),
('07d16b0a-dfe6-42f8-b5de-3e006ccf614f','次韻張錄携書見過  其一','方岳','宋','宋诗','song-poetry','','[]','家在屏山東復東，高軒肯過白雲中。',64,'全唐诗/poet.song.212000.json','["家在屏山東復東，高軒肯過白雲中。", "石橋自是神仙處，竹屋相傳工律工。", "日暮春江愁李白，山寒秋菊老龜蒙。", "時平莫袖揮毫手，此論於予却未公。"]'),
('5c46b6ba-5748-4654-be1c-669727bc0eb1','次韻張錄携書見過  其二','方岳','宋','宋诗','song-poetry','','[]','君家自有神奇在，底用濃熏到馬班。',64,'全唐诗/poet.song.212000.json','["君家自有神奇在，底用濃熏到馬班。", "黄石一編燈火外，紫芒雙劍斗牛間。", "誰能莫府初開印，聞有詩人便入山。", "雨過勘廳春草綠，與吾意思政相關。"]'),
('7c6949c8-c60e-4836-a88f-5b1e567fc442','西崦','方岳','宋','宋诗','song-poetry','','[]','西崦東岡取次行，倚松小立又詩成。',64,'全唐诗/poet.song.212000.json','["西崦東岡取次行，倚松小立又詩成。", "山風溪月寶無價，牧笛樵歌畫有聲。", "半頃萊田供伏臘，一間茅屋老昇平。", "未知沮溺今何似，却怕諸生問姓名。"]'),
('6b848f35-12b8-4705-9903-d1d8d1fca6fa','答客問','方岳','宋','宋诗','song-poetry','','[]','本自滄浪一釣竿，秋風還我舊沙灘。',64,'全唐诗/poet.song.212000.json','["本自滄浪一釣竿，秋風還我舊沙灘。", "未論袁聖宜休去，只作劉蕡不第看。", "書授我猶慙取履，位因人莫便彈冠。", "不然林下何曾見，靈澈能拈作笑端。"]'),
('8f9fdde1-be9c-483b-8a19-5ac7cf3d2625','以越箋與三四弟有詩次韻','方岳','宋','宋诗','song-poetry','','[]','無復花生拙筆頭，一生長負剡藤羞。',64,'全唐诗/poet.song.212000.json','["無復花生拙筆頭，一生長負剡藤羞。", "過門盡是陳驚坐，得句今誰趙倚樓。", "社友書來煩寄語，山翁鬢已不禁秋。", "老干仙去吾宗冷，有繼華星一字不。"]'),
('d82c788a-8074-45ab-8f1c-5a8577c67570','百十一弟致陶印','方岳','宋','宋诗','song-poetry','','[]','不妨主掌舊林泉，山澤癯儒半列仙。',64,'全唐诗/poet.song.212000.json','["不妨主掌舊林泉，山澤癯儒半列仙。", "判月可無方寸印，勘書猶有一朝權。", "陶人解作蟲魚篆，道號寧須金石鎸。", "約束風煙聽驅使，吾家季子似差賢。"]'),
('7468c763-ee3d-41bd-a30a-6d89ae75981c','小集次韻','方岳','宋','宋诗','song-poetry','','[]','纔能詩便不能閒，與客提壺且看山。',64,'全唐诗/poet.song.212000.json','["纔能詩便不能閒，與客提壺且看山。", "紫翠夕陽煙漠漠，綠陰深樹鳥關關。", "酒盃不負林泉約，春事已非桃李顔。", "我醉欲眠君莫去，竹間自有月三間。"]'),
('bf2e0bfb-5a05-4d8a-a312-d634c79cc66f','時事','方岳','宋','宋诗','song-poetry','','[]','閒身久矣屬煙波，時事誰傳到釣蓑。',64,'全唐诗/poet.song.212000.json','["閒身久矣屬煙波，時事誰傳到釣蓑。", "無一可忻真老矣，有三太息奈渠何。", "君爲堯舜寧非幸，人在羲皇不啻過。", "擊壤共歌年穀熟，此生帝力已居多。"]'),
('819b27be-3a59-449f-912a-6805a7e579cf','買菊栽','方岳','宋','宋诗','song-poetry','','[]','新綠叢叢手自培，東籬準擬白衣來。',64,'全唐诗/poet.song.212000.json','["新綠叢叢手自培，東籬準擬白衣來。", "荷鋤政欠半畦雨，抱甕空遺滿逕苔。", "說與園丁重九近，毋煩老子再三催。", "徑須尋覓誰家有，带土移將一兩栽。"]'),
('277ebc05-7d6a-4314-9547-4745ccdd87ab','木犀  其一','方岳','宋','宋诗','song-poetry','','[]','香到人間香更幽，月明風露正颼颼。',64,'全唐诗/poet.song.212000.json','["香到人間香更幽，月明風露正颼颼。", "天開金粟如來藏，人立廣寒宮殿秋。", "幾許多清冰腦片，一些來大雪花頭。", "此生若並凡紅紫，安得奇芬死不休。"]'),
('99ac4ab5-c544-4bd8-8b8a-59a6a048abf9','木犀  其二','方岳','宋','宋诗','song-poetry','','[]','葉葉寒清粟粟黄，何年月斧落吳剛。',64,'全唐诗/poet.song.212000.json','["葉葉寒清粟粟黄，何年月斧落吳剛。", "秋風誤到人間世，幽壑難藏天上香。", "渺立塵氛羣玉府，獨餐沆瀣碧雲鄉。", "生來不並凡紅紫，合在蟾蜍硯滴旁。"]'),
('e48ff1c0-2ef0-4048-9101-ab7104ab2425','木犀  其三','方岳','宋','宋诗','song-poetry','','[]','羽觴和月嚼冰黄，自笑詩腸老更剛。',64,'全唐诗/poet.song.212000.json','["羽觴和月嚼冰黄，自笑詩腸老更剛。", "四出雪花些小大，五千書傳一齊香。", "君從底處移仙籍，日飲無何作醉鄉。", "風露清寒付誰可，携歸天祿校偏旁。"]'),
('247cc103-cd52-48da-a3bf-ee51abb504f9','枕石','方岳','宋','宋诗','song-poetry','','[]','短簟相携入薜蘿，且容眠石略婆娑。',64,'全唐诗/poet.song.212000.json','["短簟相携入薜蘿，且容眠石略婆娑。", "未曾八月暑如此，何處中秋天最多。", "一壑風烟貧受用，百年時序老消磨。", "夕陽籬落誰橫笛，似識山樵扣角歌。"]'),
('3a0b6ad4-eef1-44a8-a6b1-f45b1d52dc8b','八月十四月食中秋遂無月','方岳','宋','宋诗','song-poetry','','[]','妖蟇不爲中秋地，老兔先奔昨夜寒。',64,'全唐诗/poet.song.212000.json','["妖蟇不爲中秋地，老兔先奔昨夜寒。", "世事相違劇晴雨，人生何苦許悲歡。", "雲窗自照青藜杖，月戶重修白玉盤。", "坐想西風萬袍鵠，政飛健筆寫琅玕。"]'),
('d53cbc89-0032-4937-ad64-9133472ccc4e','山中  其一','方岳','宋','宋诗','song-poetry','','[]','繚碧縈青一逕深，倦隨扶老上遥岑。',64,'全唐诗/poet.song.212000.json','["繚碧縈青一逕深，倦隨扶老上遥岑。", "耕雲自識本來面，曝日誰知見在心。", "浮世事如風雨過，貴人頭亦雪霜侵。", "草庵雖窄乾坤闊，野鶴孤雲不可尋。"]'),
('c0e5d645-eee2-423c-a1f5-99e340096cd6','山中  其二','方岳','宋','宋诗','song-poetry','','[]','十畝荒園斸野煙，蔬畦麥隴带平田。',64,'全唐诗/poet.song.212000.json','["十畝荒園斸野煙，蔬畦麥隴带平田。", "相忘魚鳥無餘地，自信貂蟬有老天。", "靜處亦忙詩意思，貧中之樂酒因緣。", "梅花不隔前村路，只在霜橋雪屋邊。"]'),
('5c14ce19-b081-4475-9561-1f8d525b6ffb','次韻探梅首尾吟','方岳','宋','宋诗','song-poetry','','[]','三花五蘂把春來，縞袂誰將玉尺裁。',64,'全唐诗/poet.song.212000.json','["三花五蘂把春來，縞袂誰將玉尺裁。", "世外風煙甘寂寞，胸中冰雪自崔嵬。", "提壺東閣詩仍在，檢點南枝暖獨回。", "已辦藤溪瀉寒月，三花五蘂把春來。"]'),
('a7131434-8fe2-4a96-aaf7-a7c96e3e6e27','次韻魏監丞鹿鳴詩','方岳','宋','宋诗','song-poetry','','[]','舍蓋中堂肯治齊，山川人物鳳師師。',64,'全唐诗/poet.song.212000.json','["舍蓋中堂肯治齊，山川人物鳳師師。", "拔鯨牙一添賓貢，歌鹿鳴三樂聖時。", "郡有龔黄金玉汝，君爲堯舜蓼蕭斯。", "老農扣角風煙外，但播中和樂職詩。"]'),
('913297d2-c9ac-4831-8662-6f98463afd01','十二月十日','方岳','宋','宋诗','song-poetry','','[]','酒醒開門雪滿山，徑穿疎竹上危欄。',64,'全唐诗/poet.song.212000.json','["酒醒開門雪滿山，徑穿疎竹上危欄。", "溪山與我俱成畫，草樹惟梅大耐寒。", "留伴夜深銀鑿落，莫緣春近玉闌珊。", "老枝擎重供詩嚼，一洗相如渴肺肝。"]'),
('1f53e556-910e-4e75-bf6e-3b55e24346f3','送程伯茂僉書武昌','方岳','宋','宋诗','song-poetry','','[]','平時浪說筆如杠，誰不玉堂雲霧窗。',64,'全唐诗/poet.song.212000.json','["平時浪說筆如杠，誰不玉堂雲霧窗。", "采石月明纔夜講，武昌魚美又春江。", "洲橫鸚鵡天爲限，竈列貔貅陣未降。", "重國西門煩老檄，秋風莫倚暗埋樁。"]'),
('27c35022-c979-465a-b8c4-6f3717c06104','飯牛','方岳','宋','宋诗','song-poetry','','[]','北闕南門各路頭，不才多病兩相投。',64,'全唐诗/poet.song.212000.json','["北闕南門各路頭，不才多病兩相投。", "無錢使鬼貧何害，有句驚人死亦休。", "春意不關花代謝，吾生聊與世沈浮。", "挼挲雙手煙嵐濕，笑向前坡飽飯牛。"]'),
('97a567ef-55f1-4f99-a437-2dd68e460b41','上巳溪汎','方岳','宋','宋诗','song-poetry','','[]','舴艋舟輕暖欲酣，鸕鷀杓重老何堪。',64,'全唐诗/poet.song.212000.json','["舴艋舟輕暖欲酣，鸕鷀杓重老何堪。", "風霜兩鬢五十五，楊柳幾番三月三。", "禊帖又逢今癸丑，蘭亭仍是舊東南。", "死生政亦尋常事，却笑諸賢苦未諳。"]'),
('b5ddb03f-a028-43d7-a88d-0b67408f71c5','次韻貽姪','方岳','宋','宋诗','song-poetry','','[]','鶴形煉得不勝癯，樵笛漁竿只自娛。',64,'全唐诗/poet.song.212000.json','["鶴形煉得不勝癯，樵笛漁竿只自娛。", "人倚草亭今夜月，天開山市晚晴圖。", "片雲留住吾焉往，斗酒能携誰與俱。", "三十年前頭已雪，久知公道世間無。"]'),
('5b2f8131-336e-4153-86ac-1f0f92bafa12','鑿山爲墳貽姪有詩次韻','方岳','宋','宋诗','song-poetry','','[]','著書無復可藏山，朽骨何堪定眼觀。',64,'全唐诗/poet.song.212000.json','["著書無復可藏山，朽骨何堪定眼觀。", "從左右旋天倚蓋，哉生死魄月循環。", "虛空身亦爲吾患，見在心誰乞汝安。", "試問春風舊蹤跡，不知天上與人間。"]'),
('812c7eb0-cdc9-4775-90f4-6985fe80feba','郡爲表弟程起狀元坊並爲陳人重起省元坊','方岳','宋','宋诗','song-poetry','','[]','場屋華然采選圖，采來喝雉偶成盧。',64,'全唐诗/poet.song.212000.json','["場屋華然采選圖，采來喝雉偶成盧。", "敢同君子名吾里，不料公卿出此塗。", "華表自旌新進士，廢人併起躄浮屠。", "少年三五時堪笑，差覺今吾非故吾。"]'),
('60b8b68a-effa-463d-bee3-eb997acaf74d','墐屋','方岳','宋','宋诗','song-poetry','','[]','旋墐山寮準備冬，石爐松火儘從容。',64,'全唐诗/poet.song.212000.json','["旋墐山寮準備冬，石爐松火儘從容。", "功名那及生前酒，機會多如飯後鐘。", "誰寄一詩同保社，自將千竹比侯封。", "客來欲覓秋崖去，知在白雲何處峯。"]'),
('6ac44e92-8f1e-4617-8a75-85fd1cf36fe2','老態','方岳','宋','宋诗','song-poetry','','[]','看書之眼看山脚，二事俱妨可奈渠。',64,'全唐诗/poet.song.212000.json','["看書之眼看山脚，二事俱妨可奈渠。", "藥自不能專忌蟹，酒吾甚愛未浮蛆。", "處人間世每如此，微造物遊誰與居。", "衰病老來常態耳，莫教左右手孤予。"]'),
('75c969a1-5507-4af7-802b-915931196604','九日','方岳','宋','宋诗','song-poetry','','[]','把住秋雲繞菊籬，野情未覺老垂垂。',64,'全唐诗/poet.song.212000.json','["把住秋雲繞菊籬，野情未覺老垂垂。", "古今不遇豈惟我，風雨相過莫問誰。", "未郭索前空有酒，自陶潜後久無詩。", "底須計較明年健，只麽悠然自一奇。"]'),
('d9a0ef6a-a4f8-442e-84b7-a86d1d018c62','雪後','方岳','宋','宋诗','song-poetry','','[]','雪後山齋鶴睡殘，登臨等得蘚泥乾。',64,'全唐诗/poet.song.212000.json','["雪後山齋鶴睡殘，登臨等得蘚泥乾。", "毋多酌酒亦成醉，儘足看梅不道寒。", "籬落十分春意思，人家一色玉欄干。", "小詩未足冰生硯，洗盡人間渴肺肝。"]'),
('bf8487ff-4ffe-4a07-bfcb-656818802afd','梅邊','方岳','宋','宋诗','song-poetry','','[]','野人暖入狼頭帽，雪後寒生鶴膝枝。',64,'全唐诗/poet.song.212000.json','["野人暖入狼頭帽，雪後寒生鶴膝枝。", "杖屨與峯回路轉，溪山又物換星移。", "酒能作祟可忘酒，詩不窮人未是詩。", "筆走秋蛇情爛熳，誰知方寸太平時。"]'),
('ad361683-2648-476b-861b-cd453ae1061b','復雪  其一','方岳','宋','宋诗','song-poetry','','[]','老夫茅屋住冰壺，山市人家亦畫圖。',64,'全唐诗/poet.song.212000.json','["老夫茅屋住冰壺，山市人家亦畫圖。", "世界空花春勢力，神仙乾汞水工夫。", "詩情浩浩迷高厚，元氣茫茫混有無。", "一夜東風天萬里，併歸石銚小磚爐。"]'),
('321b7a86-f255-4698-a3ca-acecd2db2fb8','復雪  其二','方岳','宋','宋诗','song-poetry','','[]','自領蒼頭挈短壺，興成何必剡溪圖。',64,'全唐诗/poet.song.212000.json','["自領蒼頭挈短壺，興成何必剡溪圖。", "有難爲者梅兄弟，豈易卑哉竹丈夫。", "賓從野情紛爛熳，山川雲氣上虛無。", "相隨石鼎清如水，底用侯家暖玉爐。"]'),
('135befab-1440-47f3-983a-e8883ff94a1a','轉孫初生程弟有詩次韻時予頭風適愈','方岳','宋','宋诗','song-poetry','','[]','一庵深掩兩三峯，白髮從渠自不公。',64,'全唐诗/poet.song.212000.json','["一庵深掩兩三峯，白髮從渠自不公。", "但有孫同開口笑，縱無檄亦愈頭風。", "鳶肩火色非吾事，牛背煙霏在眼中。", "要識之無堪底用，歸鋤荷月且扶翁。"]'),
('8871ed97-0bd9-46d1-9f87-ece16776fa52','病目','方岳','宋','宋诗','song-poetry','','[]','病眸未老已昏眵，近廢秋堂幾卷書。',64,'全唐诗/poet.song.212000.json','["病眸未老已昏眵，近廢秋堂幾卷書。", "世事難看寧閉却，人生自擾正紛如。", "棋聲久避燈前雨，菜本猶堪月下鋤。", "面壁且容趺足坐，此心雅與俗人疎。"]'),
('f0c4d1d2-d913-4d7d-b657-c04eddff4030','山間逢梅','方岳','宋','宋诗','song-poetry','','[]','自脫羸驂野水濱，隔橋孤倚欲迎人。',64,'全唐诗/poet.song.212000.json','["自脫羸驂野水濱，隔橋孤倚欲迎人。", "經年不覩雪霜面，一夜頓回天地春。", "姑射仙猶疑昨夢，首陽人恐是前身。", "歲寒莫問香何晚，畢竟凡花落後塵。"]'),
('66d4db05-3fe5-486f-94cf-8c5bf1d1bd14','胡得唯索寫近詩','方岳','宋','宋诗','song-poetry','','[]','生涯未辦闊疎酒，書冊相携檢點梅。',64,'全唐诗/poet.song.212000.json','["生涯未辦闊疎酒，書冊相携檢點梅。", "過眼事真如墮甑，向人口合且銜枚。", "昨窺古鏡十分瘦，病起晴窗一硯埃。", "舉世好竽吾好瑟，故人猶索寫詩來。"]'),
('0b516843-f40a-494f-93be-547b75a11ac1','簡王尉','方岳','宋','宋诗','song-poetry','','[]','買書終欲寄幽村，槿樹籬遮水際門。',64,'全唐诗/poet.song.212000.json','["買書終欲寄幽村，槿樹籬遮水際門。", "滿聽秋聲移竹母，徑眠明月枕桐孫。", "諸公未逸市朝累，六籍坐爲場屋昏。", "有客不來吾亦病，欲推此語與誰論。"]'),
('f91f7626-bbb6-4b4a-babd-7720568004d6','用葉司理韻簡趙尉','方岳','宋','宋诗','song-poetry','','[]','灞橋曾繫雪中鞍，本自無愁可得寬。',64,'全唐诗/poet.song.212000.json','["灞橋曾繫雪中鞍，本自無愁可得寬。", "山雨吹燈留客醉，官梅隔屋挾詩寒。", "月明烏鵲占佳晤，蓴老鱸魚夢故關。", "住近短牆通草徑，却須時一過方干。"]'),
('978fcec8-b6e4-4673-b83d-c8837f1a5a6a','十月六日園丁置墨紫','方岳','宋','宋诗','song-poetry','','[]','已是年時欲雪天，誰回冷落作芳妍。',64,'全唐诗/poet.song.212000.json','["已是年時欲雪天，誰回冷落作芳妍。", "極知品在羣葩上，忽與梅爭一著先。", "顔色依然香墨重，花頭不減暮春圓。", "人言桃李多如此，有底能移造化權。"]'),
('bcd94dfb-231c-4052-a447-4a1cfc748dfe','歐陽相士謁書詣梁權郡詩以代之','方岳','宋','宋诗','song-poetry','','[]','江臯誤洗荷鋤手，滴盡滄浪書滿家。',64,'全唐诗/poet.song.212000.json','["江臯誤洗荷鋤手，滴盡滄浪書滿家。", "第一諱窮人謬甚，再三稱好子虛耶。", "霜眠茅屋可無酒，春到梅梢怕有花。", "煩見歙州梁別駕，爲言詩骨雪槎牙。"]'),
('72ea1c3f-31a6-40ca-a0a2-18c25470d5bf','病起木犀已謝','方岳','宋','宋诗','song-poetry','','[]','一年秋是桂花開，誰道今年負酒杯。',64,'全唐诗/poet.song.212000.json','["一年秋是桂花開，誰道今年負酒杯。", "造物小兒真惡劇，癡頑老子久摧頹。", "清風明月不常有，溪友山翁試與來。", "夜寂尚憐詩骨在，時能引手作敲推。"]'),
('806ff33f-848f-4e61-b257-1f27d63dee86','桂子白大監饟酒冰炭','方岳','宋','宋诗','song-poetry','','[]','尺雪專爲我輩寒，故人亦肯記袁安。',64,'全唐诗/poet.song.212000.json','["尺雪專爲我輩寒，故人亦肯記袁安。", "麒麟紅作千金直，鸚鵡綠隨雙玉乾。", "貸米不煩臨古帖，敲門未敢兀吟鞍。", "明朝第一番花信，也辦瓊絲翠縷盤。"]'),
('1353089f-845d-4430-91ab-23ac09523004','除夜宿桐廬','方岳','宋','宋诗','song-poetry','','[]','才有佳山便歇程，島煙汀雨正關情。',64,'全唐诗/poet.song.212000.json','["才有佳山便歇程，島煙汀雨正關情。", "世於吾道亦聊爾，我與梅花各瘦生。", "無處不曾供夜話，有田誰肯廢春耕。", "年華俱在客中過，只爲天公乞一晴。"]'),
('17456803-1350-4ab1-a2d5-1bc5bc2c58e2','除夜  其一','方岳','宋','宋诗','song-poetry','','[]','年華三百六十日，塵勞八萬四千門。',64,'全唐诗/poet.song.212000.json','["年華三百六十日，塵勞八萬四千門。", "高眠茅屋人亦老，相對梅花燈欲昏。", "靜中頗窺造物意，極處是爲天地根。", "生菜春盤一杯酒，明朝花柳又村村。"]'),
('65c95707-bbd2-418a-ba85-ecce7f910a6c','除夜  其二','方岳','宋','宋诗','song-poetry','','[]','挑盡寒燈歲又殘，一年彈指幾悲歡。',64,'全唐诗/poet.song.212000.json','["挑盡寒燈歲又殘，一年彈指幾悲歡。", "人情何啻吳江冷，世路從來蜀道難。", "春酒正須今夕共，梅花併作百年看。", "團欒但得吾親健，未辦生涯意自寬。"]'),
('8675cef9-9a12-4297-958d-bebea4b3c98d','上巳修禊社謝兩園','方岳','宋','宋诗','song-poetry','','[]','海棠過了只垂楊，合與良辰卜醉鄉。',64,'全唐诗/poet.song.212000.json','["海棠過了只垂楊，合與良辰卜醉鄉。", "定勝永和三月禊，併遊社謝兩流觴。", "定州刻石猶真贋，晉代衣冠今在亡。", "陶寫豈無絲竹在，不醻酒渴與詩狂。"]'),
('84061caa-948a-41f8-94a9-f4021276005c','檢校塢中','方岳','宋','宋诗','song-poetry','','[]','檢校平生瓜芋區，鋤雲荷月儘堪娛。',64,'全唐诗/poet.song.212000.json','["檢校平生瓜芋區，鋤雲荷月儘堪娛。", "山中鶴帳依然在，天下魚羹何處無。", "古蘚蒼厓松老大，夕陽黄犢草荒蕪。", "縱無田亦歸來是，說與秋風不爲鱸。"]'),
('04fcf582-2ae0-443d-832f-2be43444a21f','次韻鄭僉判  其一','方岳','宋','宋诗','song-poetry','','[]','老我菟裘月一間，仰眠黄犢看青山。',64,'全唐诗/poet.song.212000.json','["老我菟裘月一間，仰眠黄犢看青山。", "有詩倚竹猿猱逕，無夢排雲虎豹關。", "城郭是非溪隔斷，風煙滅沒筆追還。", "底須一局銷長日，併不能棋方是閒。"]'),
('8c0d2417-8e25-475a-a4a6-7d768b9fec32','次韻鄭僉判  其二','方岳','宋','宋诗','song-poetry','','[]','不論山北與山南，是處移將竹兩三。',64,'全唐诗/poet.song.212000.json','["不論山北與山南，是處移將竹兩三。", "亦愛村深工部屋，尚嫌門對相公潭。", "夕陽歸鳥占花塢，山雨飯牛規草庵。", "口掛壁從生白醭，是中除酒百無堪。"]'),
('98b80ed0-ec88-4a49-ae79-48d7d3c7b85c','次韻鄭僉判  其三','方岳','宋','宋诗','song-poetry','','[]','漁村留得舊蓑衣，鷺侶鷗朋共斷磯。',64,'全唐诗/poet.song.212000.json','["漁村留得舊蓑衣，鷺侶鷗朋共斷磯。", "衰髮三千餘丈白，倦遊五十二年非。", "清風明月天四壁，老木蒼藤草半扉。", "寂寞相從交有道，驪駒未可遽言歸。"]'),
('02a0324f-7e66-4234-ab78-4c36e7e1955f','次韻鄭僉判  其四','方岳','宋','宋诗','song-poetry','','[]','一枕羲皇失午熇，久知吾道定寥寥。',64,'全唐诗/poet.song.212000.json','["一枕羲皇失午熇，久知吾道定寥寥。", "客來且撥浮蛆甕，事過真成覆鹿蕉。", "野性從來便水石，此生自合老漁樵。", "移床更入深雲處，厥木惟喬厥草夭。"]'),
('9e2dfe91-448a-4fed-91cf-922fc3239500','次韻鄭僉判  其五','方岳','宋','宋诗','song-poetry','','[]','十畝山園賦遂初，左花右竹了無餘。',64,'全唐诗/poet.song.212000.json','["十畝山園賦遂初，左花右竹了無餘。", "擇陰老我自麋鹿，甘带何人不蝍蛆。", "佛社獨容陶令醉，帝城難作子公書。", "行山且不携詩卷，只許鴟夷載後車。"]'),
('b25b91e7-e248-41d0-84aa-d61b40bfbd6f','次韻鄭僉判  其六','方岳','宋','宋诗','song-poetry','','[]','白菰紫芰更紅蕖，不枉平生水竹居。',64,'全唐诗/poet.song.212000.json','["白菰紫芰更紅蕖，不枉平生水竹居。", "醉眼豈知吾是我，機心亦笑子非魚。", "無能涉世何妨睡，有道登山只是徐。", "六月好風清樾底，付渠天地一蘧蒢。"]'),
('0eef0612-7688-4d01-b88e-f971d5bbbe6a','次韻鄭僉判  其七','方岳','宋','宋诗','song-poetry','','[]','煙藤雲木捲蒼虬，更放琅玕出一頭。',64,'全唐诗/poet.song.212000.json','["煙藤雲木捲蒼虬，更放琅玕出一頭。", "山下人家方酷暑，此中棋局自驚秋。", "圖書如昨不堪煮，風月無多誰與酬。", "怪得縱橫蘇季子，歲寒也憶舊貂裘。"]'),
('836ddb29-f5b3-4f89-a804-4b41e99513fe','次韻鄭僉判  其八','方岳','宋','宋诗','song-poetry','','[]','詩窮不易辦亭材，只恁荒寒處處苔。',64,'全唐诗/poet.song.212000.json','["詩窮不易辦亭材，只恁荒寒處處苔。", "種秫便當終老去，愛花能有幾人來。", "生前儘足竹三逕，身外無窮水一杯。", "未必諸賢知此意，柴門雖設不曾開。"]'),
('2f2feb64-f402-48f4-b886-f0679fd9472e','次韻陳祭酒直舍木犀','方岳','宋','宋诗','song-poetry','','[]','西雝夜直秋風底，斷是龍涎不敢香。',64,'全唐诗/poet.song.212000.json','["西雝夜直秋風底，斷是龍涎不敢香。", "月府肯分金粟粟，書床相對玉琅琅。", "人間富貴夢不到，世外高寒味儘長。", "亦笑柴桑千載士，同時祇識菊花黄。"]'),
('ae59fbe0-1898-4445-bb1d-98284870d36a','雨花臺','方岳','宋','宋诗','song-poetry','','[]','孤雲落日倚西風，歷歷興亡望眼中。',64,'全唐诗/poet.song.212000.json','["孤雲落日倚西風，歷歷興亡望眼中。", "山入六朝青未了，江浮五馬恨無窮。", "客愁已付葡萄綠，逕雨空餘瑪瑙紅。", "我亦欲談當世事，無人喚醒紫髯翁。"]'),
('47372a38-e436-42f3-acf5-aca2b53e7dce','鳳凰臺','方岳','宋','宋诗','song-poetry','','[]','白髮久孤鸚鵡盃，碧梧自老鳳凰臺。',64,'全唐诗/poet.song.212000.json','["白髮久孤鸚鵡盃，碧梧自老鳳凰臺。", "管夷吾亦僅知許，李謫仙今安在哉。", "城郭是非秋雨外，江山形勝暮潮來。", "小留只等中秋月，且放青冥萬里開。"]'),
('330b210b-a6b6-4aa3-b39e-f665f22aa8bc','白鷺亭','方岳','宋','宋诗','song-poetry','','[]','荻花蘆葉老風煙，獨上秋城思渺然。',64,'全唐诗/poet.song.212000.json','["荻花蘆葉老風煙，獨上秋城思渺然。", "白鷺不知如許事，赤烏又復幾何年。", "六朝往事秦淮水，一笛晚風江浦船。", "我輩人今竟誰是，只堪漁艇夕陽邊。"]'),
('bbecca53-54fd-4fc7-ad6e-61e01f3407d5','次韻王兄','方岳','宋','宋诗','song-poetry','','[]','江分曉色洗征衣，吾道非邪儻是歟。',64,'全唐诗/poet.song.212000.json','["江分曉色洗征衣，吾道非邪儻是歟。", "與世無緣傷骨鯁，歸田有日放眉舒。", "虎頭食肉亦安用，牛背看山却自如。", "留得荷鋤雙手在，儘堪老瓦一軒渠。"]'),
('41b74096-bea8-444f-bf50-048708eb64ae','次韻陳料院  其一','方岳','宋','宋诗','song-poetry','','[]','紅旗破賊本非才，白首爲郎更此來。',64,'全唐诗/poet.song.212000.json','["紅旗破賊本非才，白首爲郎更此來。", "羣玉府應羞噲伍，碧油幢誤築燕臺。", "江行莫等蛟鼉怒，雨歇能令鷗鷺猜。", "三逕未荒歸路好，秋風籬落菊花開。"]'),
('88594609-6e4a-439a-ad28-fb1192f5c4ca','次韻陳料院  其二','方岳','宋','宋诗','song-poetry','','[]','涉世曾經幾折肱，徑須歸卧北村燈。',64,'全唐诗/poet.song.212000.json','["涉世曾經幾折肱，徑須歸卧北村燈。", "往來屑屑無家燕，去住匆匆旦過僧。", "浦淑舟寒秋婉娩，江湖人老雪鬅鬙。", "草堂便在山深處，無復蓴鱸累季鷹。"]'),
('0ddb36a6-497e-4c25-b181-083b2ac65bf4','次韻陳料院  其三','方岳','宋','宋诗','song-poetry','','[]','書冊元非幕府才，江山牽率老夫來。',64,'全唐诗/poet.song.212000.json','["書冊元非幕府才，江山牽率老夫來。", "略分秋色歸吟卷，又誤春蓑下釣臺。", "有意及時常轗軻，無心於物莫驚猜。", "幽居亦有窮生活，麥隴蔬畦手自開。"]'),
('38fa2c6c-8bd3-46dd-a2e5-b8d0b8c72bdb','次韻陳料院  其四','方岳','宋','宋诗','song-poetry','','[]','久矣寒窗美曲肱，絕交書到短檠燈。',64,'全唐诗/poet.song.212000.json','["久矣寒窗美曲肱，絕交書到短檠燈。", "向來問舍漁樵侶，肯作歸田粥飯僧。", "耕罷夕陽牛觳觫，睡殘明月鶴鬅鬙。", "年來老懶略相似，見兔何能便放鷹。"]'),
('f0d2b1b8-5ef9-4a44-a61f-bfd9bb29f083','烏衣園','方岳','宋','宋诗','song-poetry','','[]','吳宮晉苑半桑麻，路入長干野草花。',64,'全唐诗/poet.song.212000.json','["吳宮晉苑半桑麻，路入長干野草花。", "秋晚夕陽空巷陌，蓄時燕子幾人家。", "不携妓與東山醉，曾賭碁輸別墅譁。", "已近重陽風雨少，菊花籬落酒旗斜。"]'),
('f781f551-5cd7-4793-a72f-01ab966a5ece','次韻吳樞密烏衣園舊韻','方岳','宋','宋诗','song-poetry','','[]','舊家門巷綠岧嶤，尚憶狨韉馬意驕。',64,'全唐诗/poet.song.212000.json','["舊家門巷綠岧嶤，尚憶狨韉馬意驕。", "金鑿落浮朱雀浦，玉丁東上紫宸朝。", "燕隨往事秋蕭瑟，鴈带夕陽江泬寥。", "九日黄華晴亦好，底須風雨又瀟瀟。"]'),
('e069e1dd-f5f6-44a6-90f2-39c923728903','九日集清凉佳處','方岳','宋','宋诗','song-poetry','','[]','老筆盤空墨未乾，最佳處與著危欄。',64,'全唐诗/poet.song.212000.json','["老筆盤空墨未乾，最佳處與著危欄。", "江山分與諸賢管，風雨專爲九日寒。", "白髮自驚秋節序，黄花曾識晉衣冠。", "未須計較明年健，別做茱萸一等看。"]'),
('78e1f959-ac6d-4df4-82eb-c5eb2b455f68','移飲治城樓','方岳','宋','宋诗','song-poetry','','[]','亭臯渺渺葉聲乾，更與西風一倚欄。',64,'全唐诗/poet.song.212000.json','["亭臯渺渺葉聲乾，更與西風一倚欄。", "鸚鵡杯深遺恨在，麒麟冢沒莫煙寒。", "山如有約欲排闥，詩不中書屢免冠。", "采菊東籬偶然耳，有人傳作畫圖看。"]'),
('4d1f291f-00e0-4941-80b1-95e4e5e14c73','金陵懷古','方岳','宋','宋诗','song-poetry','','[]','過江諸老儘風流，煞有佳娛竟未酬。',64,'全唐诗/poet.song.212000.json','["過江諸老儘風流，煞有佳娛竟未酬。", "杯滑釀成千古恨，角寒吹老一城秋。", "蟹初上籪詩仍雋，燕已還家客自愁。", "漁父不知興廢事，月明多在荻花洲。"]'),
('dccd98ab-dffc-48a3-a810-6f9f6ed392d9','病中酬王尉','方岳','宋','宋诗','song-poetry','','[]','造物無何亦小兒，一生心事只山知。',64,'全唐诗/poet.song.212000.json','["造物無何亦小兒，一生心事只山知。", "江湖晚歲勤行李，風雨重陽倒接䍦。", "硯老自研明月露，蟹香新在菊花時。", "與君共住維摩室，何日重携鶴膝枝。"]'),
('f6c70870-002c-40ce-b078-a2697e57e97f','雨夜持螯','方岳','宋','宋诗','song-poetry','','[]','白鷗盟在且歸休，吾道非邪自白鷗。',64,'全唐诗/poet.song.212000.json','["白鷗盟在且歸休，吾道非邪自白鷗。", "識字不供餘子笑，能詩贏得一生愁。", "寒花已共歲年晚，薄酒難禁煙雨秋。", "郭索解圍功獨雋，中書君擬內黄侯。"]'),
('1dee13fb-0e02-4d6e-922e-8786c0467713','呂宗卿以病謝客明日約飯則予行矣詩以代簡','方岳','宋','宋诗','song-poetry','','[]','長松落落雪霜姿，欲往從之我所思。',64,'全唐诗/poet.song.212000.json','["長松落落雪霜姿，欲往從之我所思。", "剝啄始知摩詰病，推敲誰話賈僧詩。", "可羞吾事蚊䖟等，坐失先生鷄黍期。", "細雨斷雲秋晚路，此情猶有菊花知。"]'),
('f400fb51-4140-482d-93a0-fde7ae3e868a','寄別季桐廬','方岳','宋','宋诗','song-poetry','','[]','一湖寒淥記傳杯，三見孤山雪底梅。',64,'全唐诗/poet.song.212000.json','["一湖寒淥記傳杯，三見孤山雪底梅。", "脫我素冠惟骨在，聽君清話得眉開。", "底須政事喧京輦，例合詩人管釣臺。", "債縣近來那可向，江山雖美盍歸來。"]'),
('50d3acb6-88b7-48ca-bc42-6806c82e2096','次韻趙同年贈示進退格  其一','方岳','宋','宋诗','song-poetry','','[]','半生湖海老元龍，不肯函書問子公。',64,'全唐诗/poet.song.212000.json','["半生湖海老元龍，不肯函書問子公。", "蓬鬢此來真潦倒，荷衣久已倦迎逢。", "春風期集幾年夢，夜醉比鄰一笑同。", "已洗從前箏笛耳，豈堪奉缶雜倕鍾。"]'),
('8c044e28-a817-4e11-b698-77f2482a4d50','次韻趙同年贈示進退格  其二','方岳','宋','宋诗','song-poetry','','[]','鬼自揶揄劉伯龍，文窮斷不怨天公。',64,'全唐诗/poet.song.212000.json','["鬼自揶揄劉伯龍，文窮斷不怨天公。", "諸侯王表今安用，中聖賢人時一逢。", "凡事無心從我拙，獨詩有癖與君同。", "簷花細雨從容夜，待發華鯨鏗鉅鐘。"]'),
('76bac518-e88f-4434-8db8-bcb0c965ebfe','有蟹無酒','方岳','宋','宋诗','song-poetry','','[]','左手持螯欠酒杯，枉烹郭索亦冤哉。',64,'全唐诗/poet.song.212000.json','["左手持螯欠酒杯，枉烹郭索亦冤哉。", "老饕借爾爲詩地，多病憑誰作睡媒。", "歸釣興隨春浩蕩，獨醒人與月徘徊。", "淵明未必窮於我，薄有公田辦秫材。"]'),
('ac130bd3-5d5f-42b5-8ead-c9673ffaa5b3','九日與同年沈貫卿飲月墅','方岳','宋','宋诗','song-poetry','','[]','自摘黄花插滿頭，誰憐白髮不禁秋。',64,'全唐诗/poet.song.212000.json','["自摘黄花插滿頭，誰憐白髮不禁秋。", "同年肯過盧仝屋，九日共登王粲樓。", "天氣政爲吾輩設，酒香莫對俗人篘。", "渠儂儘把茱萸看，更與淵明風馬牛。"]'),
('d63c40c2-6e01-42f5-bc6d-338fa067e4a4','春行','方岳','宋','宋诗','song-poetry','','[]','蘚石闌干一欠伸，垂楊無力不禁顰。',64,'全唐诗/poet.song.212000.json','["蘚石闌干一欠伸，垂楊無力不禁顰。", "清明此去幾何日，燕子未來誰可人。", "病起不知雙鬢雪，雨中老却一分春。", "西山雲卧蕨拳紫，待約溪翁飽食新。"]'),
('b61bdf34-e3e1-4637-b359-aed8e9a3ce85','饒監丞惠詩有未能上下逐東野之句次韻寄呈','方岳','宋','宋诗','song-poetry','','[]','誰肯低頭老孟郊，譬之草木等荃茅。',64,'全唐诗/poet.song.212000.json','["誰肯低頭老孟郊，譬之草木等荃茅。", "倚松人好傳聞久，采蕨山深夢寐勞。", "飛兔妙摛青玉案，胎仙重脫紫雲胞。", "小奚容入江西社，四海眼空毋甚高。"]'),
('2d50c7e4-03e8-4f6f-93a6-b1eeb5e85bdb','修胥山路','方岳','宋','宋诗','song-poetry','','[]','兩山壁立束微行，石齒參差半已傾。',64,'全唐诗/poet.song.212000.json','["兩山壁立束微行，石齒參差半已傾。", "莫等危時扶使穩，但逢險處放教平。", "一毫以上諸人力，半月之間樂事成。", "安得坦夷三萬里，家家門外是鵬程。"]'),
('39c663b7-db11-4c3c-8e0f-2d1cdb575943','宿耕舍','方岳','宋','宋诗','song-poetry','','[]','題詩蘚壁墨花新，俛仰之間迹已陳。',64,'全唐诗/poet.song.212000.json','["題詩蘚壁墨花新，俛仰之間迹已陳。", "檢點不同今老大，受持只是舊清貧。", "蓬蔂笠漬班班雨，荷葉衫枯䔩䔩塵。", "枉廢春鋤成底事，重來慙見耦耕人。"]'),
('d6962823-dcd1-41a1-9b13-cc4a07015474','僧至','方岳','宋','宋诗','song-poetry','','[]','生計蕭條老杜陵，秋風檢校又東屯。',64,'全唐诗/poet.song.212000.json','["生計蕭條老杜陵，秋風檢校又東屯。", "碧雲句好山圍屋，黄葉村深僧扣門。", "雨滑且留煨芋栗，夜長聊欲話田園。", "掉歌笑指風僧耳，已喜聞思斷一根。"]'),
('354ec58f-56ab-4446-8f74-437402960da2','郡宅舊有飛泉湮廢不治予接竹重理之','方岳','宋','宋诗','song-poetry','','[]','竹泉重理舊潺湲，能費亭前玉幾竿。',64,'全唐诗/poet.song.212000.json','["竹泉重理舊潺湲，能費亭前玉幾竿。", "雲卧半簷晴亦雨，雪飛六月午猶寒。", "野人久有煙霞癖，官屋何如天地寬。", "白傅極知兒戲耳，一生水石作奇觀。"]'),
('26febd4f-a48c-4205-9257-e972bdc31fbe','送史子貫歸覲且迎婦也','方岳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久住西湖夢亦佳，鷺朋鷗侶自煙沙。',64,'全唐诗/poet.song.212000.json','["久住西湖夢亦佳，鷺朋鷗侶自煙沙。", "江行楓葉幾何里，春到梅梢次第花。", "儘有好山容對榻，却因吾子轉思家。", "青燈書冊夜深雨，莫爲乘鸞學畫鴉。"]'),
('a9078709-78d2-4cd1-b11e-d6d0b38011f4','官滿將歸與同幕別平山堂  其一','方岳','宋','宋诗','song-poetry','','[]','鷗未寒盟儻可尋，歸與雅不負登臨。',64,'全唐诗/poet.song.212000.json','["鷗未寒盟儻可尋，歸與雅不負登臨。", "江南山作故人面，雲北鴈知遊子心。", "淮海三年雙鬢短，乾坤萬里一杯深。", "秋風正愜蓴羹腹，松菊猶存月滿林。"]'),
('f7e40681-4dd6-45b6-b92e-594cef4c2cd9','官滿將歸與同幕別平山堂  其二','方岳','宋','宋诗','song-poetry','','[]','貂敝那禁塞上寒，所成何事許悲酸。',64,'全唐诗/poet.song.212000.json','["貂敝那禁塞上寒，所成何事許悲酸。", "雪深茅屋歸巢冷，月老蘆洲鴈影單。", "官薄偶書三考滿，客懷已受一分寬。", "秋帆但趁好風便，酒在不愁行路難。"]'),
('8e53ca2a-2149-4125-9cce-3bb9c13f18af','陪吳總侍集研山用趙端明送行韻','方岳','宋','宋诗','song-poetry','','[]','煙波畫出暮江天，著我蘆花明月船。',64,'全唐诗/poet.song.212000.json','["煙波畫出暮江天，著我蘆花明月船。", "官滿只稱前進士，路貧休問小行年。", "一歸已後陶元亮，衆論寧無班孟堅。", "不負登臨重九約，過江猶及菊花前。"]'),
('944c7598-d74c-45ce-bbb4-65fd7e7d190b','次韻鄭司理時以掌故贅梱幙歸未能也','方岳','宋','宋诗','song-poetry','','[]','二月江南柳正花，扶携貧病又天涯。',64,'全唐诗/poet.song.212000.json','["二月江南柳正花，扶携貧病又天涯。", "愁予夜雨蓴鱸夢，老却春山笋蕨芽。", "太白有芒兵未歇，殺青無補事堪嗟。", "書生迂闊多如此，不爲吟詩兩鬢華。"]'),
('a68bc300-9a59-4b1e-a754-e9188015f45e','惠山月印師用予尋家韻詩見簡輒復賡載寺前老松僵卧風雨中月印因其摧剝而封殖之返成奇觀欲爲下一轉語未暇也故卒章及之','方岳','宋','宋诗','song-poetry','','[]','相逢僧話了幽尋，不負滄浪一訪臨。',64,'全唐诗/poet.song.212000.json','["相逢僧話了幽尋，不負滄浪一訪臨。", "對菊莫談當世事，品茶猶識古人心。", "白雲共住山前後，黄葉自知秋淺深。", "龍卧蒼髯曾有約，鴈回分月供叢林。"]'),
('a8634843-c967-4dd3-ab64-22c6b7ca6daf','九日道中','方岳','宋','宋诗','song-poetry','','[]','重陽却喜無風雨，野菊迎人亦自花。',64,'全唐诗/poet.song.212000.json','["重陽却喜無風雨，野菊迎人亦自花。", "年去年來秋又老，江南江北鬢將華。", "離騷如此那無酒，羈旅雖諳不似家。", "但得東籬堪種菊，儘容吾子岸烏紗。"]'),
('9bea9e63-b903-4e00-ac26-4a3f1516c550','送蔡子奇節推之官廬陵','方岳','宋','宋诗','song-poetry','','[]','春不多寒風已柔，數君到日正紅稠。',64,'全唐诗/poet.song.212000.json','["春不多寒風已柔，數君到日正紅稠。", "庵藏澹叟詩成集，山護醉翁書滿樓。", "岸柳欲眠維鷁首，幕蓮俱起看鼇頭。", "無忘曉殿三千字，一洗公孫富貴羞。"]'),
('9e82ce25-896e-4719-8d5c-33177259f5ca','宋君挽詞','方岳','宋','宋诗','song-poetry','','[]','持家不廢夜窗書，未了功名志竟違。',64,'全唐诗/poet.song.212000.json','["持家不廢夜窗書，未了功名志竟違。", "是處青山曾對飲，祇今白羽爲誰揮。", "楊花亂落春無極，燕子重來人已非。", "手斸蒼煙營葬地，可堪晴樹轉斜暉。"]'),
('3462304c-85ff-43ba-b1e9-54227de3ee11','次韻謝兄見寄','方岳','宋','宋诗','song-poetry','','[]','寒入吟肩兀蹇鞍，灞橋風雪幾躋攀。',64,'全唐诗/poet.song.212000.json','["寒入吟肩兀蹇鞍，灞橋風雪幾躋攀。", "諸賢有意起更化，老我無能悔出山。", "談到時文真破碎，情知吾道轉間關。", "武元衡事傳聞否，倦翼孤飛正欲還。"]'),
('6462dea3-aeb6-4f73-989d-9ce6e4487605','蟹至十數日而價比異時特貴貧者只得忍口薄暮有以爲餉者作詩回餉','方岳','宋','宋诗','song-poetry','','[]','蟹之風月元無價，只賣百錢那是錢。',64,'全唐诗/poet.song.212000.json','["蟹之風月元無價，只賣百錢那是錢。", "醉墮多生貪愛業，貧隨現在喜歡緣。", "以名怒爾吾何敢，謂腹負予誰不然。", "新與客嘗秋已老，豈堪持到菊花前。"]'),
('de141e17-d66e-4468-8f77-1cda56c1a7dd','陪汪少卿遊紫陽次梁倅韻','方岳','宋','宋诗','song-poetry','','[]','此行許老亦津津，連夜催將雪樹春。',64,'全唐诗/poet.song.212000.json','["此行許老亦津津，連夜催將雪樹春。", "溪隔更無塵土事，山矜便識謫仙人。", "雲依欄過香仍濕，墨带冰磨句轉新。", "丘壑自容吾入社，不論五馬兩朱輪。"]'),
('35babaa9-76bc-4db6-839f-074aff41e2f8','次韻酬洪監倉','方岳','宋','宋诗','song-poetry','','[]','我輩從來不入時，知心粗有硯相隨。',64,'全唐诗/poet.song.212000.json','["我輩從來不入時，知心粗有硯相隨。", "肯分雪屋十年夢，寫作秋山一段奇。", "簾靜堂深無比客，歲寒亭老有先師。", "梧桐带晚西風起，笑拂床頭鐵蒺藜。"]'),
('3ba19ade-4e82-431c-8e4d-4e18d38fa8f5','再用韻簡趙簿','方岳','宋','宋诗','song-poetry','','[]','相逢傾蓋幾何時，世俗於君亦詭隨。',64,'全唐诗/poet.song.212000.json','["相逢傾蓋幾何時，世俗於君亦詭隨。", "但覺文名驚朽鈍，徑令詩腹化神奇。", "別來已賦三秋句，久欲尊爲一字師。", "洗耳正須過習簿，强於太乙夜燒藜。"]'),
('c34438e7-358b-4af2-b752-62f0adc5e936','次韻王尉贈別  其一','方岳','宋','宋诗','song-poetry','','[]','十載春泥濺客衣，江湖半已入吾詩。',64,'全唐诗/poet.song.212000.json','["十載春泥濺客衣，江湖半已入吾詩。", "事今豈得文章力，心亦難求世俗知。", "山意向人如有語，鷗盟於我合歸誰。", "月明昨夜欺寒夢，未了西齋竹外棋。"]'),
('ee7e59f0-f1b4-4d76-9067-e78c493a0f47','次韻王尉贈別  其二','方岳','宋','宋诗','song-poetry','','[]','摩挲老硯欲生衣，煞欠梅花別後詩。',64,'全唐诗/poet.song.212000.json','["摩挲老硯欲生衣，煞欠梅花別後詩。", "明月夜憐無客共，故人心豈不吾知。", "相看白眼了無忤，除却青山更有誰。", "但得秫田供醉夢，世情付與爛柯棋。"]'),
('75c60fc5-a56d-4e9c-bf17-80dc8a45bb83','次韻王尉白事幕府','方岳','宋','宋诗','song-poetry','','[]','一癡便了公家事，儘可與詩寬作程。',64,'全唐诗/poet.song.212000.json','["一癡便了公家事，儘可與詩寬作程。", "書冊不嫌官屋冷，香匜相對歙溪晴。", "熟知白鷺難爲伴，煩見青山且寄聲。", "此別不過旬日耳，又携孤嘯上江城。"]'),
('a3907ed3-ff59-44b2-a09a-6ff53133408e','山中用放翁韻  其一','方岳','宋','宋诗','song-poetry','','[]','一盂之飯一盤蔬，底用橫身犯毀譽。',64,'全唐诗/poet.song.212000.json','["一盂之飯一盤蔬，底用橫身犯毀譽。", "與世無緣空落落，登山有道但徐徐。", "體中不快惟讀易，老去更貧常典書。", "四海誰知今夜月，梅花飄雪縞吾廬。"]'),
('d7e8d1c3-b245-4e67-8ecf-37ac32318565','山中用放翁韻  其二','方岳','宋','宋诗','song-poetry','','[]','山畦夜雨入春蔬，此手猶存足自譽。',64,'全唐诗/poet.song.212000.json','["山畦夜雨入春蔬，此手猶存足自譽。", "甚愛踏青人已至，未能浮白子姑徐。", "有山拄頰寧須笏，無策資身不爲書。", "莫向夕陽多感慨，百年長短一蘧廬。"]'),
('9a945e0a-5f46-442b-abcc-6f052c22dba3','元日','方岳','宋','宋诗','song-poetry','','[]','釣寂耕閒老病身，何堪附翼與攀鱗。',64,'全唐诗/poet.song.212000.json','["釣寂耕閒老病身，何堪附翼與攀鱗。", "山中是處有詩思，天上自來無故人。", "歲事共知雙鬢雪，梅花又過一年春。", "晴妍已有溪村興，牛下柴車或可巾。"]'),
('e54e2527-35ce-4925-bd72-686e72d38bad','元日','方岳','宋','宋诗','song-poetry','','[]','坎止流行一任他，年華其奈老夫何。',64,'全唐诗/poet.song.212000.json','["坎止流行一任他，年華其奈老夫何。", "貧知醉有回天日，早得閒爲却日戈。", "野燒青歸煙髣髴，溪痕晴漲雪坡陀。", "屠蘇只對梅花飲，茅屋竹籬春意多。"]'),
('9cb1715b-983f-48ea-aedd-edac773a4577','元日雨  其一','方岳','宋','宋诗','song-poetry','','[]','那得工夫作往還，一犂取日破荒灣。',64,'全唐诗/poet.song.212000.json','["那得工夫作往還，一犂取日破荒灣。", "春今又綠山中草，酒不能朱鏡裏顔。", "六十只餘三歲在，百年亦是霎時間。", "村村雨色冥濛外，已覺天公露一斑。"]'),
('f537f7c2-5bc5-4407-aafa-785b3168c733','元日雨  其二','方岳','宋','宋诗','song-poetry','','[]','雲泥隔斷拜年人，天自憐予老病身。',64,'全唐诗/poet.song.212000.json','["雲泥隔斷拜年人，天自憐予老病身。", "薺菜共挑元日雨，梅花未放去年春。", "風煙不盡惟吾老，造化無他只此仁。", "小試園林栽接手，山中亦是一洪鈞。"]'),
('d8cf29b0-3fcd-4d34-8113-c362d19302b1','立春  其一','方岳','宋','宋诗','song-poetry','','[]','初信東風入綵幡，自挑雪薺飣春盤。',64,'全唐诗/poet.song.212000.json','["初信東風入綵幡，自挑雪薺飣春盤。", "土牛又送一年老，野鶴不知三逕寒。", "筋力尚堪耕綠野，鬢毛併欲掛黄冠。", "無人共跨南山犢，便作尋花問柳看。"]'),
('0832bbd9-5c35-4bf4-8ea9-ceedb635085c','立春  其二','方岳','宋','宋诗','song-poetry','','[]','詩儻窮人莫送窮，但窮詩亦不須工。',64,'全唐诗/poet.song.212000.json','["詩儻窮人莫送窮，但窮詩亦不須工。", "銀幡雪柳人何似，翠縷瓊絲菜則同。", "百事到頭惟早白，一年彈指又春紅。", "漁溪亦喜溪冰冸，新綠生肥撼釣筒。"]'),
('21a75103-f24e-4e3e-8d22-ec00bdede680','立春前一日雪  其一','方岳','宋','宋诗','song-poetry','','[]','入冬妍暖幾兼旬，明日銀幡歲又新。',64,'全唐诗/poet.song.212000.json','["入冬妍暖幾兼旬，明日銀幡歲又新。", "絕意六花無復臘，等閒一尺不勝春。", "老天咳唾何難事，瘦地耕鉏亦幸民。", "徑就梅梢嚼清冷，相如渴肺久生塵。"]'),
('5a42261a-f470-460e-a808-b53a04687ab7','立春前一日雪  其二','方岳','宋','宋诗','song-poetry','','[]','歷眼看看剩浹旬，山河大地一齊新。',64,'全唐诗/poet.song.212000.json','["歷眼看看剩浹旬，山河大地一齊新。", "不成過臘都無雪，只隔明朝便是春。", "夜半有誰過剡曲，年豐無處不堯民。", "草亭只在梅花外，知與人間隔幾塵。"]'),
('c522f5b4-e22c-4483-b7b1-d6e8016872ac','立春','方岳','宋','宋诗','song-poetry','','[]','花柳胚胎午夜風，一尊聊與破紅封。',64,'全唐诗/poet.song.212000.json','["花柳胚胎午夜風，一尊聊與破紅封。", "醉餘安用淄澠口，妙處元無涇渭胸。", "紙帳不知寒浩蕩，銀幡自愛雪髼鬆。", "小樓認得春來處，晴靄蒼茫南北峯。"]'),
('f2ef1d0d-2d3e-4de6-96e0-5964320a8bda','人日  其一','方岳','宋','宋诗','song-poetry','','[]','柳思花情曉夜春，空山煙水亦精神。',64,'全唐诗/poet.song.212000.json','["柳思花情曉夜春，空山煙水亦精神。", "閒中富貴陽和月，靜處乾坤自在身。", "久悟前三吾是客，又經上七日爲人。", "一蓑耕綠山南北，有賦何煩問大鈞。"]'),
('a2056829-9c57-4127-b1bb-e51d4d01053c','人日  其二','方岳','宋','宋诗','song-poetry','','[]','頼有空山著此翁，不然高論與誰同。',64,'全唐诗/poet.song.212000.json','["頼有空山著此翁，不然高論與誰同。", "百年會盡玄尚白，一氣不停春又紅。", "詩卷每隨煙水外，鳥聲多在夕陽中。", "年豐已卜晴人日，亦是平生𤱶畝忠。"]'),
('db370a5c-f864-4e0a-884f-08f7afd48e1f','人日吳明輔招不往','方岳','宋','宋诗','song-poetry','','[]','江湖老我百無堪，嬾過紬書太史談。',64,'全唐诗/poet.song.212000.json','["江湖老我百無堪，嬾過紬書太史談。", "雨脚又連人日暗，酒腸那似少年酣。", "一生出處龜藏六，萬事乘除狙賦三。", "且試半篙春水綠，南山之北北山南。"]'),
('e7930efa-c09e-4205-9bf7-0213c9af6071','元夕','方岳','宋','宋诗','song-poetry','','[]','茅屋相看冷似冰，蒲團孤坐澹於僧。',64,'全唐诗/poet.song.212000.json','["茅屋相看冷似冰，蒲團孤坐澹於僧。", "數行老墨閒居賦，一炷寒燈耐久朋。", "時異不供三太息，吾衰何啻百無能。", "後山亦有梅花月，不復年時興可乘。"]'),
('c127057c-f881-497a-9b3d-e3fba586ab0e','元夕雪用韻','方岳','宋','宋诗','song-poetry','','[]','山蹊一色輕明玉，遮盡青青印屐苔。',64,'全唐诗/poet.song.212000.json','["山蹊一色輕明玉，遮盡青青印屐苔。", "元夕不知今日是，春愁政用此時來。", "年華鼎鼎雙蓬鬢，身世悠悠一酒杯。", "好事斷無人問字，竹門隔塢不須開。"]'),
('fc089f3c-075d-4162-8657-2501c9221ace','歸來館成再用韻','方岳','宋','宋诗','song-poetry','','[]','後門穿過荷葭塢，春草池塘一逕苔。',64,'全唐诗/poet.song.212000.json','["後門穿過荷葭塢，春草池塘一逕苔。", "盡廢秫田妨醉去，旋苫山館號歸來。", "知無骨相取金印，莫與春秋著玉杯。", "自有梅花可人意，南枝開了北枝開。"]'),
('14259a84-5d35-4f97-9263-56c56e1a94e8','上元大雪重賦','方岳','宋','宋诗','song-poetry','','[]','愁霖半月辦此雪，元夕山城特地寒。',64,'全唐诗/poet.song.212000.json','["愁霖半月辦此雪，元夕山城特地寒。", "頓有園林春富貴，略無燈火夜闌珊。", "年饑那得花成市，天巧聊將玉作欄。", "百紫千紅生意動，不知后土幾時乾。"]'),
('0ff9f377-10f7-43f9-8c36-e98e9f59ffdd','明日登後山用韻','方岳','宋','宋诗','song-poetry','','[]','雪林籬落行清曉，畢竟山人太耐寒。',64,'全唐诗/poet.song.212000.json','["雪林籬落行清曉，畢竟山人太耐寒。", "酒聖坐來春泛泛，梅仙飛去玉珊珊。", "草塘喚就荷葭塢，竹徑生成花藥欄。", "詩敵只愁成小怯，邇來自覺筆頭乾。"]'),
('54dfaeed-e93e-4262-96ca-7642fd49f5b1','聞雨','方岳','宋','宋诗','song-poetry','','[]','夜聞一霎兩霎雨，春著村南村北花。',64,'全唐诗/poet.song.212000.json','["夜聞一霎兩霎雨，春著村南村北花。", "紫綿撲撲海棠藟，翠毯茸茸沙蔣芽。", "遊芳要非老者事，幽意自屬山人家。", "東風莫漫盡桃李，留與繞屋深桑麻。"]'),
('5fae95db-f988-4d88-9565-420a8124ae8a','大雨','方岳','宋','宋诗','song-poetry','','[]','蟄龍怒欲起春霆，併挾髯虬上杳冥。',64,'全唐诗/poet.song.212000.json','["蟄龍怒欲起春霆，併挾髯虬上杳冥。", "老色干雲鱗甲動，蒼皮粘雹爪痕腥。", "物方神變誰能測，山不高深亦有靈。", "誰與護持詩墨在，略無風雨損吾亭。"]'),
('906c6da9-59ad-41c1-9957-fdabe0555cb7','春雨','方岳','宋','宋诗','song-poetry','','[]','茅齋堅坐日日雨，竹杖長閒處處苔。',64,'全唐诗/poet.song.212000.json','["茅齋堅坐日日雨，竹杖長閒處處苔。", "半面不曾梅別去，四愁無奈草生來。", "好山能費幾兩屐，勝日須傾三百杯。", "說與海棠毋造次，不論蚤晚待晴開。"]'),
('9f985ac0-36ec-41ee-b8d4-09970dd1152c','雨中有感','方岳','宋','宋诗','song-poetry','','[]','山蟄驚塵已發聲，移花移竹正忙生。',64,'全唐诗/poet.song.212000.json','["山蟄驚塵已發聲，移花移竹正忙生。", "相成老子一春事，只費天公幾日晴。", "何以消憂惟酒可，無能爲役以詩鳴。", "身其隠矣名安用，寄語諸賢月旦評。"]'),
('ffedb186-cc1d-4b46-9a6f-53efc2931c04','百舌','方岳','宋','宋诗','song-poetry','','[]','巧語如簧不待頻，東皇已爲轉洪鈞。',64,'全唐诗/poet.song.212000.json','["巧語如簧不待頻，東皇已爲轉洪鈞。", "五更風雨知巢冷，幾處宮商隔塢春。", "時說一篇新陸賈，橫連六國舊蘇秦。", "恃吾舌在吾何患，從古不無渠輩人。"]'),
('c8b0aeba-eecb-4401-a0ed-d890f320cf4c','泗州之約令君以雨不至次韻奉酬','方岳','宋','宋诗','song-poetry','','[]','已料天公作好晴，近山初試一筇輕。',64,'全唐诗/poet.song.212000.json','["已料天公作好晴，近山初試一筇輕。", "溪平染就縠紋縐，雨急眠驚瀑布聲。", "醉裏梨花俱瘦盡，夢中池草太愁生。", "未知誰是文昌段，看得春風亦世情。"]'),
('4ee70b7a-ec7a-4f4e-b073-eead839a9a43','次韻徐宰集珠溪  其一','方岳','宋','宋诗','song-poetry','','[]','山家鳬鶩散平田，沙路雲深屐屢穿。',64,'全唐诗/poet.song.212000.json','["山家鳬鶩散平田，沙路雲深屐屢穿。", "半醉半醒寒食酒，欲晴欲雨杏花天。", "春能醖藉如相識，柳自風流未肯眠。", "野老不知詩思好，但言啼鳥亦欣然。"]'),
('8b042a67-7f1f-425f-a5f2-135938192946','次韻徐宰集珠溪  其二','方岳','宋','宋诗','song-poetry','','[]','僧不須敲飯後鐘，自携茶去借松風。',64,'全唐诗/poet.song.212000.json','["僧不須敲飯後鐘，自携茶去借松風。", "斬新山色佛頭綠，依舊桃花人面紅。", "春甕貯冰摇玉螘，夜堂烘蠟綴釵蟲。", "山靈共欲留人住，新月隔溪煙霧濛。"]'),
('f33ca5cd-86ea-4dbd-ab67-b6990fcb2aa6','乙酉歲遊浙中道聞盜起霅川遂寓珠溪','方岳','宋','宋诗','song-poetry','','[]','未到山陰興已闌，相傳道路正間關。',64,'全唐诗/poet.song.212000.json','["未到山陰興已闌，相傳道路正間關。", "故人坐隔月千里，老宿肯分雲半間。", "有客誰家無白酒，能詩何處不青山。", "一聲啼鳥長廊靜，花落花開春自閒。"]'),
('d88832ee-8bc3-48b0-8c62-fef784856b5e','過北固山下舊居','方岳','宋','宋诗','song-poetry','','[]','池塘燕子舊人家，楊柳春寒一逕斜。',64,'全唐诗/poet.song.212000.json','["池塘燕子舊人家，楊柳春寒一逕斜。", "夜讀自生書带草，朝饑曾對米囊花。", "侯誰在矣山如昨，今我來思鬢已華。", "舍館不知何日定，竹輿鳴雨又吚啞。"]'),
('53b2a84a-b292-4cb0-905f-769225254911','有感','方岳','宋','宋诗','song-poetry','','[]','桃花紅雨柳花綿，風物愁予重惘然。',64,'全唐诗/poet.song.212000.json','["桃花紅雨柳花綿，風物愁予重惘然。", "滿目江山分楚越，舊遊池館鎖塵煙。", "朝雲漠漠今安在，夜月荒荒空自圓。", "只有雪衣孤鶴在，竹間曾共聳吟肩。"]'),
('7daf9699-55e3-4db2-bc81-603ea6a3e17d','社日萬監招飲不往','方岳','宋','宋诗','song-poetry','','[]','土潤如酥麥已鞭，社公滿意作豐年。',64,'全唐诗/poet.song.212000.json','["土潤如酥麥已鞭，社公滿意作豐年。", "吹筒撾鼓兒童競，宰肉分膰父老專。", "欲事田園供歲課，未甘花鳥老春煙。", "客中不飲聾何害，正厭夜窗啼杜鵑。"]'),
('0e22b683-bd7a-43dc-af44-2809618a9fd5','約君用','方岳','宋','宋诗','song-poetry','','[]','十日春寒挾雨俱，新晴物色總歡娛。',64,'全唐诗/poet.song.212000.json','["十日春寒挾雨俱，新晴物色總歡娛。", "花曾識面若含笑，鳥不知名時自呼。", "流水短橋宜畫取，煖風遲日有詩無。", "儻來須蠟登山屐，村北村南路欲蕪。"]'),
('b4b5ee58-2216-4c53-a7c4-9eae96cb3ffe','留別','方岳','宋','宋诗','song-poetry','','[]','喚得篷船載幅巾，島煙畫出渭城春。',64,'全唐诗/poet.song.212000.json','["喚得篷船載幅巾，島煙畫出渭城春。", "匆匆笑語情何限，草草杯盤意甚真。", "經歲別家千里夢，浮生寄我一鷗身。", "舟人報道潮平早，舉白浮君莫厭頻。"]'),
('440f7277-1ac6-46f0-a64e-74175cb1c023','子魚','方岳','宋','宋诗','song-poetry','','[]','桃花水暖正魚肥，子脹連胞迸腹腴。',64,'全唐诗/poet.song.212000.json','["桃花水暖正魚肥，子脹連胞迸腹腴。", "黄栗玉燖春寸寸，水晶鹽醋粟銖銖。", "鮫人泣下甘孥戮，龍伯刑淫併孕刳。", "老子胸中兵百萬，酒船不枉到江湖。"]'),
('2c75ebc7-566c-4597-bfab-435ec4f72015','上冢  其一','方岳','宋','宋诗','song-poetry','','[]','煙水初平穩放閶，解纓聊復濯滄浪。',64,'全唐诗/poet.song.212000.json','["煙水初平穩放閶，解纓聊復濯滄浪。", "每年上冢天無準，是處下田春正忙。", "歲月可驚寒悄悄，賢愚同盡綠茫茫。", "早知識字能爲祟，不廢吾翁百本桑。"]'),
('422d163c-ddc2-46fa-a83f-ca43042965a6','上冢  其二','方岳','宋','宋诗','song-poetry','','[]','一盃麥飯灑悲辛，不盡烟蕪舊與新。',64,'全唐诗/poet.song.212000.json','["一盃麥飯灑悲辛，不盡烟蕪舊與新。", "地下豈無擔板漢，世間但有乞墦人。", "荼䕷芍藥幾何日，寒食清明又一春。", "自是老懷多感慨，非干芳草負蹄輪。"]'),
('e28ff66d-c49d-4449-bb0e-ef39166a23ed','春日雜興  其一','方岳','宋','宋诗','song-poetry','','[]','漁翁樵叟自行藏，裹飯過從樂未央。',64,'全唐诗/poet.song.212000.json','["漁翁樵叟自行藏，裹飯過從樂未央。", "撲滿自緣錢作祟，鴟夷聊以酒爲鄉。", "老來願棄人間世，病去欲荒牆下桑。", "黄犢不嫌人日雨，村村犂曉綠微茫。"]'),
('430ffac6-de39-4151-833e-5e88b09ecdd5','春日雜興  其二','方岳','宋','宋诗','song-poetry','','[]','殘雪初消月正明，茅簷自雨竹窗晴。',64,'全唐诗/poet.song.212000.json','["殘雪初消月正明，茅簷自雨竹窗晴。", "肩寒聳聳吟詩骨，肺渴泠泠醉酒羹。", "苟有梅方成野趣，不多松亦作江聲。", "高人合著山巖裏，縱有窮愁徹底清。"]'),
('49b27421-4a6d-463c-aff3-4130ca7c9463','春日雜興  其三','方岳','宋','宋诗','song-poetry','','[]','野性最於魚鳥親，自知不是世間人。',64,'全唐诗/poet.song.212000.json','["野性最於魚鳥親，自知不是世間人。", "生成雪壑冰崖面，收得烟蓑雨笠身。", "楊柳春來青眼舊，山林老去白頭新。", "毋多感慨令君瘦，獨立斜陽一欠伸。"]'),
('a95dfdd6-2efe-48c8-9257-d399621768e8','春日雜興  其四','方岳','宋','宋诗','song-poetry','','[]','吾生身世信天緣，一死何須較後先。',64,'全唐诗/poet.song.212000.json','["吾生身世信天緣，一死何須較後先。", "未怕時逢真太歲，或言壽過古稀年。", "窮餘祿料虀百甕，醉負生涯囊一錢。", "又見山林春意思，辦隨芳草落花眠。"]'),
('857ba365-6fc0-4a3e-bc08-1485e083da97','春日雜興  其五','方岳','宋','宋诗','song-poetry','','[]','天與之愚竟不移，經年兀兀槿花籬。',64,'全唐诗/poet.song.212000.json','["天與之愚竟不移，經年兀兀槿花籬。", "拙於生事可無粥，工乃窮人頼有詩。", "只恁麽休身是客，知何以故鬢成絲。", "寒欺雪屋青燈夜，六十猶癡始是癡。"]'),
('51d73faa-2b03-46be-8140-86f8fdd08335','春日雜興  其六','方岳','宋','宋诗','song-poetry','','[]','綠繞西疇小作勞，溪村寒入舊綈袍。',64,'全唐诗/poet.song.212000.json','["綠繞西疇小作勞，溪村寒入舊綈袍。", "五窮政坐沒梁斗，百技不如無口匏。", "穫稻條桑豳雅頌，紉蘭餐菊楚離騷。", "客來更話唐虞上，盍且卑之毋甚高。"]'),
('91ea2227-04d4-442f-a080-254dba1136f8','春日雜興  其七','方岳','宋','宋诗','song-poetry','','[]','鶴骨嶄嶄疾未瘳，怯行山亦倦登樓。',64,'全唐诗/poet.song.212000.json','["鶴骨嶄嶄疾未瘳，怯行山亦倦登樓。", "久知老去事當爾，自入春來雨不休。", "虛器甚慙居士屩，實封難覓醉鄉侯。", "小遲須有佳晴日，待試山翁已健不。"]'),
('aae9b544-cb7b-4c5d-920e-84b8df0acdf7','春日雜興  其八','方岳','宋','宋诗','song-poetry','','[]','春來多病感頹齡，草藥泥瓶不暫停。',64,'全唐诗/poet.song.212000.json','["春來多病感頹齡，草藥泥瓶不暫停。", "身似漏船難補貼，齒如敗屐久凋零。", "炎黄豈解留年壽，莊老聊堪悅性靈。", "長劍拄頤兒戲耳，底須麟閣更圖形。"]'),
('1b72a4a4-4f5d-4d39-96c2-5daff80be966','春日雜興  其九','方岳','宋','宋诗','song-poetry','','[]','花柳村村奈老何，一春門巷斷經過。',64,'全唐诗/poet.song.212000.json','["花柳村村奈老何，一春門巷斷經過。", "無繩可繫西沈日，有水皆隨東逝波。", "妄想已空騎鶴夢，勞生亦厭飯牛歌。", "正須秉燭遊清夜，轉眼蘭亭舊永和。"]'),
('eec1ca0a-ad0a-42e5-a270-6d9836415485','春日雜興  其一○','方岳','宋','宋诗','song-poetry','','[]','幽蹊幾日不曾來，半是紅香半綠苔。',64,'全唐诗/poet.song.212000.json','["幽蹊幾日不曾來，半是紅香半綠苔。", "樂事每從忙裏過，好花偏向雨中開。", "慣貧可使居無竹，高隠共忻山有萊。", "投老田廬筋力倦，不才多病兩悠哉。"]'),
('ffddef48-72d0-423b-b03d-af2c3c49aaa4','春日雜興  其一一','方岳','宋','宋诗','song-poetry','','[]','高下雲藏野老家，縱橫水漱竹籬斜。',64,'全唐诗/poet.song.212000.json','["高下雲藏野老家，縱橫水漱竹籬斜。", "勒將春去許多雨，流出山來都是花。", "白首風煙三逕草，清時鼓吹一池蛙。", "身閒不耐閒雙手，洗甑炊香夜作茶。"]'),
('a43dce1a-e88b-45a0-865d-f76461c686ae','春日雜興  其一二','方岳','宋','宋诗','song-poetry','','[]','南岡北嶺對窗扉，看盡朝嵐與夕霏。',64,'全唐诗/poet.song.212000.json','["南岡北嶺對窗扉，看盡朝嵐與夕霏。", "社後未曾聞燕語，雨中誰不惜花飛。", "山醅約莫幾時熟，沙笋輪囷一尺圍。", "莫怨風光損桃李，荼䕷芍藥又芳菲。"]'),
('a2c36f97-c176-4392-bfc7-1b581f52f066','春日雜興  其一三','方岳','宋','宋诗','song-poetry','','[]','衝雨衝泥處處行，物情殊不可詩情。',64,'全唐诗/poet.song.212000.json','["衝雨衝泥處處行，物情殊不可詩情。", "牡丹又是一年過，春事略無三日晴。", "先後筍爭滕薛長，東西鷗背晉齊盟。", "山居寂寞誰堪共，杞𦶓菊苗俱可耕。"]'),
('256707ac-7d89-4696-8fa7-30f52c363b7d','春日雜興  其一四','方岳','宋','宋诗','song-poetry','','[]','綠陰芳樹鳥啼春，與客相携發興新。',64,'全唐诗/poet.song.212000.json','["綠陰芳樹鳥啼春，與客相携發興新。", "半落杏花初過雨，微酸梅子已生仁。", "每尋詩去必遷坐，穩跨牛歸不問津。", "筋力尚堪蓑笠在，莫欺老子髮如銀。"]'),
('1037164a-93b4-4e46-9d25-eea796ab4f06','春日雜興  其一五','方岳','宋','宋诗','song-poetry','','[]','凈掃山房不以貧，旋炊野飯喚比鄰。',64,'全唐诗/poet.song.212000.json','["凈掃山房不以貧，旋炊野飯喚比鄰。", "子規啼處一村雨，芍藥開時三逕春。", "丘壑自成安樂國，漁樵尚有老成人。", "茅簷相對坐終日，只說桑麻語自真。"]'),
('9ff7f018-3d6e-4506-a565-2f5a1d2ab32c','山中  其一','方岳','宋','宋诗','song-poetry','','[]','山中從事亦賢勞，安得眠雲獨自高。',64,'全唐诗/poet.song.212000.json','["山中從事亦賢勞，安得眠雲獨自高。", "兩席地栽青紫芥，一株樹接碧紅桃。", "春風多可移花信，夜雨無聲入土膏。", "那辦工夫到詩句，溪燈穿屋未編茅。"]'),
('db8e2127-317a-428b-a4be-771600d50198','山中  其二','方岳','宋','宋诗','song-poetry','','[]','世間塵土隔丘林，竹遶松園不厭深。',64,'全唐诗/poet.song.212000.json','["世間塵土隔丘林，竹遶松園不厭深。", "一片野雲人寂寂，幾番山雨夜沈沈。", "桑麻事業本來面，竹帛功名過去心。", "持戒十年今始定，邯鄲夢不到寒衾。"]'),
('18f95f65-c412-4fb5-95e4-d2791af60d0e','山中  其三','方岳','宋','宋诗','song-poetry','','[]','人間久矣倦迎逢，歸路牛羊带夕舂。',64,'全唐诗/poet.song.212000.json','["人間久矣倦迎逢，歸路牛羊带夕舂。", "千點梅沈山店月，一溪煙咽寺樓鐘。", "窮猶羞澀巉巖面，老自平夷磊磈胸。", "曾笑古人多晚謬，草庵雖小幸相容。"]'),
('c667aa03-a095-424c-a323-165684b9055f','山中  其四','方岳','宋','宋诗','song-poetry','','[]','消閒未必在林泉，要自胸中別有天。',64,'全唐诗/poet.song.212000.json','["消閒未必在林泉，要自胸中別有天。", "面壁九年曾悟道，觀棋一局偶成仙。", "不知老圃風煙外，請祝聖人香火緣。", "莫道秋崖長是懶，無求何處不超然。"]'),
('06fce79c-0ad9-44a9-8b83-549f367a2279','送春','方岳','宋','宋诗','song-poetry','','[]','不等薰風已問津，小樓無處認蹄輪。',64,'全唐诗/poet.song.212000.json','["不等薰風已問津，小樓無處認蹄輪。", "極知中歲難爲別，未必明朝不是春。", "黄鳥閙時山寂寂，綠陰深處水粼粼。", "老來寧與芳菲競，俯仰人間迹已陳。"]'),
('2c9048cb-2c95-4a3b-8e0a-053364d224b0','山行  其一','方岳','宋','宋诗','song-poetry','','[]','亦愛盧仝屋數間，野猿臯鶴共躋攀。',64,'全唐诗/poet.song.212000.json','["亦愛盧仝屋數間，野猿臯鶴共躋攀。", "纔登樓見一溪月，不出門行十里山。", "有興自携殘藁醉，無人得似老夫閒。", "樵青莫掩柴扉路，留與春風作往還。"]'),
('0c05f189-3a53-4ea5-a6b2-517ade201df2','山行  其二','方岳','宋','宋诗','song-poetry','','[]','詩卷空留紫翠間，風花飛絮豈堪攀。',64,'全唐诗/poet.song.212000.json','["詩卷空留紫翠間，風花飛絮豈堪攀。", "埋雲已笑夢中夢，敲月更煩山上山。", "長短百年誰是主，死生一概匹如閒。", "病餘勘破人間事，底用瞿曇說八還。"]'),
('1cd50362-3394-4678-a442-5a6668ed9b2b','山行  其三','方岳','宋','宋诗','song-poetry','','[]','寒食清明數日間，青青楊柳與誰攀。',64,'全唐诗/poet.song.212000.json','["寒食清明數日間，青青楊柳與誰攀。", "乾坤不盡雲邊眼，冰雪相堪屋上山。", "時序只將詩撥遣，窮愁聊以酒防閒。", "無心自是長生藥，莫誤丹爐覓大還。"]'),
('9f3d6c82-b8bc-48db-b4a6-fcca883d3427','山行  其四','方岳','宋','宋诗','song-poetry','','[]','聲名空自落人間，要是龍鱗不可攀。',64,'全唐诗/poet.song.212000.json','["聲名空自落人間，要是龍鱗不可攀。", "春水白鷗多載酒，夕陽黄犢飽看山。", "老吾於傳懶成癖，之子有詩忙是閒。", "四海流傳如見問，爲言飛鳥倦知還。"]'),
('b0582db4-e88c-45cc-b9da-08fc6a9f3843','山行  其五','方岳','宋','宋诗','song-poetry','','[]','人情何翅抵黄間，鴥彼鴻冥杳莫攀。',64,'全唐诗/poet.song.212000.json','["人情何翅抵黄間，鴥彼鴻冥杳莫攀。", "寵辱可驚浮世事，是非不到好溪山。", "怒鵬已較三千里，老馬寧思十二閒。", "丘壑儻容詩入社，肯將宗派繼還還。"]'),
('bd640dfd-7f01-4c24-9e35-c67c664a4932','山行  其六','方岳','宋','宋诗','song-poetry','','[]','不肯諸賢季孟間，歸來雲月儘躋攀。',64,'全唐诗/poet.song.212000.json','["不肯諸賢季孟間，歸來雲月儘躋攀。", "誰憎命達昔工部，未必詩窮今巨山。", "兩鬢雪霜多是病，一蓑煙雨可曾閒。", "花前得酒微成醉，歡頰春紅覺頓還。"]'),
('7af64f87-3295-4695-847b-161bd1f9c7e7','山行  其七','方岳','宋','宋诗','song-poetry','','[]','住世間須出世間，世情何事苦牽攀。',64,'全唐诗/poet.song.212000.json','["住世間須出世間，世情何事苦牽攀。", "蟠胸自作三分國，覿面相懸兩戒山。", "大好閉門贏得睡，不多識字煞妨閒。", "長鬚赤脚頑於我，未必淳風不再還。"]'),
('19bd1b17-4b2f-4bf9-8c82-bd5e1361220c','乞梅花','方岳','宋','宋诗','song-poetry','','[]','晚雲撩亂商量雪，家傍梅花合有詩。',64,'全唐诗/poet.song.212000.json','["晚雲撩亂商量雪，家傍梅花合有詩。", "不寄一枝春苦吝，相思五夜夢先知。", "乘雲而下惟姑射，得聖之清者伯夷。", "已戒管城三盥沐，詎令空手對冰姿。"]'),
('362019ec-1b8d-4b81-94db-afab30963239','約黄成之觀瓊花予不及從以詩代簡','方岳','宋','宋诗','song-poetry','','[]','杜宇聲中鬢欲華，春風將綠又天涯。',64,'全唐诗/poet.song.212000.json','["杜宇聲中鬢欲華，春風將綠又天涯。", "欠隨江夏無雙士，共看揚州第一花。", "想像煙雲人跨鶴，淋漓詩句字栖鴉。", "蹇馿不管唐衫濕，醉兀歸鞍暮雨斜。"]'),
('02c994ba-fadd-4be7-a746-d4e7dae54d49','夢尋梅','方岳','宋','宋诗','song-poetry','','[]','野逕深藏隠者家，岸莎分路带溪斜。',64,'全唐诗/poet.song.212000.json','["野逕深藏隠者家，岸莎分路带溪斜。", "馬蹄殘雪六七里，山觜有梅三四花。", "黄葉擁籬埋藥草，青燈煨芋話桑麻。", "一生烟雨蓬茅底，不夢金貂侍玉華。"]'),
('52546774-6d7e-4702-b1a4-b83b47b47085','趙龍學寄陽羨茶爲汲蜀井對瓊花烹之','方岳','宋','宋诗','song-poetry','','[]','三印誰分陽羨茶，自煎蜀井瀹瓊花。',64,'全唐诗/poet.song.212000.json','["三印誰分陽羨茶，自煎蜀井瀹瓊花。", "數間明月玉川屋，兩腋清風銀漢槎。", "團鳳烹來奴僕等，老龍畢竟當行家。", "相思幾夢山陰雪，搜攪平生書五車。"]'),
('6e802e87-7281-4fe9-9f59-f7937da9fb43','繭窩','方岳','宋','宋诗','song-poetry','','[]','百年三萬六千場，擬挈乾坤入睡鄉。',64,'全唐诗/poet.song.212000.json','["百年三萬六千場，擬挈乾坤入睡鄉。", "世事何常雲聚散，古人安在草荒凉。", "不禁杜宇催春老，莫怪吳蠶作繭忙。", "已擅一丘吾事足，人間蟻垤自侯王。"]'),
('56aa82c8-10ab-462b-ae57-f1d5703ba9a8','夏日簡王尉','方岳','宋','宋诗','song-poetry','','[]','松蘿爲屋芰荷衣，只與鳬鷗共釣磯。',64,'全唐诗/poet.song.212000.json','["松蘿爲屋芰荷衣，只與鳬鷗共釣磯。", "雌霓橫溪遮雨斷，雄風吹雨作塵飛。", "山林誰可閒來往，世俗難論真是非。", "頗喜雪舟王逸少，夜凉吾欲扣齋扉。"]'),
('c554d0ec-1ae9-4b1b-8f87-f4b6fd27813b','葉秘書致白龍涎','方岳','宋','宋诗','song-poetry','','[]','閉門老去著幽禪，趺坐時參柏子煙。',64,'全唐诗/poet.song.212000.json','["閉門老去著幽禪，趺坐時參柏子煙。", "書冊懶隨黄犢角，巖霏寧識白龍涎。", "蓬萊山復在何處，杞菊賦今誰與傳。", "不道寶書天尺五，肯分風月到林泉。"]'),
('062c435e-704a-44fe-a25a-69aac7d82cad','去年五月十七廬山禱而雨嘗有詩今年五月十七昭武禱而晴因用韻','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','浪漫東西不自期，此公猶有鬼神知。',64,'全唐诗/poet.song.212000.json','["浪漫東西不自期，此公猶有鬼神知。", "江閩易地誰爲祟，晴雨在天皆及時。", "年熟且從犀首飲，宦情聊付虎頭癡。", "舉杯試問樵溪月，今世寧須我輩爲。"]'),
('66023c88-0d82-44a2-92d2-cbc60084b9f0','黄倅饟鱟一徐尉饟蝤蛑十同時至','方岳','宋','宋诗','song-poetry','','[]','誰饟螯如徑尺盤，更分鱟似惠文冠。',64,'全唐诗/poet.song.212000.json','["誰饟螯如徑尺盤，更分鱟似惠文冠。", "麯生醉嚼玉五殻，劍客生劙珠一簞。", "我與爾元同蠢動，冤哉烹亦到蹣跚。", "不知南食詩何似，待問昌黎老子看。"]'),
('11b6c41f-57bb-4792-a1fb-b3a06d157eca','熱  其一','方岳','宋','宋诗','song-poetry','','[]','脫巾無計避炎熇，安得長風上泬寥。',64,'全唐诗/poet.song.212000.json','["脫巾無計避炎熇，安得長風上泬寥。", "自浴寒泉眉子硯，時澆蒼石膽瓶蕉。", "老來轉覺身爲累，貧甚豈爲山可樵。", "坐想草亭新竹上，一林碎月玉翛翛。"]'),
('858b7451-afdd-4055-a4eb-c44125a01f9a','熱  其二','方岳','宋','宋诗','song-poetry','','[]','借使長空插羽翰，人間無地著高寒。',64,'全唐诗/poet.song.212000.json','["借使長空插羽翰，人間無地著高寒。", "一丘自作清凉國，兩曜誰司赤白丸。", "老去詩猶堪杖屨，快哉風亦懶衣冠。", "貴人要與常人別，寶带圍腰大耐官。"]'),
('671fa486-f916-4f6e-996c-27e61e02a36d','熙春臺用戴式之韻','方岳','宋','宋诗','song-poetry','','[]','山城無處著鼇頭，與客相携汗漫遊。',64,'全唐诗/poet.song.212000.json','["山城無處著鼇頭，與客相携汗漫遊。", "六月亦寒空翠合，一溪不盡夕陽流。", "有蔬笋氣詩逾好，無綺羅人山更幽。", "白雪翻匙秋已近，洗吾老瓦起相酬。"]'),
('cd22d5ad-3dba-458c-8fb7-6244628b4ac9','宿芙蓉驛','方岳','宋','宋诗','song-poetry','','[]','鳳皇山下芙蓉驛，零落殘碑半蝕苔。',64,'全唐诗/poet.song.212000.json','["鳳皇山下芙蓉驛，零落殘碑半蝕苔。", "黄鳥有時穿戶過，青山無數摺溪迴。", "麥秋天氣半明暗，蠶月人家忌往來。", "俯仰十年如夢耳，舊題剝落已塵埃。"]'),
('bac66d71-7fc7-4adb-8675-49b378b3958f','寄至能','方岳','宋','宋诗','song-poetry','','[]','江上歸來即定巢，牆陰野竹破新梢。',64,'全唐诗/poet.song.212000.json','["江上歸來即定巢，牆陰野竹破新梢。", "有人問字時相過，無事觀書手自抄。", "世態十年多客夢，月明千里少朋交。", "茅齋亦有秋崖藁，留與青山作解嘲。"]'),
('1b3d267e-905d-422e-903b-64f00c168e77','山中  其一','方岳','宋','宋诗','song-poetry','','[]','此身只合著林泉，安得纏腰十萬錢。',64,'全唐诗/poet.song.212000.json','["此身只合著林泉，安得纏腰十萬錢。", "百事懦無拖地膽，一生愚似信天緣。", "青山有約不知老，黄犢與人相對眠。", "問訊春蓑故無恙，亂雲深處更超然。"]'),
('eb44663c-2069-4a61-a5f7-386ee4374d85','山中  其二','方岳','宋','宋诗','song-poetry','','[]','茅葺山堂竹打籬，尚餘老鶴共襟期。',64,'全唐诗/poet.song.212000.json','["茅葺山堂竹打籬，尚餘老鶴共襟期。", "一生朝市幾何日，五畝園林都是詩。", "身後誰澆胸磊磊，命中不带印纍纍。", "薄田有秫聊堪釀，儘足秋崖作受持。"]'),
('4a186288-2587-4b58-a2a9-5a853c412503','山中  其三','方岳','宋','宋诗','song-poetry','','[]','老去筋骸轉覺衰，閒忙猶復費支持。',64,'全唐诗/poet.song.212000.json','["老去筋骸轉覺衰，閒忙猶復費支持。", "傍山新接龜頭屋，爲菊重編麂眼籬。", "仕宦已忘如隔世，力田斷不似逢時。", "北窗高卧美無價，山鳥竟知吾是誰。"]'),
('e511cac7-3e54-49dc-86d1-b8a64e1c813b','山中  其四','方岳','宋','宋诗','song-poetry','','[]','古木蒼藤自一丘，草廬吾亦愛深幽。',64,'全唐诗/poet.song.212000.json','["古木蒼藤自一丘，草廬吾亦愛深幽。", "斷無俗物敢排闥，儘有好山堪倚樓。", "已老始知書作祟，不才寧與命爲仇。", "石床只在松陰底，拳手支頭百不憂。"]'),
('d90b2917-2ff5-4f9f-9cc1-51122c2e5662','送留圯父寺簿倅嚴','方岳','宋','宋诗','song-poetry','','[]','纔立班行便佐州，九年回首不渠留。',64,'全唐诗/poet.song.212000.json','["纔立班行便佐州，九年回首不渠留。", "千峰榭與柯山對，七里灘從嚴子遊。", "未用笑談驚五馬，只銷詩句狎雙鷗。", "團綱殿最非吾事，夜半一編歸借籌。"]'),
('1cc957ef-bb6f-4bd8-acc9-5c6bcabf0deb','過李季子丈','方岳','宋','宋诗','song-poetry','','[]','易在床頭注未成，晦庵往矣與誰評。',64,'全唐诗/poet.song.212000.json','["易在床頭注未成，晦庵往矣與誰評。", "深衣靜對山逾好，語錄重抄眼尚明。", "春晚有詩供杖屨，日長無事樂鋤耕。", "家風終與常人別，只聽芭蕉滴雨聲。"]'),
('fa7b72cf-778c-4ae4-8187-2538799a2dec','獨往','方岳','宋','宋诗','song-poetry','','[]','黄冠野服隨孤鶴，竹逕松岡共往還。',64,'全唐诗/poet.song.212000.json','["黄冠野服隨孤鶴，竹逕松岡共往還。", "不肯避人當道筍，相看如客對門山。", "窮居作計未爲左，造物於吾本不慳。", "徑掃石床供晝寢，自憐詩骨尚堅頑。"]'),
('90c7cb7d-e6b1-4fc9-9778-e888d7846cdf','趙尉送菜  其一','方岳','宋','宋诗','song-poetry','','[]','虛老空山學圃翁，荷鋤頭白雪髼鬆。',64,'全唐诗/poet.song.212000.json','["虛老空山學圃翁，荷鋤頭白雪髼鬆。", "芥臺如臂何曾夢，菜腦生筋漫自供。", "不料官園蒼玉束，絕勝禁臠紫駝峯。", "更煩詩手剪春雨，剩與一番風露胸。"]'),
('d75a4e59-bdbf-49be-8ed6-a79b823a5c99','趙尉送菜  其二','方岳','宋','宋诗','song-poetry','','[]','豈可常貧料此翁，齋盂頓有玉瓏鬆。',64,'全唐诗/poet.song.212000.json','["豈可常貧料此翁，齋盂頓有玉瓏鬆。", "春山藥草能同飯，夜雨茅堂未缺供。", "杞菊共傳寒綠賦，柴桑不隔紫霄峯。", "冰甆嚼出宮商羽，一洗人間芥蔕胸。"]'),
('2b7ab118-730e-4cb6-ae2a-6a0bc0f7cacb','趙尉送菜  其三','方岳','宋','宋诗','song-poetry','','[]','山雲一塢住山翁，菘韭成畦带雪鬆。',64,'全唐诗/poet.song.212000.json','["山雲一塢住山翁，菘韭成畦带雪鬆。", "飛食肉奚關我事，乳蒸豚亦爲誰供。", "衡茅高枕人間世，蓑笠歸鋤雨外峯。", "曾讀坡公菜羹賦，斷無塵土到奇胸。"]'),
('3fd4e106-7076-478a-8c9c-51742b01987e','江尉見過','方岳','宋','宋诗','song-poetry','','[]','夢筆諸郎住筆峰，斷橋春水肯過從。',64,'全唐诗/poet.song.212000.json','["夢筆諸郎住筆峰，斷橋春水肯過從。", "千巖萬壑真仙吏，兩屨一蓑予老農。", "鐵硬脊梁長偃蹇，糊塗面目易迎逢。", "半生誤我難相誤，只許秋崖獨自惷。"]'),
('40ae969c-4976-4f03-8d2e-b45476062915','太廟齋宿','方岳','宋','宋诗','song-poetry','','[]','正爾梅蒸苦翳霾，翛然清廟得心齋。',64,'全唐诗/poet.song.212000.json','["正爾梅蒸苦翳霾，翛然清廟得心齋。", "雲連魏闕天尤近，樹暗吳山雨亦佳。", "黄道正中垂日月，赤囊猶遽接江淮。", "思皇列考神靈在，儻許孤臣借玉階。"]'),
('ecc014ee-5636-413f-afc3-b193ea04c623','山中  其一','方岳','宋','宋诗','song-poetry','','[]','莫怪山翁老更迂，竹庵終日一團蒲。',64,'全唐诗/poet.song.212000.json','["莫怪山翁老更迂，竹庵終日一團蒲。", "萬言萬當不如默，百技百窮同是愚。", "往事自驚天大膽，近詩空撚雪成鬚。", "未憂卒歲無衣褐，紫鳳天吳拆海圖。"]'),
('9ce95fcb-be2d-4c09-b860-3750e542f275','山中  其二','方岳','宋','宋诗','song-poetry','','[]','長嘯出門山月高，古來寧獨我蓬蒿。',64,'全唐诗/poet.song.212000.json','["長嘯出門山月高，古來寧獨我蓬蒿。", "拙於生事豈無粥，猶有故情焉用袍。", "壠畝桑麻豳雅頌，亭臯木葉楚離騷。", "不知公相今誰是，已與人間久絕交。"]'),
('fa5e421b-919b-49f1-92e1-f3a352f4ab11','山中  其三','方岳','宋','宋诗','song-poetry','','[]','野煙啼鳥各忻然，一枕山籬又幾年。',64,'全唐诗/poet.song.212000.json','["野煙啼鳥各忻然，一枕山籬又幾年。", "不可奈何天有命，久當已矣世無緣。", "跨牛仰面自橫笛，騎鶴纏腰那辦錢。", "蘆葦秋聲石橋月，只餐荷氣亦成仙。"]'),
('800d84a9-6831-4f50-8e91-e4e66978cbbc','山中  其四','方岳','宋','宋诗','song-poetry','','[]','半塢幽深近物情，一筇老健愜山行。',64,'全唐诗/poet.song.212000.json','["半塢幽深近物情，一筇老健愜山行。", "月於水底見逾好，風打松邊過便清。", "鶴睡不驚舂藥臼，鳥啼時作讀書聲。", "山翁兩手渾無用，只把犂鋤做太平。"]'),
('829e7051-8025-4b9c-badc-5243ebe37fde','山中  其五','方岳','宋','宋诗','song-poetry','','[]','剩斸荒寒地百弓，儘供弄月與吟風。',64,'全唐诗/poet.song.212000.json','["剩斸荒寒地百弓，儘供弄月與吟風。", "太平世界豐登外，小有洞天閒適中。", "野服染成駝樣褐，山花開到鴈來紅。", "夕陽籬落誰呼喚，盂酒蹄肩賽社翁。"]'),
('4b5fbcb3-a55e-4f46-bb07-6012505e86d2','山中  其六','方岳','宋','宋诗','song-poetry','','[]','無心出岫懶於雲，生死交情一付君。',64,'全唐诗/poet.song.212000.json','["無心出岫懶於雲，生死交情一付君。", "五柳當門陶令宅，百梅共塢老逋墳。", "山雖甚淺略堪隠，硯不能靈併可焚。", "我亦平生輕俗子，向來魚鳥自同羣。"]'),
('545f4d3d-59e9-4d30-9ebd-3dcd69323002','次韻才老','方岳','宋','宋诗','song-poetry','','[]','藏拙欲分蘿月陰，十年回首愧重臨。',64,'全唐诗/poet.song.212000.json','["藏拙欲分蘿月陰，十年回首愧重臨。", "吾徒空倚橫天劍，此老長閒布地金。", "案有法華山寂寂，門無俗客竹深深。", "瘦藤莫厭頻來往，同社壺觴手自斟。"]'),
('dcea3fb6-00f5-4586-bb67-84b34f1d2c90','性老致廬山茶','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','枉作江南半世人，安知五老不吾嗔。',64,'全唐诗/poet.song.212000.json','["枉作江南半世人，安知五老不吾嗔。", "自參茶壑風煙美，略識廬山面目真。", "澗汲每思佳客共，雲眠誰謂老師貧。", "秋崖只有詩如此，回向山靈報答春。"]'),
('446347b3-5f43-482f-81af-84857d7554ac','息軒','方岳','宋','宋诗','song-poetry','','[]','種田儘辦甕頭春，倦矣風波謾損神。',64,'全唐诗/poet.song.212000.json','["種田儘辦甕頭春，倦矣風波謾損神。", "萬事不償雙短鬢，百年等是一微塵。", "祇今蝸戰誰知誤，凡我同盟人認真。", "夢亦妄生顛倒想，何如明月自由人。"]'),
('9d99705e-3ad1-4a27-af8c-ab0726069239','入局','方岳','宋','宋诗','song-poetry','','[]','鴈鶩行餘紙尾箝，岸湖老屋壓題籤。',64,'全唐诗/poet.song.212000.json','["鴈鶩行餘紙尾箝，岸湖老屋壓題籤。", "印文生綠空藏柜，草色蟠青欲刺簷。", "茶話略無塵土雜，荷香剩有水風兼。", "官曹那得閒如此，亦奉一囊慙屬厭。"]'),
('190596aa-51a9-4938-99cc-cb48568a1040','僦舍','方岳','宋','宋诗','song-poetry','','[]','僦舍真如百漏船，一番風雨一騷然。',64,'全唐诗/poet.song.212000.json','["僦舍真如百漏船，一番風雨一騷然。", "從頭避席遍遷坐，併手移書已絕編。", "歎息敢爲三宿戀，支吾那得一囊錢。", "世間事更多如屋，聊復因循過目前。"]'),
('8a6c878a-c5f2-4400-a5cd-943c3e3cf941','葛帳','方岳','宋','宋诗','song-poetry','','[]','水紋湘簟碧雲厨，從舊詩窮一例無。',64,'全唐诗/poet.song.212000.json','["水紋湘簟碧雲厨，從舊詩窮一例無。", "豹脚羣飛相料理，麈毛併落不支吾。", "泠然欲作乘風興，老去誰臨却暑圖。", "付與北窗黄葛帳，逍遥略與世人俱。"]'),
('09561065-5e43-4136-998b-a544c3eb5190','水月園送王侍郎','方岳','宋','宋诗','song-poetry','','[]','送別孤山步繞湖，闌干盡處倚菰蒲。',64,'全唐诗/poet.song.212000.json','["送別孤山步繞湖，闌干盡處倚菰蒲。", "翁之樂者山林也，客亦知夫水月乎。", "萬事不如歸自好，百年聊與醉爲徒。", "藕花初醒蓴絲老，喚住罾船鱠腹腴。"]'),
('53108379-760f-400a-813a-0f25825569e7','次韻章太博遷匠丞不入  其一','方岳','宋','宋诗','song-poetry','','[]','誰喚山民亦此來，蒼浪猶带野田埃。',64,'全唐诗/poet.song.212000.json','["誰喚山民亦此來，蒼浪猶带野田埃。", "秋風吊古琴三疊，夜雨論文酒一杯。", "巨筆瀉成鸚鵡賦，細書飛過鳳凰臺。", "恨君不入秋堂瑣，校定雄文鼎亞魁。"]'),
('36dea5d1-0d69-4803-ba71-306fe7988c75','次韻章太博遷匠丞不入  其二','方岳','宋','宋诗','song-poetry','','[]','問字無人載酒來，渴思老瓦洗晴埃。',64,'全唐诗/poet.song.212000.json','["問字無人載酒來，渴思老瓦洗晴埃。", "半生自作鷗盟主，何物遽移蛇影杯。", "官品强令松出世，家園苦憶芥生臺。", "青衫潦倒枯荷似，慙媿爐亭夜聚魁。"]'),
('6d4fe89c-a685-4765-90a1-047b94e8e8f9','次韻章太博遷匠丞不入  其三','方岳','宋','宋诗','song-poetry','','[]','解頤鼎鼎得匡來，浄洗詩脾萬古埃。',64,'全唐诗/poet.song.212000.json','["解頤鼎鼎得匡來，浄洗詩脾萬古埃。", "何以報君青玉案，誰其醑我紫霞杯。", "此生只可誇耕墅，小藁曾經到講臺。", "富貴自嫌吟骨瘦，底須雌甲問河魁。"]'),
('c0c5c799-52b7-43b0-ba6b-bb199f473379','直汀晚望','方岳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','沙頭新雨沒潮痕，獨立蒼茫欲斷魂。',64,'全唐诗/poet.song.212000.json','["沙頭新雨沒潮痕，獨立蒼茫欲斷魂。", "如以長江限南北，何堪醜虜共乾坤。", "中年歲月疾飛鳥，舊隠文移驚夜猿。", "鷗鷺不能知許事，煙寒袖手與誰論。"]'),
('3ab08efb-6245-46cd-a952-e37c30a5aafe','泊龍灣','方岳','宋','宋诗','song-poetry','','[]','安得蓬籠雨一蓑，蘆花深處卧煙波。',64,'全唐诗/poet.song.212000.json','["安得蓬籠雨一蓑，蘆花深處卧煙波。", "籌邊事付韓擒虎，種樹書傳郭橐駝。", "從古市朝如此耳，攙閒天地奈之何。", "秫田雖少亦堪釀，底處不容人醉歌。"]'),
('cb3300bd-1442-45b9-beee-9671727b2ba6','登瓜步山','方岳','宋','宋诗','song-poetry','','[]','繫船孤嶼重躋攀，衰草荒煙亦厚顔。',64,'全唐诗/poet.song.212000.json','["繫船孤嶼重躋攀，衰草荒煙亦厚顔。", "丁日不爲春燕許，卯年猶放佛狸還。", "諸賢所恃江千尺，此虜奚爲第一間。", "欲訪前朝無故老，浪痕自濺蘚花斑。"]'),
('d7c10806-9bbc-42af-aafa-9dd330ed04be','次韻徐太博  其一','方岳','宋','宋诗','song-poetry','','[]','宗派鸕鷀煙雨外，釣蓑能得幾多清。',64,'全唐诗/poet.song.212000.json','["宗派鸕鷀煙雨外，釣蓑能得幾多清。", "坐無相印田二頃，撚到吟髭雪幾莖。", "剡曲船今寒昨夢，灞橋馿亦笑塵纓。", "南州高士難爲客，相許相從文字盟。"]'),
('c1208843-1df7-4d73-807a-fa5d0454c910','次韻徐太博  其二','方岳','宋','宋诗','song-poetry','','[]','沈郎吟處秋風老，今代何人詩斗南。',64,'全唐诗/poet.song.212000.json','["沈郎吟處秋風老，今代何人詩斗南。", "鍊石補天君特妙，追雲逐月我何堪。", "極知才倍曹丕十，不但人如漢傑三。", "欲與東湖傳活法，當家衣鉢付誰參。"]'),
('920f5614-0f20-468e-86e0-2bf3ea22285c','次韻徐太博  其三','方岳','宋','宋诗','song-poetry','','[]','湖山雨過晚雲濕，解榻文堂夢亦清。',64,'全唐诗/poet.song.212000.json','["湖山雨過晚雲濕，解榻文堂夢亦清。", "秋入黄香金粟粟，苔侵蒼翠玉莖莖。", "蟲魚枉註書連屋，蠻觸令人笑絕纓。", "講罷肯同詩保社，有如江水敢寒盟。"]'),
('50cc9676-0338-40dd-aa8e-854b0ca5530e','次韻徐太博  其四','方岳','宋','宋诗','song-poetry','','[]','蘆荻花寒山月小，西風吹鴈又江南。',64,'全唐诗/poet.song.212000.json','["蘆荻花寒山月小，西風吹鴈又江南。", "夜談往事六太息，老覺吾儕七不堪。", "舉世人情如格五，平生分量等朝三。", "次山亦復漫吾耳，清夢何曾到四參。"]'),
('44f3b643-1172-4daa-8d7e-902655c6dc01','次韻牟監簿齋宮','方岳','宋','宋诗','song-poetry','','[]','蠻觸追奔競一豪，市朝酣戰萬靈鼉。',64,'全唐诗/poet.song.212000.json','["蠻觸追奔競一豪，市朝酣戰萬靈鼉。", "齋房只在秋山外，吟卷自隨明月多。", "問字人須煩謝絕，敲門僧亦莫誰何。", "竹宮曾見神君否，且乞天瓢爲挽河。"]'),
('c371c56f-48fc-4adf-b06f-1f733b2c9adc','是夕雨再用韻','方岳','宋','宋诗','song-poetry','','[]','生計蕭條老杜陵，秋風檢點又東屯。',64,'全唐诗/poet.song.212000.json','["生計蕭條老杜陵，秋風檢點又東屯。", "碧雲句好山圍屋，黄葉村深僧扣門。", "雨滑且留煨芋栗，夜長聊欲話田園。", "棹歌笑指風僧耳，已喜聞思斷一根。"]'),
('96e9ae83-2e99-48c9-b5ea-61f08e36e647','漫興','方岳','宋','宋诗','song-poetry','','[]','秋風寂寞斷過從，只有殘書伴夜蛬。',64,'全唐诗/poet.song.212000.json','["秋風寂寞斷過從，只有殘書伴夜蛬。", "官職到頭三品石，世情對面九疑峯。", "人間漫浪老元結，鬼物揶揄劉伯龍。", "明日黄花定何似，無錢相待若爲容。"]'),
('2b5ef20d-9b43-421b-9a45-ca0a81825a87','古巖','方岳','宋','宋诗','song-poetry','','[]','廿年前此借僧單，留得松聲入夢寒。',64,'全唐诗/poet.song.212000.json','["廿年前此借僧單，留得松聲入夢寒。", "歲月可驚吾輩老，風煙仍作故人看。", "山泉與佛結茶供，石屋無人蝕蘚瘢。", "亭角雨晴秋更碧，斷雲片片泊欄干。"]'),
('33ff545b-0d1f-4427-9512-580cb2c3244e','晚眺','方岳','宋','宋诗','song-poetry','','[]','晴沙漠漠水沄沄，更倚翠微搔白紛。',64,'全唐诗/poet.song.212000.json','["晴沙漠漠水沄沄，更倚翠微搔白紛。", "不可以風秋後葉，何傷於月晚來雲。", "憂時自有夔龍在，投老政須麛鹿羣。", "旋拾枯松澆瀑布，小奚亦足張吾軍。"]'),
('445d529d-637f-4046-8da0-d3c0149152e4','七夕','方岳','宋','宋诗','song-poetry','','[]','明河此夕會雙星，滓穢圓清太不經。',64,'全唐诗/poet.song.212000.json','["明河此夕會雙星，滓穢圓清太不經。", "牛豈其然耕觳觫，女何爲者嫁娉婷。", "閒中但覺人間巧，老去誰邀帝子靈。", "千古文章柳州事，解將蹇拙說惺惺。"]'),
('c21ef1f7-0d97-4c4f-8fb3-7bbae6ee695c','題登雲約','方岳','宋','宋诗','song-poetry','','[]','昨夜秋風到漢庭，又催鵬翮上青冥。',64,'全唐诗/poet.song.212000.json','["昨夜秋風到漢庭，又催鵬翮上青冥。", "同年前有三人傑，渾化今聯千佛經。", "路入桂花通月府，筆摇霜氣動文星。", "宮商十四絃俱應，總向祁山一處聽。"]'),
('62d57e1c-86a8-4925-aa09-09e7d69729dc','偶題','方岳','宋','宋诗','song-poetry','','[]','空煩社友問何如，筋力猶堪月下鉏。',64,'全唐诗/poet.song.212000.json','["空煩社友問何如，筋力猶堪月下鉏。", "爲米折腰長乞米，緣書損目苦觀書。", "山翁迂闊每如此，吾道寂寥誰與居。", "獨立西風人自老，枉悲宋玉不關渠。"]'),
('7d40e682-9394-47ed-8225-49591c3bca4c','野步  其一','方岳','宋','宋诗','song-poetry','','[]','秋風欲下題詩葉，午枕初醒破悶茶。',64,'全唐诗/poet.song.212000.json','["秋風欲下題詩葉，午枕初醒破悶茶。", "六七里行溪詰曲，二三子共酒讙譁。", "乾坤何似一傳舍，日月不停雙轉車。", "富貴政妨人作樂，抵須辛苦問乘槎。"]'),
('28dfb595-974f-4cb4-9f11-1d267bfef021','野步  其二','方岳','宋','宋诗','song-poetry','','[]','雲埋莎徑閒看竹，瀑煮松風旋作茶。',64,'全唐诗/poet.song.212000.json','["雲埋莎徑閒看竹，瀑煮松風旋作茶。", "山骨未如詩骨瘦，澗聲欲亂語聲譁。", "相逢杯有友名玉，所恨坐無人姓車。", "到手新詩遣誰寫，驚鴉棲壁落枯槎。"]'),
('27128609-ce84-474f-8dcb-2d89d03e59f8','送別趙尉','方岳','宋','宋诗','song-poetry','','[]','細草輕煙畫出愁，一船明月大刀頭。',64,'全唐诗/poet.song.212000.json','["細草輕煙畫出愁，一船明月大刀頭。", "苔痕欲暗藍田記，楓葉正寒江渚樓。", "無酒可澆鸚鵡賦，有山頻典鷫鸘裘。", "功名正恐不免耳，拄笏練溪南北秋。"]'),
('4a479844-0cf6-4174-882f-626792cc56ee','次韻吳侍郎同集硯山','方岳','宋','宋诗','song-poetry','','[]','晚寒閒袖揮毫手，曲角欄干倚斷雲。',64,'全唐诗/poet.song.212000.json','["晚寒閒袖揮毫手，曲角欄干倚斷雲。", "丘壑儘容詩獨步，江淮相望月平分。", "艱難鬢葆成霜茁，冷落梅花带雪芬。", "酒不能平詩磊磈，盃行到手已醺醺。"]'),
('e29956cf-5583-476f-b790-e397c883f41b','再用韻酬退庵侍郎','方岳','宋','宋诗','song-poetry','','[]','飛蓋重臨霜葉老，江山吞吐自煙雲。',64,'全唐诗/poet.song.212000.json','["飛蓋重臨霜葉老，江山吞吐自煙雲。", "詩情不論隔千里，酒令何妨寬一分。", "到處經行多舊感，等閒談笑亦奇芬。", "平生不負梅花月，未是黄昏已半醺。"]'),
('810487a6-4db9-424a-8629-912dcde0b246','瓜洲晚渡','方岳','宋','宋诗','song-poetry','','[]','天地中間一葉舟，與鷗等是此生浮。',64,'全唐诗/poet.song.212000.json','["天地中間一葉舟，與鷗等是此生浮。", "江淮千里水天碧，南北六朝煙樹愁。", "浪挾禹功吞巨海，寺騎媧石礙中流。", "漁蓑不涉興亡事，自醉自醒今白頭。"]'),
('7372ec91-c405-415d-937a-08d9d0e81842','晚眺','方岳','宋','宋诗','song-poetry','','[]','摩挲倦眼風煙上，萬木歸根葉已零。',64,'全唐诗/poet.song.212000.json','["摩挲倦眼風煙上，萬木歸根葉已零。", "衰髮不知何事白，遥岑只是舊時青。", "功名一夢屈伸肘，身世百年長短亭。", "莫向夕陽多感慨，夜寒重勘相牛經。"]'),
('dcbe5661-9e85-4e19-9fbd-ba88a0c2cdf0','次韻  其一','方岳','宋','宋诗','song-poetry','','[]','書冊元非幕府才，江山牽率老夫來。',64,'全唐诗/poet.song.212000.json','["書冊元非幕府才，江山牽率老夫來。", "略分秋色歸吟卷，又誤春簑下釣臺。", "有意及時常轗軻，無心於物莫驚猜。", "幽居亦有窮生活，麥隴蔬畦手自栽。"]'),
('7baf1eb4-be20-4fba-b003-45d214ff2fc6','次韻  其二','方岳','宋','宋诗','song-poetry','','[]','久矣寒窗美曲肱，絕交書到短檠燈。',64,'全唐诗/poet.song.212000.json','["久矣寒窗美曲肱，絕交書到短檠燈。", "向來問舍漁樵侶，肯作歸堂粥飯僧。", "耕罷夕陽牛觳觫，睡殘明月鶴鬅鬙。", "年來老懶略相似，見兔何能便放鷹。"]'),
('0bcc511b-c42a-442d-9605-4e5295571e48','次韻秋夜','方岳','宋','宋诗','song-poetry','','[]','雨浥浮梁逗碧紗，短更催睡不停撾。',64,'全唐诗/poet.song.212000.json','["雨浥浮梁逗碧紗，短更催睡不停撾。", "一聲鴈带塞愁過，八月槎隨鄉信賒。", "別後故人頻入夢，秋來燕子已還家。", "相逢却喜詩無恙，醉墨淋漓黑老鴉。"]'),
('115ec901-f081-402a-86ea-7ff06b7b8c8a','中秋','方岳','宋','宋诗','song-poetry','','[]','曉入雲堂已起單，病留法喜太無端。',64,'全唐诗/poet.song.212000.json','["曉入雲堂已起單，病留法喜太無端。", "當塗月擬中秋見，建鄴水仍江上寒。", "與世不供三笑別，暮年轉覺四并難。", "鸕鷀杓有銅花綠，最負今宵白玉盤。"]'),
('7c995815-d853-4216-92ce-1e764fa07505','月夜','方岳','宋','宋诗','song-poetry','','[]','人間執熱難爲睡，起聽松風視月明。',64,'全唐诗/poet.song.212000.json','["人間執熱難爲睡，起聽松風視月明。", "天浄略無雲一點，夜深已是鶴三更。", "自經秋後可曾雨，纔入山來如許清。", "能得幾多殘暑在，草根何處不蛩聲。"]'),
('dffe3daf-ccd1-4f8e-bce8-62d99c13e438','閏中秋','方岳','宋','宋诗','song-poetry','','[]','摩挲倦眼一登樓，鴈落寒聲半古愁。',64,'全唐诗/poet.song.212000.json','["摩挲倦眼一登樓，鴈落寒聲半古愁。", "付與老天推甲子，徑將明月閏中秋。", "功名不直一杯水，人世寧須萬戶侯。", "坐對青山談到此，政應舉白與君浮。"]'),
('f69b7483-ab9f-4065-a0a4-f5892661243f','月墅','方岳','宋','宋诗','song-poetry','','[]','老我初營茅蓋頭，墅成林壑恰中秋。',64,'全唐诗/poet.song.212000.json','["老我初營茅蓋頭，墅成林壑恰中秋。", "詩人例合三間月，餘子從教百尺樓。", "已斸荒畦秧早韭，旋呼老瓦壓新篘。", "客來問字煩傳語，扣角前岡政飯牛。"]'),
('89ac137d-1226-46c4-a571-b1a013763155','次韻梁倅中秋日雨','方岳','宋','宋诗','song-poetry','','[]','天公不吝常時月，每到中秋苦作難。',64,'全唐诗/poet.song.212000.json','["天公不吝常時月，每到中秋苦作難。", "醽醁又孤今夕醉，梧桐仍是去年寒。", "萍花風老鱸魚夢，蘆葉雨宜鷗鷺看。", "我欲與公天柱去，月明多處倚闌干。"]'),
('7b516023-5948-4540-a77b-d1a1f36ef2ab','次韻梁倅','方岳','宋','宋诗','song-poetry','','[]','只與青山對面居，白雲侵屨有詩無。',64,'全唐诗/poet.song.212000.json','["只與青山對面居，白雲侵屨有詩無。", "故人咫尺隔千里，明月嬋娟共一壺。", "鷗鷺盟應憐久客，梧桐雨亦問歸塗。", "近來煞得秋風力，老桂吹香滿座隅。"]'),
('f7c2c9ab-0562-4151-98ee-a0dc98b32536','此君亭','方岳','宋','宋诗','song-poetry','','[]','此君雅有冰雪操，阿堵難爲金石交。',64,'全唐诗/poet.song.212000.json','["此君雅有冰雪操，阿堵難爲金石交。", "亭上月明晚色浄，江頭潮落秋聲高。", "舉杯相屬非俗物，著我於中亦世豪。", "對之清坐欲忘日，凜有直氣如吾曹。"]'),
('c66ad5e6-d35c-4f88-8425-0660e6481a58','送胡兄歸嶽','方岳','宋','宋诗','song-poetry','','[]','風飽橫江十幅蒲，秋聲正有玉花鱸。',64,'全唐诗/poet.song.212000.json','["風飽橫江十幅蒲，秋聲正有玉花鱸。", "淮渜一夢雨中別，嶽麓諸峯天下無。", "場屋抵須新議論，書堂更做好規模。", "未知雪徑青燈夜，誰記臨分岸岸蘆。"]'),
('0d44f1a0-9a74-4ce6-9f54-af5f74e9f646','次韻吳殿撰多景樓見寄','方岳','宋','宋诗','song-poetry','','[]','多情王粲怕登樓，誰遣人間汗漫遊。',64,'全唐诗/poet.song.212000.json','["多情王粲怕登樓，誰遣人間汗漫遊。", "蓴菜夢回千里月，蘋花老却一江秋。", "人如沙燕年年別，騷到湘纍字字愁。", "正爾相觀衣带水，角聲孤起暮雲稠。"]'),
('1a4a372f-e6af-41f4-863e-128e36a58462','旅思','方岳','宋','宋诗','song-poetry','','[]','索米長安鬢易絲，向來書劍亦奚爲。',64,'全唐诗/poet.song.212000.json','["索米長安鬢易絲，向來書劍亦奚爲。", "無詩傳與雞林去，有賦羞令狗監知。", "兩戒山河饒虎落，五湖煙水欠鴟夷。", "喜無光範三書草，此段差强韓退之。"]'),
('a48bc434-4aa2-4b91-87de-eb16aa0cb225','寄友人','方岳','宋','宋诗','song-poetry','','[]','面熟青山亦故人，霜逢肯負月粼粼。',64,'全唐诗/poet.song.212000.json','["面熟青山亦故人，霜逢肯負月粼粼。", "如聞行李且家住，未必梅花知路貧。", "薺老自堪供野飯，罾寒誰與鱠溪鱗。", "商量只有歸耕是，不料歸耕也誤身。"]'),
('f95cfc5b-42c5-43ee-87bd-f94c03aece53','次韻葉兄雲崖','方岳','宋','宋诗','song-poetry','','[]','以酒爲鄉墨作莊，厓寒雲亦爲詩忙。',64,'全唐诗/poet.song.212000.json','["以酒爲鄉墨作莊，厓寒雲亦爲詩忙。", "春山藥草誰同斸，雲逕梅花只自香。", "竹不礙山青入戶，蘚緣謝客綠侵床。", "豈無楓葉吳江句，夜雨何時稻韭黄。"]'),
('8e14f741-338f-44f5-9586-f249b5615757','客有餉水母線者坐人賦之因次其韻','方岳','宋','宋诗','song-poetry','','[]','蒼潮漱雪儘風流，寒擁春沙了雋遊。',64,'全唐诗/poet.song.212000.json','["蒼潮漱雪儘風流，寒擁春沙了雋遊。", "霜髓英英矜客夢，冰絲一一做詩愁。", "有騷風味秋能老，非酒生涯誰與酬。", "解佩楚臯雲杳渺，月明正在玉搔頭。"]'),
('bbb6d267-5fcc-428c-a8b6-bbd7b05fa989','山行  其一','方岳','宋','宋诗','song-poetry','','[]','歲晚誰同澗谷槃，一牛呼犢野煙寒。',64,'全唐诗/poet.song.212000.json','["歲晚誰同澗谷槃，一牛呼犢野煙寒。", "村如有雪蕎花白，山未著霜桐葉丹。", "是處豐登茅店酒，老夫閒散竹皮冠。", "醉歸更草郊居賦，傳與詩人作畫看。"]'),
('a26d8798-90ec-481d-b60d-275e1801035b','山行  其二','方岳','宋','宋诗','song-poetry','','[]','亦笑先生蔬一槃，雲沈作塢卧荒寒。',64,'全唐诗/poet.song.212000.json','["亦笑先生蔬一槃，雲沈作塢卧荒寒。", "童顔併已無班白，槁面舊曾如渥丹。", "底用魚烹雙素尺，共知鶴化一黄冠。", "芙蓉冷落秋蕭索，只有籬花耐久看。"]'),
('98c021b9-c50f-4d69-b49d-648661b2e798','送別季觀','方岳','宋','宋诗','song-poetry','','[]','山留遷客秋風寺，想得梧桐怨夜長。',64,'全唐诗/poet.song.212000.json','["山留遷客秋風寺，想得梧桐怨夜長。", "正欠蹇馿相就語，其如征燕欲歸忙。", "蘋花思與晴江渺，桂樹寒生老月香。", "一路有詩煩拾取，寄書猶及鴈前霜。"]'),
('b49e756a-ad6b-4f89-8b99-1fa8a2215849','偶閲夷堅志見梁鄭公有九月梅花詩因復次韻','方岳','宋','宋诗','song-poetry','','[]','秋容正待滿林雪，春色因何到草堂。',64,'全唐诗/poet.song.212000.json','["秋容正待滿林雪，春色因何到草堂。", "地脈頓回消息早，天葩不作等閒香。", "丹楓欲老已如許，黄菊同時未敢芳。", "不等歲寒催鼎實，角聲自與月平章。"]'),
('bc2b6004-9779-4ad9-bbc7-4234e02b2913','道中','方岳','宋','宋诗','song-poetry','','[]','山寒苦厭連宵雨，溪滑頓添兼尺水。',64,'全唐诗/poet.song.212000.json','["山寒苦厭連宵雨，溪滑頓添兼尺水。", "輿行兩驛費十程，篷卧一篙餘百里。", "世事乘除類如此，人生俛仰知何似。", "紫螯美不負秋風，但媿前頭子陵耳。"]'),
('327f3912-ac19-403a-b5ef-c74b4d6ee564','呈知郡汪少卿','方岳','宋','宋诗','song-poetry','','[]','集英賜對已專城，竟拂爐煙上翠瀛。',64,'全唐诗/poet.song.212000.json','["集英賜對已專城，竟拂爐煙上翠瀛。", "蹕靜共傳新太守，硯寒仍是舊書生。", "詩如霜月五更曉，人與梅花一樣清。", "昨夜紫陽山雪外，漏傳鼓角亦分明。"]'),
('1b6c9c3a-97d5-46c6-a7eb-9d62686efb08','次韻汪少卿禱雪有感','方岳','宋','宋诗','song-poetry','','[]','梅梢了未知寒在，剪取清溪作雪飛。',64,'全唐诗/poet.song.212000.json','["梅梢了未知寒在，剪取清溪作雪飛。", "正草綠章箋玉帝，頓驚碧宙舞瑶妃。", "賣刀我亦耕侯土，歌袴今誰典客衣。", "想得夜窗春滿袖，燕彜香煖醉吟歸。"]'),
('84abe397-2e58-4633-8413-7903e040b696','陪汪少卿遊紫陽次梁倅韻','方岳','宋','宋诗','song-poetry','','[]','此行許老亦津津，連夜催將雪樹春。',64,'全唐诗/poet.song.212000.json','["此行許老亦津津，連夜催將雪樹春。", "溪隔便無塵土事，山矜便識謫僊人。", "雲依欄過香仍濕，墨带冰磨句轉新。", "丘壑自容吾入社，不論五馬兩朱輪。"]'),
('3784c960-e2d1-43f2-a0c9-640ee5bf7245','三巖','方岳','宋','宋诗','song-poetry','','[]','山入蒼州翠作層，何年鑿此玉崚嶒。',64,'全唐诗/poet.song.212000.json','["山入蒼州翠作層，何年鑿此玉崚嶒。", "瀑從峭壁飛將落，雪沍蒼崖危欲崩。", "寺老尚堪支古佛，地靈不肯著凡僧。", "定應嫌客留名姓，雲逼人寒一硯冰。"]'),
('cf79063c-af8c-4fa7-ac55-71475ff27cfd','簡竹外','方岳','宋','宋诗','song-poetry','','[]','山肯相容作此行，又携老石寄江城。',64,'全唐诗/poet.song.212000.json','["山肯相容作此行，又携老石寄江城。", "毛錐於我獨無補，歡伯向人如有情。", "幾夢不知連鴈遠，一詩元只爲梅清。", "蹇馿欲過吳門尉，雲凍商量雪未成。"]'),
('abf44d44-ab80-47a6-b3d7-777aef9e69f4','得家信','方岳','宋','宋诗','song-poetry','','[]','雲凍窗櫺香未殘，月欹沙渚角聲乾。',64,'全唐诗/poet.song.212000.json','["雲凍窗櫺香未殘，月欹沙渚角聲乾。", "相思千里夢初斷，又是五更霜正寒。", "客路不知花代謝，家書只報竹平安。", "詩情却與山如舊，但做吾鄉一等看。"]'),
('fb4c1d19-f8a9-4da5-8ad1-3a078898b699','次韻方叔','方岳','宋','宋诗','song-poetry','','[]','江樓識面一跫然，語带煙霞似欲仙。',64,'全唐诗/poet.song.212000.json','["江樓識面一跫然，語带煙霞似欲仙。", "山雨竟寒清夜約，好風吹落碧雲篇。", "相逢客路思歸日，幾立梅花欲暮天。", "有興話詩吾儻住，一蓑須辦雪溪船。"]'),
('6b57d497-0c02-4845-bd6b-8cf4b314ff18','簡王尉借書畫','方岳','宋','宋诗','song-poetry','','[]','雪屋燈寒費廿年，春臯悔不早歸田。',64,'全唐诗/poet.song.212000.json','["雪屋燈寒費廿年，春臯悔不早歸田。", "書無靈聖今猶爾，句有神奇亦偶然。", "如此溪山那得酒，幸而風月不論錢。", "三三習氣除難盡，忽憶朱家書畫船。"]'),
('ded3ad2f-d92b-4e70-a8b4-ad17f4ba7fc7','次韻山居  其一','方岳','宋','宋诗','song-poetry','','[]','孤亭危受衆峯朝，歲晚移床借避囂。',64,'全唐诗/poet.song.212000.json','["孤亭危受衆峯朝，歲晚移床借避囂。", "梅次第花春漠漠，鶴相隨睡夜寥寥。", "諸公安用怒生癭，老子豈爲饑折腰。", "更入亂雲深處去，極知與世不同條。"]'),
('f485406e-809a-4153-b15b-9ebc8558d1e6','次韻山居  其二','方岳','宋','宋诗','song-poetry','','[]','諸老鳴靴日上朝，有人幽處厭喧囂。',64,'全唐诗/poet.song.212000.json','["諸老鳴靴日上朝，有人幽處厭喧囂。", "江鄉十月稻成熟，茅屋一燈山寂寥。", "天不與生犀插腦，人今能幾寶圍腰。", "從吾所好寧相誤，洙泗壇荒有玉條。"]'),
('13892a32-5125-4e9d-b43c-33455a9ae98f','次韻山居  其三','方岳','宋','宋诗','song-poetry','','[]','文如翻海百川朝，不說從前兩耳囂。',64,'全唐诗/poet.song.212000.json','["文如翻海百川朝，不說從前兩耳囂。", "徑與此山俱寂寂，未應吾道竟寥寥。", "一生不辦雕龍口，十萬誰纏騎鶴腰。", "但得草茅休歇去，何如快活有新條。"]'),
('825b2312-2dee-4808-9205-c36b197a3dff','次韻山居  其四','方岳','宋','宋诗','song-poetry','','[]','閒民亦幸樂清朝，蓑笠過從語不囂。',64,'全唐诗/poet.song.212000.json','["閒民亦幸樂清朝，蓑笠過從語不囂。", "儵忽豈能知混沌，玄冥頗亦識參寥。", "年華鼎鼎分杯面，筋力時時借樹腰。", "月冷霜寒驚鶴帳，住山活計太蕭條。"]'),
('c16cd4fb-2e8a-4f8a-a108-65962ceb1db9','重題釣臺','方岳','宋','宋诗','song-poetry','','[]','落帆曾傍蘆花宿，借得先生月一灘。',64,'全唐诗/poet.song.212000.json','["落帆曾傍蘆花宿，借得先生月一灘。", "鷗鳥未忘吾道在，江山肯作故人看。", "樹昏斷岸潮聲急，雪洗孤臺石罅寒。", "最喜吾宗詩有派，每依蒼石插檣竿。"]'),
('a9d474e7-b75b-4196-baee-253526d2f2cd','送客','方岳','宋','宋诗','song-poetry','','[]','瘦馬孤征雪滿衣，山長誰不念庭闈。',64,'全唐诗/poet.song.212000.json','["瘦馬孤征雪滿衣，山長誰不念庭闈。", "燈寒竹屋無人共，月到梅花有夢歸。", "抵掌相逢連夕語，轉頭頓覺十年非。", "武夷人老君行矣，莫待墨池春浪肥。"]'),
('0d5f82a1-723c-4d25-9d90-cbd6ec445281','次韻鄭省倉見寄  其一','方岳','宋','宋诗','song-poetry','','[]','倦客京華鬢已疎，詩顛草聖了無餘。',64,'全唐诗/poet.song.212000.json','["倦客京華鬢已疎，詩顛草聖了無餘。", "別離菊酒纔秋晚，流落椒盤忽歲除。", "東閣士應羞噲伍，北山人有絕秦書。", "草蘆十具牛如辦，却是求田勝本初。"]'),
('ad740531-908e-4616-864f-1ae1f8d5433d','次韻鄭省倉見寄  其二','方岳','宋','宋诗','song-poetry','','[]','老年夢不到歌姝，一笑離尊孰與娛。',64,'全唐诗/poet.song.212000.json','["老年夢不到歌姝，一笑離尊孰與娛。", "歲事沈沈江上月，時情汎汎水中鳬。", "路貧如此誰來往，山意於人定有無。", "牢落不堪持說似，詩成時一寄奚奴。"]'),
('d039a7d6-ce8f-4273-9d58-b4178d231252','訪張居卿不值','方岳','宋','宋诗','song-poetry','','[]','與客敲門野竹邊，蹇馿何許兀吟鞭。',64,'全唐诗/poet.song.212000.json','["與客敲門野竹邊，蹇馿何許兀吟鞭。", "蒼頭不訪孤山鶴，素手空回剡曲船。", "書不療饑聊爾耳，酒能作病豈其然。", "曾留一則山中話，可問南湖雪後天。"]'),
('8076c7bb-2c1e-4190-92a3-827fb20f68bb','湖上','方岳','宋','宋诗','song-poetry','','[]','老藤支我步湖滣，借與晴光一欠伸。',64,'全唐诗/poet.song.212000.json','["老藤支我步湖滣，借與晴光一欠伸。", "楊柳得春青眼舊，山巒留雪白頭新。", "鐵琅璫語尋齋鉢，銀鱍剌肥收釣緡。", "有兩黄冠共棋局，相携便作所歡人。"]'),
('8ad69bec-f71d-488e-bdca-56047e752e7f','易地昭武去之日與家人集新作南門書水鏡壁上蓋十一月廿六也','方岳','宋','宋诗','song-poetry','','[]','晦庵呼我住山南，五老人知百不堪。',64,'全唐诗/poet.song.212000.json','["晦庵呼我住山南，五老人知百不堪。", "極目無窮江渺渺，滿頭歸去雪毿毿。", "吾生只可龜藏六，世事何如狙賦三。", "政有梅花管迎送，歲寒行路飽曾諳。"]'),
('0b911b8e-4188-49c4-8d38-ff45ef612b4b','十二月二十四日雪蓋予三年于淮纔見此耳時東師援淝水捷書西來走筆呈趙公借官奴與幕友一醉','方岳','宋','宋诗','song-poetry','','[]','淝水風聲欲破苻，文城雪意趁禽吳。',64,'全唐诗/poet.song.212000.json','["淝水風聲欲破苻，文城雪意趁禽吳。", "詩筒擬醉玉跳脫，捷羽已飛金僕姑。", "剡曲但能乘興逸，灞橋僅不負詩癯。", "那知莫府文書外，更解飛瓊打陣圖。"]'),
('ba4eecf6-2221-482d-aa69-8dff7fea922f','除日雪甚約客不至乃擁貂驟馬于郊外獨飲摘星樓舉鞭謝客曰未可使城中諸公知之但當誇與灞橋馿子上鄭五耳','方岳','宋','宋诗','song-poetry','','[]','揚州二十四橋月，莫作灞橋同調看。',64,'全唐诗/poet.song.212000.json','["揚州二十四橋月，莫作灞橋同調看。", "詩果位登銀色界，酒風流倚玉闌干。", "六花比似瓊花巧，一歲翻成兩歲寒。", "明日屠蘇催短鬢，過從更覺欠袁安。"]'),
('b373cf9a-2fc0-46fb-a934-46eb400bcfb2','催雪','方岳','宋','宋诗','song-poetry','','[]','作箋擬上朝元殿，爲說梅須雪轉香。',64,'全唐诗/poet.song.212000.json','["作箋擬上朝元殿，爲說梅須雪轉香。", "杯雋已生詩意思，硯寒更作夜商量。", "輕明玉費天工巧，頃刻花催帝子忙。", "醉夢蓬萊宮闕冷，共題新曲按霓裳。"]'),
('456a25cc-d041-4475-9e2a-4757bede687e','次韻梁權郡喜雪','方岳','宋','宋诗','song-poetry','','[]','雪易商量不等詩，徑傳寒令舞冰夷。',64,'全唐诗/poet.song.212000.json','["雪易商量不等詩，徑傳寒令舞冰夷。", "夢分曉殿香仍悄，心到春蓑帝未知。", "擬寄新花誇北客，共憐英氣小南枝。", "凍雲滿有豐年意，併與農謠入燕彝。"]'),
('f3a1f2d4-54ce-47fc-87a7-8dbd41ddbf18','雪作泊七里灘','方岳','宋','宋诗','song-poetry','','[]','春聲賓鴈鴈賓年，倚盡沙頭欲暮天。',64,'全唐诗/poet.song.212000.json','["春聲賓鴈鴈賓年，倚盡沙頭欲暮天。", "蒼石生成嚴子瀨，雪篷畫出剡溪船。", "相望江樹隔千里，不與梅花留一錢。", "此去更尋林處士，南山之後北山前。"]'),
('24a41801-74bc-45e9-ad58-37be84755c76','次韻汪少卿雪晴','方岳','宋','宋诗','song-poetry','','[]','夜寒吹角落孤城，吹得詩成天未明。',64,'全唐诗/poet.song.212000.json','["夜寒吹角落孤城，吹得詩成天未明。", "雪沍賓鴻催歲事，霜晴烏鳥作春聲。", "一床書老客中夢，二頃田微郭外耕。", "但得年豐歌袴飲，茅齋猶有舊甆觥。"]'),
('5e5300b1-6a56-46d0-a965-99833ba9a641','次韻陳祭酒喜雪  其一','方岳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曉聽爐亭瀉竹聲，老仙呵墨已詩成。',64,'全唐诗/poet.song.212000.json','["曉聽爐亭瀉竹聲，老仙呵墨已詩成。", "春連宇宙開皇極，天與君王作太平。", "草木有生皆潤澤，山河無處不清明。", "寒蓑莫袖垂綸手，萬里長江一艇橫。"]'),
('465bfed0-1b6d-42c6-ad3d-0cc2aa2ae984','次韻陳祭酒喜雪  其二','方岳','宋','宋诗','song-poetry','','[]','飛到裘茸不肯飛，危樵孤倚暮江時。',64,'全唐诗/poet.song.212000.json','["飛到裘茸不肯飛，危樵孤倚暮江時。", "袁安家在鴻濛外，剡曲人誰汗漫期。", "氛祲不傳青海箭，豐年又入紫皇詩。", "春風吹落人間世，只有梅花聖得知。"]'),
('93f5e60d-c241-4177-9239-e276ac28bf8e','餐雪轆轤體','方岳','宋','宋诗','song-poetry','','[]','酒渴來時海不供，山寒餐玉有奇功。',64,'全唐诗/poet.song.212000.json','["酒渴來時海不供，山寒餐玉有奇功。", "柘漿滴處絲糕紫，冰盌擎將片腦鬆。", "透骨洗清煙火氣，滿腔頓著水晶宮。", "人間塵土何堪住，徑住瓊瑶第一峯。"]'),
('0b8d1b7c-26ce-4f3d-9c47-4c7d3b12c8dd','歲晚','方岳','宋','宋诗','song-poetry','','[]','山雲之東東復東，一蓑寂歷鳴霜風。',64,'全唐诗/poet.song.212000.json','["山雲之東東復東，一蓑寂歷鳴霜風。", "儻來軒冕外物外，別有宇宙中扃中。", "春容已自柳梢碧，人面未必桃花紅。", "六十看看遽如許，世間白髮何曾公。"]'),
('c3e6530b-6c0d-47e3-8525-d88e918d4b93','除夜','方岳','宋','宋诗','song-poetry','','[]','雪甕冰齏了歲除，停杯且聽話迂疎。',64,'全唐诗/poet.song.212000.json','["雪甕冰齏了歲除，停杯且聽話迂疎。", "山居雖窄可無竹，家計甚貧猶有書。", "但覺是非驚化鶴，不將喜怒等羣狙。", "耦耕久與鄰翁約，春雨寧辭手拮据。"]'),
('07675136-342d-4819-acab-742f153b62b6','歲朝','方岳','宋','宋诗','song-poetry','','[]','青山不似歲華老，白酒最於鷗鳥親。',64,'全唐诗/poet.song.212000.json','["青山不似歲華老，白酒最於鷗鳥親。", "十事九休書作祟，百無一有硯生春。", "貧中只是尋常日，醉裏何知見在身。", "却喜東風公道在，池塘吹綠漲痕新。"]'),
('a14ef2d2-f069-495f-a91e-30c21d1861f4','約劉良叔觀苔梅  其一','方岳','宋','宋诗','song-poetry','','[]','雪侵橫驛苔枝古，莫作江南一樣看。',64,'全唐诗/poet.song.212000.json','["雪侵橫驛苔枝古，莫作江南一樣看。", "醖藉春情何遜老，稜層詩骨孟郊寒。", "也知餘子十分俗，雅有書生半點酸。", "政恐劉郎識桃耳，相從冷澹亦良難。"]'),
('79be7d2d-a241-434b-8f1b-5aefcc4c81ae','約劉良叔觀苔梅  其二','方岳','宋','宋诗','song-poetry','','[]','黄昏疎影橫斜月，說似詩人仔細看。',64,'全唐诗/poet.song.212000.json','["黄昏疎影橫斜月，說似詩人仔細看。", "蘚樹卧龍鱗甲老，霜橋立馬骨毛寒。", "共尋雪句心猶苦，只嚼冰鬚齒亦酸。", "涪老未爲知己在，水仙畢竟弟兄難。"]'),
('e856bdc7-6c79-4d78-8de4-c67644c67749','約劉良叔觀苔梅  其三','方岳','宋','宋诗','song-poetry','','[]','自洗銅壺倚碧欄，丁寧莫遣俗人看。',64,'全唐诗/poet.song.212000.json','["自洗銅壺倚碧欄，丁寧莫遣俗人看。", "春柔轉覺沈郎瘦，雨重那知范叔寒。", "東閣酒深詩興浩，南枝月冷角聲酸。", "孤山逋老曾題品，到得吾曹著語難。"]'),
('10c2b649-8806-4a97-aa65-35562ae88fca','約劉良叔觀苔梅  其四','方岳','宋','宋诗','song-poetry','','[]','白玉爲堂月一欄，何如茅屋雪中看。',64,'全唐诗/poet.song.212000.json','["白玉爲堂月一欄，何如茅屋雪中看。", "笑堪索否便堪醉，盟可尋歟不可寒。", "枝北春風驚婉娩，江南煙雨幾悲酸。", "清香吹落騷人手，墨妙筆精并二難。"]'),
('732eab5d-9798-4ee4-9901-c6f4995ae596','約劉良叔觀苔梅  其五','方岳','宋','宋诗','song-poetry','','[]','水曹爲骨逋爲髓，風雪灞橋誰共看。',64,'全唐诗/poet.song.212000.json','["水曹爲骨逋爲髓，風雪灞橋誰共看。", "千里夢回歸路遠，一枝春占暮江寒。", "飛飛兩片猶堪醉，點點晴香亦带酸。", "雙玉瓶乾情正洽，與君落筆不辭難。"]'),
('730f4c9b-0774-4dc4-9487-52ef3a63cc3c','以梅送王尉  其一','方岳','宋','宋诗','song-poetry','','[]','雪澗偶逢山澤癯，相携茅屋對團蒲。',64,'全唐诗/poet.song.212000.json','["雪澗偶逢山澤癯，相携茅屋對團蒲。", "古心不爲世情改，老氣了非流俗徒。", "三讀離騷多楚怨，一生知己只林逋。", "詩成不值渠爲伴，持醉主人雙玉壺。"]'),
('ed761b6a-2066-4083-8cea-9991bacec653','以梅送王尉  其二','方岳','宋','宋诗','song-poetry','','[]','才有騷情例合癯，只銷清供老伊蒲。',64,'全唐诗/poet.song.212000.json','["才有騷情例合癯，只銷清供老伊蒲。", "孔方兄自非吾黨，木上座堪尋酒徒。", "寄子梅花逢驛使，敗人詩興苦催逋。", "夜寒夢到西窗竹，明月一床冰一壺。"]'),
('608007ae-ca89-42c9-9c8d-0d9cf3d7a5f8','正月盡山間梅花猶有未放者','方岳','宋','宋诗','song-poetry','','[]','南枝寒盡著花遲，入我新年第一詩。',64,'全唐诗/poet.song.212000.json','["南枝寒盡著花遲，入我新年第一詩。", "明月向人應有語，老天於物本無私。", "自逋之後誰相得，未雪以前春不知。", "儘讓世間凡草木，再三守此歲寒姿。"]'),
('7553a58b-9412-4696-a0dc-9006e95b6b3d','次韻海棠  其一','方岳','宋','宋诗','song-poetry','','[]','暖酣翠袖倚清妍，露洗輕紅待舉鞭。',64,'全唐诗/poet.song.212000.json','["暖酣翠袖倚清妍，露洗輕紅待舉鞭。", "嬌懶不知春二月，風流堪聘晉諸賢。", "天生富貴家何在，花有神仙譜未編。", "誰鎖二喬深院落，只將愁思過年年。"]'),
('d1a441d1-1e50-4de8-acaa-4a35b9f9c660','次韻海棠  其二','方岳','宋','宋诗','song-poetry','','[]','殘風剩雨今如此，莫遣臙脂雪滿枝。',64,'全唐诗/poet.song.212000.json','["殘風剩雨今如此，莫遣臙脂雪滿枝。", "洛浦夢酣花半醉，華清浴困手雙垂。", "一杯而別亦何恨，十日之春能幾時。", "不遇少陵休悵惋，醉中試作補亡詩。"]'),
('84cd0eb9-271d-4154-8795-6f986b14b2f0','次韻','方岳','宋','宋诗','song-poetry','','[]','海棠寂寂香埋玉，山雨浪浪負雙足。',64,'全唐诗/poet.song.212000.json','["海棠寂寂香埋玉，山雨浪浪負雙足。", "閉門長憾虎頭癡，對客不供貂尾續。", "徑呼伯雅相拍浮，試坐毛錐三沐浴。", "滿身花片爲誰春，政欠太虛明月燭。"]'),
('51f29878-862c-441b-9636-66b5fabff16a','海棠盛開而雨  其一','方岳','宋','宋诗','song-poetry','','[]','閉門十日雨淋漓，洗盡紅香了未知。',64,'全唐诗/poet.song.212000.json','["閉門十日雨淋漓，洗盡紅香了未知。", "纔一霎晴齊睡去，幾何人見半開時。", "世無解語玉超脫，春欲負予金屈巵。", "自是晦明天不定，非干工部欠渠詩。"]'),
('4c55bcee-b60b-4fd5-af9d-b9b3d2ab1491','海棠盛開而雨  其二','方岳','宋','宋诗','song-poetry','','[]','醉紅睡去不勝扶，遮盡丹荑蓋綠蕪。',64,'全唐诗/poet.song.212000.json','["醉紅睡去不勝扶，遮盡丹荑蓋綠蕪。", "四立壁成花世界，一年春在錦屠蘇。", "山中富貴遽如許，詩外豪奢有是夫。", "已與婦謀須斗酒，不知明日定晴無。"]'),
('a38a7508-24ad-44ce-b4a8-93870444f0d9','又次韻謝司法','方岳','宋','宋诗','song-poetry','','[]','風光已是二分時，翻覆人間幾局棋。',64,'全唐诗/poet.song.212000.json','["風光已是二分時，翻覆人間幾局棋。", "山雨不容春到眼，海棠無復曉凝脂。", "情懷未必禽魚識，歲月何堪駟馬追。", "只有荼䕷香似酒，等閒開自不妨遲。"]'),
('2f45a079-9613-4a31-88e9-5f84eb264a66','接花','方岳','宋','宋诗','song-poetry','','[]','楚籜并刀社雨前，掇紅接紫自年年。',64,'全唐诗/poet.song.212000.json','["楚籜并刀社雨前，掇紅接紫自年年。", "顛風稗子僧成佛，白日爛柯人詐仙。", "半霎時移愚智性，一丸泥奪化工權。", "可憐人自生荆棘，却變初心失本然。"]'),
('fde71321-f6d6-4980-9868-b85d926c05ea','種瑞香','方岳','宋','宋诗','song-poetry','','[]','自種幽香傍短櫺，荷鋤政用雨冥冥。',64,'全唐诗/poet.song.212000.json','["自種幽香傍短櫺，荷鋤政用雨冥冥。", "山家安得瑞龍腦，春事不專紅鶴翎。", "持向東風論甲乙，與遮西日費丁寧。", "何年得似熏籠錦，茗盌時時爲乞靈。"]'),
('72e03bc7-bbc4-4c02-88da-2960ef7637c0','食猫筍','方岳','宋','宋诗','song-poetry','','[]','此君乃有寧馨兒，犀角豐盈玉不如。',64,'全唐诗/poet.song.212000.json','["此君乃有寧馨兒，犀角豐盈玉不如。", "老去煙姿元聳壑，生來風骨已專車。", "詩腸慣識貓頭筍，食指寧知熊掌魚。", "莫遣匆匆上竿綠，一春心事政關渠。"]'),
('a8ee0f8d-caef-4f57-a885-614b2090b52c','楊妃牡丹','方岳','宋','宋诗','song-poetry','','[]','馬嵬殘恨久銷沈，花撚粧痕尚不禁。',64,'全唐诗/poet.song.212000.json','["馬嵬殘恨久銷沈，花撚粧痕尚不禁。", "當日願爲連理木，春風不負合歡心。", "病維摩減詩情盡，窮孟嘗添酒債深。", "醉面欲醒如有舊，沈香亭北記曾吟。"]'),
('52b65e45-5875-4180-a7cd-a8f67af19e13','次韻牡丹','方岳','宋','宋诗','song-poetry','','[]','洛陽兒女惜花殘，認得愁痕入黛巒。',64,'全唐诗/poet.song.212000.json','["洛陽兒女惜花殘，認得愁痕入黛巒。", "夜雨正驚春冉冉，晴風欲墮玉珊珊。", "一詩自直連城璧，千葉誰分徑尺槃。", "煩與丁寧留醉在，窗綃深掩護輕寒。"]'),
('dfc17895-9d7f-42f7-9def-e1d57badbab0','答惠牡丹','方岳','宋','宋诗','song-poetry','','[]','不識桃花過一年，已甘無分牡丹邊。',64,'全唐诗/poet.song.212000.json','["不識桃花過一年，已甘無分牡丹邊。", "開園肯剪夜欄雨，抱甕亟分山澗泉。", "書室乍驚春富貴，草廬誰結酒因緣。", "如聞花貢今成例，獨未時情也自賢。"]'),
('24d4a740-1e28-4ca4-8f07-d42ab16a65cd','水仙初花','方岳','宋','宋诗','song-poetry','','[]','叢叢低綠玉參差，抱甕春畦手自治。',64,'全唐诗/poet.song.212000.json','["叢叢低綠玉參差，抱甕春畦手自治。", "地暖乍離煙雨氣，歲寒不改雪霜姿。", "太真妃以香爲骨，虢國人嫌粉涴眉。", "莫道秋崖無造化，解令朽壤出神奇。"]'),
('60e34621-0b90-47a5-ac5f-6ca1f93b4752','晚汎草塘有魚入舟呼童鱠之適見瑞蓮駢植與客賦首尾吟  其一','方岳','宋','宋诗','song-poetry','','[]','草塘晚汎亦佳哉，誰爲貧謀獻鱠才。',64,'全唐诗/poet.song.212000.json','["草塘晚汎亦佳哉，誰爲貧謀獻鱠才。", "自入船來銀潑剌，且留客共月徘徊。", "不須溪友投竿線，徑與詩人上酒盃。", "著意出奇殊未也，柳邊又報瑞蓮開。"]'),
('335d876c-cf02-4e83-bdda-a6e29d5af432','晚汎草塘有魚入舟呼童鱠之適見瑞蓮駢植與客賦首尾吟  其二','方岳','宋','宋诗','song-poetry','','[]','柳邊又報瑞蓮開，持與南薰討論來。',64,'全唐诗/poet.song.212000.json','["柳邊又報瑞蓮開，持與南薰討論來。", "君子花寧兒女態，隠居人豈艷陽才。", "一經在昔曾雙薦，三世於今不異財。", "自有老天知我在，草塘晚汎亦佳哉。"]'),
('9785ac19-dc89-4062-85f2-60f6528a7180','次韻瑞蓮','方岳','宋','宋诗','song-poetry','','[]','得種初非相府蓮，誰令連蔕擢山泉。',64,'全唐诗/poet.song.212000.json','["得種初非相府蓮，誰令連蔕擢山泉。", "東西玉已幾相屬，大小喬今雙欲仙。", "塢曰荷嘉真是矣，人言花是豈其然。", "山居但憶遠公社，却與遺民孰後先。"]'),
('81f596ce-a867-42bb-8f2e-2391acbe52f3','效茶山詠楊梅','方岳','宋','宋诗','song-poetry','','[]','五月梅晴暑正袢，楊家亦有果堪攀。',64,'全唐诗/poet.song.212000.json','["五月梅晴暑正袢，楊家亦有果堪攀。", "雪融火齊驪珠冷，粟起丹砂鶴頂殷。", "併與文園消午渴，不禁越女蹙春山。", "略如荔子仍同姓，直恐前身是阿環。"]'),
('3584502a-6d43-4c57-8a4b-a60475e3014d','次韻紅蕉','方岳','宋','宋诗','song-poetry','','[]','霜林蕉葉尚橫陳，不易禁寒夜嚮晨。',64,'全唐诗/poet.song.212000.json','["霜林蕉葉尚橫陳，不易禁寒夜嚮晨。", "以貌取人通體似，其心如我別般春。", "兩年開就花何晚，千里移將句有神。", "待學伊蒲修浄供，自烹菡萏當猩唇。"]'),
('765770ee-2cd9-4c86-9cf2-01a6284d29e5','次韻林同年見寄','方岳','宋','宋诗','song-poetry','','[]','水驛山城幾往來，雪鷗亦怪面生埃。',64,'全唐诗/poet.song.212000.json','["水驛山城幾往來，雪鷗亦怪面生埃。", "徑歸不爲麒麟楦，多病竟孤鸚鵡杯。", "老子地寒餘草逕，廣文官冷合蘭臺。", "山居美不堪持贈，雲濕墮樵羹芋魁。"]'),
('539fe790-a773-4361-8c7a-5854cefa9f77','用韻簡趙尉無牡丹','方岳','宋','宋诗','song-poetry','','[]','亂山深處有誰來，詩硯荒寒一寸埃。',64,'全唐诗/poet.song.212000.json','["亂山深處有誰來，詩硯荒寒一寸埃。", "特未可知天下事，斷無相負掌中杯。", "人傳梅隠近入幙，我但糟丘高築臺。", "竹友松朋真耐久，可曾將口問花魁。"]'),
('d077c4d9-919f-44db-acb0-28e4310a40dd','三用韻酬沈同年','方岳','宋','宋诗','song-poetry','','[]','兩屨適從何許來，雙蓬無處避風埃。',64,'全唐诗/poet.song.212000.json','["兩屨適從何許來，雙蓬無處避風埃。", "江湖誰共月千里，軒冕真同水一杯。", "縱有窮愁侵病骨，斷無榮辱到靈臺。", "只銷處士星明潤，未用三台入斗魁。"]'),
('73f2e619-7f13-419c-b194-6a962e1111df','汪校正送鸚鵡','方岳','宋','宋诗','song-poetry','','[]','山中寂寞無與語，隴客適從何許來。',64,'全唐诗/poet.song.212000.json','["山中寂寞無與語，隴客適從何許來。", "每慨俗人言少味，寧知凡物忌多才。", "關山坐隔月千里，湖海相忘酒一杯。", "畢竟與渠毛羽別，窺簷羣雀漫驚猜。"]'),
('e2fcb821-81f8-48a0-b436-0c23ed78c35b','寄范參政','方岳','宋','宋诗','song-poetry','','[]','逐客無書入帝城，靈光今闕幾公卿。',64,'全唐诗/poet.song.212000.json','["逐客無書入帝城，靈光今闕幾公卿。", "當時何敢書三宿，諸老誰招魯兩生。", "雙碧崔嵬容雪卧，一黄觳觫了春耕。", "極知窮薄難爲力，猶幸林間識太平。"]'),
('b12d1f04-1e5c-4f19-9f74-d707fe63733f','寄史監丞','方岳','宋','宋诗','song-poetry','','[]','雲卧空山抱月明，不將此手揖公卿。',64,'全唐诗/poet.song.212000.json','["雲卧空山抱月明，不將此手揖公卿。", "詩狂肯換五花馬，酒興徑乘雙玉缾。", "老子胸吞雲夢澤，夜寒筆捲雪濤聲。", "三生杜牧能容否，醉眼何妨一笑橫。"]'),
('4180e8fb-77b1-44d7-a8d0-53a3adf3414d','挽謝公王','方岳','宋','宋诗','song-poetry','','[]','白鹿遺書山澤癯，歸來花木儘堪娛。',64,'全唐诗/poet.song.212000.json','["白鹿遺書山澤癯，歸來花木儘堪娛。", "功名之夢晦庵晦，禮樂其家迂叟迂。", "雪屋一燈春夜半，竹山千古暮雲孤。", "雨寒愁絕蘭亭禊，靈壽空餘九老圖。"]'),
('f2e41ecb-db49-4f0e-aeda-a209143fbdfe','謝管轄挽詩','方岳','宋','宋诗','song-poetry','','[]','劍吼空山鶴夢寒，聶仙夜訪碧雲冠。',64,'全唐诗/poet.song.212000.json','["劍吼空山鶴夢寒，聶仙夜訪碧雲冠。", "兩山拔起煙塵外，一壑歸來天地寬。", "月滿石壇朝斗罷，雲眠竹所乞詩刊。", "松花落盡不知曉，留得殘碑與世看。"]'),
('9e6bdb59-34ea-4060-aba1-a3220e2075fe','內翰程端明挽詩  其一','方岳','宋','宋诗','song-poetry','','[]','倒瀉銀河洗肺肝，初傳冰句落人間。',64,'全唐诗/poet.song.212000.json','["倒瀉銀河洗肺肝，初傳冰句落人間。", "吾州誰繼龍溪老，內相寧論豹尾斑。", "汲冢以來書盡讀，商盤而上筆追還。", "豈無名字藏金匱，只與君王丐一閒。"]'),
('752825b0-6d87-4dc2-bcae-1990ddf73405','內翰程端明挽詩  其二','方岳','宋','宋诗','song-poetry','','[]','旋踵之間政事堂，掛冠神武一何忙。',64,'全唐诗/poet.song.212000.json','["旋踵之間政事堂，掛冠神武一何忙。", "松風醉卧山前後，梅障留題春在亡。", "八十磻溪纔事業，百年落水自平章。", "老天肯使斯文墜，劍履已空笙鶴翔。"]'),
('79bb1dc7-cd4a-4a49-a915-7c900f516128','次韻程汪二兄投贈  其一','方岳','宋','宋诗','song-poetry','','[]','未論知己定誰歟，却恐春臯失故吾。',64,'全唐诗/poet.song.212000.json','["未論知己定誰歟，却恐春臯失故吾。", "窮老不隨時世薄，行藏猶識聖人汙。", "陶元亮已覺今是，祁孔賓毋費夜呼。", "便擬耕桑教豚犬，不令渠輩指之無。"]'),
('ecfc284e-31a7-4023-8d3d-67a53c341c35','次韻程汪二兄投贈  其二','方岳','宋','宋诗','song-poetry','','[]','誰放詞林出一頭，窮愁自欲著春秋。',64,'全唐诗/poet.song.212000.json','["誰放詞林出一頭，窮愁自欲著春秋。", "傳杯有手堪持蟹，解佩無刀可買牛。", "何苦文章驚海內，已甘煙雨老巖幽。", "芷汀蘭渚離騷在，付與春江自在流。"]'),
('c9d73a7b-3ea4-4a6a-aca5-4ab6c26fbba0','寄題鹽城方令君摇碧閣','方岳','宋','宋诗','song-poetry','','[]','有山無水山枯槁，有閣無書閣未清。',64,'全唐诗/poet.song.212000.json','["有山無水山枯槁，有閣無書閣未清。", "作計者誰三太息，美君於此四難并。", "宰官身落秋城柝，處士星寒雪墅耕。", "蚤晚檣竿插蒼石，重拈禿筆與逢迎。"]'),
('b99bfd58-ce84-47c9-a6de-9ea2fc1d258c','次韻程兄見寄','方岳','宋','宋诗','song-poetry','','[]','萬事於吾一羽輕，未忘情處聖人清。',64,'全唐诗/poet.song.212000.json','["萬事於吾一羽輕，未忘情處聖人清。", "抵須賦奏長楊館，只以詩爲細柳營。", "歲月凋零霜後葉，交游聚散水中萍。", "短書忽到維摩室，未信已寒文字盟。"]'),
('635dfac5-58f6-401f-8edc-e55f5da52d45','簡季桐廬','方岳','宋','宋诗','song-poetry','','[]','愧面何堪見客星，移舟且莫近前汀。',64,'全唐诗/poet.song.212000.json','["愧面何堪見客星，移舟且莫近前汀。", "鷗沙草長連江暗，蟹舍潮回带雨腥。", "歸去尚餘初繭栗，生來能費幾笭箵。", "詩腸一夜生芒角，試問故人雙玉缾。"]'),
('87ca5436-8b16-4a20-b6e5-bea722872a17','始見臺章彈予面目可憎唇吻可畏','方岳','宋','宋诗','song-poetry','','[]','生無燕頷可封侯，貧有牛衣可省愁。',64,'全唐诗/poet.song.212000.json','["生無燕頷可封侯，貧有牛衣可省愁。", "老矣江湖雙短鬢，悠哉天地一歸舟。", "野夫疇昔友麋鹿，人世是非風馬牛。", "口角雌黄吾豈敢，併忘皮裏有春秋。"]'),
('0c645252-25f1-49d9-ac4a-629d44bfcb2d','次韻辟雍同舍用予魁字韻','方岳','宋','宋诗','song-poetry','','[]','行輩參差落後來，未經老筆掃氛埃。',64,'全唐诗/poet.song.212000.json','["行輩參差落後來，未經老筆掃氛埃。", "閒知天地摩銅狄，莫誤春秋著玉杯。", "斷藁略堪供醤瓿，騷人徑欲築詩臺。", "更煩同舍郎題品，只欠同年舊榜魁。"]'),
('c5da4815-9bfd-495e-90fb-c3cd75770622','送寺丞韓君守新安  其一','方岳','宋','宋诗','song-poetry','','[]','君家集有陸參序，老筆誇張歙大州。',64,'全唐诗/poet.song.212000.json','["君家集有陸參序，老筆誇張歙大州。", "三百年來非昔比，二千石喜得今侯。", "早田已槁曾關念，舊石雖奇不到收。", "沃沃桑麻山雨外，歸歟甿亦買羸牛。"]'),
('5a88f19e-ac60-4fb9-a02c-968ffa7957ec','送寺丞韓君守新安  其二','方岳','宋','宋诗','song-poetry','','[]','吾州可但佳山水，薰沐詩書自不同。',64,'全唐诗/poet.song.212000.json','["吾州可但佳山水，薰沐詩書自不同。", "牧守曾留今相國，郡人況有我文公。", "諸賢雅欲相俎豆，一念底須多缿筒。", "三十六峰吟更筆，只將無事過年豐。"]'),
('d2c615f9-f1fb-4034-8ec7-54e095bf5106','夢平山','方岳','宋','宋诗','song-poetry','','[]','擊楫濤江二十春，平生蹤跡已成陳。',64,'全唐诗/poet.song.212000.json','["擊楫濤江二十春，平生蹤跡已成陳。", "秋城一別芙蓉老，夜柝幾番楊柳新。", "社燕欲歸仍擇木，佛貍不死每驚塵。", "如聞露布今三捷，莫遣天驕返隻輪。"]'),
('e43d1598-b672-4a05-9f57-48d565d63eda','寄呂宗卿','方岳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔我林臯麋鹿姿，云胡今我復來思。',64,'全唐诗/poet.song.212000.json','["昔我林臯麋鹿姿，云胡今我復來思。", "舟行嚴瀨多逢雨，山識吾宗少有詩。", "風月厭談當世事，乾坤獨與古人期。", "西湖煙水春無恙，坐想梅花聖得知。"]'),
('52d5ebe2-9ff3-4076-be48-c65ec0fe524c','次韻李君携示唐告','方岳','宋','宋诗','song-poetry','','[]','唐家甲乙尊門族，誰有流傳直到今。',64,'全唐诗/poet.song.212000.json','["唐家甲乙尊門族，誰有流傳直到今。", "一代衣冠王子表，三朝雨露聖人心。", "曾經竹巷醉雙玉，盡出花綾諾百金。", "湖海半生今見子，摩挲未負老侵尋。"]'),
('ccd5c29c-8cab-4842-9523-a9bdec144eac','次韻黎倅','方岳','宋','宋诗','song-poetry','','[]','幸自青山肯見分，一蓑何不竟眠雲。',64,'全唐诗/poet.song.212000.json','["幸自青山肯見分，一蓑何不竟眠雲。", "魚肥西塞儘堪釣，鶴怨北山誰勒文。", "自脫唐衫尋輦路，只將周易對爐薰。", "追奔蠻觸非吾事，終欲茅廬老聘君。"]'),
('d3c0205c-a0b2-4c7f-b3a6-561bb0a7d168','次韻盧監','方岳','宋','宋诗','song-poetry','','[]','蘭亭人寂幾何年，著我糟丘亦冗員。',64,'全唐诗/poet.song.212000.json','["蘭亭人寂幾何年，著我糟丘亦冗員。", "尋訪雪溪無酒債，主張禊帖有詩權。", "千巖秀處書如堵，五月凉時藕似船。", "只麽拍浮真足矣，底須妄想到花邊。"]'),
('8a5d532f-e34f-43b3-a4d3-25389aa814ef','次韻徐宰題岳王祠','方岳','宋','宋诗','song-poetry','','[]','殺氣猶纏岳字旗，秋風鐵馬已南歸。',64,'全唐诗/poet.song.212000.json','["殺氣猶纏岳字旗，秋風鐵馬已南歸。", "和之一字誤人國，今且百年遭禍機。", "白骨自荒公論在，青山良是物情非。", "羊腥犬穢長陵土，淚落囊封御筆依。"]'),
('b6991463-f03b-423f-a330-1d1432ff6a6f','悼祭酒徐仁伯  其一','方岳','宋','宋诗','song-poetry','','[]','皇天老眼定何居，禍酷如公古亦稀。',64,'全唐诗/poet.song.212000.json','["皇天老眼定何居，禍酷如公古亦稀。", "酖毒不令猜叔子，藥家誰實死顔畿。", "人心縱嶮難清白，世變不磨真是非。", "畢竟若爲書史冊，暮江倚徙淚沾衣。"]'),
('24b31f4a-a206-4408-bbd5-580d455a4224','悼祭酒徐仁伯  其二','方岳','宋','宋诗','song-poetry','','[]','同謁翹材話直前，別纔信宿訃驚傳。',64,'全唐诗/poet.song.212000.json','["同謁翹材話直前，別纔信宿訃驚傳。", "等之百世無今日，殺我三良不半年。", "公與朝端清到底，人言次相直如弦。", "奏篇共上寥陽殿，未必精忠隔九泉。"]'),
('88d9098c-bc88-470c-99ec-85569bdd91e6','次韻徐宰齋宿學宮','方岳','宋','宋诗','song-poetry','','[]','孔堂雨宿盍儒簪，自與諸儒守誨箴。',64,'全唐诗/poet.song.212000.json','["孔堂雨宿盍儒簪，自與諸儒守誨箴。", "白髮一經流俗眼，青山千古聖賢心。", "夜窗燈冷書如堵，春草壇荒杏滿林。", "想得夢回科斗壁，隠然絲竹尚遺音。"]'),
('6f6f24e0-ad52-45ec-a746-cae203be5c80','別羣玉同舍','方岳','宋','宋诗','song-poetry','','[]','纔入蓬山路已迷，青虬夜吼又東西。',64,'全唐诗/poet.song.212000.json','["纔入蓬山路已迷，青虬夜吼又東西。", "荼䕷略有一日雅，蘚石未乾千佛題。", "冊府敲茶玄鶴舞，軍門草檄玉驄嘶。", "羣仙定說粗官在，臺史今占太白低。"]'),
('c9364cf0-63bf-4779-86e7-ca9fdb0cbeb0','次韻劉架閣和予壬寅入局詩','方岳','宋','宋诗','song-poetry','','[]','入開圖籍底須箝，誰校蓬山三萬籤。',64,'全唐诗/poet.song.212000.json','["入開圖籍底須箝，誰校蓬山三萬籤。", "有竹兩窗聊下榻，爲梅一笑幾巡簷。", "虎頭食肉亦安用，熊掌與魚那得兼。", "好事人來勤載酒，縱無奇字不渠厭。"]'),
('513479a9-abdc-4b92-bd46-da3ac254cfb9','銓瑣','方岳','宋','宋诗','song-poetry','','[]','綠漬苔痕蝕斷碑，摩挲名字笑衰遲。',64,'全唐诗/poet.song.212000.json','["綠漬苔痕蝕斷碑，摩挲名字笑衰遲。", "雲寒昨夜人何似，雨鎖重門春不知。", "莫倚離騷堪僕命，從來造物亦兒癡。", "轉頭十五年前話，獨立東風舉似誰。"]'),
('f39e0f86-6a56-425e-b242-07bc2141967e','送滕廣叔銓試','方岳','宋','宋诗','song-poetry','','[]','矮屋曾分雪夜燈，相期各已上青冥。',64,'全唐诗/poet.song.212000.json','["矮屋曾分雪夜燈，相期各已上青冥。", "得官誰謂非黄甲，如我今猶祇白丁。", "別久不論清濁酒，情親或夢短長亭。", "一生科目十名上，自有君家舊典刑。"]'),
('50deefa7-ab32-4952-84f7-41766d9a2ab2','和知郡史監丞鹿鳴宴詩','方岳','宋','宋诗','song-poetry','','[]','文物聲明極盛秋，傅巖人不待形求。',64,'全唐诗/poet.song.212000.json','["文物聲明極盛秋，傅巖人不待形求。", "筆扛龍鼎雄豪在，手拔鯨牙汗漫遊。", "溫飽定知非雅意，治安誰與借前籌。", "老予曾到慈恩頂，更放諸賢出一頭。"]'),
('4c80a712-6c0e-4a38-873f-45a85ab9f325','縣送邸報','方岳','宋','宋诗','song-poetry','','[]','綠陰門巷冷沈沈，何許文書忽見尋。',64,'全唐诗/poet.song.212000.json','["綠陰門巷冷沈沈，何許文書忽見尋。", "誰愛屋烏方引玉，同騎竹馬或登金。", "今吾久已忘人世，故紙焉能損道心。", "只有斷雲知此意，爲驅一雨洗山林。"]'),
('26d029e5-8164-439f-b296-a75457b1cdf4','次韻浄照','方岳','宋','宋诗','song-poetry','','[]','一筇一衲出山相，不道斯人故可人。',64,'全唐诗/poet.song.212000.json','["一筇一衲出山相，不道斯人故可人。", "我已久聞揮翰手，師寧相對坐禪身。", "山林有味青燈古，天地無情白髮新。", "認取本來真面目，瀑泉詩好未知津。"]'),
('b560c7d6-5e7a-4ecc-bde6-4045a542f33b','贈談命者','方岳','宋','宋诗','song-poetry','','[]','客有携詩夜扣扃，典衣何惜倒吾缾。',64,'全唐诗/poet.song.212000.json','["客有携詩夜扣扃，典衣何惜倒吾缾。", "山城難覓葡萄綠，竹火終强鵓鴿青。", "迕俗坐談捫蝨略，治生欲讀相牛經。", "向來人亦多稱好，正坐無錢語不靈。"]'),
('db7ed88d-818d-47fe-9e14-9e016754eb8e','贈術者王髯','方岳','宋','宋诗','song-poetry','','[]','王髯過我秋崖底，未識青囊且對棋。',64,'全唐诗/poet.song.212000.json','["王髯過我秋崖底，未識青囊且對棋。", "萬事只銷三字好，一生寬破百年癡。", "有田種秫便可耳，無分讀書姑寘之。", "苦勸勿寒場屋夢，此言却恐白鷗知。"]'),
('72db0424-5b23-4ed9-9c63-317a8e537a84','次韻葉宗丞約遊括蒼','方岳','宋','宋诗','song-poetry','','[]','一詩不了蒼州債，曾泊春沙問水程。',64,'全唐诗/poet.song.212000.json','["一詩不了蒼州債，曾泊春沙問水程。", "山自强如吾郡好，酒今聞有括灘清。", "文章未得半分力，故舊難忘少日情。", "已斸莓苔新種竹，恐無辭與此君盟。"]'),
('fc157397-e8a5-4ddc-9e2f-a670567523a8','題歸來館','方岳','宋','宋诗','song-poetry','','[]','莫問淵明隔幾塵，歸來甕面綠粼粼。',64,'全唐诗/poet.song.212000.json','["莫問淵明隔幾塵，歸來甕面綠粼粼。", "醉眠明月元無價，對畫凌煙自有人。", "絕口不談當世事，掉頭寧作太平民。", "春來春去棋聲外，不管人間局面新。"]'),
('9ea651a6-e450-4f24-a6e2-b258b7208bda','與蔡吏部林直院別江樓','方岳','宋','宋诗','song-poetry','','[]','又拋蓑笠出山來，那得江鷗不見猜。',64,'全唐诗/poet.song.212000.json','["又拋蓑笠出山來，那得江鷗不見猜。", "一醉真成吞溟涬，三人曾共住蓬萊。", "翰林詞伯玉爲骨，直指繡衣霜作臺。", "莫笑樵溪窮太守，短篷煙雨亦佳哉。"]'),
('337d05f8-0024-474b-8ada-764e9e2777fc','小集垂絲海棠下  其一','方岳','宋','宋诗','song-poetry','','[]','春風定何物，所至成芳妍。',72,'全唐诗/poet.song.212000.json','["春風定何物，所至成芳妍。", "牆陰樹憔悴，寧識歲月遷。", "今晨步吾屧，珠纓粲紅鮮。", "餘酲不勝扶，背面低晴煙。", "風日不貸人，坐恐隨翾翩。", "强起從吾遊，一笑俱嫣然。"]'),
('45139093-6630-46f3-bb69-0f21456589a6','小集垂絲海棠下  其二','方岳','宋','宋诗','song-poetry','','[]','酌我紫金盞，醉此紅玉蕤。',72,'全唐诗/poet.song.212000.json','["酌我紫金盞，醉此紅玉蕤。", "爲經老天手，元氣之所滋。", "萬生有不齊，時至俱紛披。", "一一得自性，亦豈造化私。", "君看枝上花，榮落方自茲。", "所可必者性，不可違者時。"]'),
('6b57477d-4f88-499b-b034-8d0167373281','南窗偶書  其一','方岳','宋','宋诗','song-poetry','','[]','吾徒例迂疎，與世自少可。',84,'全唐诗/poet.song.212000.json','["吾徒例迂疎，與世自少可。", "不工口囁嚅，正坐胸磊砢。", "折腰迂人情，高論常轗軻。", "歸哉夜窗雨，喜不失故我。", "琴尊日多暇，未覺此計左。", "秋風挾佳月，流光侑孤坐。", "持觴酹伯倫，彼豪真蜾蠃。"]'),
('d8fe59d5-6e16-44ea-8b9b-769b5861b208','南窗偶書  其二','方岳','宋','宋诗','song-poetry','','[]','西風忽凄厲，皎月流素光。',60,'全唐诗/poet.song.212000.json','["西風忽凄厲，皎月流素光。", "客從何方來，蘭佩芙蓉裳。", "揮琴發哀彈，夜寂山蒼蒼。", "可人者麴生，挽我無何鄉。", "醉中眇萬物，拄頰歌滄浪。"]'),
('0df3881f-e696-41e1-8d5d-a2fe495a9d30','南窗偶書  其三','方岳','宋','宋诗','song-poetry','','[]','毛穎輕俗子，孔方疎吾曹。',72,'全唐诗/poet.song.212000.json','["毛穎輕俗子，孔方疎吾曹。", "未須奴事錢，正可僕命騷。", "持此將安之，聊足以自豪。", "向來與諸儒，尚論夔與臯。", "此言終當酬，時命不我遭。", "欲語恐驚紛，卑之無甚高。"]'),
('66d1bbe9-02db-46f0-9674-ef7c66dfcdec','夢方飲藥或告之曰攻伐太過斯傷天和覺而識之','方岳','宋','宋诗','song-poetry','','[]','過恭爲足恭，過敬爲繆敬。',72,'全唐诗/poet.song.212000.json','["過恭爲足恭，過敬爲繆敬。", "禮猶不可過，況以毒攻病。", "甚毒傷沖和，一快喪軀命。", "萬事有厥中，毋使血氣橫。", "子姑小徐徐，亦或見自性。", "忽輕夢中語，克念可以聖。"]'),
('8b2c5767-a97d-4ee8-865b-885b91c09565','和三四弟韻','方岳','宋','宋诗','song-poetry','','[]','清明乍佳遊，適與元巳并。',84,'全唐诗/poet.song.212000.json','["清明乍佳遊，適與元巳并。", "但有松葉醪，寧須杏花餳。", "漁篷半篙綠，煙雨涵幽清。", "緬懷蘭亭人，高冢亦已平。", "空餘數行墨，日月老送迎。", "不知狂李白，醉面騎長鯨。", "宇宙曾幾何，一笑吾詩成。"]'),
('87973555-ffc5-49b7-92fd-24e9376c5bec','用韻還學者詩卷','方岳','宋','宋诗','song-poetry','','[]','製芰以爲衣，緝荷以爲屋。',84,'全唐诗/poet.song.212000.json','["製芰以爲衣，緝荷以爲屋。", "樵水秋夜寒，悲風入琴曲。", "不怨山澤癯，有道式金玉。", "百年肘屈伸，萬事手翻覆。", "拙哉富貴人，胡椒不論斛。", "何如遺編詩，自足寄幽獨。", "貧者士之常，前言炳如燭。"]'),
('cad58278-587c-413b-846f-884e7d670e8a','畦菜','方岳','宋','宋诗','song-poetry','','[]','踏雲課園丁，趁雨鉏菜甲。',72,'全唐诗/poet.song.212000.json','["踏雲課園丁，趁雨鉏菜甲。", "土甘春繞畦，煙重曉携鍤。", "毋令蔓草滋，旋拾枯篠插。", "詩腸風露香，碧脆已可搯。", "誰言庾郎貧，未覺三韭乏。", "那知世有人，猶嫌萬錢狹。"]'),
('824fb9d4-83fb-43ea-a215-60f601b3b4bf','丐祠不獲','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','老馬倦長路，歸鴻愜深林。',111,'全唐诗/poet.song.212000.json','["老馬倦長路，歸鴻愜深林。", "廬山共江左，久已費越吟。", "樵川邈何方，豈解操南音。", "三書光範門，香火盟初心。", "頗聞丞相嗔，竟欲煩窺臨。", "寧知新種梅，條{艹拱}雪霜侵。", "誰與旋移竹，藝此十畝陰。", "所嗟飯不足，未能决投簪。", "出處方兩難，搔首成孤斟。"]'),
('f107aa4c-4c94-4b1f-84ed-e1545ab28858','亨道至能對棋月下文振聞後堂歌聲逃席而起','方岳','宋','宋诗','song-poetry','','[]','高梧動凉吹，月色如新磨。',96,'全唐诗/poet.song.212000.json','["高梧動凉吹，月色如新磨。", "吾儕冰雪胸，如此良夜何。", "二客信不凡，一局欲爛柯。", "中庭人語寂，玉佩鳴相摩。", "勝士何灑落，俗子誰譏訶。", "安得玉跳脫，酌我金叵羅。", "昭華不露面，獨繭抽長歌。", "徑令鄭子真，飛夢巫山阿。"]'),
('c29c4c3d-8f19-4034-9ab3-930195a95709','泊釣臺','方岳','宋','宋诗','song-poetry','','[]','落帆鸕鷀步，倚策羊裘軒。',96,'全唐诗/poet.song.212000.json','["落帆鸕鷀步，倚策羊裘軒。", "紛披穉篠閒，森鬰古木尊。", "幽蹊石齒齒，醉袖風翻翻。", "緬懷臺上人，老蘚雙骭存。", "寧知天九重，不博月一痕。", "咄哉侯君旁，坐受富貴吞。", "先生無乃誤，肯與癡人言。", "吾詩亦贅矣，舐舌不可捫。"]'),
('52442725-aed9-4142-a09a-d79688154a54','牛屋','方岳','宋','宋诗','song-poetry','','[]','苫以連茹茅，編以带葉篠。',96,'全唐诗/poet.song.212000.json','["苫以連茹茅，編以带葉篠。", "俾予繭栗犢，安卧煙雨曉。", "架犂初學耕，敲扑固不少。", "我廩何時高，爾室勿嫌小。", "半山月荒凉，四壁雲繚繞。", "相期一飽外，短笛秋渺渺。", "黄鍾忽滿脰，聲欲撼林杪。", "豈歎不耕人，華榱上雲表。"]'),
('c4f769c6-5b9f-4ea5-bc19-9318d1307dc6','山行  其一','方岳','宋','宋诗','song-poetry','','[]','山欲窈而深，路欲繚而曲。',120,'全唐诗/poet.song.212000.json','["山欲窈而深，路欲繚而曲。", "向來始開荒，惟恐日不足。", "松行四五里，雲繞上下谷。", "振衣千仞岡，邀月噴橫玉。", "於今曾幾何，此與不可續。", "一筇筋力疲，籃笋或更僕。", "平生愛山心，安得兩黄鵠。", "昔如鴻翩翻，今如駒局促。", "盛衰固其常，細甚太倉粟。", "付之琉璃黄，澆以葡萄綠。"]'),
('8d204474-4625-43f8-a38f-b8a1ea7e71ea','山行  其二','方岳','宋','宋诗','song-poetry','','[]','吾州固多士，霞珮相上下。',120,'全唐诗/poet.song.212000.json','["吾州固多士，霞珮相上下。", "懿哉考亭老，伊洛與並駕。", "清廟薦鼎彝，黄琮加繅藉。", "遂令晉之鄙，嗜學如嗜炙。", "豈徒挾老筆，秋風趁雄跨。", "奇文吐寒芒，明月夜相射。", "要當抱遺經，與帝陳廣厦。", "平津二三策，夫我則不暇。", "士以器識先，蘭鮑在所化。", "行矣其勉旃，勿爲子虛詫。"]'),
('5c0c3fd0-4434-418e-92a5-a8ffe9b65194','寄陳國錄','方岳','宋','宋诗','song-poetry','','[]','秋宵一何長，客夢一何短。',120,'全唐诗/poet.song.212000.json','["秋宵一何長，客夢一何短。", "坐爲識丁累，彈鋏落孤館。", "所思渺寒江，苦惜會面罕。", "豈無相携人，情話誰與款。", "昔爲爨下桐，今爲溝中斷。", "江風摇青燈，几硯塵欲滿。", "不慣事典籤，與子書亦嬾。", "傳聞教辟雍，如樂得嶰管。", "諸生聲利塵，頗欲一湔澣。", "何時夜雨床，共話晴雲盌。"]'),
('9201453e-9190-429b-9a7e-9f2c3a51810b','感風謝客','方岳','宋','宋诗','song-poetry','','[]','閤閤官蛙鳴，齁齁老牛喘。',120,'全唐诗/poet.song.212000.json','["閤閤官蛙鳴，齁齁老牛喘。", "政坐一朝喧，作此十日沴。", "天公信難料，氣候隨手轉。", "吾貧了目前，遽脫春衣典。", "寧知昨夜雪，縮若蠶作繭。", "坐令鼻流沫，客邪閉關犍。", "畏風甚防秋，畏酒甚把淺。", "呼童語之故，有客姑謝遣。", "使吾早自覺，安得訛謬舛。", "乃知天下事，以謹失者鮮。"]'),
('11a8e4c0-67c0-4e69-b733-aabc48e6474c','採菌','方岳','宋','宋诗','song-poetry','','[]','溪行近里所，雪菌朵寒蘀。',132,'全唐诗/poet.song.212000.json','["溪行近里所，雪菌朵寒蘀。", "久晴危欲枯，抱甕日商略。", "可憐書生愚，爲口不計脚。", "龜腸慣饑虛，雞肋忍饞嚼。", "獨奇白雲芝，風露專一壑。", "自尋墮樵歸，遠掬飛泉瀹。", "此豈不足歟，更嫌村釀薄。", "世塗語百車，官倉陳一龠。", "胡爲犯譏彈，而負兩芒屩。", "甘餐自當肉，石鼎香漠漠。", "寧憶武昌魚，況復揚州鶴。"]'),
('fa128a44-04f8-41fa-b698-e3ff18435a72','有以晦庵真跡見寄者乃寒栖精舍詩也因次其韻','方岳','宋','宋诗','song-poetry','','[]','富貴不可期，貧賤未易驕。',120,'全唐诗/poet.song.212000.json','["富貴不可期，貧賤未易驕。", "山人乃爾昧，過眼風煙飄。", "鷦鷯一枝足，不知有層霄。", "我知古之人，千載俱寥寥。", "寒栖訪精舍，野綠摇輕𦨣。", "一屏直聳聳，萬里直蕘蕘。", "至今空堂雲，巾屨遺高標。", "笛聲橫者誰，有些不可招。", "却後五百年，容我摩青瑶。", "尚憐沈東陽，燕雀空喧囂。"]'),
('44f2e63e-ab27-4090-b1c9-d31ec69ebab3','夢有饟予寶器一奩者曰僧某甲入寂奉以別也一念不敢受當與善知識作供耳顧眡僧在傍恢然偉岸與之揖甚野劃然笑曰我不管也因墨格上筆書云老藤一枝孤雲萬里如是我聞我聞如是放筆趺坐而逝既覺因作偈言焉知僧非異人與予宿有緣契庶幾聞之','方岳','宋','宋诗','song-poetry','','[]','何師何許人，何用與世絕。',120,'全唐诗/poet.song.212000.json','["何師何許人，何用與世絕。", "向來修何行，於今得寂滅。", "復以何因緣，夢與老夫訣。", "是身如虛空，而有何差別。", "云何作我相，饟別何屑屑。", "彼分香賣履，何者謂豪傑。", "老師出世間，亦復何戀結。", "我法一切無，何以此寶訣。", "問寶何從來，豈爲我輩設。", "師今何方去，更吐廣長舌。"]'),
('c17356f0-e576-4647-8c3f-6b917883a45f','燕來巢','方岳','宋','宋诗','song-poetry','','[]','吾貧自無家，客戶寄村疃。',120,'全唐诗/poet.song.212000.json','["吾貧自無家，客戶寄村疃。", "槿籬月三間，荒寒天不管。", "燕亦何所聞，乃於我乎館。", "豈以菊未莎，而有竹可款。", "不叩富兒門，寧爲老夫伴。", "此意殊可人，然亦似吾懶。", "所須半丸泥，不費一秉稈。", "云胡及風薰，相宅無乃緩。", "勉哉爾翁姥，坐席寧暇暖。", "主人當賀成，落以晴雲盌。"]'),
('76b2661a-863a-4b8b-8bd8-c325c0f2d482','次韻久雨','方岳','宋','宋诗','song-poetry','','[]','老我不解事，束書別溪堂。',120,'全唐诗/poet.song.212000.json','["老我不解事，束書別溪堂。", "寧知十日雨，換此兩鬢霜。", "苔滑螾爭席，雲蒸蝸篆梁。", "移床夜避濕，仰見天隙光。", "長安亦何好，肯墮聲利場。", "人情愛吾廬，對此良自傷。", "蚤知一官誤，悔不三逕藏。", "沙觜竹萬箇，屋頭木千章。", "晴當相與屐，雨亦可以觴。", "毋令鼃黽曹，張王喧我傍。"]'),
('ae4bb334-5372-4b32-812e-c70dab4dadc2','客有致鸂鶒者','方岳','宋','宋诗','song-poetry','','[]','沙禽有鸂鶒，偕老矢靡他。',120,'全唐诗/poet.song.212000.json','["沙禽有鸂鶒，偕老矢靡他。", "語語浴晴渚，處處眠春莎。", "三生愛欲牽，不避弋者羅。", "雙籠致厓下，窮蹙愁相睋。", "吾將逸之歸，如此紅裳何。", "方池尺有咫，亦足供逶迤。", "眷言樹之柵，結屋如漁蓑。", "相攸奠爾居，謹勿思江河。", "豈但林外鳩，晴雨不我訛。", "人斯其視斯，妻柔而夫和。"]'),
('afe058bb-f19b-4c5e-8582-41179db9428b','答吳尚書','方岳','宋','宋诗','song-poetry','','[]','今夕復何夕，翠籠蒲艾香。',132,'全唐诗/poet.song.212000.json','["今夕復何夕，翠籠蒲艾香。", "明朝做端午，節物追楚鄉。", "客從何方來，寄我錦雲章。", "江山渺何許，宛然挹清揚。", "忽憶老先生，方上千歲觴。", "北園竹萬箇，想見清簟凉。", "安得子列子，御我蘚古傍。", "劇談坐抵掌，一吐冰雪腸。", "當時寫巴曲，本擬書數行。", "筆閣不得下，聊與歌慨慷。", "迺今亦復爾，歌短意則長。"]'),
('7b6aa3e7-41ef-4265-8140-f30cadb113ba','社日以旱蔬食','方岳','宋','宋诗','song-poetry','','[]','驕陽挾融風，合力爲此旱。',144,'全唐诗/poet.song.212000.json','["驕陽挾融風，合力爲此旱。", "南山膚寸雲，六合望彌滿。", "怒吹不待族，赤日行火繖。", "幽窗幾長身，玉立拯蕭散。", "中乾不自持，槁項何足算。", "以茲占西疇，可想一本稈。", "社公亦耐事，水舊不渠管。", "方勤玉食憂，下令屠牛坦。", "坐令宰平手，無肉醉町畽。", "但聞寬大書，已責寧使緩。", "龍湫有潜鱗，鬰屈睡欲懶。", "移文頌風伯，九關誰可款。"]'),
('e32ffbb9-4685-4d35-b896-ee7fed1f2759','秋熱  其一','方岳','宋','宋诗','song-poetry','','[]','衰老不耐暑，喜甚秋咫尺。',108,'全唐诗/poet.song.212000.json','["衰老不耐暑，喜甚秋咫尺。", "秋來幾何時，炮煮乃爾劇。", "老夫大失望，亦自媿兩屐。", "青山吾故人，可想不可覿。", "農家請言田，使我舌屢唶。", "六月潴爲泥，七月稿爲腊。", "十無一二存，政苦蝗狼藉。", "吾饑不能臘，子熱不能夕。", "子熱猶可凉，吾饑那可常。"]'),
('384a2fe0-59a9-4b98-94cb-7c5bb0f26d87','秋熱  其二','方岳','宋','宋诗','song-poetry','','[]','殘暑何姦雄，酷烈不肯退。',120,'全唐诗/poet.song.212000.json','["殘暑何姦雄，酷烈不肯退。", "穉秋太君子，斂避不敢對。", "薰風來無期，民慍良憒憒。", "吳牛方喘月，渴想蓐收代。", "金行既用事，炎赫乃故在。", "於今幾何時，秋夏終晦昧。", "畏熱如畏虎，悸汗流浹背。", "南山殷其雷，崛起雲霮䨴。", "誰當牋老天，與世思盥頮。", "風雨一洗之，此熱不可再。"]'),
('c648f21a-e2e6-40ff-970a-8593ffb36c54','與至能夜話','方岳','宋','宋诗','song-poetry','','[]','吾生如征鴻，歲月如脫兔。',132,'全唐诗/poet.song.212000.json','["吾生如征鴻，歲月如脫兔。", "江上煙雨寒，花老春已暮。", "肯辭白髮親，我蓋坐貧故。", "文章未得力，儒冠豈余誤。", "至能我輩人，未隨時俗惡。", "青燈竹窗底，健論時一吐。", "風雷萬馬奔，滄溟百川赴。", "策名藉奉常，顔色若有迕。", "堂堂湖海豪，豈供折腰具。", "欲於我乎館，西山美無度。", "謹勿袖笏來，恐犯西山怒。"]'),
('ceb02264-14a8-4d18-9775-6df7fb7f5d1b','山莊書事','方岳','宋','宋诗','song-poetry','','[]','晨興抹兩屨，爲口見驅迫。',156,'全唐诗/poet.song.212000.json','["晨興抹兩屨，爲口見驅迫。", "課童督秋刈，野穫夜彭魄。", "田翁適過予，繿縷黑而瘠。", "具言土力貧，年登苦囏阨。", "一飯不自期，未議了稱責。", "昨者耆長來，名復掛欠籍。", "截絹入官輸，官怒邊幅窄。", "拋擲下堂階，退字印文赤。", "賣牛重買絲，篝燈不停息。", "明當扣東鄰，假牛下牟麥。", "久貧少人情，恐復不見借。", "既去重感傷，行行猶欠息。", "我歸不能眠，草根鳴蟋蟀。"]'),
('395f7559-540d-4825-8497-8df7148f73dc','八月十四夜對月','方岳','宋','宋诗','song-poetry','','[]','澄空四無雲，明月如凝霜。',120,'全唐诗/poet.song.212000.json','["澄空四無雲，明月如凝霜。", "岸巾南窗下，領略今夕凉。", "鴟夷渴生塵，風味不可忘。", "欲上排九關，箋此世故忙。", "百年幾今夕，今我持空觴。", "竹君自可人，清影飛度牆。", "挹彼風露姿，浣此冰雪腸。", "明當醅甕熟，春溜翻糟床。", "良夜難虛拘，當復會此堂。", "所不償予言，有如明月光。"]'),
('04a5e82a-af84-4c4e-8e77-7d947b60e9da','明日雨再用韻','方岳','宋','宋诗','song-poetry','','[]','竹君頗介特，高節凌秋霜。',120,'全唐诗/poet.song.212000.json','["竹君頗介特，高節凌秋霜。", "朝來雨聲寒，意色俱凄凉。", "此豈子敗盟，而不能相忘。", "秋色雨亦佳，遣我冥搜忙。", "離騷日在眼，捃摭方濫觴。", "安得靈運屐，共窺公幹牆。", "涉世三折肱，悲秋九迴腸。", "脫巾漉浮蛆，醉卧六尺床。", "竹意亦自持，儼立何堂堂。", "會當有良夜，披戶延寒光。"]'),
('fa72def3-7b20-46c4-8317-38078b10802d','讀白詩效其體  其一','方岳','宋','宋诗','song-poetry','','[]','我貧良亦囏，未老生白鬚。',132,'全唐诗/poet.song.212000.json','["我貧良亦囏，未老生白鬚。", "策名奉常第，年已三十餘。", "半生苦無幾，寧不欲疾驅。", "山麋野而僻，所至皆崎嶇。", "一登督視府，兩駕太守車。", "意見有不合，索去不待炊。", "所以二十載，同一優侏儒。", "豈如雲水身，自適瓜芋區。", "夕吾酒一瓢，朝吾飯一盂。", "貧賤與富貴，本自無羞殊。", "寄語劉伯龍，毋煩鬼揶揄。"]'),
('83eaa289-f5ca-4cae-8387-e21c1276992b','讀白詩效其體  其二','方岳','宋','宋诗','song-poetry','','[]','人生有窮達，不係才不才。',120,'全唐诗/poet.song.212000.json','["人生有窮達，不係才不才。", "造物所付與，聖賢不能回。", "君看孔孟氏，遇世何如哉。", "豈其有不如，王驩與桓魋。", "以茲自忖度，所遭已踰涯。", "前瞻固不反，後顧又可咍。", "同時第進士，或未離蒿萊。", "歸來亦云幸，瀟散月下盃。", "山池芰荷過，野岸芙蓉開。", "幅巾一筇竹，適可眠秋厓。"]'),
('bed8e760-5bb1-46f8-a778-ebb36afabfa4','讀白詩效其體  其三','方岳','宋','宋诗','song-poetry','','[]','左耳聽比鄰，哀哀哭其夫。',108,'全唐诗/poet.song.212000.json','["左耳聽比鄰，哀哀哭其夫。", "家破肉未寒，欲與死者俱。", "右耳聽嫠婦，呱呱哀其雛。", "夫亡僅一女，不自禁毒痡。", "攬衣夜向晨，鐃鼓何喧呼。", "誰何過喪車，送骨荒山隅。", "中年自多感，人世何所娛。", "聞見又如此，坐歎歲月徂。", "明朝計安出，痛飲真良圖。"]'),
('27f48bb4-a244-4bd5-9326-eb0b9e1b99d1','徐仁伯侍郎挽詩','方岳','宋','宋诗','song-poetry','','[]','諸老遺書在，情親獨考亭。',216,'全唐诗/poet.song.212000.json','["諸老遺書在，情親獨考亭。", "學卑時俗陋，文起衆人醒。", "壯筆扛周鼎，危言聳漢庭。", "羣公俱避易，吾道未凋零。", "綸綍泥封璽，蓬萊月鎖廳。", "冰霜寒挺操，霄漢倦梳翎。", "有碣留南劍，無心徙北溟。", "一襟梅野雪，半世草堂星。", "晚對螭坳墨，親探虎穴猩。", "豹關傳曉蹕，蟄戶動春霆。", "彼相隳人紀，臣言準老經。", "綱常通宇宙，機阱駭朝廷。", "躔宿驚霄隕，乾坤爲晝冥。", "囊封爭論切，詔敕費丁寧。", "憤極空流涕，時平竟失刑。", "憶曾歌楚些，忍復弔湘靈。", "光蝕星奎壁，冤沈古鼎鉶。", "茫茫千載恨，不盡月巖青。"]'),
('3dd62e25-4734-4e6a-8f95-549e9d57f8dd','寄題朱塘晦翁亭','方岳','宋','宋诗','song-poetry','','[]','吾州斷雲邊，山水則大好。',168,'全唐诗/poet.song.212000.json','["吾州斷雲邊，山水則大好。", "不知幾何年，有一晦翁老。", "去爲考亭人，草樹日枯槁。", "兒時所釣遊，豈不槩懷抱。", "歸來乎令威，杖屨費幽討。", "寒綠翁家塘，昨夢幾傾倒。", "田田君子花，籍籍書带草。", "誰其月三間，聊以寄吾浩。", "翁今爲飛仙，落葉紛不掃。", "滕侯所書紳，歲月略可考。", "諸郎表章之，三峯倚晴昊。", "藐予抱遺書，生世恨不早。", "至今章句間，兀兀首空皓。", "緬懷草堂雲，春風動芹藻。"]'),
('0ed08247-5dbc-4679-a9a6-831b02aab867','簡劉尉','方岳','宋','宋诗','song-poetry','','[]','秋風昨夜起，碧宙已澄穆。',72,'全唐诗/poet.song.212000.json','["秋風昨夜起，碧宙已澄穆。", "肯乘鷄栖車，遠過蝸殻屋。", "縱無二頃秫，亦有兩窗竹。", "喜逢諫議面，未負將軍腹。", "燈寒一夜話，夢破十年讀。", "貧味故自佳，柔蔬雨中綠。"]'),
('196f6ed1-55d8-4370-a6ca-c07006e645d5','藝蘭','方岳','宋','宋诗','song-poetry','','[]','猗蘭杳幽茂，深林自吹香。',48,'全唐诗/poet.song.212000.json','["猗蘭杳幽茂，深林自吹香。", "何必九畹滋，一枝有餘芳。", "春鉏斸寒煙，渺渺懷江湘。", "靈均㤯未死，憔悴歌滄浪。"]'),
('63326cd8-c37e-42f3-b8c8-26a2d718de31','夏日珠溪賦八音體  其一','方岳','宋','宋诗','song-poetry','','[]','金篩薜蘿月，玉戛琅玕風。',96,'全唐诗/poet.song.212000.json','["金篩薜蘿月，玉戛琅玕風。", "石根一睡美，幽尚誰與同。", "絲棼俗士懷，顛倒崔烈銅。", "竹筇肯俱來，獨予兩詩窮。", "匏瓠亦纏藤，永日閉梵宮。", "土花侵道碧，晚翠初空濛。", "革華共徘徊，愛此山叢叢。", "木犀約重遊，小待香玲瓏。"]'),
('4fb4a109-c611-41cd-a1f0-4785220f39af','夏日珠溪賦八音體  其二','方岳','宋','宋诗','song-poetry','','[]','金谷已塵土，珠履如飈風。',96,'全唐诗/poet.song.212000.json','["金谷已塵土，珠履如飈風。", "石崇與平原，癡處正爾同。", "絲毫挂世網，空錮南山銅。", "竹窗理殘書，久已不諱窮。", "匏樽吾秋人，許訪青蓮宮。", "土甘蔬亦香，小摘空濛濛。", "革革有鳴禽，留我幽花叢。", "木屑落飛談，煙霏晚葱瓏。"]'),
('13274835-547b-4217-a4dc-50275e497ccc','與胡子安眺雲林','方岳','宋','宋诗','song-poetry','','[]','共搜括中奇，邂逅瘦筇兩。',48,'全唐诗/poet.song.212000.json','["共搜括中奇，邂逅瘦筇兩。", "溪甘茶自香，雪盡梅更爽。", "硯寒了佳娛，林迥答幽響。", "日暮僧不歸，山雲自來往。"]'),
('8c53f3bb-0fc8-486a-a264-64d0662a84d1','懶庵','方岳','宋','宋诗','song-poetry','','[]','坐兀忘晝長，睡熟苦夜短。',48,'全唐诗/poet.song.212000.json','["坐兀忘晝長，睡熟苦夜短。", "一衲六十年，肘見不渠管。", "華鯨撼林樾，飯香雲子盌。", "欠伸起卧堂，云何師不懶。"]'),
('c921ac0a-75e4-412e-8f4d-87b53f8e4839','夜夢至何許巖壑深窈石上苔痕隠起如小篆有僧謂予曰楊誠齋范石湖題也明日續洪舜俞登玲瓏詩有幾人記曾來老苔蝕琱鎪之句恍然如夢因次韻記之','方岳','宋','宋诗','song-poetry','','[]','大楊風日春，小范林壑秋。',168,'全唐诗/poet.song.212000.json','["大楊風日春，小范林壑秋。", "去予幾何年，各已如雲浮。", "誰歌黄金縷，共醉白玉舟。", "夢中到蓬萊，名字留巖幽。", "寧知地下郎，草記天上樓。", "老石翠嵐濕，古篆蒼蘚稠。", "摩挲踞虎兕，鬰屈蟠蛟虬。", "想當得意時，落筆不自休。", "江山有二老，文字照九州。", "神物儼護持，剝蝕吾奚憂。", "是間定何許，玲瓏窈相綢。", "雲根與僧憇，雪罅如神鎪。", "欲呼古時月，爲洗今人愁。", "夢耶其非歟，起坐搔白頭。"]'),
('0daf5503-d1f5-416d-8850-8116bffa261e','題陳叔茂二亭 觀瀾','方岳','宋','宋诗','song-poetry','','[]','噴騰浙江潮，奔放呂梁水。',48,'全唐诗/poet.song.212000.json','["噴騰浙江潮，奔放呂梁水。", "人情駭奇觀，所見濤浪耳。", "見浪不見瀾，滔滔者皆是。", "天晴風日佳，試叩二三子。"]'),
('75244709-3cce-4964-82cf-b0a6e7af9da2','題陳叔茂二亭 弄月','方岳','宋','宋诗','song-poetry','','[]','月從東峯來，豈但千里共。',48,'全唐诗/poet.song.212000.json','["月從東峯來，豈但千里共。", "四天本無壁，誰不得受用。", "而彼山中人，塞向以自擁。", "徑煩子陳子，普請作清供。"]'),
('6b6fc230-86dd-42a8-9917-2f7da7fcd108','雙頭蘭','方岳','宋','宋诗','song-poetry','','[]','夷齊首陽餓，宇宙難弟兄。',48,'全唐诗/poet.song.212000.json','["夷齊首陽餓，宇宙難弟兄。", "同心倚雪厓，世外一羽輕。", "紫莖孕雙茁，豈有兒女情。", "賢哉二丈夫，萬古離騷情。"]'),
('b286edef-a840-4b88-9062-fa9868a36264','次韻酬季兄  其一','方岳','宋','宋诗','song-poetry','','[]','客夢落江外，時情付杯中。',60,'全唐诗/poet.song.212000.json','["客夢落江外，時情付杯中。", "願言烽火低，不到甘泉宮。", "吾道易荆棘，此身久萍蓬。", "鶴眠伴官屋，猶有林下風。", "吹燈讀離騷，佳處時一逢。"]'),
('2111433e-72ad-4873-abf8-10cbe12393af','次韻酬季兄  其二','方岳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','嗟哉蠹書魚，生死文字中。',60,'全唐诗/poet.song.212000.json','["嗟哉蠹書魚，生死文字中。", "向來阿房賦，誰奏明光宮。", "長江一帆雨，半世雙鬢蓬。", "酒邊得吾子，擘蟹談秋風。", "江南有茅廬，山色相迎逢。"]'),
('97a3612a-139c-435b-96f9-e34e3cf51cb1','與同幕集南樓再用韻','方岳','宋','宋诗','song-poetry','','[]','飛蓋臨邊城，敵在吾目中。',60,'全唐诗/poet.song.212000.json','["飛蓋臨邊城，敵在吾目中。", "古今一俯仰，衰草迷隋宮。", "書生故倦遊，龐眉感秋蓬。", "安得雙飛鴻，跨此萬里風。", "下視渺塵土，毋與俗士逢。"]'),
('b2ecff0c-fc54-4113-8b80-4eb7b21ad08b','又次韻','方岳','宋','宋诗','song-poetry','','[]','月寒弄清琴，石齒鳴澗水。',60,'全唐诗/poet.song.212000.json','["月寒弄清琴，石齒鳴澗水。", "寥寥古音在，難入箏笛耳。", "鍾期渺秋江，停手子姑已。", "齊竽雜秦缶，乃傾市門倚。", "歸從柴桑人，醉漉春甕蟻。"]'),
('fc4adbd4-cf8f-4feb-a0af-de27fed1fc49','次韻酬章教授','方岳','宋','宋诗','song-poetry','','[]','江山渺愁予，歲月如羽疾。',216,'全唐诗/poet.song.212000.json','["江山渺愁予，歲月如羽疾。", "適烹雨前茶，已擘霜後橘。", "夜窗秋氣悲，栩栩夢圭蓽。", "荒唐失飯牛，迂闊坐捫蝨。", "書生夫何愚，因子請具述。", "端平元二間，舊學賫良弼。", "聘賢驛流庚，馭吏魚去乙。", "人言萬化新，太平適今日。", "起與鉏耒辭，欲補萬分一。", "寧知事大謬，青衫乃吾桎。", "五月謁吏銓，禁營干宥密。", "六月道南徐，宵掠無寧室。", "七月絕濤江，秦渺亂師律。", "戍樓角聲哀，夕烽酣戰卒。", "兵精晝經天，肉食者遑恤。", "臨風一長嘆，歸計吾已必。", "胡爲癡兒事，屢奏齊王瑟。", "願言猛士心，化作班侯筆。"]'),
('5185ea5d-8dbe-49de-a097-54cd609f5375','次韻舒尉','方岳','宋','宋诗','song-poetry','','[]','故山渺寒江，抱此明月睡。',48,'全唐诗/poet.song.212000.json','["故山渺寒江，抱此明月睡。", "煙簑失春鋤，萬事同一喟。", "可人期不來，乃獨以詩至。", "持觴聘梅花，我醉花亦醉。"]'),
('7dadc017-160b-4091-b041-cc47f02b1e1b','再用韻酬朱制幹憶梅','方岳','宋','宋诗','song-poetry','','[]','風挾柳花狂，晴酣海棠睡。',48,'全唐诗/poet.song.212000.json','["風挾柳花狂，晴酣海棠睡。", "玉人山之阿，爲爾增歎喟。", "春妍老欲僊，敢不一告至。", "惜哉桃李場，獨醒紛衆醉。"]'),
('13dc3478-5f53-4128-95fe-34ca5a9ce813','三用韻酬行甫平山之約','方岳','宋','宋诗','song-poetry','','[]','我家江南村，煙雨對山睡。',48,'全唐诗/poet.song.212000.json','["我家江南村，煙雨對山睡。", "與山幾何別，塵土發深喟。", "歐陽有佳踐，花驄一鞭至。", "亟報江南雲，共此故人醉。"]'),
('a780f7cf-79c9-4693-a4bf-9c3a30f242e5','四用韻','方岳','宋','宋诗','song-poetry','','[]','花愁牽勝遊，禽哢破佳睡。',48,'全唐诗/poet.song.212000.json','["花愁牽勝遊，禽哢破佳睡。", "點爾春何如，妙在夫子喟。", "宇宙一瑟間，誰知道之至。", "而彼章句儒，心爲六經醉。"]'),
('e61da992-10d1-4130-9a6b-4ac4e321c9c3','五用韻','方岳','宋','宋诗','song-poetry','','[]','能官不如歸，能詩不如睡。',48,'全唐诗/poet.song.212000.json','["能官不如歸，能詩不如睡。", "春風遽如許，對酒每三喟。", "駕言平山遊，歲月驚屢至。", "豈不賢於人，逐逐利名醉。"]'),
('59bffebb-8343-436a-a0d9-c5256303f061','次韻楊先輩古調  其一','方岳','宋','宋诗','song-poetry','','[]','陌上有蕩子，金鞍飛華韉。',96,'全唐诗/poet.song.212000.json','["陌上有蕩子，金鞍飛華韉。", "閨中有思婦，玉指調悲絃。", "當時兩相得，誤作容易看。", "那知新婚別，負此如花顔。", "妾身如秋葉，君意如春煙。", "恨妾不恨君，勸君長加餐。", "于飛者雙燕，人獨胡不然。", "悲哉結交行，難語之時賢。"]'),
('a79f5f58-a313-454a-bb5d-6778fbc66316','次韻楊先輩古調  其二','方岳','宋','宋诗','song-poetry','','[]','南山有於菟，雪齒雙銅睛。',120,'全唐诗/poet.song.212000.json','["南山有於菟，雪齒雙銅睛。", "霧深忽軒鬐，孤嘯開青冥。", "槲林歲月老，猶以文炳名。", "胡爲食牛志，無復當時英。", "吾聞楊儀之，筆落風雨驚。", "乃今已老矣，囊錦携一兵。", "平時號詩將，窮處圍愁城。", "何當胾西崑，與爾樽南溟。", "高談動星斗，萬物皆欣榮。", "秋風吾亦歸，空山多月明。"]'),
('ca39979b-0a29-4740-bbb9-c4a8b6fbb90f','次韻范侍郎寄趙校正','方岳','宋','宋诗','song-poetry','','[]','嗚呼小雅廢，邊角摇軍聲。',192,'全唐诗/poet.song.212000.json','["嗚呼小雅廢，邊角摇軍聲。", "采芹舊青衿，亦須事力征。", "朱轓挾武將，白眼輕儒生。", "區區衆濁間，嗟子難爲清。", "向來意何如，豈惟以文鳴。", "乃今事大謬，老氣猶崢嶸。", "論事抉石猊，摛辭吸川鯨。", "久抱一束書，空山卧月明。", "竊憂蠢詖胡，鱗介腥神京。", "幸存三寸舌，寧守二尺檠。", "有愚欲獻璞，無意望報瓊。", "云何山陰興，莫寫塞下情。", "竹牀撼夜柝，茅屋荒秋城。", "回首閶闔門，何啻九萬程。", "願言大白低，滁山足春耕。", "堂皇坐醉翁，開閤延羣英。"]'),
('cd46c58b-ee8d-49a7-80e0-d99ed1af1487','題王尉半竹','方岳','宋','宋诗','song-poetry','','[]','吾始過西齋，破於玉川屋。',156,'全唐诗/poet.song.212000.json','["吾始過西齋，破於玉川屋。", "中有山澤癯，雪燈共夜讀。", "秋聲入雨聽，手携牆下竹。", "携鋤斸荒苔，寧甘食無肉。", "今春初行鞭，稍覺風月肅。", "既成爲詩喜，破奉起新築。", "舊聞君家猷，興寄尚幽獨。", "一日無此君，亦自憎面目。", "君其幾代孫，秀色若可掬。", "萬事不挂口，翛然對寒玉。", "城中寸金地，官舍迫林麓。", "曾微百肘寬，難雜以花木。", "尚遺一半何，留之與雲宿。"]'),
('25baab8b-1a30-4095-b70f-bd83cc305a56','蟄室','方岳','宋','宋诗','song-poetry','','[]','室中度以几，其脩去尋一。',108,'全唐诗/poet.song.212000.json','["室中度以几，其脩去尋一。", "廣長尺而贏，崇爲咫者七。", "牖一以爲明，墐三以爲密。", "不供並橫肱，所貴劣容膝。", "蠖屈忘春霆，龜穹美朝日。", "玄冥方用事，萬木僵欲凓。", "窮陰易中人，戒子謹無出。", "於時則然耳，天者儻可必。", "相爾室外寒，磚爐坐捫蝨。"]'),
('6d486efb-b970-4904-bdeb-82604620c603','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其一','方岳','宋','宋诗','song-poetry','','[]','挂冠與結綬，孰者爲良圖。',120,'全唐诗/poet.song.212000.json','["挂冠與結綬，孰者爲良圖。", "忍貧殊亦難，乃有山水娛。", "一官落世網，耳目皆非吾。", "以此裁量之，回也終不愚。", "茅屋八九間，左右瓜芋區。", "旋篘薄薄酒，美如步兵厨。", "醉中天地寬，渺視騶侏儒。", "六合日清曠，吾道寧榛蕪。", "何幸𤱶畝間，身親見唐虞。", "不學張季鷹，秋風但蓴鱸。"]'),
('0778c900-cfd1-4fa3-ab52-9666fd11b14e','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其二','方岳','宋','宋诗','song-poetry','','[]','骯髒自山林，伊優自朝市。',120,'全唐诗/poet.song.212000.json','["骯髒自山林，伊優自朝市。", "是耶其非歟，一笑付圖史。", "紛華勿與戰，深溝閉堅壘。", "歲月曾幾何，折北俱披靡。", "問君胡能然，待以不爭耳。", "北山有微行，聊足屣吾履。", "未莎者維菊，未棘者維杞。", "擷之復湘之，寒綠冰人齒。", "秋聲在樹間，餉我一睡美。", "誰其驚周公，山鳥亦逝矣。"]'),
('284d2466-1bf4-421c-84cb-d78d9f8e3897','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其三','方岳','宋','宋诗','song-poetry','','[]','澡身乎書圃，晞髮於禮園。',120,'全唐诗/poet.song.212000.json','["澡身乎書圃，晞髮於禮園。", "靜中觀我生，父乾而母坤。", "寧不自愛重，日夕聲利昏。", "前脩亦人耳，而我何沄沄。", "飄流衆濁間，我者能幾存。", "人言千丈清，不如一寸渾。", "吾方洗吾耳，爾舌寧可捫。", "人情習華競，何啻於乞墦。", "此固吾不能，歸袖風翻翻。", "寘矣勿復道，荷鉏過前村。"]'),
('e4619417-b0db-44b9-ad89-7542ea7a43d7','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其四','方岳','宋','宋诗','song-poetry','','[]','我觀衆草樹，等是氣所囿。',108,'全唐诗/poet.song.212000.json','["我觀衆草樹，等是氣所囿。", "蓬茅一何荒，桃李一何秀。", "榮悴固不齊，受命了無繆。", "所以山中人，翩然拂歸袖。", "丁寧語泉石，此誤不可又。", "開簾受微颸，排闥入孤岫。", "是身如虛空，一室寬宇宙。", "夫何不訾省，與世爭决驟。", "天分有固然，吾力豈其究。"]'),
('f11e20b2-ea43-4274-9bf0-4c514563b8c6','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其五','方岳','宋','宋诗','song-poetry','','[]','往年鄭子真，口語挂吏文。',144,'全唐诗/poet.song.212000.json','["往年鄭子真，口語挂吏文。", "寧知世間事，變化紛如雲。", "有司出納吝，但守吾見聞。", "參互漏一錢，怒氣欲嚼齦。", "鞭笞敢誰何，竟取衆犬狺。", "大官飽谿壑，此特其毫分。", "奮髯一軒渠，要亦何足云。", "人言老先生，膏以明自焚。", "歸來北窗底，寸田得鉏耘。", "諸公直汲黯，羔鴈當成羣。", "乃肯巾柴車，林壑伴野麇。", "相從亦何樂，頼有中書君。"]'),
('8d5ce750-953c-4ad3-9dfa-7b11676bfb93','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其六','方岳','宋','宋诗','song-poetry','','[]','我本耕田夫，老矣紆郡章。',120,'全唐诗/poet.song.212000.json','["我本耕田夫，老矣紆郡章。", "頭童齒欲豁，顧視俱茫茫。", "胸中了無有，寧敢高頡頏。", "牧民如牧羊，惟恐隳官常。", "秋田失一飽，我食不下吭。", "寧知事大繆，以肉齒步光。", "每遭官長駡，剛腸怒生芒。", "歸來幾何時，有過牆下桑。", "西風一葉脫，野草忽已黄。", "君行不可挽，吾意不可忘。"]'),
('79d8a2c0-f482-4234-81de-6b5f412c73ab','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其七','方岳','宋','宋诗','song-poetry','','[]','吾仕竟三黜，吾氣竭再鼓。',144,'全唐诗/poet.song.212000.json','["吾仕竟三黜，吾氣竭再鼓。", "百年會有極，等作一抔土。", "寧當友魚蝦，勿謂怒豺虎。", "靜中試遐觀，一一皆自取。", "但恨齒髮衰，無力供保伍。", "結茅得幽深，杉竹自成塢。", "食貧秋田少，酒不供小戶。", "醒眼對佳山，日夕迭賓主。", "有談及世故，使我舌屢吐。", "常恐天地間，愧仰而怍俯。", "所以猿鶴居，不嫌蓬藋拄。", "可惜秋風至，送君又南浦。"]'),
('073c7051-cb03-4a08-81b7-6e134648e489','鄭僉判取蘇黄門圖史園囿文章鼓吹之語爲韻見貽輒復賡載  其八','方岳','宋','宋诗','song-poetry','','[]','他山有高梧，摵摵入凉吹。',120,'全唐诗/poet.song.212000.json','["他山有高梧，摵摵入凉吹。", "物情競趨新，不覺失故翠。", "吾生夫何如，坐爲有身累。", "青山久蹉跎，白髮竟顦顇。", "平生老瓦盆，笑我識丁字。", "爲言已衰遲，有口不如醉。", "醉中當自知，生世略如寄。", "何爲爭市朝，以死博一愧。", "一杯爲引滿，遂及二三四。", "頹然乎林間，客去吾欲寐。"]'),
('30ade3af-3445-4db0-9b06-e7be6ea9db10','雜興  其一','方岳','宋','宋诗','song-poetry','','[]','百年一瞬息，萬事皆塵埃。',131,'全唐诗/poet.song.212000.json','["百年一瞬息，萬事皆塵埃。", "所以身後名，不如掌中杯。", "山園足花草，雨露相先開。", "獨有下松，春風不曾來。", "青林曉霜重，百卉顔如灰。", "蒼然五大夫，鬰鬰何佳哉。", "佳花費事治，十無二三本。", "惡草時埽除，已復相苯䔿。", "試嘗問園丁，否泰乃爾反。", "渠方倚鋤笑，謂我見事晚。", "老天亦何心，生化日衮衮。"]'),
('2eaf197b-8563-4c0b-ab04-94374e325cd7','雜興  其二','方岳','宋','宋诗','song-poetry','','[]','梁武欲爲佛，秦皇欲爲仙。',72,'全唐诗/poet.song.212000.json','["梁武欲爲佛，秦皇欲爲仙。", "萬乘猶不足，要與天齊年。", "人生幾兩屐，過眼如風煙。", "此心苦無已，憂患長烹煎。", "不見客斯逐，力詆爭秦權。", "寧知咸陽市，父子更相憐。"]'),
('2415496e-f877-465f-a435-a0473af41109','去郡三思  其一','方岳','宋','宋诗','song-poetry','','[]','我思种明逸，與帝自賓友。',84,'全唐诗/poet.song.212000.json','["我思种明逸，與帝自賓友。", "歸眠青山雲，未醒紫宸酒。", "誰何敢譏彈，乃有此健守。", "天心本無私，以一調衆口。", "徙之嵩山陽，寧勿爲法受。", "夫何狐兔羣，能振霹靂手。", "此事關綱常，吾身竟何有。"]'),
('443f9983-2ffa-4042-8d4a-6934869e50ea','去郡三思  其二','方岳','宋','宋诗','song-poetry','','[]','我思老任棠，規我一本薤。',48,'全唐诗/poet.song.212000.json','["我思老任棠，規我一本薤。", "薤本猶可鉏，而况此稊稗。", "拔之血人指，咄咄吁可怪。", "吾斯以爲常，未敢以爲戒。"]'),
('d425ef8a-c91a-4a03-96ab-c82a10e2467f','去郡三思  其三','方岳','宋','宋诗','song-poetry','','[]','我思渤海龔，一語鉏獷俗。',60,'全唐诗/poet.song.212000.json','["我思渤海龔，一語鉏獷俗。", "竟令隴畝間，刀劍化牛犢。", "樵民亦人耳，乃不受約束。", "時時弄梃刃，誰肯繼往躅。", "歸來乎山中，無靦爾面目。"]'),
('307cabc7-0adc-48f8-93a8-0d86efa7c76d','感春','方岳','宋','宋诗','song-poetry','','[]','春風來無邊，草木含華滋。',48,'全唐诗/poet.song.212000.json','["春風來無邊，草木含華滋。", "道旁有枯荄，昨夜方葳蕤。", "陽和本根在，芽甲生光輝。", "造化亦何心，榮悴各有時。"]'),
('473169e5-85cf-400f-a683-c8d4d909314d','和放翁社日四首 社日雨','方岳','宋','宋诗','song-poetry','','[]','今茲淫春霖，曾不避甲子。',48,'全唐诗/poet.song.212000.json','["今茲淫春霖，曾不避甲子。", "荷鉏做秧田，寧欠三寸水。", "社戊占豐登，不以此故已。", "徑起觳觫公，鳴簑共于耜。"]'),
('c5aa2b98-76f6-4333-b2ae-7c28437fbd91','和放翁社日四首 社鼓','方岳','宋','宋诗','song-poetry','','[]','鼕鼕枌榆社，坎坎桑竹野。',48,'全唐诗/poet.song.212000.json','["鼕鼕枌榆社，坎坎桑竹野。", "初非有均度，意欲薄豳雅。", "侯家按新聲，視此寧勿赭。", "且從羣兒嬉，吾耒已可把。"]'),
('e015c26d-aeee-4f20-ab45-3e5b9bd7827c','和放翁社日四首 社酒','方岳','宋','宋诗','song-poetry','','[]','春風潑醅甕，夜雨鳴糟牀。',48,'全唐诗/poet.song.212000.json','["春風潑醅甕，夜雨鳴糟牀。", "相呼薦蠲潔，洗盞方敢嘗。", "不辭酩酊紅，所願䆉稏黄。", "家家飯牛肥，歲歲浮蛆香。"]'),
('869c5ed6-5072-4da6-a5ad-99f7b380df16','和放翁社日四首 社牲','方岳','宋','宋诗','song-poetry','','[]','年登斂牲錢，日吉視牢筴。',48,'全唐诗/poet.song.212000.json','["年登斂牲錢，日吉視牢筴。", "烹庖香滿村，未覺膰脤窄。", "餕餘裹青蒻，籬落笑言啞。", "咄哉陳孺子，乃有天下責。"]'),
('34bfdbb7-fe66-4f54-9a9a-1e1562796502','溪行  其一','方岳','宋','宋诗','song-poetry','','[]','春風何時來，柳色已如此。',48,'全唐诗/poet.song.212000.json','["春風何時來，柳色已如此。", "山中不知年，或告以于耜。", "鳴簑起飯牛，青青渺煙水。", "獨有頭上霜，春風不吾以。"]'),
('15ac17e7-2ddb-4a87-ad6a-045a44761667','溪行  其二','方岳','宋','宋诗','song-poetry','','[]','煙埋草堂路，雨暗梅花村。',48,'全唐诗/poet.song.212000.json','["煙埋草堂路，雨暗梅花村。", "起尋南溪翁，隔此一水渾。", "獨酌固自佳，業已携山尊。", "我醉即翁醉，何必親與言。"]'),
('ffd59d52-1dc5-4e74-bc1d-df7c091df6ec','溪行  其三','方岳','宋','宋诗','song-poetry','','[]','宇宙一傳舍，日月雙車輪。',48,'全唐诗/poet.song.212000.json','["宇宙一傳舍，日月雙車輪。", "人於萬古中，何翅肘屈伸。", "顔跖有不同，同作松下塵。", "吾年已如此，幾見花柳新。"]'),
('d6860d05-b61b-4791-b4f3-92314f31856d','溪行  其四','方岳','宋','宋诗','song-poetry','','[]','萬彙之散殊，各具一太極。',48,'全唐诗/poet.song.212000.json','["萬彙之散殊，各具一太極。", "人言造化工，生物不可測。", "寧知有自性，無所用爾力。", "試嘗問春風，春風誰能識。"]'),
('21006e69-9933-4c94-984d-6c67fb236a45','溪行  其五','方岳','宋','宋诗','song-poetry','','[]','冬雪不到地，春雪方連天。',48,'全唐诗/poet.song.212000.json','["冬雪不到地，春雪方連天。", "山園亦珊瑚，暄暖亦已妍。", "舒舒者丹荑，忽作凍蝟拳。", "寒燠固不齊，勿與時爭先。"]'),
('163790f4-1ca5-418b-89a5-c1e7607a7b18','次韻洪尉  其一','方岳','宋','宋诗','song-poetry','','[]','書生一何愚，出與世紛敵。',48,'全唐诗/poet.song.212000.json','["書生一何愚，出與世紛敵。", "眇哉朱兩轓，强名二千石。", "於世竟無補，苒苒老已逼。", "歸尋紫陽人，獨速釣寒碧。"]'),
('139e9599-7bfb-4332-9774-c4191c972b5e','次韻洪尉  其二','方岳','宋','宋诗','song-poetry','','[]','平生坐狷狹，無與同襟期。',48,'全唐诗/poet.song.212000.json','["平生坐狷狹，無與同襟期。", "寧論馬得喪，但問蛙公私。", "其初或取憎，其究還見思。", "不思亦何傷，此癖終難移。"]'),
('b720deba-0376-463d-acdc-cbfe96340801','次韻洪尉  其三','方岳','宋','宋诗','song-poetry','','[]','此郡如敗弓，一弛不可張。',48,'全唐诗/poet.song.212000.json','["此郡如敗弓，一弛不可張。", "吾曹如庸醫，了未分陰陽。", "幸哉歲小稔，意中猶差强。", "與民同一飽，䆉稏秋風黄。"]'),
('119bf9b1-20e6-4020-9bfe-8b0f796c0ad0','次韻洪尉  其四','方岳','宋','宋诗','song-poetry','','[]','孰使邦人士，不聞夷惠風。',48,'全唐诗/poet.song.212000.json','["孰使邦人士，不聞夷惠風。", "带刀與佩犢，剸刃嘻笑中。", "守雖老無能，此心與天通。", "豈敢不自省，刈人以爲功。"]'),
('5972c770-32f3-4c21-aed5-1a4679641d79','次韻洪尉  其五','方岳','宋','宋诗','song-poetry','','[]','氣當以志帥，心豈爲形役。',48,'全唐诗/poet.song.212000.json','["氣當以志帥，心豈爲形役。", "未知政奚先，亦各職其職。", "相期邊幅捐，安用竿牘飭。", "勉旃正吾鵠，其中非爾力。"]'),
('39490cc6-6a5e-411f-b47f-a44aa90c582c','送俞尉','方岳','宋','宋诗','song-poetry','','[]','空山十日雨，茅屋無炊煙。',228,'全唐诗/poet.song.212000.json','["空山十日雨，茅屋無炊煙。", "吾饑尚可忍，夜讀聲琅然。", "荒寒數家聚，生理尤堪憐。", "頻年歲不入，枯草生秋田。", "春深麥猶穉，米斗直萬錢。", "悲哉幾斛愁，博此半釜𩜾。", "前村老翁姥，語笑何由緣。", "問知好官人，發廩不我朘。", "常時有司吝，寧肯圭撮捐。", "官來剖私量，不受吏舞權。", "中流一壺濟，空復寬眼前。", "高軒忽予過，剪韭相留連。", "九華元老蒼，歸袖何翩翩。", "官無高與卑，爲政要可傳。", "使我一念存，所至民瘼痊。", "常平吾故人，問俗惟初搴。", "爲言民戚休，毋或諉老天。", "吾方屏田廬，不敢馳書箋。", "併聲絕宣城，倘寄晴雲篇。"]'),
('827f52f1-e80a-4ebc-8572-c00905c9504d','山中作人名詩','方岳','宋','宋诗','song-poetry','','[]','負郭太幽深，結茅容易得。',48,'全唐诗/poet.song.212000.json','["負郭太幽深，結茅容易得。", "雖無桃李園，石老松柏直。", "山北雨后蒼，山南霽雲白。", "荷鋤課諸兒，陸續蔬甲拆。"]'),
('24c42bdc-4e8e-4da4-9dae-0704c350360f','九日新種梅花開','方岳','宋','宋诗','song-poetry','','[]','木葉綠未脫，菊叢黄始華。',147,'全唐诗/poet.song.212000.json','["木葉綠未脫，菊叢黄始華。", "泛萸幾何日，尚覺陶巾斜。", "寒梅殊不情，矜秋吐奇葩。", "霜鬚半含蕾，春{艹拱}新茁芽。", "記初手鋤月，垂楊已藏鴉。", "了無盤錯根，但有枯槎牙。", "真同棄之耳，生意詎可涯。", "歲行不能半，孤秀則汝嘉。", "眷言抱幽獨，乃亦紛競耶。", "妨處在歲寒，奚取俗眼夸。", "盍守虬龍姿，毋汙蜂蝶譁。", "雪霜政凌厲，春自不我遐。"]'),
('b7d13875-8156-4666-be01-457718f5f97c','次韻蕭同年古意  其一','方岳','宋','宋诗','song-poetry','','[]','春臯有耕夫，扣角卧林麓。',144,'全唐诗/poet.song.212000.json','["春臯有耕夫，扣角卧林麓。", "朝饑不能忍，肯受世熏沐。", "脫身從牛衣，入耳皆狗曲。", "何如一蓑寒，風雨立於獨。", "人言骨相屯，自信亦良篤。", "空山多白雲，萬此寧有足。", "幽然閨中秀，不如倚市門。", "彼美林下風，不如刺繡文。", "冰懷獨耿耿，寧入俗眼觀。", "歲月不我留，老蒼眉宇間。", "舉世無與娛，逝言從綺園。", "一歌一歎息，寘此忽復論。"]'),
('2bf29af3-4933-4d3e-9b7d-c62485a2e811','次韻蕭同年古意  其二','方岳','宋','宋诗','song-poetry','','[]','猗猗者芳蘭，翳翳彼幽麓。',144,'全唐诗/poet.song.212000.json','["猗猗者芳蘭，翳翳彼幽麓。", "不煩漢陰人，抱甕相灌沐。", "春風自桃李，急管亂繁曲。", "紛紛衆醉間，美此一醒獨。", "造化本何心，亦因材以篤。", "所以古之人，身外無不足。", "客有古琴瑟，得之自龍門。", "於今幾何代，庚庚裂奇紋。", "携持過齊王，自意當駭觀。", "何如適獻笑，棄置笙竽間。", "時世我不遭，歸其老丘園。", "鍾期今安之，誰與俗士論。"]'),
('3d52febf-87ac-4e8b-961b-8e812b5c8901','用簡齋建除體韻','方岳','宋','宋诗','song-poetry','','[]','建旗凜大將，負弩紛前驅。',144,'全唐诗/poet.song.212000.json','["建旗凜大將，負弩紛前驅。", "除此兩不能，鋤荷則有餘。", "滿畦老菘韭，貧猶未饑虛。", "平生錯料事，不到齊王竽。", "定無相携人，歲晚誰與娛。", "執杯手欲龜，風雪侵貂褕。", "破顔劃孤嘯，鬰屈終不舒。", "危坐發深省，寧若巾柴車。", "成敗未可知，蕪我瓜芋區。", "收身黄觳觫，心迹何裕如。", "開口不言錢，未害書生迂。", "閉戶聊課詩，政與俗士疎。"]'),
('5a91506a-ce33-4a80-bb6d-a5446c74e0b5','田制','方岳','宋','宋诗','song-poetry','','[]','井田變阡陌，萬世以罪秦。',156,'全唐诗/poet.song.212000.json','["井田變阡陌，萬世以罪秦。", "商君信苛刻，不過民自民。", "漢名反秦火，當與三代鄰。", "今年田欲方，明年田欲均。", "寧知古井田，不爲賦稅湮。", "百畝官所予，無甚富與貧。", "所爲經界者，要使風俗淳。", "豈爲橫江網，竭不遺一鱗。", "乃知三代時，官與民爲春。", "秦民自生生，官不與笑顰。", "孰云漢田制，顧不如秦仁。", "秦姑寘勿問，漢已掎摭狺。", "誰其起鄒叟，重與畢戰陳。"]'),
('806cb7ab-5e8d-4c73-94d1-de4fa2ff5ef8','夜聞雨用誠齋新凉韻','方岳','宋','宋诗','song-poetry','','[]','歲事不可常，吾生復餘幾。',120,'全唐诗/poet.song.212000.json','["歲事不可常，吾生復餘幾。", "立秋五十日，殊未凉風至。", "山田欲生煙，旱氣亦可已。", "摵摵聲入桐，中夜攬衣起。", "未議填饑腸，且與洗渴髓。", "霢霂倘優渥，安用雷電駛。", "相傳水晶宮，法施政如此。", "焦枯寬一分，熱惱清十倍。", "稽首不昧香，我意則佛意。", "問雨從何來，君其無罪歲。"]'),
('e386dcbc-5fbb-414b-a81f-1208641b0e72','汪運幹容安齋','方岳','宋','宋诗','song-poetry','','[]','筆峰插天碧，其下可以廬。',132,'全唐诗/poet.song.212000.json','["筆峰插天碧，其下可以廬。", "誰與半間雲，共此一束書。", "君看柴桑人，自愛松菊居。", "北窗天地寬，不受世卷舒。", "脫巾漉老瓦，高枕眠華胥。", "日月雙車轂，乾坤一蘧蒢。", "是身亦安用，吾膝猶自如。", "煙波健跨犢，蘚石寒緡漁。", "農人告春暮，山月隨歸鋤。", "尚堪抱文度，談詩到黄初。", "謹毋屈聲利，望塵拜軒車。"]'),
('194dbdcb-5614-4b46-91f7-9a845d95daf3','避暑冷泉','方岳','宋','宋诗','song-poetry','','[]','火雲散鱗甲，萬瓦如炊燖。',168,'全唐诗/poet.song.212000.json','["火雲散鱗甲，萬瓦如炊燖。", "東華車馬塵，褦襶不自禁。", "誰能半日閒，脫身此窺臨。", "百錢買漁篷，橫截南北岑。", "追隨二三子，未害山水淫。", "邂逅十八公，俱作笙鶴吟。", "頗聞彼上人，振鬣萬馬瘖。", "試詩沒字碑，往聽無絃琴。", "空堂無枯秀，契我回向心。", "清凉一味禪，揮玉開煩襟。", "笑指亭下泉，杉竹涵幽深。", "蘚橋於三閘，龍怒飛出林。", "奔雷吼春壑，晴雪生午陰。", "人間正炎熱，去作三日霖。"]'),
('0a7712fe-b3b6-4d5c-b066-b93636f1a19b','答費宰','方岳','宋','宋诗','song-poetry','','[]','野人拙生事，缾粟蓋無幾。',120,'全唐诗/poet.song.212000.json','["野人拙生事，缾粟蓋無幾。", "唯有松下風，領略時一至。", "邇來風亦無，抱甕豈得已。", "頼有大夫公，入山喚龍起。", "鐵笛橫秋潭，山骨冰詩髓。", "歸來白雲篇，出語更清駛。", "自非境中人，其孰能與此。", "吾等纔噲伍，君才與丕倍。", "一聞老農言，遽得言外意。", "徑煩寫呈佛，十年亦中歲。"]'),
('27a09ef4-a8a6-4723-bab3-d5372e8127ff','答費司法  其一','方岳','宋','宋诗','song-poetry','','[]','長房一青竹，閲世不知幾。',120,'全唐诗/poet.song.212000.json','["長房一青竹，閲世不知幾。", "下視區中人，歲月老分至。", "頗聞第二泉，風煙未渠已。", "謫墮脩茶經，政坐一念起。", "誰令哀鴻號，手足痛入髓。", "秋江渴到底，安得半帆駛。", "大士慈愍故，慮豈不及此。", "軍持乞餘滴，厥德安敢倍。", "願言出岫心，慰我在原意。", "歸尋舊時杖，小住五百歲。"]'),
('489ffa0c-4c12-4c33-82ad-113462d58720','答費司法  其二','方岳','宋','宋诗','song-poetry','','[]','斐然偶成章，和者蓋凡幾。',120,'全唐诗/poet.song.212000.json','["斐然偶成章，和者蓋凡幾。", "風騷李杜壇，可望不可至。", "而况濂洛徒，每嘆吾已已。", "豈無願學心，衰懦鼓不起。", "何方有神醫，與我三換髓。", "道在一唯間，不在落筆駛。", "君談何容易，僕也敢當此。", "平生一青燈，事半功則倍。", "遺書亦具存，言固不盡意。", "勉矣山林人，優哉聊卒歲。"]'),
('65a4d75a-1f40-48f1-910f-3aeeada59d1c','中秋雨','方岳','宋','宋诗','song-poetry','','[]','明月如佳人，會晤良亦難。',132,'全唐诗/poet.song.212000.json','["明月如佳人，會晤良亦難。", "疇昔相與娛，誤作容易看。", "何如費傾結，欲語不可殫。", "雲間金背蟇，愛惜白玉盤。", "寧受妬婦欺，不借俗世觀。", "坐令四中秋，雨滴梧桐寒。", "人情重今夕，吳缾蘚花乾。", "亦知月不老，終當出林端。", "豈無三百錢，醉此素所歡。", "舉杯吞寒光，流入詩脾肝。", "令我書傳香，一洗儒生酸。"]'),
('6bffe0b7-142d-473c-9cde-8663fc6961ff','次韻招汪汝淵','方岳','宋','宋诗','song-poetry','','[]','俗子費應酬，對面隔千里。',144,'全唐诗/poet.song.212000.json','["俗子費應酬，對面隔千里。", "可人天一方，情親不盈咫。", "毛錐吾故人，商略每及此。", "道逢孔方兄，偃蹇不受使。", "豈知世俗眼，睥睨輒嗤訾。", "語言雜土氣，屢欲洗吾耳。", "客從何方來，力疾爲倒屣。", "出迎未暇揖，肝肺已相委。", "平生寡交游，正坐此曹鄙。", "鄰牆有麴生，之子差可喜。", "試呼與之談，時或發名理。", "往持邯鄲枕，分此一睡美。"]'),
('d50159d3-a583-4041-88f5-9c865187e7f3','雨望','方岳','宋','宋诗','song-poetry','','[]','前溪雨埋村，咫尺不我過。',132,'全唐诗/poet.song.212000.json','["前溪雨埋村，咫尺不我過。", "雷霆但濛鴻，林莽亦掀簸。", "竟微一飄灑，起此北窗卧。", "對面自胡越，孰爲天宇大。", "得非老龍公，憫念茅屋破。", "田父適在傍，出語驚四坐。", "指予兩青虹，可見不可唾。", "是能隔截之，帝澤誰與播。", "坐令水南人，一蹉成百蹉。", "上天本均平，夫豈不渠奈。", "虹亦何能神，書生例窮餓。"]'),
('6948a93e-4e52-4708-b09c-93f69e1e1f56','新晴','方岳','宋','宋诗','song-poetry','','[]','久雨村仍暝，新晴物自欣。',288,'全唐诗/poet.song.212000.json','["久雨村仍暝，新晴物自欣。", "蝶翎穿戶過，禽哢隔溪聞。", "野徑忙穿屐，山泥儘濺裙。", "柳垂春寂寂，花落雪紛紛。", "半月風雷雹，四郊烟水雲。", "畫圖寒不捲，林壑遠難分。", "好在魚蝦侶，甘同鳥獸羣。", "塢深藏曲折，竈冷鬰氛氳。", "野碓多舂藥，山庖少膳葷。", "瓶儲徵士粟，澗煮野人芹。", "美可冰甆茹，香惟瓦甑醺。", "鷹芽長及寸，貓笋重兼斤。", "淡泊諳貧味，熹微策睡勳。", "意行隨遠近，高卧送朝曛。", "原隰桑麻沃，衡門卉木薰。", "隠居捐世累，處士應星文。", "詩憶春池草，書忘秘閣芸。", "桐孫涵古色，柏子吐奇芬。", "載籍悲千古，枰棋憖兩軍。", "烏藤同寢飯，黄犢了耕耘。", "目爲蠅頭眩，肱緣鸛嘴皸。", "一科曾不補，四體正須勤。", "陋巷瓢供飲，文窮硯待焚。", "剛腸猶木彊，皺面自靴紋。"]'),
('4006b511-0869-4925-850c-9e9937fc6576','次韻程務實見寄','方岳','宋','宋诗','song-poetry','','[]','客來問奚自，曰予自虞庠。',204,'全唐诗/poet.song.212000.json','["客來問奚自，曰予自虞庠。", "有友猿鶴姿，與子鴻鴈行。", "石崖鬰崔嵬，玉灑高頡頏。", "昔爲斗與牛，今爲參與商。", "銜袖尺素書，寄此明月光。", "吾詩眇何似，雞羣之昂昂。", "唱予和者誰，一叫孤鳳凰。", "孰云噲等伍，乃與國士雙。", "大書適豪縱，深刻何煒煌。", "尚餘煙雨痕，急埽莓苔牆。", "所嗟眼中人，未試肘後方。", "平生湖海氣，收拾歸短章。", "故雖百車渠，僅同一毫芒。", "極知不入時，面有半寸霜。", "再三約梅花，雪谷深韜藏。", "少須具筆硯，鼓枻凌寒江。", "君紉杜若佩，我製芙蓉裳。"]'),
('f3c15cba-9821-482f-9649-1602da72771c','次韻程少章投贈','方岳','宋','宋诗','song-poetry','','[]','十稔眠半村，一醉子萬象。',288,'全唐诗/poet.song.212000.json','["十稔眠半村，一醉子萬象。", "向來此方寸，甚矣似元亮。", "釣石自寒煙，誰知太公望。", "北山忽移文，猿鶴費尋訪。", "老夫竟何有，豪奪牛背上。", "時時夢中歸，樵笛故悲壯。", "始予斥祈下，天地方絪縕。", "綱常幾何在，梟嘯千乾文。", "林希亦入耳，擲筆爭書勳。", "羣憸併附和，四面皆楚軍。", "當時此事集，不可夷狄聞。", "風雷忽飛厲，聖矣堯舜君。", "方今紫宸朝，落落盡圭璧。", "予雖草茅士，亦有二三策。", "不愁衫故青，所恨頭盡白。", "古人如可作，雅欲分半席。", "誰當爲斧斤，恐不中柱石。", "一官乞閒外，此計吾已必。", "平生剛直胸，不肯偶土木。", "諫書上文石，親見天穆穆。", "諸賢忍不言，諾諾恐非福。", "急回狂瀾倒，何啻焦釜沃。", "如聞左璫橫，爾音乃金玉。", "因聲訊諸賢，往事炳如燭。"]'),
('d47c5100-0e7f-46c4-823b-587bae6a8223','別蒙姪','方岳','宋','宋诗','song-poetry','','[]','嗚呼吾與汝，生世何不辰。',288,'全唐诗/poet.song.212000.json','["嗚呼吾與汝，生世何不辰。", "每思十年事，雪涕時沾巾。", "方予第奉常，堂有未老親。", "當時爾父母，綠鬢猶青春。", "乃各不待年，拱木號蒼旻。", "禍予不自殞，降喪無太頻。", "骨肉纔百指，踵作松下塵。", "乃今所存者，欲言鼻酸辛。", "我父惟我耳，爾父惟爾身。", "綿延僅不絕，一絲引千鈞。", "所以叔姪間，不啻父子真。", "豈不念爾孤，聚族守一貧。", "曰惟門戶故，戀戀官倉陳。", "雅欲携爾俱，守舍無可人。", "向來惡少子，覆轍那可遵。", "譍門故自佳，爾學憂荆榛。", "索居寡師友，則與不學均。", "老夫本無似，嗜書如嗜醇。", "少時共燈火，往往夜嚮晨。", "但患業不精，寧往父母嗔。", "爾今既婚冠，不與兒童鄰。", "一念及泉壤，於何敢因循。", "此身所係重，安事予諄諄。", "俚諺亦有之，一日計在寅。"]'),
('053d15a5-6cac-4b2a-9012-de41b5691d97','上鶴山作圖書所扁','方岳','宋','宋诗','song-poetry','','[]','我本耕田夫，識字略可數。',144,'全唐诗/poet.song.212000.json','["我本耕田夫，識字略可數。", "誰令半窗燈，奪此一犁雨。", "明經爲青紫，無乃以書賈。", "晚知事大謬，於學竟何補。", "歸來抱遺經，頗欲窺門戶。", "忍饑堪丹鉛，環坐書作堵。", "時或躋唐虞，身親到鄒魯。", "吾方忘吾貧，三徑蓬藋拄。", "獨慙鶴山翁，健筆照衡宇。", "赤手盤蛟蛇，今已泉下土。", "連雲甲第多，未必快此覩。", "乃知癡書人，差勝守錢虜。"]'),
('4b96c6d3-0bae-4f09-9668-bfc1c1547465','二禽','方岳','宋','宋诗','song-poetry','','[]','鵲噪令公喜，鴉噪令公怒。',142,'全唐诗/poet.song.212000.json','["鵲噪令公喜，鴉噪令公怒。", "福兮挽不來，禍兮推不去。", "咄哉之二蟲，於爾竟何與。", "茅簷新雨晴，鵲聲哢圓嗉。", "主人顔色和，甘諛終不悟。", "禍常十八九，鴉故告之故。", "城頭尾畢逋，唾者滿行路。", "佞鵲不我忤，忠鴉不我誤。", "試嘗問主人，無乃乖好惡。", "嗚呼平生所聞唐太宗，切齒不平田舍翁。", "昨朝墳上土花墮，斷碑零落悲秋風。"]'),
('a4eb06f7-cfd3-4da3-8740-89b4e39a7a14','白鹿洞','方岳','宋','宋诗','song-poetry','','[]','茲山信雄深，鐘梵上雲雨。',144,'全唐诗/poet.song.212000.json','["茲山信雄深，鐘梵上雲雨。", "微吾紫陽翁，幾何不豪取。", "有來青牛車，肯作白鹿主。", "詩書夜被之，一變至鄒魯。", "唐虞際淳熙，此道日方午。", "澗聲撼皇墳，山翠濕章甫。", "紛其四方人，會此共談麈。", "岳也互鄉童，屨二不及戶。", "却後七十年，空堂凜遺矩。", "四書在乾坤，六老自今古。", "昭回雲漢光，不隔天尺五。", "厥惟貂續難，謹勿小吾土。"]'),
('13216707-405f-464e-8a95-cad552648117','清明','方岳','宋','宋诗','song-poetry','','[]','何哉清明乃爾愁，雨聲中間花事休。',64,'全唐诗/poet.song.212000.json','["何哉清明乃爾愁，雨聲中間花事休。", "一春留春不肯住，况無酒與春相酬。", "牆頭筍已吹成竹，奪我齋厨蒼玉束。", "滿牀書卷爲不平，亦怨秋崖長負腹。"]'),
('385e287d-7261-4d75-9580-8b8af2ed49ec','春暮','方岳','宋','宋诗','song-poetry','','[]','人生會有百年極，春事略無三日晴。',64,'全唐诗/poet.song.212000.json','["人生會有百年極，春事略無三日晴。", "豈惟坐隔海棠醉，亦未曾逐楊花行。", "綠樹陰陰遽如許，黄鳥飛飛寂無語。", "先生欲作送春詩，似此一春那用爾。"]'),
('522234e8-6e55-4907-881a-87dccc5348f0','出關','方岳','宋','宋诗','song-poetry','','[]','一坐一百二十日，柳初黄落今青青。',63,'全唐诗/poet.song.212000.json','["一坐一百二十日，柳初黄落今青青。", "索輿徑去有忙事，忽憶曾與春丁寧。", "牡丹徑尺妙天下，許釀醽呼娉婷。", "到家二月亦晚矣，未辦翠色官窯缾。"]'),
('894fe2b0-d9e1-4a21-a0b3-0c458a3b04de','松棚','方岳','宋','宋诗','song-poetry','','[]','濤聲盤空吹海立，夜拔蒼髯老蛟泣。',64,'全唐诗/poet.song.212000.json','["濤聲盤空吹海立，夜拔蒼髯老蛟泣。", "陰森一片翠微寒，不放驕陽排闥入。", "歸來歸來乎山中，人間六月方藴隆。", "寧減明月添清風，誰其云者十八公。"]'),
('430b0a5c-2487-44e9-8018-f473d2836fb1','日食守局','方岳','宋','宋诗','song-poetry','','[]','乙巳之秋七月朔，太陽無光天索寞。',64,'全唐诗/poet.song.212000.json','["乙巳之秋七月朔，太陽無光天索寞。", "辟雍諸儒坐讀書，談古談今自驚愕。", "玉皇不受紫宸朝，百官拜表羣陰消。", "明朝丞相做禮數，宣押歸堂只如故。"]'),
('9fb13c35-7570-404d-a4fd-691b7fe6a443','秋江引','方岳','宋','宋诗','song-poetry','','[]','水天一色磨古銅，落日欲沒蘆花風。',64,'全唐诗/poet.song.212000.json','["水天一色磨古銅，落日欲沒蘆花風。", "雙飛野鴨忽驚起，漁歌漸遠秋江空。", "煙波渺渺無終極，中有江南未歸客。", "短篷夜泊洲渚寒，孤鴈橫江聲正急。"]'),
('7af466f1-fcc7-488a-9ebf-9095b28127c8','爭棋','方岳','宋','宋诗','song-poetry','','[]','江南底處無楊柳，海內何人解詩酒。',64,'全唐诗/poet.song.212000.json','["江南底處無楊柳，海內何人解詩酒。", "春簑雨濕蕙煙寒，閒却鷗沙釣竿竹。", "塞雲漠漠方笞兵，油幢安用白面生。", "東山屐齒蘚花綠，鶴唳風聲到棋局。"]'),
('f348e420-b49d-4a57-bd76-00af288992a2','過采石','方岳','宋','宋诗','song-poetry','','[]','靈官行雨鱗幢濕，雷吼黑風吹水立。',64,'全唐诗/poet.song.212000.json','["靈官行雨鱗幢濕，雷吼黑風吹水立。", "英雄不奈劍花寒，然犀夜午魚龍泣。", "雪浪掀天箭能急，紫茸投箠胡星失。", "吳宮酒醒岸花愁，不是龍驤勇無敵。"]'),
('94c95079-3476-4164-b6e3-87f2581d499b','戲簡文孺林劑局','方岳','宋','宋诗','song-poetry','','[]','廣文氈寒不可忍，月邊頓作乘鸞興。',64,'全唐诗/poet.song.212000.json','["廣文氈寒不可忍，月邊頓作乘鸞興。", "府公給告使者嗔，甘坐畫眉取歸徑。", "曉携手版中書堂，春風滿身芝朮香。", "物無疵癘清晝長，倘有囊中醫國方。"]'),
('4eb7e962-7530-4171-a421-0d39ad92ed72','書斷厓','方岳','宋','宋诗','song-poetry','','[]','老木枯藤絞蒼石，嵐重雲寒土花碧。',64,'全唐诗/poet.song.212000.json','["老木枯藤絞蒼石，嵐重雲寒土花碧。", "巨靈探璞夜不眠，斧斤睥睨魚龍泣。", "中分一片落溪邊，此祕未覩乾坤前。", "試留名字與後世，戒爾謹護青瑶鎸。"]'),
('2294ea42-9981-4b4d-9657-a02be8e9f075','贈背書人王生','方岳','宋','宋诗','song-poetry','','[]','我無王書二千六百紙，空有六經四十三萬字。',68,'全唐诗/poet.song.212000.json','["我無王書二千六百紙，空有六經四十三萬字。", "荒山寒入雪夜燈，三十年來無本子。", "壁魚不生糊法死，君欲如何染君指。", "石爐煮餠深注湯，自向胸中相料理。"]'),
('03452036-3887-4816-9e1f-19f6419ae7bd','三禽言  其一','方岳','宋','宋诗','song-poetry','','[]','麥熟熟，黄雲壓肩堆滿屋。',71,'全唐诗/poet.song.212000.json','["麥熟熟，黄雲壓肩堆滿屋。", "大兒燒穟事治穀，小兒擷蔬歸作粥。", "阿翁飽去摩挲腹，柿葉濃陰對黄犢，快活一生甘碌碌。", "君不見秋崖白頭守殘牘，麥雖熟，飯不足。"]'),
('98d4ac46-483e-4423-b35b-fafe60b429d1','三禽言  其二','方岳','宋','宋诗','song-poetry','','[]','不如歸，燒痕青青春蕨肥。',83,'全唐诗/poet.song.212000.json','["不如歸，燒痕青青春蕨肥。", "茅籬數掩山四圍，有秫可釀荷可衣。", "世間何地非危機，曷不長守西山饑。", "君不見秋崖醉眠釣魚磯，六年不出山下扉。", "不如歸，長安道上煙塵飛，莫向山家怨落暉。"]'),
('f38a8905-f73c-46c0-8d14-221409c564d3','三禽言  其三','方岳','宋','宋诗','song-poetry','','[]','呂望非熊亦非龍，後車載歸作三公。',83,'全唐诗/poet.song.212000.json','["呂望非熊亦非龍，後車載歸作三公。", "龐眉皓髮八十翁，幾何日月土一叢。", "盍不徑老磻溪風，以文見醫方自功。", "西山之人不爾容，君不見秋崖無才終不逢，長年垂釣煙波中。", "公非熊，同不同。"]'),
('fca29891-8370-4535-923e-2747b52d69fe','無寐','方岳','宋','宋诗','song-poetry','','[]','雨寒不寒苔蘚紫，霜落未落楊柳黄。',68,'全唐诗/poet.song.212000.json','["雨寒不寒苔蘚紫，霜落未落楊柳黄。", "野鷹饑嘯獸擇肉，邊馬戰摧烏啄瘡。", "兵氛甚惡寸心折，劍無恙，雙毛蒼。", "極知三百六旬氣月短，其奈二十五點更漏長。"]'),
('af860178-88d6-42b8-840c-707eb0b39cef','胡道士山房聽琴','方岳','宋','宋诗','song-poetry','','[]','石亭老入維摩室，三尺流泉長挂壁。',96,'全唐诗/poet.song.212000.json','["石亭老入維摩室，三尺流泉長挂壁。", "雲寒夜半山鬼號，十年兩耳秋蕭瑟。", "村溪水落尋山房，顔如渥丹鬢未霜。", "麻姑大鵬不勝載，挽住且與歌滄浪。", "菊近重陽破青蘂，猶带潘郎舊風雨。", "彈冠政自不須彈，我欲挂冠神武去。"]'),
('74ecf087-7d46-45a7-b844-8ad23e4412a9','聽琴','方岳','宋','宋诗','song-poetry','','[]','寧食三斗塵，不受緩歌雙黛顰。',140,'全唐诗/poet.song.212000.json','["寧食三斗塵，不受緩歌雙黛顰。", "寧食三斗葱，不受急管融春風。", "吾二三子相知心，平時比之雙南金。", "扣門剝啄倒屐出，喜我謂我山水淫。", "牆頭呼酒意頗急，何以侑之霹靂琴。", "太虛爲室月爲燭，悠然此意無古今。", "山空江靜夜如水，但見四岸花木深。", "大聲久不入衆聽，誰復好古同風襟。", "自非我輩但癡坐，噲等之俗難砭鍼。"]'),
('9de668bb-d012-4238-b86f-43b5c6a63cf5','東西船','方岳','宋','宋诗','song-poetry','','[]','昨日東船使風下，突過未興快於馬。',96,'全唐诗/poet.song.212000.json','["昨日東船使風下，突過未興快於馬。", "今日西船使風上，適從何來急於浪。", "東船下時西船怨，西船上時東船羨。", "篙師勞苦自相覺，明日那知風不轉。", "推篷一笑奚爾爲，怨遲羨速無休時。", "沙頭漠漠杏花雨，依舊年時檣燕語。"]'),
('bbd7f412-4766-437c-a289-f56ef0303ef0','丫頭巖','方岳','宋','宋诗','song-poetry','','[]','君不見新婦磯、女兒浦，小姑嫁與彭郎去。',99,'全唐诗/poet.song.212000.json','["君不見新婦磯、女兒浦，小姑嫁與彭郎去。", "天開地闢本何心，以邪見我成疑誤。", "風煙高並雙丫石，舊已知名今始識。", "佳山要自勝佳人，未見好山如好色。", "滿壁題詩吾所恥，倒激西江誰與洗。", "安得人間馬長卿，盡作山中魯男子。"]'),
('96f2a6c8-fe01-467c-a951-356e5c0d3904','用佚老園叟韻簡直孺併寄園叟','方岳','宋','宋诗','song-poetry','','[]','趙君規模要名世，徐君人物南州穉。',96,'全唐诗/poet.song.212000.json','["趙君規模要名世，徐君人物南州穉。", "欲携老硯共研冰，梅花不許山礬弟。", "今年識徐如識春，未識佚老園中人。", "似聞竹外一溪碧，天與隔斷俗子塵。", "此詩到眼情已浹，吾曹終與常人別。", "不然持問溪頭雲，渠自容吾分半榻。"]'),
('d3a0f462-e13f-4513-b699-4026e4f1caa6','題高皇過沛圖','方岳','宋','宋诗','song-poetry','','[]','芒碭真人赤龍子，一劍入關秦鹿死。',99,'全唐诗/poet.song.212000.json','["芒碭真人赤龍子，一劍入關秦鹿死。", "黥王菹醢過故鄉，仍冠竹皮相爾汝。", "故人父老喜欲狂，至尊含笑袍花光。", "酒酣擊筑自起舞，歌聲悲壯雲飛揚。", "此意今人棄如土，豈但當時沐猴楚。", "君不見相如草檄西入秦，蜀山憔悴生煙塵。"]'),
('d18391fb-ce7f-46c0-88e4-d5d88014d54f','諭俗','方岳','宋','宋诗','song-poetry','','[]','稻壓田塍穡頭重，蛟蛇糾蟠扶不動。',98,'全唐诗/poet.song.212000.json','["稻壓田塍穡頭重，蛟蛇糾蟠扶不動。", "得霜欲老晴下鎌，捲野秋雲堆作隴。", "昨日糴米如糴珠，頓落半價多年無。", "賣刀買牛政不惡，一字入官妨爾樂。", "不如阿婆殺雞賽田神，阿翁買酒邀田鄰。", "三盃徑醉客歸去，茅簷曝背溫如春。"]'),
('e0dac56e-5824-42ff-b7d1-5e28eff1fa8b','觀漁','方岳','宋','宋诗','song-poetry','','[]','林光漏日煙霏濕，鸕鷀族立春沙碧。',112,'全唐诗/poet.song.212000.json','["林光漏日煙霏濕，鸕鷀族立春沙碧。", "湘竿擊水雪花飛，鸕鷀沒入春溪肥。", "銀刀撥剌爭三窟，烏兔追亡健於鶻。", "搜淵剔藪無噍類，餘勇未厭心突兀。", "十十五五斜陽邊，聽呼名字方趨前。", "吐魚筠籃不下咽，手捽瑣碎勞爾還。", "嗚呼奇哉子漁子，塞上將軍那得爾。"]'),
('f70ce6f2-2c2b-4182-99e3-82ab358bbf45','扣角','方岳','宋','宋诗','song-poetry','','[]','東家打麥聲彭魄，西家繅絲雪能白。',96,'全唐诗/poet.song.212000.json','["東家打麥聲彭魄，西家繅絲雪能白。", "中間草屋眠者誰，不農不桑把書冊。", "書中宇宙三千年，凡幾變滅成飛煙。", "不知讀此竟何用，蓬藋拄逕荒春田。", "東家麥飯香撲撲，西家賣絲糴新穀。", "先生带經駕黄犢，扣角前坡煙水綠。"]'),
('d9cb3a2f-ee99-45b7-a621-d587c9c2f3de','次韻採菌','方岳','宋','宋诗','song-poetry','','[]','秋崖不慣大官肉，雪屋爲出齋房芝。',96,'全唐诗/poet.song.212000.json','["秋崖不慣大官肉，雪屋爲出齋房芝。", "山靈頗憐世味薄，風格略與詩情宜。", "菘膰何但退三舍，蕨拳恨不同一時。", "自尋墮樵了幽寂，豈料枯枿能神奇。", "羣僊餐霞吸沆瀣，豪貴蒸乳盛琉璃。", "磚爐石鼎煮飛瀑，此妙勿令渠輩知。"]'),
('e7fe9d31-2e35-4e0a-b9af-6e930dd66fab','題刊字蔡生','方岳','宋','宋诗','song-poetry','','[]','六經四十三萬字，古未版行天所秘。',96,'全唐诗/poet.song.212000.json','["六經四十三萬字，古未版行天所秘。", "魯纔得見易春秋，書到漢時猶默記。", "不知何年有爾曹，誤我百世惟寸刀。", "日傳萬紙未渠已，宇宙迫窄聲嘈嘈。", "一第竟爲吾子慁，辦筆如椽補龍衮。", "生毋謂我不讀書，待撿麻沙見成本。"]'),
('cb812006-89b9-48da-b064-7e65cb342a0b','才老致木犀甚古','方岳','宋','宋诗','song-poetry','','[]','老桂枯寒出奇怪，知幾何年如許大。',112,'全唐诗/poet.song.212000.json','["老桂枯寒出奇怪，知幾何年如許大。", "枝枝渾是好西風，粒粒中藏香世界。", "幽人高卧崖蘚邊，野僧肯寄溪雲外。", "兔驚玉杵夜丁當，鳥嗽辟寒金瑣碎。", "併令滿屋書傳香，喚起多生酒詩債。", "我今回向語一則，云何讚歎花三昧。", "月光童子妙莊嚴，金粟如來殊勝解。"]'),
('c8e73d83-87be-4637-abf3-32fae8b6a4e4','書夢','方岳','宋','宋诗','song-poetry','','[]','君馬黄，我馬白，漠漠柳花飛送客。',82,'全唐诗/poet.song.212000.json','["君馬黄，我馬白，漠漠柳花飛送客。", "我馬跑風欲人立，紫絲袍貼黄金勒。", "輕衫一騎後者誰，黄初平家寄書信。", "泥香兩車饟外孫，人與霜蹄俱夢境。", "嗚呼人間兒戲亦前定，奈何夫人不知命。"]'),
('74d1fe6c-5592-49ec-96cc-7b40168de32b','春盤','方岳','宋','宋诗','song-poetry','','[]','萊服根鬆縷冰玉，蔞蒿苗肥點寒綠。',160,'全唐诗/poet.song.212000.json','["萊服根鬆縷冰玉，蔞蒿苗肥點寒綠。", "霜鞭行茁軟於酥，雪樹生釘肥勝肉。", "與吾同味蔊絲辣，知我長貧韭葅熟。", "更蒸㹠壓花層層，略糝鳬成金粟粟。", "青紅餖飣映梅柳，紫翠招邀醉松竹。", "擎將碧脆捲月明，嚼出宮商带詩馥。", "賜幡羞上老人頭，家園不負將軍腹。", "人生行樂未渠央，物意趨新自相續。", "五十三翁日落山，三百六旬車轉轂。", "不妨細雨看梅花，且喜春風到茅屋。"]'),
('5350ae89-48de-4d51-9029-4389f6a39c2c','題訥齋','方岳','宋','宋诗','song-poetry','','[]','世人但識三尺嘴，儀從秦橫竟誰是。',124,'全唐诗/poet.song.212000.json','["世人但識三尺嘴，儀從秦橫竟誰是。", "瀾翻口角欲懸河，秋崖聽之歸洗耳。", "萬言萬當不如默，視吾舌存政須訥。", "雲根手築月三間，是非付與西山笏。", "謂君爲訥耶，讀書夜寂聲琅琅。", "謂君爲辨耶，向人開口無雌黄。", "屋頭自有山如此，說易說難那用許。", "孔堂絲竹春風和，賜也多參惟一唯。"]'),
('da4affc4-99dd-47da-a95c-596262c7e849','掃蜜','方岳','宋','宋诗','song-poetry','','[]','須蜜之人去其國，盡以族行無敢逸。',128,'全唐诗/poet.song.212000.json','["須蜜之人去其國，盡以族行無敢逸。", "綴如垂瘤大如囊，低壓山牆於我室。", "秦人逐客真少恩，客來須看春正酣。", "咄嗟已辦四山壁，正對桃李開茅菴。", "蒼頭奴解與之語，擁篲招邀聿來宇。", "相攸新邑經始忙，先作高臺奉盟主。", "沈沈夥涉之爲王，獨無摇毒之蠆芒。", "熙熙登臺坐垂拱，花底退衙春晝長。"]'),
('090ad78f-c1b9-4778-9838-f51da1a65fb1','九日寄汪澄甫','方岳','宋','宋诗','song-poetry','','[]','山雨欲雨不敢雨，停杯待與黄花語。',96,'全唐诗/poet.song.212000.json','["山雨欲雨不敢雨，停杯待與黄花語。", "東籬人去幾何年，坐想寒香足悽楚。", "秋崖早賦歸去來，亦無茅屋荒蒼苔。", "淵明不入督郵眼，世俗寧有吾曹哉。", "綠尊索共紅裙飲，却恐黄花不渠肯。", "白衣未至酒缾乾，此意悠然要人領。"]'),
('45d5b62c-f995-46e0-8df7-c2d4fd604a0d','題曹兄耕綠軒','方岳','宋','宋诗','song-poetry','','[]','煙蒼蒼，水茫茫。',141,'全唐诗/poet.song.212000.json','["煙蒼蒼，水茫茫。", "鵓鴣喚雨蓑笠忙，春泥滑滑蒲稗長。", "駕犂叱叱牛力强，高田低田齊下秧。", "隔林人家炊黍香，有來饁者雙屨忙。", "煮芹燒筍各有將，小休吾牛飯前岡。", "共洗老瓦沽村場，相與醉語牆下桑。", "此爲豳詩第幾章，轉頭䆉稏秋風黄。", "嗚呼吾人讀書政如此，諸人讀書不如睡。", "君不聞建隆聖人之玉音，者也之乎助何事。"]'),
('46e38b64-5d35-45c6-b5b9-6004b45324b8','書樓考甫梅花百詠因徐直孺寄考甫','方岳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','以詩鳴者累百輩，誰與梅花可相配。',128,'全唐诗/poet.song.212000.json','["以詩鳴者累百輩，誰與梅花可相配。", "只傳冰影月香詩，直到如今美無對。", "疎籬把住橫斜枝，了不肯受春風知。", "自非冰腸雪洗髓，向渠正爾難爲辭。", "恨君不識林和靖，雪沍西湖老孤詠。", "恨我不識樓考甫，角聲吹殘霜月苦。", "兒曹但賞瓊瑶句，持與梅花相爾汝。", "夜深不道瑣窗寒，浥盡花香花有語。"]'),
('99d25ec5-6f71-4b23-9757-219f1fad4e5d','次韻劉簿觀雪用東坡聚星堂韻禁體物語','方岳','宋','宋诗','song-poetry','','[]','江臯黯黯飛雲葉，淅瀝破窗鳴急雪。',160,'全唐诗/poet.song.212000.json','["江臯黯黯飛雲葉，淅瀝破窗鳴急雪。", "亂飄密灑寒正苦，低唱淺斟癡亦絕。", "凍吟可但筆鋒健，醒狂不覺屐齒折。", "留連急景聊從容，俯仰幻塵空變滅。", "舒眉一笑各雲散，轉眼百年如電掣。", "風凝光眩眼欲花，酒带潮紅臉生纈。", "劇誇陶語何區區，等與謝吟爭屑屑。", "醉翁出令凡馬空，坡老揮毫風燕瞥。", "兩公仙去各已久，一代風流尚誰說。", "吸鯨今夕不可辭，醉中有句錚如鐵。"]'),
('4ec0c692-e3c0-4e67-b64c-7b9cb69fd853','三虎行','方岳','宋','宋诗','song-poetry','','[]','黄茅慘慘天欲雨，老烏查查路幽阻。',138,'全唐诗/poet.song.212000.json','["黄茅慘慘天欲雨，老烏查查路幽阻。", "田家止予且勿行，前有南山白額虎。", "一母三足其名彪，兩子從之力俱武。", "西鄰昨暮樵不歸，欲覓殘骸無處所。", "日未昏黑深掩關，毛髮爲豎心悲酸，客子豈知行路難。", "打門聲急誰氏子，束藴乞火霜風寒。", "勸渠且宿不敢住，袒而示我催租瘢。", "嗚呼李廣不生周處死，負子渡河何日是。"]'),
('ef996b86-9bfd-4579-a42d-d96d7ec48682','送少卿奉使淮西','方岳','宋','宋诗','song-poetry','','[]','金兵據城堅如石，韃人入關平如席。',144,'全唐诗/poet.song.212000.json','["金兵據城堅如石，韃人入關平如席。", "秋高塞上沙草愁，夜半軍中羽書急。", "符麟留鑰漢宗姓，風鶴爲兵謝安姪。", "貔貅野宿日增竈，鼪鼯陸梁夜鳴鏑。", "肯携金印問錢穀，盍上玉堂調筆墨。", "時平書生坐迂闊，氣蓋廷臣工激直。", "煙塵所喜毛髮青，冰雪其清肝膽白。", "朱雀橋深橘香美，白鷺洲寒荻花濕。", "我所思兮丁令威，欲往從之語胸臆。"]'),
('a2e3a1ee-4fba-4648-8d92-6e85def878ca','排門夫','方岳','宋','宋诗','song-poetry','','[]','一家一夫排門起，五家一甲單出里。',192,'全唐诗/poet.song.212000.json','["一家一夫排門起，五家一甲單出里。", "夫須襏襫潦霧愁，與官輸木供邊壘。", "沙場草青胡運衰，軍書抵急飛塵埃。", "官須排杈二十萬，巖邑配以三千枚。", "黠貪分頭挼掌唾，田里寧容高枕卧。", "望青徑指三尺墳，踏白邀爲萬金貨。", "殘爾冢，爾勿嗟，行取金錢寧爾耶。", "小人所憂在一飯，政坐爾冢殘吾家。", "待吾舉火者百指，母已癃病兒垂髽。", "社朝浸種亦已芽，秧田未翻生薺花。", "吏呼勸農今幾日，典衣已供塘堨冊。", "九年回首奈若何，夢遶江南與江北。"]'),
('07fd173c-7869-4592-b552-81072f5b0cb7','霪雨','方岳','宋','宋诗','song-poetry','','[]','朝雨暮雨不肯晴，昏昏冥冥如翳塵。',160,'全唐诗/poet.song.212000.json','["朝雨暮雨不肯晴，昏昏冥冥如翳塵。", "舍中連月汗流礎，道傍前日泥埋輪。", "東南地傾水所匯，潮汐沙擁江之滣。", "埧頭中沙坐可想，往往政與洪濤瀕。", "陵遷谷變不知代，但見萬瓦差鱗鱗。", "老錢試手建都邑，蓋亦安土非經綸。", "海鹹舄鹵易嵐霧，况此梅蒸天絪縕。", "沮洳與吾類䵷黽，爽塏久欲還麋麕。", "因思吳趙寧愛此，適已灞上翔真人。", "當時倘匪地天泰，詎知無意雲雷屯。"]'),
('0fc1b69c-bc37-4a8f-a37d-b465bef313f7','題司理采芙蓉圖','方岳','宋','宋诗','song-poetry','','[]','紉之以湘纍秋蘭之珮，載之以剡溪夜雪之舟。',162,'全唐诗/poet.song.212000.json','["紉之以湘纍秋蘭之珮，載之以剡溪夜雪之舟。", "漱之以清冰寒露之壺，澆之以碧玉晴雲之甌。", "著童船尾書船頭，荷花浦溆雙飛鷗。", "新紅如洗雲錦稠，停橈竚棹香浮浮。", "薰風滿座凉颼颼，醉面欲醒誰相酬。", "若有人兮眇中洲，把住月老叫不休。", "花亦問月愁不愁，何以了此蒹葭秋。", "蛟宮蛟宮夜泣悲靈脩，鱗幢欲濕行雲留。", "楚騷如水不可作，此意難以筆墨求，蕩予槳兮涯之幽。"]'),
('64e80cd7-8a3c-4606-86de-636932d23517','中秋','方岳','宋','宋诗','song-poetry','','[]','月出未出山蒼蒼，明毫倒射生寒芒。',176,'全唐诗/poet.song.212000.json','["月出未出山蒼蒼，明毫倒射生寒芒。", "光摇林彩已奇怪，月時猶在青山外。", "一杯兩杯呼出來，仰天喝雲雲未開。", "冰輪碾上何人推，天凉如水青如苔。", "不知今我何如哉，冰撐雪拄胸崔嵬。", "欲飛上天𣂏斗魁，手取蟾蜍探潑醅。", "醉眠老兔秋毰毸，下視茫茫青作堆。", "今人不見古時月，古月長照今人哀。", "繇來今古一丘貉，安用老滴成瓊瑰。", "如此佳月能幾回，搔吾鬢已霜皚皚。", "李白如在三百杯，與騎鯨魚游九垓。"]'),
('1cbeaaf8-0fcb-4ead-843c-95135f08c510','送徐太博守莆中','方岳','宋','宋诗','song-poetry','','[]','南州高士心如水，夜雨爐亭歲欲環。',160,'全唐诗/poet.song.212000.json','["南州高士心如水，夜雨爐亭歲欲環。", "朝蹟只如初到日，州麾猶在兩年間。", "秋來竹屋多歸夢，天與莆人一破顔。", "館下諸生能戀戀，眼中循吏故班班。", "相傳士子多于鯽，共喜府公清似山。", "慶曆諫臣書在否，乾淳文賦筆追還。", "郎官紅熟海風靜，通印子肥春網閒。", "心事太平兒女語，詩家尊宿鬢毛斑。", "歡迎騎竹來何暮，贈別垂楊不可攀。", "辦與老夫同一念，不憂吾道久間關。"]'),
('446ad546-61ff-4986-98ed-47de1a35151b','謝兄編言仁求詩','方岳','宋','宋诗','song-poetry','','[]','孟子言仁惟一字，曾子言仁惟一唯。',128,'全唐诗/poet.song.212000.json','["孟子言仁惟一字，曾子言仁惟一唯。", "風霆霜露天何言，吾夫子言非得已。", "六經在天如北斗，尚多不經聖人手。", "杏花零落曉壇荒，各自蜂房開戶牖。", "屋下架屋樓上樓，不三萬言渠不休。", "夜寒一燈供掉頭，泓穎何罪雲煙愁。", "阿連夢中春草碧，更向那邊添一筆。", "吾衰甚矣將奈何，欲共君談口荆棘。"]'),
('76daf7fd-079b-417b-b221-8f25b7fa4164','木稼','方岳','宋','宋诗','song-poetry','','[]','春日電光飛霹靂，元日奇寒雪盈尺。',96,'全唐诗/poet.song.212000.json','["春日電光飛霹靂，元日奇寒雪盈尺。", "銷瓊融玉夜色凝，贔屭穹林矗僵立。", "鮫人淚滴珊瑚枝，通身擎出青琉璃。", "霜皮溜雨凍不解，無人報與春風知。", "曉光穿漏晴相射，銳士銜枚甲初卸。", "山人不讀五行書，未省木冰吁可怕。"]'),
('8d396453-0bdf-4318-bf42-56186a248cf9','用王侍郎韻寄題醫僧道森藥山閣','方岳','宋','宋诗','song-poetry','','[]','蟻蛭侯王空培塿，大千世界無何有。',96,'全唐诗/poet.song.212000.json','["蟻蛭侯王空培塿，大千世界無何有。", "癡兒不省芭蕉身，持與冰霜鬭長久。", "三生慈愍魚十千，却來世間吁可憐。", "一百四病更相纏，縱有佛力難言詮。", "不如一念圓覺浄，四大乾坤無可病。", "雲根靈草自春風，夜立齊腰山雪盛。"]'),
('446dbe60-ace9-4051-aa86-f4dbbcb8bef8','田園居之右闢小室曰耕雨醉題壁上','方岳','宋','宋诗','song-poetry','','[]','南岡北岡鳴鵓鳩，高田低田俱怒流。',128,'全唐诗/poet.song.212000.json','["南岡北岡鳴鵓鳩，高田低田俱怒流。", "一簑煙雨駕觳觫，老手猶在吾何憂。", "燈火半生書作祟，幾欲送窮窮不去。", "吁嗟先生誰使汝，苦要革革換雙屨。", "如聞雙屨得有辭，向來棄我君何之。", "百無一成唯忍饑，胡不爛煮秋崖詩。", "歲晚相期亦不惡，莫更將書累牛角。", "併煩說似下邳侯，爾輩方當束高閣。"]'),
('2b5b39dc-ee20-4b51-9e2b-aa2fc58b3235','鄭總幹致蘆管筆','方岳','宋','宋诗','song-poetry','','[]','中書采邑初管城，笛材飽霜摇綠雲。',96,'全唐诗/poet.song.212000.json','["中書采邑初管城，笛材飽霜摇綠雲。", "春煙落紙黑蛟瘦，不可一日無此君。", "九華真人出奇計，笑指秋江雪無際。", "并刀失手劉寄奴，爨餘得與詩爲地。", "雙鈎入握如虛空，飄飄輕捷翻羣鴻。", "翰林夜召陶學士，草制進封盧國公。"]'),
('7404dd98-3882-4ccf-8d9e-716dc19c7e57','次韻題秋崖','方岳','宋','宋诗','song-poetry','','[]','秋崖何嘗與人絕，渠自胸中欠風月。',128,'全唐诗/poet.song.212000.json','["秋崖何嘗與人絕，渠自胸中欠風月。", "齊雲落星吾所無，草木深幽終是別。", "桂花正開山氣清，人間無路爭崢嶸。", "虛皇借與廣寒住，夜半擬進秋風行。", "芙蓉作城花露惹，一片月明天上下。", "風前把杯和月吞，嚼出新詩不供寫。", "醉倒寧知酒戶慳，滿身樹影蛟蛇蟠。", "羣僊挽我便歸去，雲海翻濤毛髮寒。"]'),
('5ba789ae-6552-4666-9429-258c255a88b4','次韻謝從之以表閭投贈','方岳','宋','宋诗','song-poetry','','[]','長楊奏賦三十年，已甘老死窮山巔。',200,'全唐诗/poet.song.212000.json','["長楊奏賦三十年，已甘老死窮山巔。", "醉眠獨宿秋風前，此豈有意聲名傳。", "如駑伏櫪不受鞭，要與騕褭難爭妍。", "强令作對官道邊，功名畢竟誰新鮮。", "岌岌兩傍蛟龍纏，侯曰美哉豈其然，才當如楫航長川。", "糞牆空復煩雕鎸，表閭不靳少府錢。", "粉飾休盛期半千，寧欲老我寒詩肩。", "歸來歸來直如絃，蓬萊回首慙班聯。", "安用一鳴諸子先，登樓忽思王仲宣。", "不如傍家田一廛，鋤煙犂雨仰問天。", "天生盤谷容盤旋，更有斗酒相留連。", "焉能跕跕愁墮鳶，一單堅坐三條椽。"]'),
('0af054fa-bf79-4f2c-b309-a78ba1f3e8a6','次韻山中小集','方岳','宋','宋诗','song-poetry','','[]','一生大錯空環轍，何啻糜渠六州鐵。',128,'全唐诗/poet.song.212000.json','["一生大錯空環轍，何啻糜渠六州鐵。", "不如歸來乎山中，山泉自香山酒冽。", "冰虀一釂累數觴，山中之樂那可量。", "梅花在傍具知狀，落筆煙雲生草堂。", "雪意催詩鬭清絕，與巧而遲寧速拙。", "豈知世上多路岐，莫遣胸中少風月。", "酒酣膽熱鬚髯張，老夫無復當年狂。", "乾坤許大不欠我，春猿秋鶴聊徜徉。"]'),
('0dfb540a-e609-4377-af47-d3ad23ae118e','醉歌','方岳','宋','宋诗','song-poetry','','[]','勸君且盡一杯酒，身外無窮莫問口。',188,'全唐诗/poet.song.212000.json','["勸君且盡一杯酒，身外無窮莫問口。", "近聞誰直白玉堂，或傳某佩黄金斗。", "與君何干，於我奚有。", "不如雨話耕夫，煙呼釣叟。", "問竹活無，看梅開否。", "天下事自有夔龍人，山中居只堪麋鹿友。", "乾坤蕩蕩呼不聞，今古茫茫骨俱朽。", "雞催晨，兔沒酉，春風來時又花柳。", "不知柳今幾青花幾紅，但見吾人成老醜。", "吾欲采薇西山，播穀南畝，吾牛雖健吾衰久。", "只可茅柴火酒醉幾觴，村田樂詩吟數首。", "不然空山寂寂白晝長，閒殺一雙無用手。"]'),
('e1ed9a5a-3256-4bff-befc-b2360cad5a3e','田家樂','方岳','宋','宋诗','song-poetry','','[]','前村後村場圃登，東家西家機杼鳴。',64,'全唐诗/poet.song.212000.json','["前村後村場圃登，東家西家機杼鳴。", "神林飲福阿翁醉，包裹餘胙分杯羹。", "婦子迎門笑相語，慙愧今年好年歲。", "牛羊下來翁且眠，時平無人夜催稅。"]'),
('f352f59d-a9b8-4d1e-975c-2f6afee6b609','田家苦','方岳','宋','宋诗','song-poetry','','[]','六月之雨田成溪，七月之旱煙塵飛。',64,'全唐诗/poet.song.212000.json','["六月之雨田成溪，七月之旱煙塵飛。", "眼中收拾不十年，未議索飯兒啼饑。", "夜點松明事治穀，規避債家相迫促。", "平明排闥自分沾，渠更舞權還不足。"]'),
('5be64550-a089-4833-8c2f-459dc476c227','豆苗','方岳','宋','宋诗','song-poetry','','[]','江南之筍天下奇，春風匆匆催上籬。',160,'全唐诗/poet.song.212000.json','["江南之筍天下奇，春風匆匆催上籬。", "秦郵之薑肥勝肉，遠莫致之長負腹。", "先生一缽同僧居，別有方法供齋蔬。", "山房掃地布豆粒，不煩勤荷煙中鋤。", "手分瀑泉灑作雨，覆以老瓦如穹廬。", "平明發視玉髯磔，一夜怒長堪水菹。", "自親火候瀹魚眼，带生芼入晴雲盌。", "碧絲高壓涎滑蓴，脆響平欺辛螫蔊。", "晚菘早韭各一時，非時不到詩人脾。", "何如此雋咄嗟辦，庾郎處貧未爲慣。"]'),
('3fa6c2f9-6ba2-4832-a62c-7e0ee2ba241d','月中觀梅','方岳','宋','宋诗','song-poetry','','[]','江南地暖得春早，老眼觀梅嘗草草。',232,'全唐诗/poet.song.212000.json','["江南地暖得春早，老眼觀梅嘗草草。", "今冬最暖春最遲，忽憶誠齋南海藁。", "解道晴暄殊欠寒，城中未有梅花看。", "却入山深最寒處，雪照冰溪纔一樹。", "乃知山中人，不受人閒塵。", "寧使風饕雪虐寒到骨，轉寒轉有寒精神。", "荒厓之底，野水之濱。", "太虛爲室天爲鄰，只有明月情相親。", "一團不冰今夜月，一片不飛今歲雪。", "雪意自怕老夫寒，月意寧知老夫拙。", "呼上山來强索詩，一花兩花春未知。", "南枝儘遲遲儘奇，槎牙不要東風吹。", "酣晴釀日付桃李，定自不肯君同時。", "舉杯吞月和花嚼，月自寄胸花不覺。", "少焉花亦到胸中，各自去尋詩約莫。"]'),
('b0852d22-f598-4293-a5c3-b32d5b395a94','雪中觀梅','方岳','宋','宋诗','song-poetry','','[]','一冬妍晴春意早，微茫已到閒花草。',244,'全唐诗/poet.song.212000.json','["一冬妍晴春意早，微茫已到閒花草。", "山翁平生見事遲，未緝牛衣編稻藁。", "明日是春那得寒，玄冥不作尋常看。", "交割與春排當處，萬里瑶林列銀樹。", "茅菴有詩人，肺渴方生塵。", "不知誰何駟六虯兮上天作樂府，落筆殿前如有神。", "帝咨汝岳錫圭土，佚以寬閒之野寂寞濱。", "玉田界天旁無隣，有梅百本爲賓親。", "昨夜枝上猶是月，今日枝上渾是雪。", "春工未必辦此奇，縱使巧遲寧速拙。", "雪詩不當梅花詩，詩成合報孤山知。", "老逋醉眠呼不醒，霜竹付與何人吹。", "古聲久不入俚耳，有詩寧似無詩時。", "自撼枝頭供一嚼，了了此心清浄覺。", "謂爲梅又冷冰冰，道是雪來香莫莫。"]'),
('691d3a10-04c8-4b57-b188-91c172a2c5b4','又和諸公作雪月歌','方岳','宋','宋诗','song-poetry','','[]','月觀夜午雪觀早，酒興崔嵬詩潦草。',234,'全唐诗/poet.song.212000.json','["月觀夜午雪觀早，酒興崔嵬詩潦草。", "梅花在傍具知狀，喚渠收拾秋崖藁。", "月邊雪邊同一寒，詩成不許凡人看。", "年年月寒雪寒處，老骨槎牙倚枯樹。", "不知天下人，面有三寸塵。", "政使書癡傳癖猶可憎，而况無風無味之錢神。", "麾之門外，問諸水濱。", "非我不與相比鄰，渠自胸次不我親。", "千古萬古赤壁月，千古萬古剡溪雪。", "天荒地老方可人，當日人曾笑渠拙。", "有梅不可無吾詩，無月無雪無人知。", "梅花亦不用收拾，付與萬竅更相呼。", "雪如瓊瑶月如水，青山白髮時乎時。", "有薇可羹螯可嚼，此味勿令兒輩覺。", "四海諸公共往來，雪中與渠無適莫。"]'),
('d46a198b-dcee-435b-bfb6-1f6ecae70653','山中甃墳外弟程魁有詩次韻','方岳','宋','宋诗','song-poetry','','[]','咄哉人世如飛煙，强欲作計垂千年。',176,'全唐诗/poet.song.212000.json','["咄哉人世如飛煙，强欲作計垂千年。", "寧知鬼見拍手笑，曾不一瞬雲埋阡。", "我於浮休等無二，詩卷留與荒山巔。", "平生夢想所不到，六國相印二頃田。", "古今一死百事足，安用老刻青瑶堅。", "海棠作堵錦步帳，柳花糝徑拳毛氈。", "見成林壑伴茅堂，名付身後杯生前。", "山中物物各生意，春到豈論茅與荃。", "人情變態千萬狀，所不負予惟老天。", "白虹貫巖出奇怪，一鍤不費青烏遷。", "是事且寘勿復道，老子久矣宜蚩妍。"]'),
('9934d620-3c4e-453f-9c68-6c00b787ca02','寄題龔國錄見山閣','方岳','宋','宋诗','song-poetry','','[]','吾州百嶂千峰低，斗大山城去山咫。',160,'全唐诗/poet.song.212000.json','["吾州百嶂千峰低，斗大山城去山咫。", "縈青繚碧玉四圍，曉色蒼寒莫煙紫。", "山中見山何足奇，此妙未容兒輩知。", "諸方不具頂門眼，寧了芥子藏須彌。", "我曾風月堂西醉，鞠草離離敗人意。", "摩挲龕壁幾屏篁，誰破天慳出嵐翠。", "恨我不識今楚龔，丘壑可想崔嵬胸。", "鑿開埋雨三三徑，跳出撐雲六六峰。", "騎䲔老僊滴詩硯，元氣淋漓冰片片。", "翩然下視世間人，對面有山渠不見。"]'),
('a6fc0db0-e25c-46ae-ab8d-3894937ace99','憎蚋','方岳','宋','宋诗','song-poetry','','[]','火雲燒空無處避，深入山林屏幽翳。',281,'全唐诗/poet.song.212000.json','["火雲燒空無處避，深入山林屏幽翳。", "松聲竹影差可人，高枕石頭眠薜荔。", "矇鬆欲墮無何鄉，奇痒爬搔紛芰製。", "{甍瓦=羽}{甍瓦=羽}黑子著兩股，劣視焦螟何瑣細。", "蒼頭在旁具言狀，謂特可憎是爲蚋。", "晝飛夜息繁有徒，胚胎鬰蒸育蕪蘙。", "使彼爲虺蛇之螫，則已焚於伯益之熭。", "惟其一蚊之睫有餘棲，九牛之毛不足計。", "故雖離朱莫覩其翼而善飛，䚦俞弗聞其聲而工噬。", "蓋天地萬生，其么麽微眇未有爾若者。", "而小則抓麻姑之爪，甚或疥瘍醫之齊。", "豈非族雖微而猥多，形易潜而叵測。", "吁嗟先生歸休乎，物固有時姑小憩。", "蚊蠛蠓，滿乾坤，可奈渠何苦攘袂。", "一葉秋，羣動閉，蚋何之兮豈其殪。", "先生於時，融融洩洩。", "半枕風清，千山月霽。"]'),
('e8aa2ab9-6190-4e83-b068-69c14adfe18f','義雞行','方岳','宋','宋诗','song-poetry','','[]','西家粥粥雞將雛，俛啄蚱蜢行相呼。',192,'全唐诗/poet.song.212000.json','["西家粥粥雞將雛，俛啄蚱蜢行相呼。", "羽毛未合事紛奪，四顧不虞烏畢逋。", "翻窺捷取血丹吻，性命須臾那可忍。", "草深决起落東家，垂翅離披猶蠢蠢。", "東家司晨乃有雄，平時嘴距凌秋風。", "怒冠趨前作雌伏，以翼覆藉哀窮凶。", "初脫禍機驚未定，生意中閒不能寸。", "時其饑渴經紀之，踸踔梳翎蘇委頓。", "物生知母不知父，此雖其類非其侶。", "陳嬰杵臼義所激，郭解朱家俠何取。", "嗚呼人有不如物，嗚呼今固不如古。", "從來山澤生龍蛇，人間父子成豺虎。"]'),
('c75a3031-6c83-405d-95c4-4ddfa579b76e','古人行','方岳','宋','宋诗','song-poetry','','[]','古人二十四，已自取侯印。',212,'全唐诗/poet.song.212000.json','["古人二十四，已自取侯印。", "加我三十一，擁褐猿猱逕。", "古人三十六，已自歎頭顱。", "加我十九年，雪頷埋霜鬚。", "春風秋月五十五，青山白雲自今古。", "與其浮沈於不卿不相之間，孰愈自適於老圃老農之伍。", "休休休，仰面看人吾所羞。", "莫莫莫，天下事堪幾回錯。", "既不能致君乎唐虞，又不能收身於樵漁。", "提携手板聊復爾，安用局促轅下駒。", "昌黎老韓手筆大，光範三書看渠破。", "號天叫地爲一官，宰相須還賈耽做。", "不如荷葭塢中之把茅，卧聽松聲三峽濤。", "開門夜半劃長嘯，已笑古人山月高。"]'),
('00d85f90-644f-4030-bf55-8a51a17e3ad4','元日立春','方岳','宋','宋诗','song-poetry','','[]','糟牀夜壓真珠紅，摩挲醉面迎春風。',212,'全唐诗/poet.song.212000.json','["糟牀夜壓真珠紅，摩挲醉面迎春風。", "春來春去無終極，能費幾筯蔓菁菘。", "既無長繩可以繫白日，又無大藥可以玄雙蓬。", "何怪乎玉雪可憐之孺子，忽頹然風霜不貸之衰翁。", "百年長短一丘貉，曾不芥蔕崔嵬胸。", "若夫塞翁失馬，楚人亡弓，此事細甚焦螟同。", "使吾冠冕佩玉於廟廊之上，吾不見其爲泰。", "使吾披裘带索於嵌巖之下，亦不見其爲窮。", "諸賢自作世俗眼，此老日飲亡何中。", "春秋獲麟夫子沒，本草不自醫神農。", "著書萬古知何用，况復起草明光宮。", "我今併欲焚老硯，一簑鳴雨東臯東。"]'),
('8f54156f-c4ac-440b-9811-a79c14e1e313','檻虎行','方岳','宋','宋诗','song-poetry','','[]','風低黄蘆雪模糊，南山夜獵生於菟。',119,'全唐诗/poet.song.212000.json','["風低黄蘆雪模糊，南山夜獵生於菟。", "鐵衣檻致元帥府，猶自舑舌磨牙須。", "府公起迎自除館，刻桷丹楹齊柵斷。", "分棟驍雄上下番，汛埽蠲明節寒暖。", "一鋪兵十人，一飯肉十斤，日費少府如千緡。", "惟恐不飽撩怒嗔，一旦出柙誰能踆。", "君不見有尨狺狺守門戶，舐糠纍纍奈何虎。"]'),
('d10bb87e-ac1c-4dff-81be-b2dd2dc88d42','效演雅','方岳','宋','宋诗','song-poetry','','[]','山谿斗折更蛇行，逗密穿幽見物情。',336,'全唐诗/poet.song.212000.json','["山谿斗折更蛇行，逗密穿幽見物情。", "蜜爲無花糧道絕，蟻知有雨陣圖成。", "飲風吸露蟬尸解，聳壑凌霄鶴骨輕。", "鸜鵒能爲祖仁舞，狎鷗欲與海翁盟。", "未忘王謝尋常燕，不肯酈生吾友鶯。", "鷺以先後爭食邑，鵲占南北啟門閎。", "春池潑潑魚當乳，霜渚喑喑鴈不鳴。", "啄木畫符工出蠹，提壺沽酒爲催耕。", "蚌何知識三緘口，蟹坐風騷五鼎烹。", "巴郢畫眉翻律呂，儀秦反舌定縱橫。", "鵝嗔晉帖得奇字，鷄喚祖鞭非惡聲。", "飽卧夕陽牛反嚼，誤投乾葉鹿虛驚。", "一枝棲息鷦鷯足，三窟經營狡兔𤬪。", "蝌蚪草泥文字古，蝸涎蘇壁篆書精。", "首昂蝜蝂貪寧死，壁奮螳螂禍自嬰。", "山麂見人頭卓朔，野鴟得鼠腹彭亨。", "雉傾族類甘爲翳，鴨解人言略自名。", "羊狠濫稱髯主簿，蟫肥薦食楮先生。", "色雖甚美猿深逝，骨不須多狗必爭。", "蛙爲公乎緣底怒，鳩寧拙耳了無營。", "勞形大塊皆同夢，蝶化莊周月正明。"]'),
('ade2cb92-cf11-4051-ae83-799bbdb8fc19','閲視賞射','方岳','宋','宋诗','song-poetry','','[]','邊角悲鳴霜撲地，將校寧甘潑寒戲。',192,'全唐诗/poet.song.212000.json','["邊角悲鳴霜撲地，將校寧甘潑寒戲。", "熊旗引隊柳營曉，大羽插腰生意氣。", "虎皮半捲并鐵刀，臂鞲蜀錦團鵰袍。", "士不敢喘那敢驕，肅聽號令惟所操。", "撚絃唾手試弓刀，例物角花金椀的。", "左軍右軍分兩翼，簇簇飛星點紅礫。", "一麾白羽人肩摩，三軍歡踴聲鳴鼉。", "教頭喝賜誰最多，鐵絲箭者無以過。", "大風飛雲歌漢歌，安得一箭開關河。", "漢家君王自神武，邊頭將臣如卧虎。", "覺吾目中無此虜，待射金牌大郎主。", "石崖天齊勒碑頌，那知援筆無燕許。"]'),
('9218dd59-3aae-4ad3-b45d-c6bda18322d1','呈和仲','方岳','宋','宋诗','song-poetry','','[]','何須不踏東華土，何須不吃吳山水。',208,'全唐诗/poet.song.212000.json','["何須不踏東華土，何須不吃吳山水。", "同時輩流半霄漢，徑上銀臺披鳳尾。", "幾曾禮部奏第一，十載青衫百寮底。", "相公之甥逕甚捷，頭放稍低那得爾。", "直不虎關非狂耶，胡不愛官幾歷詆。", "吏銓教授古括州，管領風雲二三子。", "孔堂絲竹秋雨荒，絃誦琅然頓盈耳。", "深衣楚楚有古意，相對青燈夜分語。", "六鼇雲海渺何許，寶字森羅風日美。", "人言欠渠揮翰手，倘及春江戒行李。", "寒氈對客澹無欲，清夢不勞曾到此。", "談經歸來喜津津，手洗翠缶香傾銀。", "何以娛子白髮親，梅花中有無邊春。"]'),
('93daaf9d-7710-4861-9f71-7780eda9fc4c','送童子盧觀國試玉堂','方岳','宋','宋诗','song-poetry','','[]','長亭柳色鵝兒黄，花事欲動春風香。',160,'全唐诗/poet.song.212000.json','["長亭柳色鵝兒黄，花事欲動春風香。", "佩觿徑趨白玉堂，淋漓翰墨孤鳳翔。", "黑頭相公紫微郎，金貂玉魚垂兩璫。", "携立螭陛穿鵷行，至尊龍飛御明光。", "催班賜見清蹕長，天顔喜動絺繡裳。", "宮花綾織雲綿章，殿前拜舞籍奉常。", "跨馬入省繙縑緗，讀書晝靜珠琅琅。", "風日不到蓬山傍，文字零落冰雪腸。", "要令汗竹俱流芳，子豈不見晏與楊。", "銅根鐵幹森秋霜，萬牛挽之供棟梁。"]'),
('0eb00c8e-909b-4ecb-8c0e-26d3955d91b4','次韻汪卿','方岳','宋','宋诗','song-poetry','','[]','霜洗梅花春滿握，夜寒吹老城頭角。',224,'全唐诗/poet.song.212000.json','["霜洗梅花春滿握，夜寒吹老城頭角。", "瑣窗硯作離騷香，吐句不教花莫落。", "裁量要是修月手，我欲追隨慙筆閣。", "平生萬事不挂口，愛詩苦未厭溪壑。", "有人肯築風騷壇，敢不束甲三距躍。", "當時只料孤鳳凰，不與雞羣同抱啄。", "拔旗趙壁决此勝，金鼓俄驚自天落。", "一嗔縱得馬辟易，已覺楚歌聲四薄。", "夜光明月以暗投，心甚愛之顔有怍。", "公詩端似大國晉，玉帛諸侯頼聯絡。", "倘令吳楚主夏盟，獲麟正恐春秋作。", "歙州雖小水如練，漚鳥亦知文字樂。", "此盟定自不可寒，把住梅花更商確。", "夜窗或許時過從，莫問聖清與賢濁。"]'),
('1eb0c372-9fef-4be9-b37e-d482d8a0e715','次韻曹宰聽舅氏彈琴','方岳','宋','宋诗','song-poetry','','[]','有客夜鼓龍門琴，風露漠漠侵秋庭。',198,'全唐诗/poet.song.212000.json','["有客夜鼓龍門琴，風露漠漠侵秋庭。", "妙彈幽響落指外，此意難以兩耳聽。", "參橫斗轉四山寂，但聞別鶴之夜怨，離鸞之晨吟。", "挐音誰適鳴滄浪，寅緣葦間情衋傷。", "忽然浩歎聲軒昂，二十八宿俱韜藏。", "少焉月出流寒光，但見山蒼蒼兮江泱泱。", "爾乃舂容大篇，寂寞短章。", "謬攸一笑天所吝，亦恐此樂不可常。", "吾當爲君譜入渭陽操，莫彈履霜似傷孝。", "碧桐翠竹夜生寒，折楊皇華何足道。", "人生百年幾今夕，我思古人心忽忽。", "黄金擬鑄鍾子期，此言每墮槐安國。"]'),
('acf83189-119b-4142-a8d0-8e769312e5a7','諸公賦翠毛筆因次韻爲羊毛筆嘆','方岳','宋','宋诗','song-poetry','','[]','髯參草卧殘陽浦，拔毛竟作文中虎。',166,'全唐诗/poet.song.212000.json','["髯參草卧殘陽浦，拔毛竟作文中虎。", "金華化石久已陳，玉署摛辭疾於羽。", "醉猩耆酒少遒勁，狡兔飽霜工媚嫵。", "磔殘鼠鬚肯收錄，剝落雞毛誰比數。", "文章諸公多好奇，往往得名專翰府。", "乃知草聖不世出，罕識公孫大娘舞。", "君不見華元分羹奇禍作，糜身鼎烹竟無補。", "又不見晉宮灑鹽兒女曹，憤鬰令人噤難吐。", "物生正係遭不遭，敢向詞林嘆辛苦。", "椽書大硯如南溟，吾其鵬乎爾鸚鵡。"]'),
('c8611ac4-3ec9-4707-8243-558d10236682','僮有彈鷺寘池上者予解其縛縱之而不去蓋不飲不食拳立而不徙者七八日作詩返之故巢','方岳','宋','宋诗','song-poetry','','[]','煙藤羃羃驚蛇蟄，雪羽飛飛羣鷺集。',176,'全唐诗/poet.song.212000.json','["煙藤羃羃驚蛇蟄，雪羽飛飛羣鷺集。", "相莜抱子林欲深，經始營巢茅未葺。", "銜枚適與惡少逢，落彈不虞奇禍及。", "毳殘玉點偶賒死，頸曲銀鉤竟遭執。", "急呼解縛縱使歸，胡自拘囚長竚立。", "白蘋久失鴻鴈洲，紅豆不窺鸚鵡粒。", "申胥併日負秦庭，莊舄愁吟思越邑。", "云何垂翅但摧頹，豈欲言情輒於悒。", "子其休矣勿介介，山曰歸哉寧汲汲。", "放之雲壑卧蘿蔦，期以春臯伴簑笠。", "臨去一語更丁寧，從此謹毋輕出入。"]'),
('1c3d0ba3-2466-4e41-8a8b-b562a1f1c0d3','陶倅母夫人挽詩','方岳','宋','宋诗','song-poetry','','[]','戴君手持黄卿辭，邀我爲作陶母詩。',240,'全唐诗/poet.song.212000.json','["戴君手持黄卿辭，邀我爲作陶母詩。", "婦言婦德不出梱，縱有令則何繇知。", "崑山生玉草木潤，欲識其母觀其兒。", "一經科目摘髭易，五丈夫子皆瓌奇。", "黄卿與世少諧可，老筆爲寫青琉璃。", "嘅予一讀怳如洗，酸風淒斷漳淮湄。", "往年將父問里舍，病痱中道驚相持。", "秋山黯慘過縣尹，取急欲謁誰何醫。", "天方罪予不孝子，行未半驛翁阽危。", "雲崩日落竟千古，永始此路行無期。", "爾時縣尹有母遺，鮐背兒齒當期頤。", "潘輿佳日訪桃李，一舍而迎聊遨嬉。", "人間僅僅幾寒暑，亦已奔月歸何時。", "暮雲春樹渺千里，同一哀痛難平治。", "此詩莫遣挽郎讀，天荒地老松風悲。"]'),
('d3b70be5-abe4-491b-ab94-9c4003eccc73','次韻徐宰三雪','方岳','宋','宋诗','song-poetry','','[]','春其幾何到端木，三信東風銀粟粟。',288,'全唐诗/poet.song.212000.json','["春其幾何到端木，三信東風銀粟粟。", "眼驚天地有奇事，喜不自持詩陸續。", "爾時茅屋亦堪畫，有竹寧甘食無肉。", "多年裋褐夜不暖，紫鳳天吳共伸縮。", "袖中書冊字蠅頭，略借瑶階明月燭。", "忍饑未慣願歲豐，口雖不言以心祝。", "一生懶作貸米書，自汲溪水煮溪蔌。", "荷鋤久欲眠秋雲，飛翰誰驚落春瀑。", "人言安用管城子，家本田家一犂足。", "分吾此雪謝老天，高吟信手三千牘。", "蟄雷之腹庶其飽，殺氣猶纏當肅穆。", "彼姝者子羔酒融，夜寒斗帳金花蹙。", "何如石鼎鳴澗松，風味之高未渠恧。", "先生堅卧袁安廬，正坐不能甘鹿鹿。", "纔晴便欲出畦麥，止可掛書騎健犢。", "脫蓑許過宓賤堂，金杯亦眩淵明菊。", "清談吾獨爲詩耳，卷軸今如春筍束。", "我所思兮孤鳳翔，欲往從之老鶬禿。"]'),
('57f6cfd3-9dc0-4636-87a4-99c4181bb488','再次韻因索紙筆','方岳','宋','宋诗','song-poetry','','[]','誰何扣門聲啄木，踏雪逢迎寒起粟。',288,'全唐诗/poet.song.212000.json','["誰何扣門聲啄木，踏雪逢迎寒起粟。", "詩筒過我捷於羽，墨滑豈供貂尾續。", "雲鏘孤響落瓊璈，頓覺聞韶不知肉。", "膽驚强韻婁吐舌，春溢長箋手幾縮。", "鈍根難除撚髭苦，夜凡晶熒殘幾燭。", "管城子老免冠謝，久不中書三致祝。", "擇交正自欠楮生，兩窮相值聲蔌蔌。", "端凝頼有弘農陶，時一浴之雲外瀑。", "山寒亦聞泓有語，未致兩生長不足。", "誰其下榻徐孺子，不以寒暄事竿牘。", "徑須回旋作詩供，縱使長貧顔有穆。", "書生得句如得官，無以藉之眉爲蹙。", "雲煙繭紙生踴躍，涕唾犀毫負慙恧。", "倘非渠輩稱揮灑，未見無虞堪即鹿。", "殘風剩月幸見分，卷軸今當汗駒犢。", "夜窗賡載有餘暇，牋注離騷到蘭菊。", "雪鋪玉箋烏絲欄，一一手抄森似束。", "毋令千載韓退之，作傳譏嘲老而禿。"]'),
('46959aca-8c8c-4fff-8be1-62acc2cea811','三次韻答惠蘭亭紙翠毫筆','方岳','宋','宋诗','song-poetry','','[]','半生書癡蟲蠹木，不管缾無舊儲粟。',288,'全唐诗/poet.song.212000.json','["半生書癡蟲蠹木，不管缾無舊儲粟。", "青燈竹屋雪村寒，聲鳴益悲夢難續。", "晚菘早韭有書味，詩腹冰清鄙粱肉。", "邇來毛穎會稽楮，乃欺余貧共羞縮。", "夜深磨墨訴石平，五色榮光隨下燭。", "窗間錯落驚暴富，每見兒曹輒相祝。", "奇牋勿污寒具油，玩弄其毋當肴蔌。", "觚稜古瓦亦懽喜，春浪生池含雪瀑。", "霜毫世輩何多耶，向者心期一夔足。", "吾生但識鼠鬚健，未省禽魚堪汗牘。", "重綈十襲不敢吮，誰作猗那頌於穆。", "最憐長安驕騃兒，翠毫入手春山蹙。", "平時作葉供媚嫵，拔羽詩書豈吾恧。", "何知梳洗曉鬟綠，解出文章排五鹿。", "策勛翰墨玉牀籍，未羨香車駕金犢。", "如聞六宮今弋綈，釵梁不飾黄花菊。", "細鈿高朵花爲筆，創巧寧知誰縛束。", "吁嗟文采信爲累，莫拯多生羽毛禿。"]'),
('9aee877f-8bec-46ad-a0a7-ba0f76f6567a','黄宰致江西詩雙井茶','方岳','宋','宋诗','song-poetry','','[]','黄侯授我以江西詩禪之宗派，瀹我以雙井老仙之雪香。',200,'全唐诗/poet.song.212000.json','["黄侯授我以江西詩禪之宗派，瀹我以雙井老仙之雪香。", "磚爐春著兔毫玉，石鼎月翻魚眼湯。", "夜窗搜攪十年讀，候蟲鳴秋聲殷牆。", "乃翁詩家第一祖，不用棒喝行諸方。", "掀翻杜陵自作古，夜半衣缽誰升堂。", "單傳橫出二十六，未許歙梅洪鴈行。", "雅聞滕閣藏墨本，欲往從之山阻長。", "牙籤大冊忽在眼，荒苔茅屋森珩璜。", "東湖柳色入眉宇，君其幾代之諸郎。", "不離文字話祖意，傳燈肯與留山房。", "寧知三生受昏闇，縱有此燈無此光。", "宜州戍樓山月苦，茫茫參到無何鄉。"]'),
('03b1257c-3a8e-4598-9c8f-cc36da03590e','合紙屏爲小閣畫卧袁訪戴其上名之曰聽雪各與長句  其一','方岳','宋','宋诗','song-poetry','','[]','空山十日雪塞門，天荒地老無行人。',128,'全唐诗/poet.song.212000.json','["空山十日雪塞門，天荒地老無行人。", "蘆花敗絮不堪著，山石夜裂蒼皮皴。", "奇寒中人僵贔屭，樵汲路迷瓶粟既。", "駕風萬鶴危欲仙，此腹久無煙火氣。", "家家暖入紅麒麟，誰肯問訊推柴荆。", "洛陽令亦可人者，惜哉史不書其名。", "此公要亦非知我，志士從前例寒餓。", "倘令開口向凡兒，寧忍春雷曲肱卧。"]'),
('90771695-5749-49d0-9453-a4a42195ab7c','合紙屏爲小閣畫卧袁訪戴其上名之曰聽雪各與長句  其二','方岳','宋','宋诗','song-poetry','','[]','颼颼飀飀風落木，淅淅瀝瀝聲撼竹。',128,'全唐诗/poet.song.212000.json','["颼颼飀飀風落木，淅淅瀝瀝聲撼竹。", "乾坤不夜起開關，一港玻璃四山玉。", "我所思兮渺中洲，幽懷欲寫誰與酬。", "世間餘子不足語，乘興徑上漁翁舟。", "未到山陰竟回棹，歘去驟來何草草。", "神交如必面相朋，逸韻高情一如掃。", "寧可一生無此人，不可一日無此君。", "襟期何必戴安道，玉立寒青自不羣。"]'),
('83d43b1f-9a2e-41c3-8fd5-cf854cdcf4f2','題董一之花木抄','方岳','宋','宋诗','song-poetry','','[]','君不見王子猷，剡溪夜雪之孤舟。',240,'全唐诗/poet.song.212000.json','["君不見王子猷，剡溪夜雪之孤舟。", "此翁百好不入眼，而雅與竹深相投。", "君不見陶淵明，徽絃不具之古琴。", "東籬把菊偶然耳，人或作圖傳至今。", "吾何曾識董一之，於此略已心相知。", "事治好春繞菴屋，豈有俗子能爾爲。", "江風山月無盡藏，時一吐出胸中奇。", "與茶作經花作譜，銓次蘅若蘭蓀蘺。", "秦碑晉帖了真贋，硯石錯落書參差。", "邇來抄注到儕友，唾視錢癖何人斯。", "長卿但有四立壁，無一持贈長嗟咨。", "煩爲傳聲語花草，倘可千里同襟期。", "吾聞奇章公石李成畫，在廬九老湘九疑。", "煙雲渺綿不可狀，世乏佳士當歸誰。", "君其持以問太空，所不與者如此詩。"]'),
('94891b66-e1ac-4bab-98a1-e0e87106241b','次韻徐宰雪句','方岳','宋','宋诗','song-poetry','','[]','雪花飛盡江頭蘆，秋崖有屋窗未糊。',336,'全唐诗/poet.song.212000.json','["雪花飛盡江頭蘆，秋崖有屋窗未糊。", "嗅梅自可了孤寂，燃竹相與留須臾。", "傳觀玉帝整嚴衛，雜沓環佩紛前驅。", "夢隨姑射扣瑶陛，身入閶闔排銀鋪。", "明毫一色寶階浄，端木六出瓊林孤。", "綠章封事見名姓，白霓仙子軒眉鬚。", "乃知天喜愛民尹，分此雪與耕田夫。", "山川盡入古圖畫，園林已作春規模。", "逢船誰可載書共，松醪未擬炊書沽。", "金僕姑寒憶戰士，玉玲瓏煖無歌姝。", "煮茶安用碧跳脫，眠蓑自勝紅氍毹。", "盟鷗久與說心腹，買犢大欠耕膏腴。", "頻年歲入少生計，何日詔下蠲田租。", "甑塵但憂脫粟飯，甌滑未議羹蓴鱸。", "羣公豈堪立仗馬，賤子只跨尋詩馿。", "第令吾民不知餒，如彼蔡人何足誅。", "衝寒索米徙者衆，啼饑載道携其孥。", "邊烽有警事方爾，民瘼未軫天地無。", "轅門誰曳丈二組，羽書夜下尺一符。", "少遲獸獮渤海盜，當復蟻浮高陽徒。", "平淮有碑倘須刻，筆墨可但唐宗儒。"]'),
('3ff85ddd-d384-4939-8eb9-ead4617d712e','趙丞饟酒蟹獐巴','方岳','宋','宋诗','song-poetry','','[]','公子無腸秋滿殻，山吏無魂飽霜蘀。',64,'全唐诗/poet.song.212000.json','["公子無腸秋滿殻，山吏無魂飽霜蘀。", "寒浦醉骨糟丘臺，鳴髇數肋凌煙閣。", "故人斜封三印紅，秋江已在吾目中。", "角聲喚起邊城夢，雪岸打圍蘆荻風。"]'),
('13d5431b-2785-49b4-bffe-c64d3de71c9e','元夕病中','方岳','宋','宋诗','song-poetry','','[]','家貧近市常喧啾，燈夕無燈冷於水。',192,'全唐诗/poet.song.212000.json','["家貧近市常喧啾，燈夕無燈冷於水。", "罷參法喜深炷香，示疾維摩低隠几。", "梅花相親不余負，酒盞成疎竟誰使。", "一生甘作癡凍蠅，百方莫趁追奔螘。", "頗聞捷奏箭飛書，想見昇平花作市。", "醉吹笙篴舞蛾眉，春入鼓鼙騰馬耳。", "落釵敖盪少年事，彈鋏悲歌游俠子。", "寧種松風眠隠居，自斸芝田餐甪里。", "掉頭塵土誰枉尺，過眼紛華不盈咫。", "吾生如月浪中翻，人情得蜜刀頭舐。", "內觀各自普光明，頓悟中生大驩喜。", "紞如三鼓雨聲寒，睡思正濃姑舍是。"]'),
('f1ea025d-7950-411a-9efe-5ab2a1ddd0fd','次韻謝兄饋李','方岳','宋','宋诗','song-poetry','','[]','往事轉頭如墮甑，獨枕書眠知雋永。',64,'全唐诗/poet.song.212000.json','["往事轉頭如墮甑，獨枕書眠知雋永。", "竹窗風好直萬金，不涉世間榮辱境。", "東山之屐北山移，坐覺室邇長相思。", "碧脆已冰烹伏雌，未害踏雲來話詩。"]'),
('482dfee1-a7a7-46ac-86a2-418c5ec92f70','非瓊花','方岳','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','舊傳瓊花無與雙，專奇擅美名此邦。',208,'全唐诗/poet.song.212000.json','["舊傳瓊花無與雙，專奇擅美名此邦。", "江南清夢入詩府，安得一念令心降。", "去年騎鶴揚州住，斗酒屢眠雲霧窗。", "月寒雪冷花未吐，正爾俗葉凡株樁。", "心期妙處在真實，不假羽節青霓幢。", "今春訪花吾第一，自折繁枝盛翠缸。", "橫看倒睨掉頭語，前語後賦何其哤。", "真珠碎簇玉蝴蝶，直與八仙同一腔。", "聞名見面足笑莞，强爲花辨幾愚憃。", "有如巨賢雜羣小，望而可識爲奇厖。", "陳餘張耳信相似，一等人耳無純尨。", "忠耶佞耶豈難別，祝鮀不類關龍逢。", "試持此論訊后土，謂予不信如長江。"]'),
('364327c8-d469-4530-b3af-e869068f3d71','再用韻酬朱行甫','方岳','宋','宋诗','song-poetry','','[]','夢中翠鳳飛來雙，駕言后土遜名邦。',208,'全唐诗/poet.song.212000.json','["夢中翠鳳飛來雙，駕言后土遜名邦。", "手持玉簡判紅紫，斂袂欲以詩城降。", "粹容喜動日月角，揖我入對玲瓏窗。", "爲言瓊花返蓬閬，下界久矣無根樁。", "乃今存者贋本耳，補亡以紿青油幢。", "人間識真蓋亦寡，載酒嘉賓寧論缸。", "黄冠誕譎謹勿信，傳訛聽舛其言哤。", "爲花作辨誰氏子，謬妄補入黄鍾腔。", "耳庸目陋惑世俗，其罪不能三赦憃。", "朱雲之孫亦奇士，文有氣骨豐而厖。", "謂瓊赤玉匪爲白，不比俗論紛茸尨。", "詩筒往來捷於響，夜發嚴鼓聲逢逢。", "咨爾岳爲謝此老，壯哉寸管飛濤江。"]'),
('3015cae5-642f-439c-991f-4f47c7e20d4c','月下大醉星姪作墨索書迅筆題爲醉矣行','方岳','宋','宋诗','song-poetry','','[]','吾醉矣，吾醉矣，醉語雖强難舉似。',293,'全唐诗/poet.song.212000.json','["吾醉矣，吾醉矣，醉語雖强難舉似。", "何年開闢有乾坤，日月左旋如磨螘。", "尊盧赫胥一聚塵，檮杌春秋幾張紙。", "道家者流李老君，儒家者流孔夫子，等一浮名世間耳。", "煙霏霏，冢纍纍，青山良是白骨非。", "欲呼古人呼不醒，待呼得醒將何如。", "世情冷暖翻覆手，人生短長屈伸肘，安用黄金印如斗。", "君不見顔子白頭纔十九，要與彭鏗骨同朽。", "天地荒老生古愁，所不負予如此酒。", "千古在前，萬古在後。", "著我中間，渺然何有。", "亦知本是麋鹿羣，那解作人牛馬走。", "白魚如玉紫蟹肥，秋風欲老蘆花飛。", "酒酣月落喝便住，螭虬蟠攫霜毫揮。", "吾婦曰君醉耶，吾姪曰非醉也。", "謂吾醉者固不然，非醉亦非知我者。", "花影滿身扶不起，此紙不知何等語。", "明朝勿與醒者傳，笑倒渠儂吾醉矣。"]'),
('1f949a6b-9b70-40a0-9a03-c64764135a2a','題祁門岳王廟','方岳','宋','宋诗','song-poetry','','[]','神京鱗介腥衣裳，三精霧塞天地光。',168,'全唐诗/poet.song.212000.json','["神京鱗介腥衣裳，三精霧塞天地光。", "鼪啼鼯笑紛披猖，中分宇宙尊犬羊。", "誰其與者淪綱常，受計於虜扼我吭。", "王心凜凜天蒼蒼，以次來縛歸朝堂。", "自南自北諾已償，焉用與虜爲胥戕。", "爲讐報仇胡不臧，至今淮塹爲河湟。", "每觀王傳心摧傷，怒髮爲立膽爲張。", "皇畀予邑於祁閶，聞王有像北山岡。", "欲往從之潔予觴，簡書之言不我遑，今且去此何敢忘。", "牲肥酒香時日良，金戈鐵馬山茫茫。"]'),
('41a59532-b9c9-407d-b0c0-79408ee3eacf','戲呈君用','方岳','宋','宋诗','song-poetry','','[]','秋崖初無負郭二頃田，向來耕舍寒炊煙。',260,'全唐诗/poet.song.212000.json','["秋崖初無負郭二頃田，向來耕舍寒炊煙。", "負薪行歌遭婦駡，往往倒崖底之枯松，煮崖邊之飛泉。", "龜腸怒吼賣牛具，龍骨倒挂行蝸涎。", "乃以農自目，其然豈其然。", "胥山之窮固亦無一錢，較之於我猶差賢。", "白頭把筆耕六籍，芸人芸己皆逢年。", "可曾腰斧響空谷，但聞種之以弘農陶，耨之以絳人玄。", "先生之號則不可，北山久欲移文鎸。", "吾嘗觀諸朝，左右分兩銓。", "若使后夔降典夷作樂，各違所長非所便。", "我今手招白雲與渠語，兩易其任盟當堅。", "君農我樵萬山綠，依舊司存雨露邊。", "亦不必承明之廬九入，亦不必歲中之官九遷。", "共披煙蓑拜新號，疏駁不到松風前。", "爛柯扣角醉眠熟，佳話留與山中傳。"]'),
('90cadad8-870b-4f51-b843-75b407c27dff','次韻劉簿寄示','方岳','宋','宋诗','song-poetry','','[]','塵世崎嶇天一握，俗子追奔蝸兩角。',224,'全唐诗/poet.song.212000.json','["塵世崎嶇天一握，俗子追奔蝸兩角。", "先生宴坐心平夷，矮屋打頭甘寂寞。", "手提老筆挾霜氣，合上蓬山直延閣。", "高人乃亦主簿耳，往往胸中自丘壑。", "銀鉤寶唾俱入妙，令我見之生踴躍。", "日酣昨暮春睡濃，柳外叩門誰剝啄。", "一書自直十從事，况有驪珠光錯落。", "風簷急轉百迴讀，花草愁深顔色薄。", "放余許出半頭地，未敢以信而以怍。", "譬如駑駘受刷飾，金環壓轡青絲絡。", "猗那清廟吁已遠，下里巴詞可無作。", "候蟲鳴秋鳥鳴春，美惡則殊俱自樂。", "焚香危坐試品藻，頗亦敢言余論確。", "公詩雖淡朱絃清，我詩雖雅黄鍾濁。"]'),
('d8b52148-2bb6-4a0b-92a1-ca38f6ca3d28','次韻十二神體  其一','方岳','宋','宋诗','song-poetry','','[]','鼠技易窮誰比數，牛衣政可眠春雨。',96,'全唐诗/poet.song.212000.json','["鼠技易窮誰比數，牛衣政可眠春雨。", "虎窺九關高莫捫，兔禿千毫老無補。", "龍嬰鱗逆事可驚，蛇畫足添心獨苦。", "馬寧坂下困鹽車，羊勿夢中翻菜圃。", "沐猴從爾楚人冠，荒雞寧起劉郎舞。", "狗監無煩誦子虛，豕亥縱分吾不取。"]'),
('2db82671-0c76-472c-99fc-648e11c70f98','次韻十二神體  其二','方岳','宋','宋诗','song-poetry','','[]','鼠穴不能容窶數，牛角自歌深夜雨。',96,'全唐诗/poet.song.212000.json','["鼠穴不能容窶數，牛角自歌深夜雨。", "虎頭肉食飛者誰，兔窟趺居狡何補。", "龍籍亦保終當還，蛇杯生疑空自苦。", "馬曹誤我盍歸田，羊羹禍人寧學圃。", "猴拳蕨嫩鮮可烹，雞毛菜香醉言舞。", "狗尾時時遣續貂，豕白獻慙吾不取。"]'),
('5306b13c-cb93-4443-aca8-21ccbd642613','立春','方岳','宋','宋诗','song-poetry','','[]','適禁樂令春啞，先辦秋治社聾。',28,'全唐诗/poet.song.212000.json','["適禁樂令春啞，先辦秋治社聾。", "銀勝鬢毛班白，瓊絲菜縷青紅。"]'),
('0670c124-c101-47e7-bd79-7defdaef1d77','牡丹多不開花','方岳','宋','宋诗','song-poetry','','[]','韶風萬物照我廬，昨歲駢頭今併疎。',32,'全唐诗/poet.song.212000.json','["韶風萬物照我廬，昨歲駢頭今併疎。", "自是愛花心不足，何知物物有乘除。"]'),
('894666e6-33c5-4804-9b49-4ea0fa9af4ec','山居七詠 經史閣','方岳','宋','宋诗','song-poetry','','[]','買書堆屋當藏珍，硯水生春玉作麟。',32,'全唐诗/poet.song.212000.json','["買書堆屋當藏珍，硯水生春玉作麟。", "此老大蒙稽古力，至今疎草墨花新。"]'),
('f0ed6e29-f703-4a5e-859e-20ffff9c76aa','山居七詠 省齋','方岳','宋','宋诗','song-poetry','','[]','聖處終難舉似人，二三子在最情親。',32,'全唐诗/poet.song.212000.json','["聖處終難舉似人，二三子在最情親。", "於中檢點平生看，香縷縈簾眇此身。"]'),
('666e2c0d-2ab7-4bd7-8436-7132ccd56e9b','山居七詠 中隠洞','方岳','宋','宋诗','song-poetry','','[]','終南少室苦躋攀，已入先生一笑間。',32,'全唐诗/poet.song.212000.json','["終南少室苦躋攀，已入先生一笑間。", "不學劉安便仙去，屋邊儘自有佳山。"]'),
('0d148de5-4664-4971-adac-e0ebad4cab83','山居七詠 丹桂軒','方岳','宋','宋诗','song-poetry','','[]','何年進入玉華宮，香到君王紫禁楓。',32,'全唐诗/poet.song.212000.json','["何年進入玉華宮，香到君王紫禁楓。", "月府歸來衫袖冷，蟾蜍滴露洗秋紅。"]'),
('98562d63-9beb-4d93-9f79-f9615476faad','山居七詠 乳泉','方岳','宋','宋诗','song-poetry','','[]','正爾清寒與世殊，地靈不受柳詩愚。',32,'全唐诗/poet.song.212000.json','["正爾清寒與世殊，地靈不受柳詩愚。", "晝長何似醒幽夢，碧玉壺深貯雪腴。"]'),
('e5c77110-44c3-4964-a04b-c272a50466c7','山居七詠 瑞萱堂','方岳','宋','宋诗','song-poetry','','[]','携得春歸通德門，等閒萬木亦霑恩。',32,'全唐诗/poet.song.212000.json','["携得春歸通德門，等閒萬木亦霑恩。", "母桃未熟蓬萊淺，連夜吹開堂北萱。"]'),
('b3de65a2-9241-4e81-b311-bdeed7c26945','山居七詠 湛然亭','方岳','宋','宋诗','song-poetry','','[]','一念惟餘睡作魔，鷗閒不與世同波。',32,'全唐诗/poet.song.212000.json','["一念惟餘睡作魔，鷗閒不與世同波。", "邇來定力空諸妄，如以摩尼照濁河。"]'),
('51088dbc-f1c5-466f-bd67-b3620231c68b','趙僉見過不值有詩次韻  其一','方岳','宋','宋诗','song-poetry','','[]','草廬不慣高軒過，莫怪樵青久未譍。',32,'全唐诗/poet.song.212000.json','["草廬不慣高軒過，莫怪樵青久未譍。", "一片斷雲尋宿處，有詩誰與錄侯鯖。"]'),
('ffc6c898-45f1-4146-b175-015a5bff10c4','趙僉見過不值有詩次韻  其二','方岳','宋','宋诗','song-poetry','','[]','向來曾管重湖月，五老當門但讀書。',32,'全唐诗/poet.song.212000.json','["向來曾管重湖月，五老當門但讀書。", "見說邦人猶感慨，恨予不學藺相如。"]'),
('6c09db80-0646-4c9f-9d2b-0181daafb334','湖山紀遊  其一','方岳','宋','宋诗','song-poetry','','[]','兩山南北詩三百，付與秋風趙倚樓。',32,'全唐诗/poet.song.212000.json','["兩山南北詩三百，付與秋風趙倚樓。", "忽憶老逋墳下路，梅花夜雪上孤舟。"]'),
('97403abb-303f-4dc6-b1de-96e6e7616be7','湖山紀遊  其二','方岳','宋','宋诗','song-poetry','','[]','鳳凰城裏花如海，選集諸人守部門。',32,'全唐诗/poet.song.212000.json','["鳳凰城裏花如海，選集諸人守部門。", "此老久漁雙脚浪，島烟湖霧又黄昏。"]'),
('9a560248-fd96-4aa2-9e0e-eda3d84882a2','次韻趙端明萬花園  其一','方岳','宋','宋诗','song-poetry','','[]','萬花錦繡同民樂，不比青山獨樂園。',32,'全唐诗/poet.song.212000.json','["萬花錦繡同民樂，不比青山獨樂園。", "辦得春風共花醉，儘教蝶閙與蜂喧。"]'),
('442c9a19-4f8d-4cf8-bead-8c5da02fe29f','次韻趙端明萬花園  其二','方岳','宋','宋诗','song-poetry','','[]','和氣能消塞上寒，却於邊事頗相干。',32,'全唐诗/poet.song.212000.json','["和氣能消塞上寒，却於邊事頗相干。", "酒旗歌鼓秋千外，新綠柔紅又幾般。"]'),
('2404a832-9315-4292-9c77-b75d87fc711c','次韻趙端明萬花園  其三','方岳','宋','宋诗','song-poetry','','[]','風逗湘簾雪絮飛，池痕雨過麴塵肥。',32,'全唐诗/poet.song.212000.json','["風逗湘簾雪絮飛，池痕雨過麴塵肥。", "揚州十里春猶在，細柳營深解鐵衣。"]'),
('1015fc74-3ae1-42c8-8b82-a4057f49dc4c','次韻趙端明萬花園  其四','方岳','宋','宋诗','song-poetry','','[]','玉簫吹斷知何許，柳徑日長嬌燕舞。',32,'全唐诗/poet.song.212000.json','["玉簫吹斷知何許，柳徑日長嬌燕舞。", "鶴城半掩人未歸，數點春愁杏花雨。"]'),
('3b81dd3e-e314-4dc7-978c-19d77c3d6efc','贈相士','方岳','宋','宋诗','song-poetry','','[]','老來學劍已無成，眼底邊塵猝未清。',32,'全唐诗/poet.song.212000.json','["老來學劍已無成，眼底邊塵猝未清。", "此輩束之高閣耳，且容黄犢伴春耕。"]'),
('f2fff00e-fbbe-4b98-a019-6db506715a50','雪中觀梅','方岳','宋','宋诗','song-poetry','','[]','落盡梅花合一杯，雪深無復舊莓苔。',32,'全唐诗/poet.song.212000.json','["落盡梅花合一杯，雪深無復舊莓苔。", "山谿莫遣人行破，安得酒從天上來。"]'),
('fe95dc3a-d9ee-425f-8df7-7c2ebf184012','月中觀梅','方岳','宋','宋诗','song-poetry','','[]','何物蒼頭不自量，踏梅踏月上山堂。',32,'全唐诗/poet.song.212000.json','["何物蒼頭不自量，踏梅踏月上山堂。", "月明幸是無痕跡，可惜瓊瑶一徑香。"]'),
('18ad8913-6b5e-4ca3-900b-97cc95c1f08a','病中','方岳','宋','宋诗','song-poetry','','[]','折鐺破釜底堪脩，縱使脩成已不侔。',32,'全唐诗/poet.song.212000.json','["折鐺破釜底堪脩，縱使脩成已不侔。", "誰與吾身自珍重，暮年藥籠漫勞收。"]'),
('2da39290-ec03-48c2-a7e2-4dd37cb877e9','觀池中鸂鶒逐其自外來者','方岳','宋','宋诗','song-poetry','','[]','久住成家不見猜，傍船水暖逐毰毸。',32,'全唐诗/poet.song.212000.json','["久住成家不見猜，傍船水暖逐毰毸。", "岸沙能占春多少，長恐諸侯客子來。"]'),
('0e7d163e-2842-47a6-bc8e-2f06255b29d1','有歎','方岳','宋','宋诗','song-poetry','','[]','月如此好吳牛喘，雪不勝寒蜀犬狺。',32,'全唐诗/poet.song.212000.json','["月如此好吳牛喘，雪不勝寒蜀犬狺。", "莫怪叔孫并祿父，不知周孔是何人。"]'),
('53c6c531-9375-4cba-9eb1-0aec6c9e32a2','小醉','方岳','宋','宋诗','song-poetry','','[]','日淡風恬獨倚筇，一池草色自溶溶。',32,'全唐诗/poet.song.212000.json','["日淡風恬獨倚筇，一池草色自溶溶。", "我猶未醉春先醉，政不關渠琥珀濃。"]'),
('ca991a67-7423-401b-a34e-314a76e1905a','山中  其一','方岳','宋','宋诗','song-poetry','','[]','寂莫空山久掩扉，殘書誰與解重圍。',64,'全唐诗/poet.song.212000.json','["寂莫空山久掩扉，殘書誰與解重圍。", "推豗時作橐駝坐，恍惚化爲蝴蝶飛。", "春事已歸雙雪鬢，生涯盡在一荷衣。", "夜寒扣角悲聲壯，但得牛肥道亦肥。"]'),
('66233e54-d5be-43a4-af13-c59fe1f01cc1','山中  其二','方岳','宋','宋诗','song-poetry','','[]','溪村楊柳好藏鴉，春水池塘已吠蛙。',64,'全唐诗/poet.song.212000.json','["溪村楊柳好藏鴉，春水池塘已吠蛙。", "詩外共誰千里月，雨中老却一山花。", "蝶將夢去客欹枕，燕寄聲來社到家。", "數掩斷籬春且住，莫隨芳草遽天涯。"]'),
('880ac3c7-88b6-4a37-86ee-6a67c2c9cc62','山中  其三','方岳','宋','宋诗','song-poetry','','[]','草草菴居絕似僧，不同劣有髮鬅鬙。',64,'全唐诗/poet.song.212000.json','["草草菴居絕似僧，不同劣有髮鬅鬙。", "空山一夜雷驅雨，老屋四圍雲擁燈。", "詩骨瘦來人似鶴，書幐懶去字如蠅。", "開門桃李俱塵土，春到園林曾不曾。"]'),
('3f38ffa3-04d3-4a3e-a7aa-2f8e70dd9439','山中  其四','方岳','宋','宋诗','song-poetry','','[]','漫道高眠晝掩關，南岡北嶺幾曾閒。',64,'全唐诗/poet.song.212000.json','["漫道高眠晝掩關，南岡北嶺幾曾閒。", "隰桑已作蝦𢋙眼，山笋時窺虎豹斑。", "一味懶堪醫傳僻，五窮技不害詩孱。", "著身何幸山巖裏，多閲人間百險艱。"]'),
('69f9f8c3-4bad-4819-9105-ddb7dd2932b3','山中  其五','方岳','宋','宋诗','song-poetry','','[]','暄風已愜綠陰凉，小簟初橫六尺床。',64,'全唐诗/poet.song.212000.json','["暄風已愜綠陰凉，小簟初橫六尺床。", "如宇宙寬容膝地，與塵埃隔及肩牆。", "鳥烏聲樂櫻桃熟，田舍人忙麥飯香。", "留得壁間雙不借，尚堪鉏水共移秧。"]'),
('28b3ed3d-cb14-4273-bf84-b4e6de5a63f4','山中  其六','方岳','宋','宋诗','song-poetry','','[]','黄紙紅旗總不宜，綠蓑青笠久相知。',64,'全唐诗/poet.song.212000.json','["黄紙紅旗總不宜，綠蓑青笠久相知。", "躬耕莘野一犂雨，親見豳風七月詩。", "老已自催蠶作繭，死時須用豹留皮。", "山深未省人間世，黑白縱橫幾局棋。"]'),
('b9c937ec-3b9d-4da9-b539-211fa987ffb7','山中  其七','方岳','宋','宋诗','song-poetry','','[]','寂寂門無長者車，穿深逗密愜幽居。',64,'全唐诗/poet.song.212000.json','["寂寂門無長者車，穿深逗密愜幽居。", "花能紅白錦相似，山自青蒼畫不如。", "鶴骨政應先狗馬，雛孫殊未辨龍豬。", "皇天老眼何緣錯，高枕松風莫管渠。"]'),
('f5b3d914-1287-4faa-963b-d7f6dd4baecb','山中  其八','方岳','宋','宋诗','song-poetry','','[]','只合空山著此身，野猿骨相鶴精神。',64,'全唐诗/poet.song.212000.json','["只合空山著此身，野猿骨相鶴精神。", "何關親戚儻來物，自笑癡頑向上人。", "手可持杯寧是病，瓶猶儲粟未爲貧。", "公卿滿壁非無畫，不畫公卿畫釣緡。"]'),
('a8a89699-29fc-4d92-9ef7-189b6d8cdc52','山行  其一','方岳','宋','宋诗','song-poetry','','[]','高卧只消雲半間，隨緣栽果與猿攀。',64,'全唐诗/poet.song.212000.json','["高卧只消雲半間，隨緣栽果與猿攀。", "不將此手遮西日，安用吾文移北山。", "雙燕來時春晻靄，一牛耕處月寬閑。", "溪居已息機心久，莫遣驚鷗去不還。"]'),
('32ed696b-3324-482c-9085-bd75a62b3717','山行  其二','方岳','宋','宋诗','song-poetry','','[]','亦笑吾身立兩間，古人轍跡渺難攀。',64,'全唐诗/poet.song.212000.json','["亦笑吾身立兩間，古人轍跡渺難攀。", "斯文在昔豹窺管，吾力不量虻負山。", "有識共知方寸好，無求方得幾多閒。", "一春大欠渠詩在，準擬晴時到處還。"]'),
('dd511d23-a410-455e-a19a-b1b659dbecdd','山行  其三','方岳','宋','宋诗','song-poetry','','[]','老子浮沉田里間，犢車轅許野人攀。',64,'全唐诗/poet.song.212000.json','["老子浮沉田里間，犢車轅許野人攀。", "飲中仙去東西玉，行處人傳大小山。", "天且莫教三月盡，我今無負一生閒。", "春寒正愜牛衣暖，富貴從渠晝錦還。"]'),
('eff02ea5-642b-42c5-8c1c-7d82dfab2d30','約黄成之觀瓊花予不及從以詩代簡  其一','方岳','宋','宋诗','song-poetry','','[]','處處春風自物華，有詩不了醉生涯。',64,'全唐诗/poet.song.212000.json','["處處春風自物華，有詩不了醉生涯。", "別離苦憶平山柳，題品翻疑后土花。", "獨倚斷雲愁戰馬，重歌流水带歸鴉。", "夢寒飛過江南岸，茅屋依然竹徑斜。"]'),
('f52c0ed1-abcc-4852-a0bb-45f4117efae3','約黄成之觀瓊花予不及從以詩代簡  其二','方岳','宋','宋诗','song-poetry','','[]','倦遊久已厭紛華，欲問春蓑未有涯。',64,'全唐诗/poet.song.212000.json','["倦遊久已厭紛華，欲問春蓑未有涯。", "宇宙一杯詩潦草，江湖十載眼昏花。", "恨身不及隨陽雁，將母何如反哺鴉。", "家在青山烟雨外，春寒幾立暮江斜。"]'),
('630e5267-194f-4a06-8911-40bfc41d08c9','次韵紅蕉  其一','方岳','宋','宋诗','song-poetry','','[]','籬根宿草已陳陳，誰護蕉紅到此晨。',64,'全唐诗/poet.song.212000.json','["籬根宿草已陳陳，誰護蕉紅到此晨。", "雪裏寸丹長似舊，人間萬綠未知春。", "翻經曾識觀身法，乞種親爲土地神。", "孤負晚風生酒興，維摩示疾不霑唇。"]'),
('61e13969-fcc3-4309-8f14-746b4de185e1','次韵紅蕉  其二','方岳','宋','宋诗','song-poetry','','[]','山花山草雜前陳，誰解芬芳霰雪晨。',64,'全唐诗/poet.song.212000.json','["山花山草雜前陳，誰解芬芳霰雪晨。", "紅菡萏肥如欲焰，綠玲瓏卷過于春。", "化工有意憐丘壑，老我無詩泣鬼神。", "待喚麯生相暖熟，雨晴禽哢是歌唇。"]'),
('ddb0cdd3-4e78-411d-a38c-61d167a764d2','漫題','方岳','宋','宋诗','song-poetry','','[]','投老自山林，灰寒寸寸心。',48,'全唐诗/poet.song.212000.json','["投老自山林，灰寒寸寸心。", "鶴眠漁屋小，僧語雪籬深。", "夜讀貧如昨，春犂懶到今。", "松根有蒼石，抱膝一長吟。"]'),
('56f6bec7-92a7-417f-aba9-5bb950edf214','次韻羅制幹投贈','方岳','宋','宋诗','song-poetry','','[]','中秋明日是，雨色半蒼厓。',48,'全唐诗/poet.song.212000.json','["中秋明日是，雨色半蒼厓。", "無月可吾子，有詩傾老懷。", "人間棋局面，身外酒生涯。", "莫及邊頭事，誰知濁與淮。"]'),
('7dc678a8-f2a6-46f3-abe2-9d5a52065b65','送石孫赴童科','方岳','宋','宋诗','song-poetry','','[]','聖澤被卷阿，髫童亦置科。',48,'全唐诗/poet.song.212000.json','["聖澤被卷阿，髫童亦置科。", "兩蝸從小競，三豕至今訛。", "亦漫爲官耳，其將奈若何。", "豈關門戶事，翁已老漁簑。"]'),
('ad8df87a-ba06-4540-a002-40982b6b3aa5','澆花','方岳','宋','宋诗','song-poetry','','[]','籬落花無頼，春寒手自治。',48,'全唐诗/poet.song.212000.json','["籬落花無頼，春寒手自治。", "但留根本在，終有發生時。", "雨露曾何擇，山林未易移。", "吾知勤抱甕，一任化工爲。"]'),
('862b941e-1114-4ade-9855-9c8316512367','次韻楚客','方岳','宋','宋诗','song-poetry','','[]','戍角吹將短鬢華，此情付與酒生涯。',64,'全唐诗/poet.song.212000.json','["戍角吹將短鬢華，此情付與酒生涯。", "兩淮無事山如畫，九日明朝菊未花。", "有客敲門緣問事，無田負郭却思家。", "鴈來不带江南信，带得新愁落晚沙。"]'),
('0b3480c6-e788-436b-a5b7-24b3a27d07c1','苻堅之苻從竹者非載賡呈似','方岳','宋','宋诗','song-poetry','','[]','天與西頭掃澤苻，飛英亦暗合孫吳。',64,'全唐诗/poet.song.212000.json','["天與西頭掃澤苻，飛英亦暗合孫吳。", "冰肌起粟愁雲母，水骨浮槎立雪姑。", "竹丈夫哉能崛强，梅兄弟者亦清癯。", "一蓑誰傍篷籠宿，畫出寒江獨釣圖。"]'),
('38323202-cbf7-45dd-9d06-846bc1322a4f','過吳江','方岳','宋','宋诗','song-poetry','','[]','風借吳松十幅蒲，春愁渺渺際烟蕪。',64,'全唐诗/poet.song.212000.json','["風借吳松十幅蒲，春愁渺渺際烟蕪。", "傍船時有能言鴨，舉網今無巨口鱸。", "欲訪龜蒙前杞菊，誰憐麋鹿舊姑蘇。", "一尊重酹沙頭月，物色分流到我無。"]'),
('0051c73c-b70a-4495-b0e4-da220c2f8205','種桂','方岳','宋','宋诗','song-poetry','','[]','山翁不辦碧油幢，辦與秋風斸老樁。',64,'全唐诗/poet.song.212000.json','["山翁不辦碧油幢，辦與秋風斸老樁。", "嚼雪未論香世界，眠雲已愜月軒窗。", "誰分兔臼玉千杵，不費鴻門璧一雙。", "蚤晚乘槎問銀漢，呼童多釀酒成缸。"]'),
('48fe12da-aa23-4caf-8fb3-2b712f8d9ac1','次韻鄭省倉  其一','方岳','宋','宋诗','song-poetry','','[]','月滿長汀晚沐新，一凉猶下耐冠巾。',64,'全唐诗/poet.song.212000.json','["月滿長汀晚沐新，一凉猶下耐冠巾。", "江連碧樹自今古，我與青山迭主賓。", "乞巧未能從帝子，坐愚寧免辱溪神。", "向來鷗鳥間何闊，莫是炎凉不我親。"]'),
('be7c14e3-f4db-4af2-993a-c65e49c1d8f8','次韻鄭省倉  其二','方岳','宋','宋诗','song-poetry','','[]','雨過苔磯片月新，黄琉璃簟岸綸巾。',64,'全唐诗/poet.song.212000.json','["雨過苔磯片月新，黄琉璃簟岸綸巾。", "平生不負楊臨賀，半夜誰呼祈孔賓。", "堪傲軒裳中酒聖，肯污筆硯論錢神。", "北山猿鶴應驚怪，已覺塵埃不可親。"]'),
('ace8407a-0656-4319-84b5-cb6671352329','又次韻  其一','方岳','宋','宋诗','song-poetry','','[]','半夜江城久已諳，白鷗眠處落烟帆。',64,'全唐诗/poet.song.212000.json','["半夜江城久已諳，白鷗眠處落烟帆。", "詩窮政有牛腰軸，身散寧爲馬口銜。", "時以酒澆胸磊磊，或嫌山似面巖巖。", "春田蕪沒歸耕是，待與豐年賦載芟。"]'),
('e301c40d-2a83-49d9-a78f-ec42b5610e96','又次韻  其二','方岳','宋','宋诗','song-poetry','','[]','綠陰政自可羸驂，舴艋何堪暑氣惔。',64,'全唐诗/poet.song.212000.json','["綠陰政自可羸驂，舴艋何堪暑氣惔。", "沙磧稍凉客且住，水程雖遠未須貪。", "吾儕焉往不三黜，此段無勞忍一慙。", "山際有田歸自好，休論暮四與朝三。"]'),
('38b13b3e-4d4c-4cce-8fab-2ae83a02abb2','風作','方岳','宋','宋诗','song-poetry','','[]','年光何啻蛇赴壑，仕宦略如魚上竿。',64,'全唐诗/poet.song.212000.json','["年光何啻蛇赴壑，仕宦略如魚上竿。", "疇昔本無溫飽志，歸來只作等閒看。", "人間萬事風濤急，雨外一蓑天地寬。", "潮落海門烟樹綠，舉頭已不見長安。"]'),
('bb9b3720-e0af-4d7b-93bf-a96745e50e3f','七夕潘宰招不往','方岳','宋','宋诗','song-poetry','','[]','投老歸歟拙獨存，剖瓜亦欲問天孫。',64,'全唐诗/poet.song.212000.json','["投老歸歟拙獨存，剖瓜亦欲問天孫。", "故人有約夜堂醉，老子不禁秋暑袢。", "却恐長繩縻日月，政須高枕問乾坤。", "北窗風好難爲客，未辨冠巾數候門。"]'),
('16c98891-f278-497f-8730-9885045e87dc','海棠  其一','方岳','宋','宋诗','song-poetry','','[]','半吐柔芳暖正妍，趁晴何不試籠鞭。',64,'全唐诗/poet.song.212000.json','["半吐柔芳暖正妍，趁晴何不試籠鞭。", "玉環醉矣春無頼，金屋貯之人孰賢。", "花比紅兒誰作譜，詩傳嬌客已成編。", "湘簾燕子人家月，一笑春風不計年。"]'),
('8edee82b-4d45-42ff-82dd-a641554a47a6','海棠  其二','方岳','宋','宋诗','song-poetry','','[]','黄州不識春風面，噲伍漫山桃李枝。',64,'全唐诗/poet.song.212000.json','["黄州不識春風面，噲伍漫山桃李枝。", "銀燭夜深粧額褪，錦屏睡足鬢絲垂。", "半醒半醉凌晨酒，幾雨幾晴寒食時。", "莫怨家人多命薄，緣愁却入老坡詩。"]'),
('9a7c5611-5c42-4d41-a0bb-6edc226951f8','用程兄韻奉諸公題跋還人','方岳','宋','宋诗','song-poetry','','[]','老硯生苔爾許時，誰憐官事落兒癡。',64,'全唐诗/poet.song.212000.json','["老硯生苔爾許時，誰憐官事落兒癡。", "江湖十載春無據，天地一舟歸有期。", "客有相從蝸殻語，詩來云受鶴山知。", "皮毛剝落惟真實，那用諸公絕妙辭。"]'),
('3e85ddd5-8e89-47bd-9385-e15a4fbad6d5','次韻鄉友','方岳','宋','宋诗','song-poetry','','[]','書生作計已差殊，況復真窮五技鼯。',64,'全唐诗/poet.song.212000.json','["書生作計已差殊，況復真窮五技鼯。", "空費寸陰酬急羽，還同斗米飽侏儒。", "鷗盟正爾隔千里，鶴夢何曾到九衢。", "茅屋春寒明月夜，梅花曾與寄聲無。"]'),
('3865db12-5772-445a-88d6-55ad75a328e1','次韻三四弟','方岳','宋','宋诗','song-poetry','','[]','入手功名不厭遲，政須努力莫傷悲。',64,'全唐诗/poet.song.212000.json','["入手功名不厭遲，政須努力莫傷悲。", "二難寧共姜肱被，一染誰憐墨子絲。", "仕宦金吾吾亦愛，饑寒玉汝汝當知。", "青燈夜寂聊參取，侑坐爲銘只此詩。"]'),
('110d801e-fc6a-4083-8c62-113ac653faf7','石孫偶中童科程弟有詩次韻','方岳','宋','宋诗','song-poetry','','[]','衰暮安能六出奇，桐孫頼有嶧陽枝。',64,'全唐诗/poet.song.212000.json','["衰暮安能六出奇，桐孫頼有嶧陽枝。", "九經庫謾無遺讀，千里駒寧不受羈。", "薄命久遭時俗態，此心莫倚老天知。", "待歸共買黄牛去，耕落煙村月一眉。"]'),
('79aead11-0720-4bf3-a111-aed58f24e356','花謝','方岳','宋','宋诗','song-poetry','','[]','駭綠紛紅醉欲沈，晚風不易阿環禁。',64,'全唐诗/poet.song.212000.json','["駭綠紛紅醉欲沈，晚風不易阿環禁。", "雙回姊弟瓊瑶面，獨試先生鐵石心。", "春事略如飛夢過，人生莫到受恩深。", "霓裳一曲今何在，不盡長吟復短吟。"]'),
('9a8246f3-a865-4963-8688-c1b6b80aef93','晚春','方岳','宋','宋诗','song-poetry','','[]','倦眼忽驚三月暮，杜鵑啼處綠陰多。',64,'全唐诗/poet.song.212000.json','["倦眼忽驚三月暮，杜鵑啼處綠陰多。", "春今且住爲佳耳，雨不能晴將奈何。", "紅紫只催人老大，蒼浪莫怨命蹉跎。", "貧中政自難留客，頼有詩情尚不磨。"]'),
('322dede0-2712-461e-a433-985d6b053729','遣興  其一','方岳','宋','宋诗','song-poetry','','[]','莫怨乘桴道不行，身方否處道方亨。',64,'全唐诗/poet.song.212000.json','["莫怨乘桴道不行，身方否處道方亨。", "大千世界愁中老，八萬障門嗔上生。", "了了不如都懡㦬，休休便是力修行。", "夜缸酒熟誰堪喚，共啜人間骨董羹。"]'),
('f3782673-0ab0-4e5e-9c95-a500240b7eef','遣興  其二','方岳','宋','宋诗','song-poetry','','[]','老去犂鋤易作勞，藤陰纔午卧衡茅。',64,'全唐诗/poet.song.212000.json','["老去犂鋤易作勞，藤陰纔午卧衡茅。", "鬚眉甚古松當戶，羽翼初成燕出巢。", "安所歸乎惟酒隠，宛其老矣只詩豪。", "忍窮不欠魚羹飯，每向人間笑獨高。"]'),
('affb113e-5932-44a0-94b0-a006fe61cb80','除夕  其一','方岳','宋','宋诗','song-poetry','','[]','生菜春盤草八珍，燈前殊未覺家貧。',64,'全唐诗/poet.song.212000.json','["生菜春盤草八珍，燈前殊未覺家貧。", "幾多荼壘中間事，第一屠蘇最後人。", "衰病不圖今夕健，須臾又是隔年春。", "東風自此無閒暇，萬里乾坤一夜新。"]'),
('4a812244-9e7f-465b-89e0-135441a05908','除夕  其二','方岳','宋','宋诗','song-poetry','','[]','梅花遶屋柳遮門，不是閭閻不是村。',64,'全唐诗/poet.song.212000.json','["梅花遶屋柳遮門，不是閭閻不是村。", "歸寄柴桑人自老，就荒松菊徑猶存。", "事關時命才何與，技止文章道未尊。", "燈火半生堪底用，只將黄犢教吾孫。"]'),
('c476cceb-e62f-4874-a068-c2269c834756','除夕  其三','方岳','宋','宋诗','song-poetry','','[]','一牛西崦又東臯，獨宿中年共作勞。',64,'全唐诗/poet.song.212000.json','["一牛西崦又東臯，獨宿中年共作勞。", "世事略如雲變滅，人生未抵玉堅牢。", "山林性氣與時背，霜雪髭鬚得酒豪。", "野屋難爲春帖子，自研冰雪寫離騷。"]'),
('64baefd2-9d2e-46a7-9523-51bde7a3166c','除夕  其四','方岳','宋','宋诗','song-poetry','','[]','當年意氣亦堪悲，歲晚胸懷只自知。',64,'全唐诗/poet.song.212000.json','["當年意氣亦堪悲，歲晚胸懷只自知。", "十有九分天不管，百無一遂老如期。", "燈寒夜雪漁蓬屋，春共梅花野竹籬。", "衰白東風那解綠，底須苦向鬢邊吹。"]'),
('130ef86a-8fd6-42fe-bf45-c5c86b24d14e','除夕  其五','方岳','宋','宋诗','song-poetry','','[]','薄薄村醪旋旋篘，一杯又了一年愁。',64,'全唐诗/poet.song.212000.json','["薄薄村醪旋旋篘，一杯又了一年愁。", "化爲道士前身鶴，驅向禪林露地牛。", "今我何如惟老圃，古人安在亦荒丘。", "牡丹且莫相孤負，已爲春風著小樓。"]'),
('d858d37c-da94-42ac-ac5f-308f87e30bf3','除夕  其六','方岳','宋','宋诗','song-poetry','','[]','一枝紫竹兩青鞋，只麽窮年亦自佳。',64,'全唐诗/poet.song.212000.json','["一枝紫竹兩青鞋，只麽窮年亦自佳。", "理亂不知閒世界，浮休自若老情懷。", "竹居可使食無肉，草具寧須菜與鮭。", "春入燈花供別歲，葛巾隨分對荆釵。"]'),
('a85c25c9-4148-4730-be09-0743c3f94be7','除夕  其七','方岳','宋','宋诗','song-poetry','','[]','家世無年事可知，況吾久矣嘆吾衰。',64,'全唐诗/poet.song.212000.json','["家世無年事可知，況吾久矣嘆吾衰。", "玉丸不住歲華老，鐵硯未穿筋力疲。", "一笛跨牛終寂寞，萬錢騎鶴兩參差。", "年年此夕椒花頌，能費先生幾首詩。"]'),
('05de7dba-9075-465f-903a-805f15d37880','除夕  其八','方岳','宋','宋诗','song-poetry','','[]','守歲團欒謝兩侯，堆盤水陸有珍投。',64,'全唐诗/poet.song.212000.json','["守歲團欒謝兩侯，堆盤水陸有珍投。", "鱘香透白瓊瑶片，蝦醉殷紅瑪瑙鈎。", "湩酪遠分閩嶠雪，枝柑猶带石橋秋。", "老饕兀兀陶陶外，一笑人間百事休。"]'),
('a45fc7d1-3f27-4b83-9ae4-a34415871907','除夕  其九','方岳','宋','宋诗','song-poetry','','[]','短髮蕭蕭老侍祠，夜壇三上華封辭。',64,'全唐诗/poet.song.212000.json','["短髮蕭蕭老侍祠，夜壇三上華封辭。", "皇儲天啟重輪日，帝座春環萬壽巵。", "材具不供當世用，林居亦望太平時。", "羽衣舞手香如霧，報答空餐但祝釐。"]'),
('2cad9bca-4f7a-46aa-83df-954859751cb8','除夕  其一○','方岳','宋','宋诗','song-poetry','','[]','追風逐月費攀躋，苒苒流光欲乳羝。',64,'全唐诗/poet.song.212000.json','["追風逐月費攀躋，苒苒流光欲乳羝。", "命薄最于窮鬼厚，氣高不爲貴人低。", "交情安得玉連瑣，世路真同鐵蒺藜。", "未及龍鍾且行樂，池塘吹綠又萋萋。"]'),
('3aa64a72-04af-442c-a178-fbe1b2506f45','府公徽猷餉酒蝦','方岳','宋','宋诗','song-poetry','','[]','長鬚翁卧甕頭春，醉不勝扶絕可人。',64,'全唐诗/poet.song.212000.json','["長鬚翁卧甕頭春，醉不勝扶絕可人。", "琥珀色濃紅透肉，珊瑚鈎嫩冷生津。", "欲酬野句不當價，粘出侯家總是珍。", "此法縱傳無此料，石橋雪水玉粼粼。"]'),
('cb35fd1f-a7dd-458c-9541-8203e0f9a28c','夜渴挑菜','方岳','宋','宋诗','song-poetry','','[]','酒醒山月欲侵樓，小摘園蔬雪滿溝。',64,'全唐诗/poet.song.212000.json','["酒醒山月欲侵樓，小摘園蔬雪滿溝。", "春入石爐然翠釜，濤翻銀海走青虬。", "十分脫出詩書味，一色本來風露秋。", "莫怪諸人難與語，滿腔元只爛羊頭。"]'),
('83a9e99c-b9fd-44e9-9260-c8c12ae4e430','祭詩','方岳','宋','宋诗','song-poetry','','[]','我生胡不辰，八齡失吾祖。',228,'全唐诗/poet.song.212000.json','["我生胡不辰，八齡失吾祖。", "今垂四十年，眉目略可覩。", "當時深根培，所望大門戶。", "岳也忝一科，遺餘曾不補。", "而乃輕濤江，飛檄淮南府。", "父兄肯相隨，薄飯共貧苦。", "寧知事大謬，俱作一抔土。", "去年汶素蹕，永痛松柏古。", "祿釜亦已矣，尚安事圭組。", "今年誤一出，竟犯時輩怒。", "去國不及炊，觸熱到環堵。", "無何七月望，新露灑秋宇。", "近郊有蘭若，梵唄薄雲雨。", "彼氓一念存，提携頗旁午。", "因果夫何如，亦各言恃怙。", "伊予祖父兄，超然定何許。", "然皆其忌月，悲豈不氓愈。", "齋盂饌伊蒲，從衆共傴僂。", "蓋以妄塞悲，有淚泚清酤。"]'),
('9fe6929e-ff09-45b7-8951-07a4feb1c737','用王深造韻觀射寄呈吳門吳侍郎','方岳','宋','宋诗','song-poetry','','[]','吳苑雲酣歌舞地，平時灞上真兒戲。',192,'全唐诗/poet.song.212000.json','["吳苑雲酣歌舞地，平時灞上真兒戲。", "府公槌鼓入轅門，盤馬彎弓士增氣。", "玉虬夜吼雙寶刀，曉霜冷透宮花袍。", "君王有意敵天驕，霹靂勁弦吾與操。", "滿月猶嫌無腕力，三軍鳴金齊破的。", "莫將電鏃驚飛翼，請射檄書青草礫。", "參旗井鉞光相摩，帳前萬疊轟靈鼉。", "呼韓要通作編戶，勿遣喘從榆塞過。", "鴈沙枯葉改凱歌，安得壯士翻銀河。", "三邊農桑俱偃武，將軍懶射南山虎。", "不須土訓喻遠人，天地中間悉臣主。", "文章四海吳狀元，那肯軍裝遽如許。"]'),
('5cfe47fd-94f4-4993-9978-6584a74d3417','拔灘','方岳','宋','宋诗','song-poetry','','[]','大灘嶅嶅，小灘嘈嘈。',110,'全唐诗/poet.song.212000.json','["大灘嶅嶅，小灘嘈嘈。", "石芒犖犖寧容刀，崩洪斗落與石鏖。", "風聲悲壯波聲豪，勢如萬馬之奔、羣熊之嗥。", "併船欲上牽縴牢，浪頭捲過船頭高。", "篙工翻身齊刺篙，蹈桅倒挂如飛猱。", "躋攀分寸相呼號，一落百尺爭秋毫。", "嗚呼行路難如此，若比出俗無波濤。"]'),
('9a941850-32ed-4914-a5a4-8de24922ece3','海棠落盡次謝司法韻  其一','方岳','宋','宋诗','song-poetry','','[]','花前誰與東西玉，但遣能詩一夔足。',64,'全唐诗/poet.song.212000.json','["花前誰與東西玉，但遣能詩一夔足。", "雨寒無奈雪飄零，酒醒却愁香陸續。", "阿嬌深貯黄金屋，阿環初出華清浴。", "騎䲔安得謫仙人，宮袍夜醉金蓮燭。"]'),
('721c3884-1991-4e50-913e-e7d0b3e0f6d7','海棠落盡次謝司法韻  其二','方岳','宋','宋诗','song-poetry','','[]','海棠寂寂香埋玉，山雨浪浪負歡足。',64,'全唐诗/poet.song.212000.json','["海棠寂寂香埋玉，山雨浪浪負歡足。", "閉門長憾虎頭癡，對客不供貂尾續。", "徑呼伯雅相拍浮，試坐毛錐三沐浴。", "滿身花片爲誰春，政欠太虛明月燭。"]'),
('7263ba63-423f-400f-b987-7a9f2b8d3c1b','大雷雨','方岳','宋','宋诗','song-poetry','','[]','黑雲壓山雨如鏃，霹靂火光龍起陸。',64,'全唐诗/poet.song.212000.json','["黑雲壓山雨如鏃，霹靂火光龍起陸。", "四壁淋漓風撼屋，一窗寒燈卧空谷。", "龍乎龍乎盍歸來，先生牀濕生青苔。", "未識青黄麥枯死，古語更占春甲子。"]'),
('2c82a94d-1f6f-484c-90c8-29a6742753a4','春暮','方岳','宋','宋诗','song-poetry','','[]','人生會有百年極，春事略無三日晴。',64,'全唐诗/poet.song.212000.json','["人生會有百年極，春事略無三日晴。", "豈惟坐隔海棠醉，亦未曾逐楊花行。", "綠樹陰陰遽如許，黄鳥飛飛寂無語。", "先生欲作送春詩，似此一春那用爾。"]'),
('06476845-3a64-4cdb-8112-f66162b0f2bf','題義約','方岳','宋','宋诗','song-poetry','','[]','向來祁山赭如天，邇來祁山翠如碧。',117,'全唐诗/poet.song.212000.json','["向來祁山赭如天，邇來祁山翠如碧。", "祁山草木皆精神，祁山人材方氣魄。", "君不見癸丑諸賢奉親策，武成殿前天咫尺。", "太微星動豹尾班，祁山人作龍頭客。", "所以天留老子山之側，爲守雲煙護山碧。", "山轉碧兮人轉奇，未許右科專此席。", "前頭更有文狀元，努力風鵬九霄翮。"]'),
('68ed60a8-f780-45da-8b4a-e2b04a932e1a','春蔭','方岳','宋','宋诗','song-poetry','','[]','玲瓏碧樹巧臨池，影在窗前作麽移。',64,'全唐诗/poet.song.212000.json','["玲瓏碧樹巧臨池，影在窗前作麽移。", "水墨畫圖春淡淡，鶯花庭院日遲遲。", "不妨明月重相憶，怎許浮雲浪得知。", "一片舞裀欹弱柳，風來時復托腰肢。"]'),
('c2fe1270-9577-4b0d-8fba-be58c089b34a','梅花','方岳','宋','宋诗','song-poetry','','[]','近看遥見總風標，不揀疏村自斷橋。',64,'全唐诗/poet.song.212000.json','["近看遥見總風標，不揀疏村自斷橋。", "大士定中蒙素衲，太真浴起却紅綃。", "別修花史爲題品，高倡離騷伴寂寥。", "歲晚道人心似鐵，愛香憐影尚魂銷。"]'),
('00542fd5-d70a-43ae-a8a1-a49a32c90919','巖桂花','方岳','宋','宋诗','song-poetry','','[]','誰遣秋風開此花，天香來自玉皇家。',32,'全唐诗/poet.song.212000.json','["誰遣秋風開此花，天香來自玉皇家。", "鬰金裳浥薔薇露，知是僊人萼綠華。"]'),
('ec76f1a9-6b1e-4e9b-b745-21562482c62c','芙蓉花','方岳','宋','宋诗','song-poetry','','[]','綠裳丹臉水芙蓉，不謂佳名偶自同。',64,'全唐诗/poet.song.212000.json','["綠裳丹臉水芙蓉，不謂佳名偶自同。", "一朵方酣初日色，千枝應發去年叢。", "莫驚墜露添新紫，更待微霜暈淺紅。", "却笑牡丹猶淺俗，但將濃艷醉春風。"]'),
('a05a5ea3-5a56-496c-8820-712aac0ebbe8','枇杷','方岳','宋','宋诗','song-poetry','','[]','擊碎珊瑚小作珠，鑄成金彈密相扶。',64,'全唐诗/poet.song.212000.json','["擊碎珊瑚小作珠，鑄成金彈密相扶。", "羅襦襟解春葱手，風露氣凉冰玉膚。", "並世身名楊氏子，舊家門戶北村盧。", "知音未必能知味，曾遣青衫淚濕無。"]'),
('1058a058-6d46-44de-a736-1d38dc4858e0','芭蕉','方岳','宋','宋诗','song-poetry','','[]','自是愁人愁不消，非干雨裏聽芭蕉。',32,'全唐诗/poet.song.212000.json','["自是愁人愁不消，非干雨裏聽芭蕉。", "芭蕉易去愁難去，移向梧桐轉寂寥。"]'),
('124fd286-d577-4333-a41d-a770d1a19a9f','式賢和杜夔府百韻過余秋崖下大篇舂容筆力遒勁于其歸也聊復效顰','方岳','宋','宋诗','song-poetry','','[]','林壑黄昏外，衡門紫翠邊。',288,'全唐诗/poet.song.212000.json','["林壑黄昏外，衡門紫翠邊。", "火耕今已老，雲卧幾何年。", "棋斂將殘局，篙回興盡船。", "畫麟真已矣，騎犢適悠然。", "野性難拘束，時情易變遷。", "獨携青玉杖，自拾錦囊篇。", "磊塊心逾小，崎嶇智未圓。", "別營三徑草，規作一壺天。", "紙帳嵐霏重，崖花雨滴偏。", "到頭新歲月，行脚舊山川。", "鶴冷通房宿，猿愁隔樹懸。", "菊餐金顥露，蘚當水衡錢。", "儘懶從吾睡，雖窮不受憐。", "半生資馬磨，三嘆向龍泉。", "霜檻千林瘦，春燈四壁穿。", "陰霾知病骨，寒意入詩肩。", "竹母誰分種，茶僧略具員。", "對山徐自遣，與世久無緣。", "風月於人厚，雲霄不爾便。", "接筩通暗溜，洗硯試輕烟。", "未暇思身後，何如了目前。", "閒爲真富貴，健是小神仙。", "夜磬番僧講，秋帆賈客傳。", "遠遊天漠漠，危誦水湲湲。"]'),
('110a0dbf-cd8c-4018-8680-d5ce4cc8ddd3','天基錫宴致語口號','方岳','宋','宋诗','song-poetry','','[]','春綠晴融太液池，好風都在萬年枝。',64,'全唐诗/poet.song.212000.json','["春綠晴融太液池，好風都在萬年枝。", "宮牆璆玉韶音遠，合殿珠環曉漏遲。", "天近六龍扶翠輦，雲深五鳳挾瑶池。", "鎬京長啟需雲宴，先奏端平第一詩。"]'),
('45e38a81-e659-4d2e-a91b-411c3ea139d0','王母望闕致語口號','方岳','宋','宋诗','song-poetry','','[]','曉蹕初催上壽班，東風連夜致人間。',64,'全唐诗/poet.song.212000.json','["曉蹕初催上壽班，東風連夜致人間。", "九重春醉金鸞殿，萬歲聲幽碧玉環。", "大地山河年穀熟，太平日月羽書閑。", "明朝第一番花吉，併與瓊幡下虎關。"]'),
('e2a3559b-a375-4e47-8de7-1d9b36f23ff0','趙制使宴吳宣參致語口號','方岳','宋','宋诗','song-poetry','','[]','二老風襟了不群，笑談自可却塵氛。',64,'全唐诗/poet.song.212000.json','["二老風襟了不群，笑談自可却塵氛。", "詞臣舊奏平淮頌，里老今傳諭蜀文。", "吳國隠然如一敵，趙邊足以張三軍。", "英辭整頓乾坤酒，捷羽飛來共策勳。"]'),
('a1fd8580-49b9-49f4-b339-6d46f15d35d2','邵武宴瞿通判致語口號','方岳','宋','宋诗','song-poetry','','[]','肯駕緹屏入古樵，熙春山更綠岧嶤。',64,'全唐诗/poet.song.212000.json','["肯駕緹屏入古樵，熙春山更綠岧嶤。", "人如第二泉清冷，路亦無多秋泬寥。", "碧色玻璃供笑語，黄雲䆉稏入歌謠。", "山城斗大能留否，見說弓旌有特招。"]'),
('19d6d4eb-0adc-4a32-b373-29db840bb03b','南康宴考試官致語口號','方岳','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山誰與主文盟，入得光芒北斗星。',64,'全唐诗/poet.song.212000.json','["廬山誰與主文盟，入得光芒北斗星。", "筆可補天親奏賦，芥如拾地久明經。", "諸賢等是良眉白，五色難迷老眼青。", "來歲不妨連舉送，編排詳定又彤庭。"]'),
('43aa8768-95bf-4586-b39e-3cf1f0ca9e7a','邵武宴進士致語口號','方岳','宋','宋诗','song-poetry','','[]','禮樂當年魯兩生，一經科目共春城。',64,'全唐诗/poet.song.212000.json','["禮樂當年魯兩生，一經科目共春城。", "數回地脈中興相，文動天家正奏名。", "詔墨泥香題處濕，恩袍草色坐中明。", "莫嫌老守衰遲甚，曾向慈恩頂上行。"]'),
('7b8ca13a-d482-451c-8a3b-49f15a6fdc1d','隔牆梅','方岳','宋','宋诗','song-poetry','','[]','寂寂度年光，堅貞玉雪香。',24,'全唐诗/poet.song.212000.json','["寂寂度年光，堅貞玉雪香。", "冶容誰氏子，終日傍垂楊。"]'),
('2e988b12-c92b-4d3d-88d2-b296e576d887','萱','方岳','宋','宋诗','song-poetry','','[]','憶被萊子服，種汝奉高堂。',24,'全唐诗/poet.song.212000.json','["憶被萊子服，種汝奉高堂。", "汝自忘憂爾，吾憂未易忘。"]'),
('81c375a0-79ae-4913-9557-0dd237269db1','杏','方岳','宋','宋诗','song-poetry','','[]','馬令園中本，移來村墅中。',24,'全唐诗/poet.song.212000.json','["馬令園中本，移來村墅中。", "太官令却獻，黄帕不來封。"]'),
('dd9df4b6-1e19-4b8d-b1e3-4c447785f445','郡齋即事  其一','方岳','宋','宋诗','song-poetry','','[]','一筇五老幾相携，吟得詩成竟未題。',32,'全唐诗/poet.song.212000.json','["一筇五老幾相携，吟得詩成竟未題。", "易地不干渠輩事，樵夫只合管樵溪。"]'),
('102c418a-72b1-4d9f-8735-d59ef8ffd94b','郡齋即事  其二','方岳','宋','宋诗','song-poetry','','[]','高下黄雲䆉稏秋，眼中一飽失千憂。',32,'全唐诗/poet.song.212000.json','["高下黄雲䆉稏秋，眼中一飽失千憂。", "雌堂自是無龔遂，莫怪耕桑人带牛。"]'),
('2d44d23c-2616-4132-8647-5e3d67295110','郡齋即事  其三','方岳','宋','宋诗','song-poetry','','[]','王淵換得玉爲環，非夢蓬萊幾日間。',32,'全唐诗/poet.song.212000.json','["王淵換得玉爲環，非夢蓬萊幾日間。", "珍重君王能記憶，予麾猶得道家山。"]'),
('96f1ea89-ac97-43a3-b770-594ce0b0fad9','用鄭少傅韻題趙參政梅卷','方岳','宋','宋诗','song-poetry','','[]','雪谷冰崖枯槁士，土銼無煙寒墮指。',240,'全唐诗/poet.song.212000.json','["雪谷冰崖枯槁士，土銼無煙寒墮指。", "朝饑鬰屈鳴不平，烏玉磨雲翻硯水。", "花光若朽補之窮，吐作冷花春几几。", "相公折箠笞神兵，肯與此輩爭詩名。", "橫梢噀墨偶然爾，別有妙處賢長城。", "單于吹葉遠關塞，張我大漢之天聲。", "老生經濟知無術，爾雅蟲魚寧閣筆。", "巖廊有此磊落人，安事儒士嘔心出。", "吾文不在奴僕騷，爾曹政可衙官屈。", "所懷浩蕩同元工，寧比八九吞雲夢。", "銘常勒鼎勳業在，未可枯木窺坡翁。", "謹勿閑揮補天手，且挈一世春風中。", "軍書夜下飛如射，彼蠢者胡猶梗化。", "梅花嶺外有傳聞，老我毛寒足驚咤。", "神樞凈洗甲兵腥，瘴月蠻烟亦堪畫。"]'),
('8e527d7b-4d63-432f-8682-9bc20532cacf','癸丑人日','方岳','宋','宋诗','song-poetry','','[]','上七日爲人，雲蒸澗壑春。',48,'全唐诗/poet.song.212000.json','["上七日爲人，雲蒸澗壑春。", "入山從此始，得句不知貧。", "宿雨行泉脈，歸禽隠樹身。", "無人閑似我，野薺共時新。"]'),
('8468cfe5-9c58-4bce-9c8c-fee55beca94d','壽教授  其一','方岳','宋','宋诗','song-poetry','','[]','昨夜長庚爛瑞光，間生賢於應明昌。',64,'全唐诗/poet.song.212000.json','["昨夜長庚爛瑞光，間生賢於應明昌。", "風雲際會當千載，天地交通復一陽。", "曾播聲名題雁塔，暫時文柄坐鱣堂。", "慶闈雅燕笙歌徹，紫詔催歸侍玉皇。"]'),
('e42452a2-eddf-468f-9150-bb7ba1fff9a1','壽教授  其二','方岳','宋','宋诗','song-poetry','','[]','精神天上石麒麟，器業無雙間世人。',64,'全唐诗/poet.song.212000.json','["精神天上石麒麟，器業無雙間世人。", "欲展經綸趨北闕，暫將去範董南閩。", "綵衣戲處勸聲溢，絳帳開時瑞氣新。", "虔祝我公難老壽，八千爲歲比莊椿。"]'),
('60c17ba0-fe2a-49ce-8878-056ce6baa19b','禮斗石','方岳','宋','宋诗','song-poetry','','[]','一方蒼石老莓苔，只合淵明共酒杯。',32,'全唐诗/poet.song.212000.json','["一方蒼石老莓苔，只合淵明共酒杯。", "歲晚出山成底事，至今笙鶴不歸來。"]'),
('3fdec905-ba68-45b3-ba0f-073fdc79f8bb','月巖','方岳','宋','宋诗','song-poetry','','[]','怪石堆雲矗大空，女媧鍊出廣寒宮。',64,'全唐诗/poet.song.212000.json','["怪石堆雲矗大空，女媧鍊出廣寒宮。", "一輪常滿陰晴見，萬古無虧晝夜同。", "搗藥聲繁驅白兔，漏天孔正透清風。", "光明自照如來境，肯學姮娥西復東。"]'),
('29695a1e-a185-449f-80f9-fd7b92fef323','句  其一','方岳','宋','宋诗','song-poetry','','[]','林暝鳥呼雨，徑深童掃雲。',12,'全唐诗/poet.song.212000.json','["林暝鳥呼雨，徑深童掃雲。"]'),
('270a3c8e-223f-4b86-abcd-e70f670155f5','句  其二','方岳','宋','宋诗','song-poetry','','[]','一錢太守今貪吏，五柳先生歙富民。',16,'全唐诗/poet.song.212000.json','["一錢太守今貪吏，五柳先生歙富民。"]'),
('4a0d4aa2-6c16-4343-9853-e171f2bf4595','存目','方岳','宋','宋诗','song-poetry','','[]','詩題：蕨菜首句：真人宮（官）府未因緣。',19,'全唐诗/poet.song.212000.json','["詩題：蕨菜首句：真人宮（官）府未因緣。"]'),
('218af118-2e2a-442b-9827-6aa324326bc8','句','趙宰父','宋','宋诗','song-poetry','','[]','野水多於地，春山半是雲。',12,'全唐诗/poet.song.212000.json','["野水多於地，春山半是雲。"]'),
('a527c1c1-519e-46df-9a90-4a03e78bce8e','句','汪聖權','宋','宋诗','song-poetry','','[]','不分桂籍一毫月，枉踏槐花十八秋。',16,'全唐诗/poet.song.212000.json','["不分桂籍一毫月，枉踏槐花十八秋。"]'),
('3a4281aa-2299-496d-b5cd-bbf612eddd7f','句  其一','釋淨照','宋','宋诗','song-poetry','','[]','盤饌春多筍，厨薪溼带苔。',12,'全唐诗/poet.song.212000.json','["盤饌春多筍，厨薪溼带苔。"]'),
('3563fadc-f04f-412a-9814-aec9b3645c15','句  其二','釋淨照','宋','宋诗','song-poetry','','[]','雲歸大似諳風勢，水咽多應恨世情。',16,'全唐诗/poet.song.212000.json','["雲歸大似諳風勢，水咽多應恨世情。"]'),
('c094c057-d708-489d-8c6a-11edb8845bcb','雨阻秦溪宿馬養拙林下','孫銳','宋','宋诗','song-poetry','','[]','櫂入江村暮，扣門求友生。',48,'全唐诗/poet.song.212000.json','["櫂入江村暮，扣門求友生。", "青衫新鹿夢，白髮舊鷗盟。", "巷僻苔痕滑，林深鳥舌清。", "共尋物外味，溪上老漁聲。"]'),
('ede23930-6edb-4e86-9ce1-e7fba14a7154','壽楊廣文六十解組南還時署邑篆事','孫銳','宋','宋诗','song-poetry','','[]','五載琴堂奏未央，烏紗紫綬鬢蒼蒼。',64,'全唐诗/poet.song.212000.json','["五載琴堂奏未央，烏紗紫綬鬢蒼蒼。", "三鱣已集弘農兆，五柳仍分彭澤芳。", "廉石一車歸吏部，清風兩袖付中郎。", "山間甲子君知否，好向關西卧夕陽。"]'),
('0711202c-22f1-44b0-b3e2-182626fdd758','過震澤別業次壁間韻','孫銳','宋','宋诗','song-poetry','','[]','一櫂烟波震澤空，筆牀茶竈滿清風。',32,'全唐诗/poet.song.212000.json','["一櫂烟波震澤空，筆牀茶竈滿清風。", "桑磐自是君家味，何羨區區涪上翁。"]'),
('eb9ab9ff-31c4-45a2-85b4-660226ae7219','漁父詞和玄真子','孫銳','宋','宋诗','song-poetry','','[]','平湖千頃浪花飛，春後銀魚霜更肥。',32,'全唐诗/poet.song.212000.json','["平湖千頃浪花飛，春後銀魚霜更肥。", "菱葉飯，蘆花衣，酒酣載月忙呼歸。"]'),
('88bade3e-30b2-4aed-9600-2bb085e96def','得家書和陶淵明問來使作','孫銳','宋','宋诗','song-poetry','','[]','我家平湖邊，碧水豁清目。',48,'全唐诗/poet.song.212000.json','["我家平湖邊，碧水豁清目。", "兒讀誰氏書，庭開幾株菊。", "綠筍可曾抽，銀魚想當馥。", "爾歸語細君，滌圃秫須熟。"]'),
('cc624529-0d65-40a0-9b0f-fa857e9cb123','上元夜送沈伯時赴南康山長','孫銳','宋','宋诗','song-poetry','','[]','十載從遊吾道南，山齋苜蓿澹于甘。',64,'全唐诗/poet.song.212000.json','["十載從遊吾道南，山齋苜蓿澹于甘。", "飛魚想得三台兆，待雪空餘□丈函。", "席冷幾番馴白鹿，羅傳此夜賦黄柑。", "太平不日經筵召，好把鱗書早晚探。"]'),
('9dd18ed7-c287-4c06-8604-7846f8dba2f2','四景圖 荻塘柳影','孫銳','宋','宋诗','song-poetry','','[]','日出烟消春晝遲，柳條無力萬絲垂。',32,'全唐诗/poet.song.212000.json','["日出烟消春晝遲，柳條無力萬絲垂。", "韶光新染鵝黄色，偏愛東風款款吹。"]'),
('c4514416-0f8b-470f-8db4-46266dbd60cb','四景圖 禪院風荷','孫銳','宋','宋诗','song-poetry','','[]','碧筒注酒晚風凉，澆得新詩字字香。',32,'全唐诗/poet.song.212000.json','["碧筒注酒晚風凉，澆得新詩字字香。", "吟罷臨風開佛座，撚花笑指浴鴛鴦。"]'),
('d7d75fcd-9693-4e7d-98a4-9dcde8d15f57','四景圖 平湖秋月','孫銳','宋','宋诗','song-poetry','','[]','月浸寒泉凝不流，櫂歌何處泛歸舟。',32,'全唐诗/poet.song.212000.json','["月浸寒泉凝不流，櫂歌何處泛歸舟。", "白蘋紅蓼西風裏，一色湖光萬頃秋。"]'),
('f7fcdc0b-6c2a-4ed7-83f6-a7f406373ce5','四景圖 仙磯晴雪','孫銳','宋','宋诗','song-poetry','','[]','湖天雪景弄朝暉，清徹如雲散雨衣。',32,'全唐诗/poet.song.212000.json','["湖天雪景弄朝暉，清徹如雲散雨衣。", "肌骨已隨雲影去，玄真仙代竟忘歸。"]'),
('24a8a4d8-8ec2-4e05-8685-41acd312e514','耀武亭別周申團練','孫銳','宋','宋诗','song-poetry','','[]','湖光一片綺筵開，老矣將軍去復來。',64,'全唐诗/poet.song.212000.json','["湖光一片綺筵開，老矣將軍去復來。", "漫說風塵輕似葉，豈教笳鼓動如雷。", "悲歌氣噴三河少，武略功高八陣才。", "平望塞亭曾耀武，漢家空數單于臺。"]'),
('0a3e5ea2-8aaf-494b-b09a-28dc2143c001','避虜入洞庭','孫銳','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朔風一夜渡江村，北望雲飛不忍言。',64,'全唐诗/poet.song.212000.json','["朔風一夜渡江村，北望雲飛不忍言。", "仙隠老尋雙橘柚，避秦人愛小桃源。", "烟波亂逐鴟夷舸，烽火遥騰馬僨轅。", "聞道此山真福地，不知何處更離魂。"]'),
('8bec20be-a629-4cc3-84c1-1d8739219138','三高祠 鴟夷子皮','孫銳','宋','宋诗','song-poetry','','[]','苧蘿仙子總無雙，一櫂烟波氣未降。',32,'全唐诗/poet.song.212000.json','["苧蘿仙子總無雙，一櫂烟波氣未降。", "如何鑄像勞臣節，却是吳江非越江。"]'),
('1bf52a31-1300-4e09-9759-c91ee619012a','三高祠 江東步兵','孫銳','宋','宋诗','song-poetry','','[]','秋風不爲紫鱸香，適志徒勞夢水鄉。',32,'全唐诗/poet.song.212000.json','["秋風不爲紫鱸香，適志徒勞夢水鄉。", "惟是此生一杯酒，宦情無日不滄浪。"]'),
('1d51f85e-34fd-4d0e-87e0-d1072d290329','三高祠 甫里先生','孫銳','宋','宋诗','song-poetry','','[]','數頃荒田負郭耕，筆牀茶竈看鋤雲。',32,'全唐诗/poet.song.212000.json','["數頃荒田負郭耕，筆牀茶竈看鋤雲。", "一琖清泉薦秋菊，不知何處弔參軍。"]'),
('3579ec6a-f649-4324-a032-1adcf415c670','早朝','孫銳','宋','宋诗','song-poetry','','[]','燭光劍珮擁千官，載月臨軒拜紫鑾。',64,'全唐诗/poet.song.212000.json','["燭光劍珮擁千官，載月臨軒拜紫鑾。", "仙掌禁寒承露穩，天顔霽曉傍雲看。", "朝陽鳴鳳諧宮律，滄海□鰲獻羽翰。", "咫尺聖明三舞蹈，報恩豈敢負彈冠。"]'),
('07abf03e-6cf8-4a5d-84f7-2cda241923a1','從軍行','孫銳','宋','宋诗','song-poetry','','[]','邊笳動地吹，鐵衣寒未卸。',24,'全唐诗/poet.song.212000.json','["邊笳動地吹，鐵衣寒未卸。", "壯士塚纍纍，骨香千載下。"]'),
('205d6982-b21d-4fd7-80ad-8f9539cf92b6','雲長公贊','孫銳','宋','宋诗','song-poetry','','[]','千載人，百世士。',48,'全唐诗/poet.song.212000.json','["千載人，百世士。", "知正統，明大義。", "漢丞相，蜀先主。", "同公心，燭三光。", "爲岳瀆，爲星雲。", "今不死，髯將軍。"]'),
('9ff34646-62bd-411c-a7e1-efa643862fb5','湖湄閒適二首  其一','孫銳','宋','宋诗','song-poetry','','[]','荻花塘外老漁家，夜夜湖邊倚釣槎。',32,'全唐诗/poet.song.212000.json','["荻花塘外老漁家，夜夜湖邊倚釣槎。", "打起秋風魚數尾，調羹儘可薦胡麻。"]'),
('4782e02d-9518-4720-9122-f38f724b70e3','湖湄閒適二首  其二','孫銳','宋','宋诗','song-poetry','','[]','推窗笑指浣溪紗，點點飛鷗拍浪沙。',32,'全唐诗/poet.song.212000.json','["推窗笑指浣溪紗，點點飛鷗拍浪沙。", "儂自有心禽解語，拋磚水激落天涯。"]'),
('b149a220-10dc-418a-a70e-8e9b26e88eb9','虜警','孫銳','宋','宋诗','song-poetry','','[]','載將傾國爾爲真，我夢扁舟作比鄰。',80,'全唐诗/poet.song.212000.json','["載將傾國爾爲真，我夢扁舟作比鄰。", "今日避兵真是夢，可知夙世有奇因。", "五湖烟水罨如畫，鴟夷老子舍其下。", "千秋聲氣夢相通，此地居停爾當借。", "仙乎仙乎與世忘，何年歸老耕閒堂。"]'),
('099592db-91cb-41ec-ac9e-5cca3b65f62b','殊勝院柬悟雪禪人','孫銳','宋','宋诗','song-poetry','','[]','百年蕭寺古雲間，五夜焚修晝掩關。',64,'全唐诗/poet.song.212000.json','["百年蕭寺古雲間，五夜焚修晝掩關。", "雪嶺衣傳方丈室，虎丘石點可中山。", "天開罨黛成仙境，地接琉璃映佛顔。", "我亦挂冠爲弟子，同參肯許是耕閒。"]'),
('3e1f5b83-1799-4d9b-bf03-f8b1b6f12cc9','楊學士廷秀過訪','孫銳','宋','宋诗','song-poetry','','[]','握手別君東渡，銜杯當我西歸。',28,'全唐诗/poet.song.212000.json','["握手別君東渡，銜杯當我西歸。", "少微星動百里，彈冠亦屬忘機。"]'),
('2eef2112-e7ed-47e3-bce0-88ad9b1df6a1','石湖別墅','孫銳','宋','宋诗','song-poetry','','[]','一水遥通西渡頭，亂山零落樹還稠。',32,'全唐诗/poet.song.212000.json','["一水遥通西渡頭，亂山零落樹還稠。", "先生唱罷村田樂，戴月披蓑理釣舟。"]'),
('65728b98-18e4-41b6-bb2e-c8fccfc14524','兵火','孫銳','宋','宋诗','song-poetry','','[]','胡馬倏南侵，羶塵夜犯心。',48,'全唐诗/poet.song.212000.json','["胡馬倏南侵，羶塵夜犯心。", "喪魚索枯肆，倒屣問焦琴。", "狼烟乘慘勢，鬼燐带愁吟。", "廬舍人無幾，還家何處尋。"]'),
('45ac9cd1-8688-4832-8cde-cc37aa457ade','桑磐贈趙隠居','孫銳','宋','宋诗','song-poetry','','[]','湖南茅屋裏，避世隠牆東。',48,'全唐诗/poet.song.212000.json','["湖南茅屋裏，避世隠牆東。", "瀹茗知泉味，栽桑助女工。", "高歌牛背笛，穩櫂艇頭風。", "憶昔天隨子，相逢樂在中。"]'),
('34d83e42-7133-4e47-813c-3cb7ab98433e','湖中蜆蚌甚佳村婦調羹名曰水菜余珍嗜之作水羹吟','孫銳','宋','宋诗','song-poetry','','[]','春風一夜浪花起，大蚌小蚌浮江沚。',112,'全唐诗/poet.song.212000.json','["春風一夜浪花起，大蚌小蚌浮江沚。", "漁蓑撒網唶嚄音，滿載論斗不論斤。", "寄語庖厨煮白湯，脫殻擊肉和椒漿。", "爛蒸鮮美波臣選，傾壺潑麵供早膳。", "調羹娘子善刀藏，尚方滋味何分辯。", "不須更說毳與皛，江南水菜人知少。", "總道奇哉君善烹，明日餉君君當擾。"]'),
('ce6473f9-3fda-4261-82eb-6b3a8f3c691a','楊郡王還鄉','孫銳','宋','宋诗','song-poetry','','[]','貤恩乘傳別金鑾，老大門楣翠鳳冠。',64,'全唐诗/poet.song.212000.json','["貤恩乘傳別金鑾，老大門楣翠鳳冠。", "咫尺玉階沾露後，尚方丹詔落雲端。", "新諧甥舅瞻蒲璧，世篤明良灑紫翰。", "遥拜聖明歸梓里，望風父老笑歌歡。"]'),
('93c089d9-748c-4f58-b6c8-504d0b8bdddd','孔明八陣石','孫銳','宋','宋诗','song-poetry','','[]','八陣圖磯天下奇，無端變化出山時。',32,'全唐诗/poet.song.212000.json','["八陣圖磯天下奇，無端變化出山時。", "要知抱膝南陽卧，早了三分一局棋。"]'),
('cf970280-cc75-4175-80d9-a6981070c574','長干送別','孫銳','宋','宋诗','song-poetry','','[]','君子于行東渡頭，江村烟雨看眠鷗。',64,'全唐诗/poet.song.212000.json','["君子于行東渡頭，江村烟雨看眠鷗。", "秋風不借游山屐，客夢長呼問酒樓。", "八斗才憐新鶴髮，十千囊盡敝貂裘。", "不須刎頸酬知己，一曲琵琶在遠舟。"]'),
('3d2cd242-a22d-4e83-95d3-7f34bc231f3f','泊平望弔玄真子','孫銳','宋','宋诗','song-poetry','','[]','仙非勝地仙不昇，地非仙跡地不靈。',319,'全唐诗/poet.song.212000.json','["仙非勝地仙不昇，地非仙跡地不靈。", "古今絕勝天下景，多爲羽客梯雲軿。", "松江之南平望驛，千古清名垂載籍。", "遺基廢井雖不存，依舊湖光接天碧。", "我聞在昔張玄真，平生活計一釣綸。", "浮家泛宅戲人世，龜魚爲友蒹葭鄰。", "故人分符刺苕水，東遊歷遍溪山美。", "翩然聯璧至此鄉，回視塵寰如敝屣。", "酒酣水戲身甚輕，席行水面同舟聲。", "祥雲瑞鶴然至，泛此凌空歸太清。", "西塞山邊飛白鷺，其間儘有朝元路。", "綠蓑平日恣遨遊，何忍臨岐弗相顧。", "爭知萬頃玻璃中，清都紫府遥相通。", "故來成此一奇事，欲將名姓傳無窮。", "風帆過後沙鳥墜，靈跡雖存人不記。", "白蘋紅蓼自爭妍，誰識此爲真福地。", "何人好事能揮金，結廬繪像湖之陰。", "寒泉一盞薦秋菊，往來不負詩人心。", "玄真今在天何處，獨立河梁望飈馭。", "丹臺玉籍若相容，携手乘風共歸去。"]'),
('0af586b6-7fcf-4997-9dd4-1b87b4217998','偈頌一百二十三首  其一','釋普度','宋','宋诗','song-poetry','','[]','前不搆店，後不迭村。',34,'全唐诗/poet.song.212000.json','["前不搆店，後不迭村。", "當陽坐斷，上下平分。", "更看直透雲霄之頂，獨步乾坤。"]'),
('04222c06-c879-40db-ad28-9dbd6a10c451','偈頌一百二十三首  其二','釋普度','宋','宋诗','song-poetry','','[]','悟道染泥沙，佛祖生冤家。',32,'全唐诗/poet.song.212000.json','["悟道染泥沙，佛祖生冤家。", "新半山爲甚燒香禮拜，明珠絕纇，皓玉無瑕。"]'),
('818945b0-eb15-49e2-b095-db3b638ccd40','偈頌一百二十三首  其三','釋普度','宋','宋诗','song-poetry','','[]','有主有賓，無疎無親。',29,'全唐诗/poet.song.212000.json','["有主有賓，無疎無親。", "直饒七佛到來。", "各與三十拄杖，少喜多嗔。"]'),
('171ff7b4-c504-4c6f-b361-a914f90477f7','偈頌一百二十三首  其四','釋普度','宋','宋诗','song-poetry','','[]','一佛出世，千佛讚揚。',38,'全唐诗/poet.song.212000.json','["一佛出世，千佛讚揚。", "十方坐斷，獨露真常。", "山蒼蒼，雲蒼蒼。", "半開半合，隠顯全彰。"]'),
('7bc962c4-5f1c-41e2-b395-c3cba58dc22d','偈頌一百二十三首  其五','釋普度','宋','宋诗','song-poetry','','[]','拄杖子，無向背。',33,'全唐诗/poet.song.212000.json','["拄杖子，無向背。", "東拄西撐，登山涉海。", "卞璧驪珠，泥團土塊，一時粉碎。"]'),
('38d2eec3-d36d-4a5d-bf5e-8aa85a147b77','偈頌一百二十三首  其六','釋普度','宋','宋诗','song-poetry','','[]','雨滌炎威，秋雲自在。',74,'全唐诗/poet.song.213000.json','["雨滌炎威，秋雲自在。", "一片兩片拄杖頭，或卷或舒林木外。", "白璧明珠，泥團土塊。", "放去收來顆顆圓，填溝塞壑無人會。", "阿呵呵，六隻骰子滿盆紅，有采無采，大家別賽。"]'),
('8fef2331-911a-490a-8ea8-be537ba4017a','偈頌一百二十三首  其七','釋普度','宋','宋诗','song-poetry','','[]','說禪說道，撒土撒沙，半山終不也隨邪。',34,'全唐诗/poet.song.213000.json','["說禪說道，撒土撒沙，半山終不也隨邪。", "重陽定在九月九，東籬何處無黄花。"]'),
('48004bdc-8553-46a0-9948-460de7d9341f','偈頌一百二十三首  其八','釋普度','宋','宋诗','song-poetry','','[]','龍門萬仞，到者還稀。',20,'全唐诗/poet.song.213000.json','["龍門萬仞，到者還稀。", "不犯清波，如何進步。"]'),
('ca1693e6-3c21-4f04-b7f5-8e5aff3532e8','偈頌一百二十三首  其九','釋普度','宋','宋诗','song-poetry','','[]','前佛性命，後佛紀綱。',28,'全唐诗/poet.song.213000.json','["前佛性命，後佛紀綱。", "開口即喪，閉口即錯。", "瘥病不假馿駝藥。"]'),
('e0a9a667-af33-4ee0-ae80-722e0752cd78','偈頌一百二十三首  其一○','釋普度','宋','宋诗','song-poetry','','[]','毫末非輕，丘山非重。',30,'全唐诗/poet.song.213000.json','["毫末非輕，丘山非重。", "按佛祖雲頭，穿衲僧鼻孔，剖破方知無罅縫。"]'),
('72a98e1e-26f0-4129-af7e-fb73d3f73f0e','偈頌一百二十三首  其一一','釋普度','宋','宋诗','song-poetry','','[]','破沙盆，沒巴鼻，盡大地人扶持不起。',51,'全唐诗/poet.song.213000.json','["破沙盆，沒巴鼻，盡大地人扶持不起。", "玉山路上，荆棘參天。", "鍾阜山前，清風匝地。", "擘破寶公面皮，德雲無處回避。"]'),
('2b7168be-cee8-49f6-8198-31dd0c7ce11f','偈頌一百二十三首  其一二','釋普度','宋','宋诗','song-poetry','','[]','十五日已前，只許老胡知，不許老胡會。',74,'全唐诗/poet.song.213000.json','["十五日已前，只許老胡知，不許老胡會。", "十五日已後，只許老胡會，不許老胡知。", "正當十五日，會不會，知不知。", "風細細，日遲遲。", "不惜黄金爲彈子，牡丹花下打黄鸝。"]'),
('df6bc98b-0af3-4ba7-ab5e-b2fe658bb17b','偈頌一百二十三首  其一三','釋普度','宋','宋诗','song-poetry','','[]','大海揚塵，高源出水。',60,'全唐诗/poet.song.213000.json','["大海揚塵，高源出水。", "狹路相逢，知心有幾。", "明明玉鑑光中，浩浩煙波萬里。", "鸑鷟擎頭，金鱗擺尾。", "江北江南絕望時，一聲霹靂清飈起。"]'),
('2eb4f494-ba0e-466b-ae20-1f0e6972ec73','偈頌一百二十三首  其一四','釋普度','宋','宋诗','song-poetry','','[]','推不去，挽不來。',56,'全唐诗/poet.song.213000.json','["推不去，挽不來。", "南天台，北五臺。", "大地寥寥兮何者當情，春風浩浩兮雨打莓苔。", "見成公案，不涉安排，豈在見桃花而後眼開。"]'),
('336c40b2-f5be-491c-85ec-eb28a13aa021','偈頌一百二十三首  其一五','釋普度','宋','宋诗','song-poetry','','[]','雲收海山橫，月印江天曉。',40,'全唐诗/poet.song.213000.json','["雲收海山橫，月印江天曉。", "擾擾紅塵中，青春有多少。", "鐵壁銀山一拶開，落花流水空徘徊。"]'),
('2baec924-683e-497c-a446-388c90a94c82','偈頌一百二十三首  其一六','釋普度','宋','宋诗','song-poetry','','[]','今朝五月五，諸方盡鳴皷。',45,'全唐诗/poet.song.213000.json','["今朝五月五，諸方盡鳴皷。", "不說藥病相治，便說書符呪士。", "金山伎倆既無，未免別行一路。", "日輪當午。"]'),
('5dab23da-3d43-4449-9e66-cdd0f5cf54fa','偈頌一百二十三首  其一七','釋普度','宋','宋诗','song-poetry','','[]','一見便見，一得永得。',70,'全唐诗/poet.song.213000.json','["一見便見，一得永得。", "四邊界至，故是分明。", "一寸筆頭，萬鈞之力。", "三十年異苗飜茂，千萬古中流偉勣。", "阿呵呵，知不知，青氈元是吾家物，好看金牛作舞時。"]'),
('c663a720-9691-4249-852c-8282f2e84100','偈頌一百二十三首  其一八','釋普度','宋','宋诗','song-poetry','','[]','火雲影裡一葉落，玉鑑光中便見秋。',66,'全唐诗/poet.song.213000.json','["火雲影裡一葉落，玉鑑光中便見秋。", "一任秋來又秋去，大江依舊向東流。", "無變易，有來由。", "塞鴻何處，白鷺滄洲。", "數聲漁笛煙村晚，狼藉斷霞閑釣舟。"]'),
('2cb5b64b-692c-457b-af53-98c80b625075','偈頌一百二十三首  其一九','釋普度','宋','宋诗','song-poetry','','[]','雨洗炎威，秋磨霄漢。',38,'全唐诗/poet.song.213000.json','["雨洗炎威，秋磨霄漢。", "風傳䆉稏香，鴈腹寒岩畔。", "位轉功回木馬嘶，劫外不須重借伴。"]'),
('c2e65c16-207e-45c5-9af3-dcb0583849d0','偈頌一百二十三首  其二○','釋普度','宋','宋诗','song-poetry','','[]','布袋頭開天地大，翠岩眉毛在不在。',32,'全唐诗/poet.song.213000.json','["布袋頭開天地大，翠岩眉毛在不在。", "一聲鴻鴈海門秋，行人已在青山外。"]');
